window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-002.json"] = [{"name":"沼泽鹧鸪","english_name":"Swamp Francolin","scientific_name":"Ortygornis gularis","overview":"沼泽鹧鸪（英文名：Swamp Francolin，学名：Ortygornis gularis），是鸡形目雉科 Ortygornis 属的鸟类。体型较大的鹧鸪，以橙色喉部和白色条纹下体为显著特征。分布于印度北部、尼泊尔至孟加拉国，尤其偏爱恒河和布拉马普特拉河流域的湿地环境。","appearance":"成年雄性沼泽鹧鸪长约36-38厘米，重约510克，拥有鲜明的白色条纹下体、锈色喉部和前颈。上体呈棕色，细密的红棕色和米色条纹。雌鸟相似但缺乏雄鸟的脚距，且腿胫较暗淡。幼鸟外观似成鸟但色泽更淡，喉部米色，下体条纹边缘为棕色而非黑色。","call":"沼泽鹧鸪发出响亮的类似海鸥的“kree-ree!”叫声，常以合唱形式呈现。","habits":"偏好低洼地带的湿地，如泛滥平原、湿地边缘和稻田。常见于高草丛生的沼泽和湿地附近，亦栖息于甘蔗种植园和稻田中。活动范围广泛，从250米以下的低地到洪水期间高达1200米的地方。主要食物为杂草种子、谷物、昆虫等。","breeding":"繁殖季节从2月底至5月，主要在3月至4月。通常一夫一妻制，巢建于水边或沼泽边缘，由雌鸟单独筑巢和孵化，雄鸟协助照顾幼鸟。巢中通常有3-4枚淡褐色斑点蛋。","identification":"与亚洲其他Francolinus物种相比，沼泽鹧鸪具有明显的白色条纹下体和锈色喉部。是印度次大陆上最大的鹧鸪种类，拥有宽阔的米色眼纹和眉纹，白色条纹下体，除锈色腹外，上体呈棕色，细密的红棕色和米色条纹。","protection":"IUCN：NT（近危）","distribution":"分布于印度北部、尼泊尔至孟加拉国，主要集中在恒河和布拉马普特拉河流域。在印度北部的多个保护区，如杜德瓦国家公园，均有记录。","other":"曾被归类于Francolinus属，但基因分析显示其与凤头鹧鸪和灰鹧鸪关系更近，现已重新分类至Ortygornis属。"},{"name":"凤头鹧鸪","english_name":"Crested Francolin","scientific_name":"Ortygornis sephaena","overview":"凤头鹧鸪（英文名：Crested Francolin，学名：Ortygornis sephaena），是鸡形目雉科 Ortygornis 属的鸟类。其特征性的头部有一簇偶尔竖起的蓬松羽冠，颈部与胸部有‘珍珠串’状的宽大斑纹环绕白色喉部。广泛分布于非洲东部和东南部的稀树草原和河岸森林。黎明和黄昏时，会以重复快速而欢快的‘cheer kirk-kik’叫声宣告其存在，通常以一对鹧鸪同步合唱的形式。凤头鹧鸪行走时自信满满，尾巴上翘，步态类似鸡类。","appearance":"凤头鹧鸪体长30至35厘米，雄鸟体重270至417克，雌鸟体重220至375克。颈部和胸部有栗色斑点，黑色喙，红色腿，白色眉线和深棕色冠。雌鸟比雄鸟小约15%，上半身条纹更密集，且无脚刺（雄鸟有单个脚刺）。幼鸟颜色较浅，上半身条纹更宽。成年凤头鹧鸪有显著的个体和地理变异，主要体现在大小和下体色彩上。五个亚种大致分为两组，指名亚种群（包括zambesiae和grantii）的下体后部有细小而不明显的虫蚀状斑纹，而rovuma亚种群（包括spilogaster）的下体有条纹，越往南条纹越重。","call":"凤头鹧鸪有八种不同的叫声，最典型的是领地叫声，这是一种重复的、节奏感强的短促粗哑叫声，通常以二重唱的形式由一对鹧鸪发出，包含高音强调的音符‘kerrek-kek-keeek!-kek’或类似的变体，叫声在地理范围内有所变化。还有单独雄鸟的重复粗哑叫声，以及可能在配偶选择中发挥作用的雄鸟和雌鸟叫声。它们尤其在黄昏时活跃，多个个体可能会同时鸣叫。","habits":"凤头鹧鸪栖息于各种灌木丛生的环境，包括沿河密集的灌木、金合欢/乳香木林地、Baikiaea森林、森林边缘和过度生长的耕地。在马拉维，它居住的灌木丛远小于。它在一些地区远离水源生存，尽管通常被认为是附近水源的指示器。凤头鹧鸪在索马里记录到高达2200米的高度，但在其余分布区内主要位于1500米以下。它们通常是定居的，通过奔跑逃避危险，但在植被较少的地区会飞入灌木或树木中躲避哺乳动物捕食者。凤头鹧鸪的食物包括白蚁、其他昆虫及其幼虫、莎草球茎、种子（主要是Commelina属）、草类和其他植物材料，可能还包括浆果、软体动物和其他可获得的食物。它们被观察到在大象粪便上觅食，可能是在寻找蜣螂。凤头鹧鸪在城镇和村庄边缘觅食，通常在遮蔽处或附近觅食，主要在清晨和傍晚活动，有时会形成多达十只的群体。","breeding":"凤头鹧鸪在南非的繁殖期为10月至次年5月（主要为10月至11月），津巴布韦为12月至3月，莫桑比克为6月至7月，但在马拉维为11月，赞比亚为10月至次年3月（主要为12月至1月），埃塞俄比亚为1月至6月（少数记录在7月至10月和12月），索马里主要为5月至8月。可能是单配偶制，因为它们具有领地性，且在繁殖季节常以对出现。巢穴是一个直径10至17厘米、深度6至10厘米的凹坑，铺有草和叶子，隐藏在灌木、岩石或草丛基部。通常产卵5至6枚（3至9枚），粉色至奶油色，带有淡棕色斑点，卵大小为37.1至43.2毫米×28.8至32.4毫米。孵化期约为19至22天，仅由雌鸟孵化。绒毛雏鸟呈锈褐色，背部黑色和缓冲色，腹部缓冲白色，由两性共同照料。雏鸟能在仅达到成鸟大小的25%时短距离飞行，但离巢期未记录。","identification":"凤头鹧鸪与其他鹧鸪的区别在于其独特的头部羽冠，白色的‘珍珠串’状颈环，以及上半身的栗色斑点。雌雄差异主要体现在大小和脚刺的存在与否。不同亚种之间的辨识要点在于下体的斑纹或条纹的密度和清晰度。","protection":"IUCN：LC（无危）凤头鹧鸪在全球范围内并不受到威胁，是非洲分布最广泛的鹧鸪之一，遍布近3,350,000平方公里的适宜栖息地。在整个分布区，它局部常见甚至丰富，且相对稳定，尽管在马拉维南部保护区外被认为正在减少。最近没有来自乌干达东南部的记录，但自1970年代以来似乎已扩散至埃塞俄比亚西部高地。它是肯尼亚最广泛分布和最丰富的猎鸟，且在索马里被认为是普遍常见的。在南非的克鲁格国家公园中并不常见，但在南非的其他几个保护区，如波洛克瓦尼野生动物保护区和博拉卡拉洛国家公园也有发现。虽然没有关于丰度的更多信息，但它在任何地方都不被认为受到威胁，但栖息地退化和可能的草原转为农田可能会影响物种。1930年代，由于栖息地变化和狩猎，它在肯尼亚人口密集的基苏穆和沿海地带被认为已经减少。在津巴布韦，狩猎应限制在7月至9月期间。","distribution":"凤头鹧鸪分布在非洲东部和东南部，具体包括埃塞俄比亚、索马里、肯尼亚、乌干达、坦桑尼亚、马拉维、莫桑比克、赞比亚、津巴布韦和南非的部分地区。","other":"凤头鹧鸪的一个亚种， rovuma，有时被视为独立物种，即Kirk's francolin。"},{"name":"林鹧鸪","english_name":"Latham's Francolin","scientific_name":"Peliperdix lathami","overview":"林鹧鸪（英文名：Latham's Francolin，学名：Peliperdix lathami），是鸡形目雉科林鹧鸪属的鸟类。本属唯一物种，广泛分布在非洲西部至中部的雨林地带。雄鸟拥有深色羽毛，背部呈栗色，腹部黑色，与白色斑点形成鲜明对比。雌鸟颜色较淡，更偏向棕色。该物种在低至中海拔的茂密雨林中难以被发现。","appearance":"林鹧鸪体长约23-26厘米，雄鸟体重约254克，雌鸟略重，约284克。雄鸟外观非常深暗，黑色喉咙与白色下部斑点形成独特组合，雌鸟则色彩较为柔和，带有淡棕色面斑和黑色斑纹的上部。嘴黑色，虹膜棕色，腿黄色。幼鸟似雌鸟，但上部更偏红褐色，有更白的喉部和下部，年轻雌鸟的下部有更多白色，胸部条纹而非斑点。","call":"林鹧鸪通过多种声音交流，包括悦耳的鸽子般的‘coo, coo, coo’声和重复的‘kwee, coo, coo’声，有时也会发出长时间的高音哨声和低沉的咕噜声。它们经常在黄昏和夜晚鸣叫。","habits":"栖息于赤道低地森林带，主要在原始森林中，高度可达乌干达的1400米和利比里亚的900米。以地面活动为主，善于奔跑，仅在必要时才会飞行。食物主要包括白蚁、蚂蚁和其他节肢动物、蜗牛、甲虫以及油棕榈果实、种子和绿叶。","breeding":"繁殖期在西喀麦隆为2月和12月，南喀麦隆为旱季12月，刚果民主共和国为12月至4月，乌干达主要在一月至三月和八月至十一月。通常每次产两枚深褐色或锈褐色的蛋，孵化成功率约为80%，主要的巢穴掠食者是蛇和獴科动物。","identification":"与纳罕鹧鸪相似，但可以通过其暗色喙、缺乏红色裸露面部皮肤和黄色而非红色的腿来区分。雄鸟schubotzi亚种具有更深的栗色上部标记和更白的脸部斑块。","protection":"IUCN：LC（无危）","distribution":"林鹧鸪分布于安哥拉、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、象牙海岸、赤道几内亚、加蓬、加纳、几内亚、利比里亚、尼日利亚、塞拉利昂、南苏丹、坦桑尼亚、多哥和乌干达。"},{"name":"栗顶鹧鸪","english_name":"Coqui Francolin","scientific_name":"Campocolinus coqui","overview":"栗顶鹧鸪（英文名：Coqui Francolin，学名：Campocolinus coqui），是鸡形目雉科 Campocolinus 属的鸟类。雄鸟头部赭色鲜明，雌鸟头部条纹繁复，腹部暗纹显著。广泛分布于非洲南部，西至萨赫勒西部，北至埃塞俄比亚，是非洲分布最广的francolin之一。","appearance":"体长20至25厘米，雄鸟体重227至284克，雌鸟体重218至259克。雄鸟头部均匀赭色，与胸部条纹形成鲜明对比。雌鸟头部具黑白色脸纹。喙黑色基部黄色，眼睛棕色，腿脚黄色。幼鸟与成年雌鸟相似，但颜色较淡，上身斑驳而非条纹，喉部白色带黑色边框和眼上黑色条纹；下体条纹较淡，胸部无条纹呈浅褐色。不同亚种间下体颜色和图案各异。","call":"发出两种特色叫声：重复的“co-qui”声和一系列短促的咯咯声。领地叫声为节奏感强的‘kek..kerrek!-kek-kek-kek-kek’音节，共7至10个音节，第二音节重读随后减弱。有时发出一系列双音尖叫，重复6至8次。群居时遇险发出柔和的‘chur-chur’声。","habits":"生活在各种草地环境，包括草原、灌木丛和茂密的森林，如米奥诺姆森林，高度可达2200米。在干燥地区沙质地带的灌木丛中也有发现。频繁出没农田，但不被视为害鸟。避免丘陵和石质地带，似乎不需要直接水源。夜间栖息地面，多只鸟紧密聚集。仅在受迫时飞行，偏好奔跑逃逸。食物包括种子、叶子和多种昆虫，如蚂蚁、甲虫和其他昆虫的幼虫。","breeding":"在尼日利亚7月、刚果民主共和国8月至次年3月、乌干达10月至11月和5月繁殖。一夫一妻制，据信有领地性。巢为草、叶等覆盖物下的微小凹陷，直径约10至12厘米。通常产4至5枚粉白色至淡棕色蛋，大小31.3至34.6毫米×25.5至28.6毫米。幼鸟与成鸟共同生活数月，但面临较高的捕食风险，如猛禽、野猫和蛇。","identification":"与栗喉鹧鸪相比，缺乏背部的红褐色，而展现出密集的条纹，类似于鹌鹑。雌鸟头部特征性的黑白脸纹是辨识关键。","protection":"IUCN：LC（无危）。在乌干达国家公园平均密度约为3只/平方公里，但在部分地区稀少或局部分布。在马里罕见，在尼日尔的W国家公园和塔莫野生动物保护区有记录，在埃塞俄比亚不常见至常见。","distribution":"广泛分布于非洲南部，西至萨赫勒西部，北至埃塞俄比亚，遍布近4,180,000平方公里的适宜生境。","other":"在肯尼亚裂谷区数量最多，在赞比亚几乎普遍存在。在马拉维，现主要局限于保护区。在南非克鲁格国家公园较为罕见。在津巴布韦，狩猎季节应限制在7月至9月。"},{"name":"白喉鹧鸪","english_name":"White-throated Francolin","scientific_name":"Campocolinus albogularis","overview":"白喉鹧鸪（英文名：White-throated Francolin，学名：Campocolinus albogularis），是鸡形目雉科 Campocolinus 属的鸟类。雄雌相似，但雄鸟色彩更丰富，胸部有条纹，而雌鸟胸部有较淡的条纹。在南部地区的鸟儿胸部带有更多的赤褐色。主要栖息在非洲西部和中南部的灌木丛生的草原和林地，偏好厚草覆盖的地方。这种鸟通常害羞，倾向于奔跑而非飞行以逃避危险。","appearance":"体型小至中等，长度约23-25厘米，体重263-284克。雄鸟与雌鸟相似，但雄鸟的胸羽呈条纹状，雌鸟的胸部条纹较细。下体颜色为栗色和淡黄色，无条纹，雌鸟比雄鸟略小，背部有较窄的奶油色条纹，胸部和侧腹有精细的条纹，几乎无刺（雄鸟有一根刺）。虹膜棕色，喙黑色，基部黄色，腿橙黄色。幼鸟与成年雌鸟相似，但下体条纹更多。","call":"发出两种独特的叫声：重复的‘chur-di’声和一系列短促的咯咯声。广告叫声类似栗顶鹧鸪，但更快，为高音的‘ter-ink-inkity-ink’或双音节的‘ter-ink, ter-ink’，也有一种穿透性的哨声和重复的‘che-cheer-che’声。","habits":"生活在开阔的草原地带，尤其是最近烧过的土地和沿路的灌木丛。它们通常避免远离遮蔽物，即使在耕地上也是如此。高度耐受人类干扰的环境，如被遗弃的耕地。它们是定居性鸟类，仅在被迫时才会飞行，更倾向于通过植被匍匐移动以逃脱。主要食物包括各种昆虫，如蚱蜢和白蚁，以及植物材料，如草籽。","breeding":"在尼日利亚于6月筑巢，在塞内加尔和刚果民主共和国于9月至12月筑巢。可能是一夫一妻制。巢是一个浅坑，铺有草和树叶。每次产卵通常6枚，颜色从淡黄到淡棕色，带有细小的棕色斑点。孵化和育雏的详细信息未知。","identification":"与栗顶鹧鸪和栗喉鹧鸪雌鸟相比，可通过头部和胸部图案的细节以及飞行中的红褐色翅膀来区分。体型小于大多数其他Francolin，大于鹌鹑和三趾鹑。","protection":"IUCN：LC（无危）。广泛分布于适宜的生境中，面积超过1,000,000平方公里，因大范围和对干扰生境的容忍度而被认为是安全的。在加纳局部地区相对常见，包括Mole国家公园等保护区，但在南部部分地区可能已消失。冈比亚只有一个近期记录。","distribution":"分布在非洲西部和中南部，包括安哥拉、贝宁、布基纳法索、喀麦隆、刚果民主共和国、科特迪瓦、冈比亚、加纳、几内亚、马里、尼日利亚、塞内加尔、多哥和赞比亚。","other":"白喉鹧鸪曾被归类于Peliperdix属，但2020年的研究发现它、栗顶鹧鸪和栗喉鹧鸪共同构成新的Campocolinus属。"},{"name":"栗喉鹧鸪","english_name":"Schlegel's Francolin","scientific_name":"Campocolinus schlegelii","overview":"栗喉鹧鸪（英文名：Schlegel's Francolin，学名：Campocolinus schlegelii），是鸡形目雉科 Campocolinus 属的鸟类。雄鸟和雌鸟外观相似，但雄鸟的色彩更丰富，胸部具条纹，而雌鸟胸部有V形斑纹。分布于喀麦隆至苏丹的草原和灌木林地带，常以成对或小群体的形式出现在厚草丛中。叫声独特，是一系列加速、下降并逐渐消失的咯咯声。","appearance":"体型介于21-25厘米，雄鸟约251克，雌鸟约223克。头部主要为锈橙色或红黄色，与暗褐色的冠部和眼纹形成鲜明对比。雌鸟背部呈棕色，带有更多的黑色斑点，腹面有不规则的斑点。喙为黑色，基部黄色，虹膜棕色，腿黄色。雄鸟单个脚上有刺，雌鸟几乎无刺。幼鸟似成年雌鸟，肩羽和背羽有红黑相间的条纹。","call":"鸣唱为快速且低沉的喇叭声，通常被描述为“ter, ink, terra”或“KWEEK! kre-kre-krekrekrekew”，首音最强，随后加速，变得更为刺耳并渐弱。","habits":"生活在有丰富树种和茂密草丛覆盖的草原林地，尤其是Isoberlinia doka树较多的地方。通常远离人类居住区，偶尔会光顾农田边缘。活动范围有限，仅进行短距离飞行，通常保持沉默。以地面的Isoberlinia doka树叶、草籽、谷物和毛虫为食，经常观察到成对或小型家庭群。","breeding":"在苏丹，繁殖期为9月至11月，可能是单配偶制。巢为简单的凹坑，铺垫草叶等物。通常产2-5枚奶油色蛋，尺寸约为33-38毫米×24-28毫米。有记录显示一窝十枚蛋，但可能为错误记录或两个雌鸟在同一巢中产卵。","identification":"与栗顶鹧鸪相似，但分布范围不重叠。与白喉鹧鸪有狭窄的分布重叠，但后者具有白色喉咙和飞行时红色的初级飞羽。雄性栗喉鹧鸪的胸背颜色为栗色，喉部为橙色，飞行时翅膀无红褐色。","protection":"IUCN：LC（无危）","distribution":"非洲西部喀麦隆东部至南苏丹一带，包括中非共和国北部和乍得南部。","other":"2020年的研究表明，栗喉鹧鸪、白喉鹧鸪和栗顶鹧鸪共同构成了新属Campocolinus。"},{"name":"环颈鹧鸪","english_name":"Ring-necked Francolin","scientific_name":"Scleroptila streptophora","overview":"环颈鹧鸪（英文名：Ring-necked Francolin，学名：Scleroptila streptophora），是鸡形目雉科环颈鹧鸪属的鸟类。具有精致的羽色图案。头部条纹、棕红色颈背、白色喉部以及颈部环绕的黑白条纹是其显著特征。分布于非洲的喀麦隆、乌干达、肯尼亚和坦桑尼亚等地。","appearance":"体长约33至35厘米，体重介于364克到406克之间。上胸与后颈具独特的黑白条纹，其余腹部为浅黄色并带有深棕色条纹；头顶和颈背暗灰褐色，长而白的眉纹，头侧和颈侧为红栗色，与白色喉部形成鲜明对比，尾巴和飞羽呈灰褐色。喙黑色基部黄色，眼棕色，腿脚淡黄色。雌雄差异不大，仅雌鸟头部及背部有更深的棕色边缘和斑纹。","call":"领土鸣叫通常从略高的位置发出，包含两声柔和的鸽子般的咕咕声，第二声音调更高，随后是一串延长的哨音。飞行时也会发出嘈杂的叫声，但常无声起飞。","habits":"栖息于海拔600至1800米的稀疏植被覆盖的山坡，偏好岩石间薄草覆盖的环境。也出现在木本草地和耕作区。以昆虫和种子为食，可能访问农田觅食。通常成对或小群家庭单位活动，清晨和傍晚时分才进入开阔地带。","breeding":"在乌干达的四月早期雨季产卵，而在肯尼亚的旱季（12月至3月）繁殖。巢穴为简单的凹陷，有时有稀疏的衬垫，通常位于岩石底部，每次产4至5枚淡灰色蛋，表面有细小的暗色斑点。繁殖习性可能是单配偶制。","identification":"与栗顶鹧鸪相似，但体型更大，下体图案不同，更简洁且腹部两侧有粗大条纹。不同于红翅鹧鸪，具有更干净的白色喉部，翅膀上缺乏大的红色斑块，下体图案也不同。","protection":"IUCN：LC（无危）。在当地常见至丰富，如在坦桑尼亚，但乌干达近年来记录较少，肯尼亚西部边缘地带分布零星。","distribution":"分布在四个不连续的区域：乌干达北部，从基德普国家公园西至尼罗河和卡通加谷地以及莫罗托山脚下；肯尼亚西部，从埃尔贡山东南坡至萨米亚山丘和尼亚多山谷；坦桑尼亚西北部的基邦多和卡苏卢地区；喀麦隆高地的孤立种群。此外，在布隆迪（鲁武布国家公园）和卢旺达也有记录。"},{"name":"灰翅鹧鸪","english_name":"Grey-winged Francolin","scientific_name":"Scleroptila afra","overview":"灰翅鹧鸪（英文名：Grey-winged Francolin，学名：Scleroptila afra），是鸡形目雉科环颈鹧鸪属的鸟类。分布于非洲南部的莱索托和南非，偏好开阔生境如灌木丛、草原和芬博斯植被。通常以小群体出现，叫声独特响亮。","appearance":"灰翅鹧鸪体长30至33厘米，雄鸟体重345至539克，雌鸟略轻，为354至410克。雌鸟较雄鸟稍小且无脚蹼（雄鸟有一单脚蹼）。喙黑褐，虹膜棕色，腿呈棕黄色。成鸟具特有的喉部斑纹，翼上有小型红褐色斑块。幼鸟较暗淡，喉部更白，腹部中央有条纹而非斑点。","call":"其鸣叫特征为响亮而富有节奏的‘chow’和‘keek’音符系列，早晨和傍晚时分尤为活跃，通常从稍微抬高的地面位置发出。","habits":"灰翅鹧鸪主要栖息于海拔约1800至2750米的山地草原，偏好短草丛和小灌木。它们在西南开普省的海平面附近也有发现。生活方式定居，有时会在同一区域停留多年。它们主要在清晨和黄昏觅食，以球茎、根、植物材料、昆虫和其他无脊椎动物为食，尤其喜食蚂蚁、甲虫和蚱蜢。","breeding":"繁殖期在开普省为7月至12月，在纳塔尔为8月至3月（高峰在11月至12月），在东奥兰治自由州为10月至12月。筑巢于草丛基部，巢呈浅凹状，内铺草叶和偶尔的羽毛。每窝产3至8枚黄褐色蛋，平均5至7枚，孵化期21至23天，仅由雌鸟承担。幼鸟出生后由双亲共同照顾，约5至6周龄时离巢，14天左右能飞翔。","identification":"与红翅鹧鸪、谢利鹧鸪和橙翅斑鹧鸪相似，但喉部有斑驳图案。与广泛共生的红翅鹧鸪相比，整体颜色更偏向红褐色，下体暖色带红斑，喉部更白，胸翼上的红褐色更为明显。","protection":"IUCN：LC（无危）","distribution":"分布于莱索托和南非，从西开普东北至姆普马兰加、莱索托和斯威士兰。","other":"面临的主要威胁包括栖息地丧失、森林开发和过度捕食，尤其是在莱索托。"},{"name":"红翅鹧鸪","english_name":"Red-winged Francolin","scientific_name":"Scleroptila levaillantii","overview":"红翅鹧鸪（英文名：Red-winged Francolin，学名：Scleroptila levaillantii），是鸡形目雉科环颈鹧鸪属的鸟类。中等体型、图案精美的鸟类。分布于非洲中东部至南部，包括安哥拉、布隆迪、刚果民主共和国、肯尼亚、莱索托、马拉维、卢旺达、南非、斯威士兰、坦桑尼亚、乌干达和赞比亚。其独特的头部花纹和飞行时展示的大型赤褐色翼斑是显著特征。","appearance":"成年红翅鹧鸪体长约33至38厘米，雄鸟体重359至567克，雌鸟354至515克。头部花纹复杂，具有一条赤褐色颈部条纹，白色喉咙，以及黑色和白色的条纹。喙呈黑褐色，基部泛黄，虹膜棕色，腿黄色至棕黄色。雄鸟单脚有刺，雌鸟无刺。幼鸟较暗淡，喉部图案不明显，以灰褐色为主。种族kikuyuensis的胸腹部条纹更多，而crawshayi种族的下巴和喉咙纯白，被宽大的锈色带环绕。","call":"红翅鹧鸪的叫声独特，雄鸟的广告叫声是一系列高音的哨声，短暂停顿后跟一个滑音，类似于“kai-al-de-werk”。两性在警报时会发出“kourrr”的声音，若受惊飞起则会发出尖锐的尖叫。雌鸟会发出轻柔的咯咯声召唤幼鸟。","habits":"红翅鹧鸪栖息于湿润的高山和高地草地，海拔高度从1100米至3000米不等。它们偏好陡峭山谷和潮湿地带，常在清晨和傍晚沿着小路和路边觅食，形成小群，最多十只一组。食物以球茎和根茎为主，尤其是Amaryllidaceae和Iridaceae科植物，同时也会摄取昆虫如蚂蚁、蜘蛛和千足虫。","breeding":"繁殖期在南部非洲全年均可发生，东部开普省为3月至7月，纳塔尔为8月至2月，赞比亚几乎每月都有记录，仅2月和5月无记录。在东非，繁殖期从1月至4月，8月和10月至11月，视具体地点而定。红翅鹧鸪可能为一夫一妻制，疑似双窝产。巢建在覆盖物底部靠近水源处，由草、叶等材料精心铺垫，通常宽约15厘米。每窝产卵3至12枚（平均4至5枚），橄榄褐色至黄褐色，带有深灰色或棕色斑点。","identification":"红翅鹧鸪通过其复杂的头部花纹、赤褐色颈部条纹、白色喉咙和黑色及白色条纹与其它类似物种区分。与谢氏鹧鸪相比，后者有整洁的黑色边缘环绕白色喉咙，胸部呈单一栗色，下体更白，有粗大的黑色标记和细的浅褐色条纹。与灰翅鹧鸪的区别在于后者翼侧标记不明显，缺乏明显的赤褐色初级飞羽，胸部有栗色带，喉咙有良好的斑点。高地鹧鸪（在肯尼亚局部重叠）具有栗色颈环和黑点赤褐色胸部。芬氏鹧鸪则更朴素，下体几乎无标记，呈灰褐色，没有明显的胸部带和颈环。","protection":"IUCN：LC（无危）红翅鹧鸪在约83万平方公里的适宜生境中广泛分布，但分布极为零散。总体上较为罕见，但在某些地区常见，密度为2至4只/平方公里，在南非优质生境中可达10至20只/平方公里。尽管数量似乎稳定，但栖息地正在收缩，特别是在肯尼亚，由于近年来高原草地的农业开发导致种群下降。在南非，依赖于未燃烧、保存良好的草地，有效保护区对其长期生存至关重要。","distribution":"红翅鹧鸪在非洲中东部至南部广泛分布，包括安哥拉、布隆迪、刚果民主共和国、肯尼亚、莱索托、马拉维、卢旺达、南非、斯威士兰、坦桑尼亚、乌干达和赞比亚。","other":"埃尔贡鹧鸪可能是红翅鹧鸪与高地鹧鸪的杂交种。"},{"name":"芬氏鹧鸪","english_name":"Finsch's Francolin","scientific_name":"Scleroptila finschi","overview":"芬氏鹧鸪（英文名：Finsch's Francolin，学名：Scleroptila finschi），是鸡形目雉科环颈鹧鸪属的鸟类。主要分布在加蓬至刚果民主共和国西南部和安哥拉西部。以纪念德国民族学家、自然学家和殖民探险家弗里德里希·赫尔曼·奥托·芬施而命名。","appearance":"体长约34至36厘米，体重约540至600克。上体主要呈灰褐色，带有赤褐色条纹；头部赤褐色，喉部白色；胸部灰褐色，后方逐渐变为淡黄色，胸侧有栗色斑点，侧面较灰色。雄鸟与Peliperdix coqui相比，头部颜色更橙，翅膀无赤褐色，体型较小且紧凑。喙棕色偏黑，虹膜棕色，腿黄褐色；两性均有单个距，雄鸟的较长。","call":"典型的叫声是响亮的‘wit-u-wit’二重奏，通常在黄昏听到，但也可能在黎明至上午中段时间发出。邻近的配偶或群体常被第一对发声的叫声所激发。","habits":"栖息于林地和草地，包括灌木丛附近的草地，海拔可达600米，甚至在安哥拉的Moco山裸露斜坡上发现，高度达到2100米。主要食用甲虫、昆虫幼虫和种子，常在最近燃烧过的区域觅食。一般以成对的形式出现。","breeding":"在刚果民主共和国记录到1月、3月、7月繁殖，在安哥拉记录到6月至8月。可能实行一夫一妻制，巢穴隐藏在地面植被中，每窝产约5枚浅棕色蛋。","identification":"与红翅鹧鸪的区别在于胸部灰褐色，脸部和颈部无黑白相间的图案。在安哥拉与红翅鹧鸪有部分重叠。","protection":"IUCN：LC（无危）。在安哥拉稀疏分布且罕见，在刚果民主共和国Gungu地区较为常见。关于实际或潜在威胁的信息未知，尽管安哥拉卡甘达拉国家公园内的物种栖息地可能在内战期间严重退化。需要详细评估其在保护区的存在情况和保护区对该物种的保护效率。","distribution":"分布于加蓬至刚果民主共和国西南部和安哥拉西部。在刚果民主共和国，位于Lékoni至下刚果河；在刚果民主共和国南部（Kwando和Kwilu）；在安哥拉西部（Cuanza Norte和S Malanje南至N Huíla）。","other":"无"},{"name":"谢氏鹧鸪","english_name":"Shelley's Francolin","scientific_name":"Scleroptila shelleyi","overview":"谢氏鹧鸪（英文名：Shelley's Francolin，学名：Scleroptila shelleyi），是鸡形目雉科环颈鹧鸪属的鸟类。非洲特有的雉科环颈鹧鸪属鸟类，以英国旅行家Sir Edward Shelley命名。主要栖息于东非和南非的多种草地与林地环境，包括高山草甸、灌木丛生的草原、以及森林中的开阔地带。物种在低至中海拔区域广泛分布，偶尔亦见于高山区。","appearance":"谢氏鹧鸪体长约33至38厘米，体形敦实，喉部白色，飞行时可见翼上的红褐色斑块。上体呈淡棕色，杂以黑色斑点和条纹，同时有大量浅色羽轴条纹。下体底色一般为白色，胸部和两侧布满栗色条纹，腹部则广泛地被黑色与白色的横纹覆盖。头部图案复杂，由红褐色、黑色和白色的条带组成。","call":"鸣声为有节奏的起伏重复的“chil-it, chil-chow”。","habits":"通常生活在低至中海拔的草地和林地环境中，偏好岩石和石质区域。在肯尼亚，物种主要分布在年降雨量为250至1000毫米的地区。在莫桑比克沿海至南非夸祖鲁-纳塔尔的沿海地带，以及津巴布韦因扬加高地海拔高达2200米，乃至马拉维南部穆兰杰山高达2700米的地区均有发现。","identification":"与怀氏鹧鸪相比，谢氏鹧鸪的标记更加清晰和突出，面部图案更复杂，腹部黑白相间的条纹明显。与橙翅斑鹧鸪的区别在于，后者下胸和腹部颜色为淡黄色至红褐色，而谢氏鹧鸪有独特的黑白色条纹。","protection":"IUCN：LC（无危）","distribution":"分布于肯尼亚、莫桑比克、卢旺达、南非、斯威士兰、坦桑尼亚、乌干达和津巴布韦的草地和林地。在东非和东南非广泛分布。","other":"已报道在南非局部地区的灭绝，原因可能是过度放牧和频繁燃烧导致的草地退化。"},{"name":"高地鹧鸪","english_name":"Moorland Francolin","scientific_name":"Scleroptila psilolaema","overview":"高地鹧鸪（英文名：Moorland Francolin，学名：Scleroptila psilolaema），是鸡形目雉科环颈鹧鸪属的鸟类。分布于埃塞俄比亚中部和南部的高海拔地区。其独特的黑色斑点白喉部与橙河鹧鸪形成鲜明对比。","appearance":"成年高地鹧鸪体长约32至35厘米，雄鸟体重在510至530克之间，雌鸟则为370至510克。头部黑褐色，耳羽和颈部侧面呈淡红褐色；上体深红褐色，具细窄的黄白色条纹，肩部有黑色斑点；喉咙纯白色，边缘有一圈黑底白点的带状标记；下体红褐色，散布黑色斑点，后腹部位更偏向淡黄红褐色，具细暗色条纹；虹膜棕色，喙黑色基部黄色，腿黄色。雌雄外观相似，但雌鸟缺少雄鸟的腿刺。雏鸟特征未详述。","call":"高地鹧鸪的鸣唱包括一系列四声缓慢的音符，频繁重复，类似“tirich-chi-che'e”。当受到惊吓时，会发出尖叫，类似于谢氏鹧鸪和红翅鹧鸪的叫声。","habits":"栖息于海拔2420至4000米的高山艾瑞卡（Erica）沼泽地和草地。以球茎和根为主食，在潮湿的草地和池塘周围的莎草中觅食，通常成对或小群体活动。","breeding":"繁殖资料有限，唯一记录到的产卵时间为10月。预计其生物学特性与埃尔贡鹧鸪相似。一年中除9月至10月外均有繁殖记录，可能为一夫一妻制。已知巢穴位于粗糙的草地中，曾发现有两只雏鸟和三个卵。家族群通常由4至5只幼鸟和成鸟组成，随着年度进展，家族群规模减小，这可能反映了捕食的影响。","identification":"与埃尔贡鹧鸪相比，高地鹧鸪的喉部具有明显的黑色斑点，而埃尔贡鹧鸪的喉部为纯色，且色彩更为鲜艳。两者的叫声也有所不同。","protection":"IUCN：NT（近危）","distribution":"高地鹧鸪分布在埃塞俄比亚的中部和南部山区，具体包括Shewa、Arussi、Bale和Sidamo等地。东部乌干达（Mount Elgon）东至肯尼亚中部（Mau Narok、Aberdares山脉和Mount Kenya）。","other":"埃尔贡鹧鸪曾被认为是高地鹧鸪的一个亚种，但在2014年由IUCN红名单和BirdLife International以及2022年由国际鸟类学大会（IOC）基于2019年的研究将其划分为独立物种。"},{"name":"橙翅斑鹧鸪","english_name":"Orange River Francolin","scientific_name":"Scleroptila gutturalis","overview":"橙翅斑鹧鸪（英文名：Orange River Francolin，学名：Scleroptila gutturalis），是鸡形目雉科环颈鹧鸪属的鸟类。具有醒目的红褐色翼斑，常见于厚草覆盖的地面，包括纯草地和开阔的灌木草原。羞涩而隐退的物种，广泛分布于非洲东北部和南部。","appearance":"橙翅斑鹧鸪体型中等，雄鸟体重在340至538克之间，雌鸟体重在379至450克之间，体长约32至35厘米。飞行时可见显著的红褐色翼斑。性别相似，但雄鸟具有一根较长的单一肉刺。虹膜呈棕色，喙为黑褐色带黄基，腿呈暗黄色。幼鸟较暗淡，下方有条纹，缺乏黑色项圈。不同亚种间颜色强度和下体标记存在差异。","call":"其叫声响亮，快速重复的‘chuk-a-cheiw’音节，声音尖锐。","habits":"生活在各种草地和林地环境，从布满岩石的草地山坡到干燥的树林地带，海拔可达2500米。通常为定居状态，但在南非部分地区，会进行约10公里的局部移动，雨季时向稍高处迁移。以球茎、块茎、落地种子、果实和昆虫为食，如蝽、蚱蜢和甲虫。","breeding":"繁殖季节在南非为2月至5月及9月至10月，而在纳米比亚为6月，安哥拉为4月、8月和12月。可能为一夫一妻制，繁殖期间常成对出现。巢穴为浅凹状，宽约17厘米，深约6.5厘米，位于草丛下或草丛间，内铺干草。每窝产卵3至8枚（通常为4至5枚），蛋色从淡粉至黄褐色，有时带有褐色斑点。孵化期约为20至21天，仅由雌鸟独自孵化。幼鸟在12至14天时能短暂飞行，但完全离巢需5至6周。","identification":"与谢氏鹧鸪相比，缺乏腹部条纹；与红翅鹧鸪不同，具有黑色项链；与高地鹧鸪的区别在于生活的海拔较低。","protection":"IUCN：LC（无危）。虽然广泛分布，但在埃塞俄比亚南部较为常见，而在北部和东北部埃塞俄比亚、邻近的索马里和厄立特里亚则较为罕见。在南非的西北开普省数量估计不足500,000只，且认为本世纪有所下降。在纳米比亚，数量稳定甚至可能增加。主要威胁来自农业用地转化和过度放牧导致的栖息地退化。","distribution":"广泛分布于非洲东北部和南部，包括埃塞俄比亚、索马里、肯尼亚、乌干达、纳米比亚、博茨瓦纳、南非和安哥拉。在纳米比亚，存在于Mudumu国家公园、Etosha游戏保护区和Daan Viljoen保护区。","other":"橙翅斑鹧鸪在南非的Heidelberg地区被观察到能在农田改造地区生存，前提是保持足够的自然草地远离泛滥平原和湿地，这些未受干扰的区域对于繁殖尤为重要。"},{"name":"埃尔贡鹧鸪","english_name":"Elgon Francolin","scientific_name":"Scleroptila elgonensis","overview":"埃尔贡鹧鸪（英文名：Elgon Francolin，学名：Scleroptila elgonensis），是鸡形目雉科环颈鹧鸪属的鸟类。具有复杂的斑纹，背部呈棕色，腹部锈色，喉部白色，边缘点缀黑色斑点。这种鹧鸪主要分布在非洲东部乌干达至肯尼亚中部的高海拔草原和灌木丛中。","appearance":"埃尔贡鹧鸪的翅膀在飞行时展现出大面积的锈色斑块。它通常以小群体的形式出现在高山草甸和灌木地带，高度超过2,300米（约7,500英尺）。其外观与谢氏鹧鸪相似，但生境位于更高海拔，且下腹部的锈色更为浓重，没有明显的黑色横纹。","call":"其鸣叫声包括一系列‘squee-chee’音符，以及在飞行时常发出的尖叫。","habits":"埃尔贡鹧鸪偏好高海拔地区的栖息地，包括阿尔卑斯式草地和灌木丛。它们以小群活动，主要在东非的特定高山区域被发现。","breeding":"关于埃尔贡鹧鸪的繁殖信息，目前文献记载有限。","identification":"与谢氏鹧鸪相比，埃尔贡鹧鸪在生境上占据更高的海拔，且其腹部颜色更偏向锈色，而非带有大量黑色条纹。此外，两者的鸣叫也存在差异。","protection":"IUCN：LC（无危）","distribution":"埃尔贡鹧鸪的分布区域集中在非洲东部，从乌干达东部的埃尔贡山到肯尼亚中部，主要在高海拔的山区。","other":"过去曾被认为是高地鹧鸪的亚种，但现在基于遗传学研究，被确认为独立物种。"},{"name":"怀氏鹧鸪","english_name":"Whyte's Francolin","scientific_name":"Scleroptila whytei","overview":"怀氏鹧鸪（英文名：Whyte's Francolin，学名：Scleroptila whytei），是鸡形目雉科环颈鹧鸪属的鸟类。分布于非洲的刚果民主共和国东南部、赞比亚和马拉维北部的草木混合地带。","appearance":"怀氏鹧鸪是一种体型健壮的鹧鸪，喉部呈浅黄色，飞行时可见翅膀外侧有一小块红褐色斑。上体颜色为淡棕色，带有黑色斑点和条纹，以及许多淡黄色的羽毛轴条纹。下体基色通常是白色，胸部和两侧重重叠叠地覆盖着栗色条纹，下胸和腹部则带有黑色细条纹。头部图案复杂，由红褐色、黑色和白色的条带组成。性别在羽毛上相似，但雄鸟有单个跗跖刺。冠部主要是灰棕色，眉纹、脸部、颈部和喉部为淡黄色，喉部有不规则的暗色斑点线从帽区延伸到后颈侧面，另一条从下喙基部向后至耳羽盖和颈部侧面，两条线在下颈处相交，横跨下喉部。","habits":"怀氏鹧鸪主要栖息于非洲的草木混生地带，它们的生活习性较为固定，被认为是高度定居的物种，很少进行迁徙。它们活动范围相对较小，通常在繁殖区域内活动。","identification":"与广泛分布的红翅鹧鸪相比，怀氏鹧鸪的下胸和腹部为淡黄色至红褐色，具有红橙色或橙黄褐色的环状颈纹，以及黑白相间的后颈。与同样广泛分布的栗顶鹧鸪相比，怀氏鹧鸪头部颜色均匀温暖，下体条纹明显，不太可能混淆。","protection":"IUCN：LC（无危）","distribution":"怀氏鹧鸪分布在非洲的刚果民主共和国东南部、赞比亚和马拉维北部。"},{"name":"鳞斑鹧鸪","english_name":"Scaly Spurfowl","scientific_name":"Pternistis squamatus","overview":"鳞斑鹧鸪（英文名：Scaly Spurfowl，学名：Pternistis squamatus），是鸡形目雉科鸡鹧鸪属的鸟类。自尼日利亚东南部至刚果民主共和国北部、东部，加蓬和刚果，刚果民主共和国东部至乌干达，肯尼亚南部，坦桑尼亚，马拉维北部和埃塞俄比亚中部。其显著特征为暗褐色的羽毛、红色的喙和腿脚。","appearance":"体型中等，约30-33厘米长，雄鸟体重372-565克，雌鸟377-515克。羽毛颜色偏暗，上部最深，头侧和腹部中央较浅，飞羽几乎统一灰色，内侧次级飞羽有黑色斑点。喙呈深棕色带橙红色下喙，眼睛为棕色，腿脚橙红色。幼鸟比雌鸟更偏赤色，背部有更宽的黑斑，腹部中央有黑白细条纹。雌鸟通常比雄鸟小，且无脚刺（雄鸟有1-2个）。","call":"鸣叫声为一系列粗糙的音符，逐渐加快且更加强调。领地叫声常为二重奏，一只鸟发出大约12声渐强的‘kerrrak’粗哑声，另一只则发出更快的‘kek’声。雌鸟叫声比雄鸟更鼻音且音调更高。家庭群可能发出低沉的‘quarek-quarek’声，保持联系时则发出非常轻的咕噜声。","habits":"栖息于海拔800米至3000米的常绿森林及其密集灌木丛，包括森林空地。偏好有浓密下层植被的环境，如种植园、过耕地区域，尤其是象草（Pennisetum purpureum）生长的地方。偶尔出现在松树林（马拉维）。夜宿于树上。","breeding":"繁殖季节在东非除二月外的各月，埃塞俄比亚为十月至十二月，喀麦隆南部为十月至三月，加蓬为六月至八月，刚果民主共和国为一月至二月和五月至六月，马拉维为八月至九月。巢穴为轻微凹陷，以草、叶、羽毛等铺垫，通常位于遮蔽处。每次产卵六枚，颜色为淡黄色至粉黄色（数量3-8枚）。绒羽雏鸟上部大多为深赤褐色，下部为淡赤色。雏鸟遭受严重捕食。","identification":"与其他鹧鸪如Handsome和Red-necked Francolins的区别在于眼周缺乏红色裸露皮肤。种族变异围绕整体色彩，西部鸟上部偏红褐色，腹部一般较浅，有强烈的赤色和淡色标记；东部鸟羽毛最暗淡。","protection":"IUCN：LC（无危）。广泛分布在适宜栖息地中，面积约为2,590,000平方公里。在埃塞俄比亚局部常见，在尼日利亚Owerri附近，其出现频率比双距鹧鸪高约20倍。在乌干达多数森林中广泛分布，包括多个森林保护区和国家公园，甚至进入坎帕拉市。在马拉维最南端相对普遍，尽管局部栖息地面临压力。","distribution":"分布于赤道非洲之间，从尼日利亚南部到刚果民主共和国西部，再到乌干达，南苏丹和埃塞俄比亚西南部，然后向南延伸至刚果民主共和国东部，坦桑尼亚东北部和马拉维极北地区；同时记录于刚果民主共和国中部和南部以及苏丹西部。","other":"系统发育历史表明，鳞斑鹧鸪与褐顶鹧鸪是姐妹物种。"},{"name":"褐顶鹧鸪","english_name":"Ahanta Spurfowl","scientific_name":"Pternistis ahantensis","overview":"褐顶鹧鸪（英文名：Ahanta Spurfowl，学名：Pternistis ahantensis），是鸡形目雉科鸡鹧鸪属的鸟类。原生于西非。此鸟种以荷兰黄金海岸（现加纳南部）的Ahanta地区命名。","appearance":"褐顶鹧鸪是一种中等体型的、外观较为暗淡的灰褐色鸡鹧鸪，具有橙红色的喙和腿。当观察条件良好时，可以看到颈部和下部有明显的白色条纹。雄鸟体重约608克，雌鸟约487克，两性差异明显，雌鸟较小，翅膀覆羽更偏红棕色。雄鸟拥有1至2个刺状突起，而雌鸟则没有。虹膜呈棕色，喙橙红色基部黑色，腿橙色，眼周皮肤淡橙色。幼鸟的肩羽和二级飞羽有类似斑点的黑色标记，下体灰白相间，有细碎的白色条纹。","call":"褐顶鹧鸪的鸣叫声是一系列粗糙的音符，开始缓慢随后逐渐加快且更加有力，通常以二重奏的形式呈现。在某些地区或季节，它们主要在夜间鸣叫，尤其是在塞拉利昂的戈拉森林一月到二月期间，以及加纳的旱季。","habits":"褐顶鹧鸪栖息于画廊森林边缘、林缘、次生灌木丛和种植园，偏好沿水道的茂密下层植被和废弃的空地。它们主要在西非三个离散地区发现，包括塞内加尔西部、冈比亚、几内亚比绍和几内亚北部；几内亚南部、塞拉利昂和利比里亚西部；以及科特迪瓦东北部至尼日利亚西南部。它们是定居性的，仅在受到极大压力时才会飞行，之后往往选择在树上栖息。饮食多样化，包括种子、小豆类、木薯、大型果实和昆虫（如白蚁）。","breeding":"褐顶鹧鸪的繁殖习性知之甚少，但认为可能实行单配偶制。在塞内加尔甘比亚地区，繁殖期在1月和9月；在加纳，繁殖期从12月中旬持续到次年1月，雏鸟可持续至4月；在尼日利亚，已记录到1月第三周有刚孵化的雏鸟；在利比里亚，4月可见雏鸟。巢穴是一个铺满叶子的凹坑，位于密集的遮蔽处，通常产4-6枚奶油色到粉红褐色的蛋。","identification":"褐顶鹧鸪通过橙红色的喙和腿与双距鹧鸪和鳞斑鹧鸪区分开来，后者腿色较暗且有更明显的白色眉纹。当处于静止状态时，褐顶鹧鸪缺乏明显的图案，只有近距离时才能看到苍白的条纹下体。","protection":"IUCN：LC（无危）","distribution":"褐顶鹧鸪分布在西非，从塞内加尔甘比亚地区向东南延伸至尼日利亚西南部。在冈比亚、塞内加尔和几内亚比绍北部较为罕见和局部分布；在塞拉利昂和加纳广泛分布，尤其在加纳非常常见，随着森林砍伐其分布范围正在扩大；在象牙海岸可能广泛但密度低且数量可能在下降；在其分布范围的东部地区较为常见。","other":"在科特迪瓦，褐顶鹧鸪受到农业转化栖息地和过度狩猎的威胁；然而，在泰伊国家公园，狩猎活动已有所减少。尽管目前不需立即关注，但关于其丰度和实际或潜在威胁的更多详细数据仍需收集。"},{"name":"灰纹鹧鸪","english_name":"Grey-striped Spurfowl","scientific_name":"Pternistis griseostriatus","overview":"灰纹鹧鸪（英文名：Grey-striped Spurfowl，学名：Pternistis griseostriatus），是鸡形目雉科鸡鹧鸪属的鸟类。体型较大，呈褐色，为安哥拉特有种。头部灰褐，侧面较淡，前额、颈侧、颈背、披肩及背部呈赤褐色，羽缘灰色，有浅色条纹和稀疏的黑色网状纹。臀部和上尾覆羽灰褐，有细黑条纹，尾羽赤褐色亦有黑条纹。翅膀暗褐色，飞羽斑驳，外缘有棕色和褐色条纹。下体呈淡黄色，有赤褐色羽轴纹，胸部纹路更密集，对比鲜明的白色颏和喉。喙橙红，尖端三分之二黑色，眼睛棕色，腿和脚橙红色。","appearance":"成鸟长约29至33厘米，雄鸟体重265至430克，雌鸟体重213至350克。头部灰褐色，侧面较浅，额头、颈侧、颈背、肩羽和背部为赤褐色，带有灰色羽缘、淡色条纹和稀疏的黑色网纹。臀部和上尾覆羽灰褐色，有细黑条纹；尾羽赤褐色，同样有黑条纹。翅膀暗褐色，飞行羽斑点和条纹交错。下体呈淡黄色，胸部有赤褐色条纹，对比明显的白色颏和喉。喙橙红色，尖端三分之二黑色，眼睛棕色，腿和脚橙红色。雌鸟可能无刺或刺退化，其余特征与雄鸟相似。幼鸟全身有黑色标记，上体更富赤红肉桂色（带黑色斑点），下体较淡（腹部更白），胸腹的赤褐色条纹不那么强烈。","call":"领地叫声非常响亮，渐强的‘ff fffffffffff’重复两到三次。广告叫声为二重奏，一只鸟发出嘶哑上扬的‘shwwii’声，紧接着另一只鸟发出嘈杂的‘ke-ke-ke-ke’声。遇险时发出响亮尖锐的‘ke’声，间隔约1秒重复。在高人口密度区域，通常仅在黄昏后和黎明前鸣叫，但在其他地方，鸣叫持续到早晨。","habits":"栖息于画廊森林、次生林的茂密下层，以及浓密灌丛，也可能造访邻近的农田和废弃棉田；分布海拔从70米至2150米，主要在约500米至1150米之间。夜间在树上休息。","breeding":"关于繁殖行为的信息尚不充分。","identification":"与其他鳞状鹧鸪的区别在于胸部、披肩和上翼覆羽的赤褐色条纹。雌雄差异主要体现在雌鸟的刺缺乏或退化。","protection":"IUCN：LC（无危）。在安哥拉国家公园Kissama存在。由于数据普遍缺失，尚未确定具体威胁，但森林破坏可能是问题所在。急需广泛调查以评估状况并建议未来行动。","distribution":"分布于安哥拉西部，从Bengo和Cuanza Norte南至Benguela和极西北Huila。","other":"灰纹鹧鸪被认为是单型物种，无亚种被认可。"},{"name":"希氏鹧鸪","english_name":"Hildebrandt's Spurfowl","scientific_name":"Pternistis hildebrandti","overview":"希氏鹧鸪（英文名：Hildebrandt's Spurfowl，学名：Pternistis hildebrandti），是鸡形目雉科鸡鹧鸪属的鸟类。中型鸟类，以性别间显著不同的羽毛颜色而著称。雄鸟拥有棕色背部，腹部以黑白斑点装饰，雌鸟较小，体色较为朴素，下体呈红褐色。分布于东非至东南非，包括肯尼亚、坦桑尼亚、赞比亚等地。","appearance":"雄性希氏鹧鸪长34-41厘米，体重约600-645克，具白色底色并密布黑色斑点的喉、颈和腹部，头部暗灰棕色，耳羽灰红色，背部黑色且饰有红棕色和淡黄色条纹，边缘呈淡黄白色。喙红色，上颚黑色，眼睛棕色，腿亦为红色。雌鸟体型更小，下体红褐色，胸腹部斑点较少。幼鸟背部条纹更为明显，腿色较暗，部分个体腹部有深色斑点。","call":"鸣叫声为一系列快速、粗哑的音符，通常由单一音符开始，随后转换为双音符，形成\"kek..kek..kek..kerek..kerek..kerek..kek..kek\"的模式，也有单独或重复的\"kek\"声，以及低沉的\"chuck-a-chuk\"接触声。","habits":"希氏鹧鸪偏好开阔地带，有散在的遮蔽处，海拔主要介于2000米至2500米之间，但在赞比亚可低至650米，马拉维甚至100米。常见于岩石斜坡、茂密灌木、蕨类植物、灌丛和灌木草甸，高海拔地区的低矮灌木，以及常绿森林边缘。它们通常在树上休息。","breeding":"繁殖季节因地区而异，赞比亚为6月至9月，马拉维为4月至11月（高峰在6月至7月），东非则在1月、3月、5月至8月及11月至12月。可能为一夫一妻制。巢穴隐蔽，铺垫草叶。每次产卵6枚，蛋色从奶油色到浅棕色，孵化出的小鸟有宽幅的红棕色背条纹和淡黄色下体。","identification":"雄性希氏鹧鸪与非常相似的的区别在于前者下体斑点不规则，更多呈斑块状。雌鸟的红褐色下体极为独特；在分布区南部，体型更小且缺乏背部的白色条纹。幼鸟背部条纹比雌鸟更明显，腿色更暗。","protection":"IUCN：LC（无危）","distribution":"分布于肯尼亚中部和西部，南至坦桑尼亚、刚果民主共和国东部、赞比亚东北部和马拉维东南部。","other":"物种以德国自然学家Johann Maria Hildebrandt命名，他在肯尼亚塔伊塔-塔维塔县收集了首批标本。"},{"name":"双距鹧鸪","english_name":"Double-spurred Spurfowl","scientific_name":"Pternistis bicalcaratus","overview":"双距鹧鸪（英文名：Double-spurred Spurfowl，学名：Pternistis bicalcaratus），是鸡形目雉科鸡鹧鸪属的鸟类。大型鹧鸪，主要分布在西非和摩洛哥一小块孤立且数量减少的区域。雄鸟拥有独特的双距，是其显著特征之一。","appearance":"成鸟长度30至34厘米，翼展45至50厘米，雄鸟约重507克，雌鸟约381克。羽毛主要呈棕色，胸腹部分有深色和奶油色条纹。头部具有一条明显的白色眉线和锈色冠羽、颈圈。雌雄两性相似，但雌鸟通常较小，面部和喉咙颜色较淡，且可能无距或仅有微小的距。幼鸟较暗淡，裸露部位颜色较浅，仅有一或无距。","call":"具有响亮、刺耳的重复双音鸣叫，\"Ku-kwah, ku-kwah…\"，通常在清晨从低处的栖木（树、岩石或白蚁丘）发出。","habits":"偏好植被覆盖的栖息地，包括林地、干河床、耕作区，以及人类居住区附近的农场、牧场和废弃耕地。广泛适应各种开阔生境，从湿润的稀树草原到干旱的稀树草原，活动范围包括密集的栓皮栎灌丛地带。活动时间主要在清晨和傍晚，善于地面奔跑，仅在强烈逼迫时才飞离地面4至5米，飞行距离不超过200米。","breeding":"繁殖季节随地理位置而异，筑巢于地面，巢穴为圆形凹坑，直径15至25厘米，深度约2.5厘米，偶尔以草、干叶等材料铺垫。每窝产卵数通常为6枚，蛋壳呈沙色或黄褐色，偶有细小暗斑。孵化率高，但雏鸟存活率受天敌影响较大。","identification":"与其他类似物种的区别在于腿色（暗绿色）、白色眉线与黑色额头和冠羽形成对比、黑色和锈色斑驳的下体、窄的白色侧腹条纹，以及眼睛周围缺乏裸露皮肤。与、和在颜色、斑纹和裸露部位上有明显差异。","protection":"IUCN：LC（无危）。然而，摩洛哥亚种（ayesha）被认为是极度濒危，主要受到栖息地退化和过度猎杀的影响。","distribution":"主要分布于西非热带地区，从几内亚比绍至尼日利亚，以及加纳东南部的部分地区。在摩洛哥，分布局限于几个孤立的小区域，包括Sidi Bettache、Sidi Yahya des Zaër和Ben Slimane。","other":"双距鹧鸪是西非非森林地区最常见的spurfowl之一，但在摩洛哥的数量急剧下降，目前仅存于少数几个地点。"},{"name":"黄嘴鹧鸪","english_name":"Heuglin's Spurfowl","scientific_name":"Pternistis icterorhynchus","overview":"黄嘴鹧鸪（英文名：Heuglin's Spurfowl，学名：Pternistis icterorhynchus），是鸡形目雉科鸡鹧鸪属的鸟类。大型褐色鸟类，由德国探险家Theodor von Heuglin首次描述。分布于中非共和国、南苏丹、刚果民主共和国北部及乌干达西部。","appearance":"体长约32厘米，雄鸟体重504至588克，雌鸟420至462克。具黄色至橙色的腿、喙及眼周裸皮，颈下部及腹部条纹和斑点明显，面部图案强烈。雌鸟平均较小，幼鸟上体条纹更鲜明。","call":"领域叫声为主，通常在清晨、傍晚或雨后发出一系列粗糙的‘kreek’声，音调逐渐加大拉长。","habits":"栖息于中海拔的草原和灌木地带，常成对或小群体活动。饮食多样，包括种子、浆果、千足虫、甲虫、蚂蚁和白蚁。逃避危险时偏好奔跑而非飞行。","breeding":"繁殖季节为3月至6月（乌干达），9月至11月（刚果民主共和国），可能单配偶制。巢建于地面灌木下或密集遮蔽处，每次产卵6至8枚，颜色为淡灰黄色。雏鸟具红褐色和深褐色条纹。","identification":"与双距鹧鸪和Clapperton's Francolins相比，黄嘴鹧鸪的裸露部位为黄色至橙色。雌鸟有较小的刺。","protection":"IUCN：LC（无危）。广泛分布，无需特别保护关注。","distribution":"分布于中非共和国、南苏丹西部、刚果民主共和国北部和乌干达西部。","other":"被认为是单型物种，无亚种被认可。"},{"name":"红眶鹧鸪","english_name":"Clapperton's Spurfowl","scientific_name":"Pternistis clappertoni","overview":"红眶鹧鸪（英文名：Clapperton's Spurfowl，学名：Pternistis clappertoni），是鸡形目雉科鸡鹧鸪属的鸟类。具有独特的红眶特征，主要分布在非洲中部和东北部。","appearance":"中等体型，背部、颈部和下体部分布满黑色和淡色斑点，眼周有大片红色裸皮。雄鸟体重450-604克，雌鸟300-530克，约32-35厘米长。雄鸟有两枚刺，雌鸟可能有一枚或无。喙黑带红基，虹膜棕色，腿红色。幼鸟标记不明显，上体条纹不清晰。雌雄均有白色喉部和前颈，红腿是其显著特征。成年个体间存在变异性，尤其是颊须纹的有无和下体棕色标记的轻重。","call":"早晨和傍晚最活跃，常从低树或白蚁丘顶发出声音。叫声为粗糙的‘kreeya’，重复数次，远距离传播。还有一种两音节的哨声。","habits":"居住在半干旱草原、开阔的灌木林地和沙质草地，最高可达2300米，也会出现在耕地上和沼泽边缘。以种子、浆果、小型软体动物和昆虫为食，有时形成多达20只的群体。","breeding":"繁殖季节在马里和苏丹为8月至9月，在乍得为2月及7月至9月，在尼日利亚为2月至3月，在埃塞俄比亚为1月至2月及7月至12月。可能是一夫一妻制。巢筑于地面隐蔽处，窝卵数未知，但有记录显示在埃塞俄比亚曾发现九枚卵。卵呈脏白色至黄褐色。","identification":"与海氏鹧鸪相比，整体更苍白，喙主要是黑色而非红色。与和的叫声相似，但在外观上有明显区别。","protection":"IUCN：LC（无危）","distribution":"分布于马里东部、尼日尔中部、尼日利亚东北部、喀麦隆北部、乍得南部和中部、苏丹南部和东部、乌干达北部和东部、埃塞俄比亚及厄立特里亚。"},{"name":"海氏鹧鸪","english_name":"Harwood's Spurfowl","scientific_name":"Pternistis harwoodi","overview":"海氏鹧鸪（英文名：Harwood's Spurfowl，学名：Pternistis harwoodi），是鸡形目雉科鸡鹧鸪属的鸟类。具有红色的喙和腿部，眼周有大片裸露的红色皮肤。雌雄两性羽毛颜色相似，但雌鸟色彩较淡，腹部呈更多的浅黄色。该物种仅分布于埃塞俄比亚，局限于蓝尼罗河两岸的埃塞俄比亚高地，自坦纳湖至其与贾玛河汇流处及其间的支流。由于其特有的红眼圈和暗色的羽毛边缘，海氏鹧鸪成为了当地特有种。","appearance":"海氏鹧鸪体型中等，长约33至35厘米，体重范围从446克到545克。背部、颈部和下部羽毛为黑色，边缘呈淡色。雄鸟有两只脚爪，而雌鸟可能有一只或无脚爪。眼睛虹膜呈棕色，眼周皮肤红色，喙为黑色带红尖和基部，腿红色。幼鸟外观最像雌鸟，但上体斑纹不那么明显，年轻雄鸟的下体斑纹介于成年雄鸟和雌鸟之间。","call":"雄性海氏鹧鸪的广告叫声是一种非常粗糙、刺耳的‘kuree’声，重复3到4次，有时发出双音节的‘kureea-kureea’声，类似Clapperton's Francolin的叫声。叫声频率在黎明和黄昏时最高，通常从隐蔽处发出。","habits":"海氏鹧鸪栖息在大型密集的香蒲床中，周围散落着树木，沿着小型浅水道。它们在附近的高粱田中觅食。该物种还生活在以金合欢为主的荆棘灌木丛中，与多种树种共存，包括Acacia seyal、Terminalia brownii、Grewia bicolor等。它们的活动范围在海拔1200至2600米之间，常在开阔地带觅食，与珠鸡共同觅食。","breeding":"关于繁殖行为的信息有限，推测可能为多配偶制，但未在其他非洲热带地区的Francolinus中观察到。繁殖季节可能从五月或六月开始，当地居民报告十月发现过鸟蛋。巢中通常有3到10枚蛋。已知的一窝三只雏鸟约在二月中旬被观察到，估计首枚蛋可能在十二月初到中旬之间孵化。","identification":"与Clapperton's Francolin相比，海氏鹧鸪整体更暗，喙为红色而非黑色。与Erckel's Francolin相比，体型较小，色彩更深沉，腿和喙为红色。雌鸟体型较小，下体颜色稍淡，腹部标记呈V形而非U形。","protection":"IUCN：NT（近危）。虽然目前数量估计在6000到15000只之间，但由于其栖息地受到人类扩张的压力，加之因食用和传统医学用途被捕猎，其保护状态需进一步明确。","distribution":"海氏鹧鸪分布于埃塞俄比亚中部山区，具体在蓝尼罗河两岸的高地上，从坦纳湖至其与贾玛河的汇流处，以及其间的支流。在Jemma和Jara山谷以及北Showa区附近较为常见。","other":"海氏鹧鸪的卵被当地人用于食物和人工饲养。"},{"name":"斯维氏鹧鸪","english_name":"Swierstra's Spurfowl","scientific_name":"Pternistis swierstrai","overview":"斯维氏鹧鸪（英文名：Swierstra's Spurfowl，学名：Pternistis swierstrai），是鸡形目雉科鸡鹧鸪属的鸟类。罕见而独特的鹧鸪，仅见于安哥拉的Afromontane森林。其特征包括红色的喙和腿，白色的脸部，黑色的胸部条带，以及白底黑纹的下体。该物种在Mount Moco和Mount Soque等快速缩小的山地森林中生存。","appearance":"斯维氏鹧鸪拥有醒目的外观，其脸部大部分为白色，胸部有一条显著的黑色带纹，下体则为黑白相间的条纹。喙和腿均为红色，这些特征使其在同类中显得独特。","call":"其典型的叫声是一系列由低渐高的'kurr-kraak'声，先逐渐增强再减弱。当受惊时，会发出连续的类似家禽的咯咯声。","habits":"栖息于蒙特山林及其边缘地带，偏好岩石和草地环境。它们在清晨和傍晚时分最为活跃，声音在这一时段最为频繁。","identification":"与其他范围内的鹧鸪相比，斯维氏鹧鸪以其大胆的白色面部和黑色胸部条带为显著标志。","protection":"IUCN：VU（易危）。据估计，成熟个体数量在1000至2500之间，其中约75对生活在Mount Moco。由于持续的生境破坏和狩猎压力，种群正在减少。","distribution":"分布在安哥拉西部，从Cuanza Sul区的Cariango向南至Huambo区的Bailundu高地和Mombolo高原，以及Huíla区的Chela悬崖和Tundavala。","other":"斯维氏鹧鸪依赖于Afromontane森林，但该生境正迅速消失，尤其是在Mount Moco的高地上，仅存大约30片真Afromontane森林，每片面积超过0.5公顷。"},{"name":"喀麦隆鹧鸪","english_name":"Mount Cameroon Spurfowl","scientific_name":"Pternistis camerunensis","overview":"喀麦隆鹧鸪（英文名：Mount Cameroon Spurfowl，学名：Pternistis camerunensis），是鸡形目雉科鸡鹧鸪属的鸟类。其身长约33厘米，雄鸟体重约593克，雌鸟约509克。雄鸟拥有暗褐色上部羽毛，头部和颈背颜色更深，喉部和颈部灰白，下部羽毛呈深灰色，尾羽和飞羽为深棕色。雌鸟较为独特，红眼眶、条纹上部羽毛和斑驳下部羽毛，体型略小于雄鸟，可能无刺或仅有一短刺。幼鸟类似雌鸟成鸟，但下部有白色条纹，翼侧羽毛有黑白尖端，眼部裸露皮肤不发达，喙和腿色较暗。","appearance":"雄性喀麦隆鹧鸪有暗褐色的背部，头部和颈背颜色更深，喉部和颈部带有灰白色的羽毛边缘，下部羽毛为深灰色，尾下覆羽最深，所有羽毛具有深色中心和黑色羽轴条纹。飞行羽毛和尾羽为深棕色。雌鸟具有独特的红色裸露部分，上部羽毛有条纹，下部羽毛有斑点和蠕虫状图案，体型略小于雄鸟，可能无刺或仅有一短刺。幼鸟类似成年雌鸟，但在下部有白色条纹，翼侧羽毛有黑白相间的尖端，眼睛周围裸露皮肤较少或没有，喙和腿呈暗红色。","call":"喀麦隆鹧鸪的领土叫声为一系列短促的号角声‘kilu..kilu..kilu’，或较慢的‘kee-ku..kee-ku..kee-ku’，有时两者结合。通常在黄昏时从隐蔽的栖木发出，也可能成对合唱。","habits":"喀麦隆鹧鸪生活在喀麦隆山东西两侧的原始森林和次生林中，海拔介于850米至2100米之间，偏好茂密的灌木丛。它们通常是定居的，遇险时会飞到树上躲避狗类，但平时更倾向于奔跑。以浆果、草籽和昆虫为食。","breeding":"喀麦隆鹧鸪在干季繁殖，筑巢期在10月至12月间。具体繁殖行为尚缺乏详细信息。","identification":"喀麦隆鹧鸪与艳鹧鸪相比，上部羽毛颜色更广泛地为暗褐色，下部羽毛无栗色或浅灰色花纹。与共存，但性别特征不明显，缺乏眼周红皮。雌鸟具有独特的组合特征，易于区分。","protection":"IUCN：EN（濒危）。种群估计在600至1700只成熟个体之间，栖息地受限于喀麦隆山东南和东北坡的200平方公里范围内。1982年火山爆发破坏了大量适宜栖息地。物种可能受到过度狩猎威胁。","distribution":"喀麦隆鹧鸪主要分布在喀麦隆山的东西斜坡，位于非洲喀麦隆境内。"},{"name":"艳鹧鸪","english_name":"Handsome Spurfowl","scientific_name":"Pternistis nobilis","overview":"艳鹧鸪（英文名：Handsome Spurfowl，学名：Pternistis nobilis），是鸡形目雉科鸡鹧鸪属的鸟类。拥有暗红褐色的羽毛，头部呈灰色，喙与腿为红色，虹膜棕色，眼周裸露皮肤红色，腹部呈现红灰色。雌雄外观相似，但雌鸟体型较小，羽色较淡。幼鸟羽毛色泽更为暗淡。主要分布在非洲东部的刚果民主共和国东部、乌干达西南部、卢旺达和布隆迪的山地森林。","appearance":"艳鹧鸪体长约33至35厘米，雄鸟体重862至895克，雌鸟600至670克。其最显著的特征是红色裸露的眼周皮肤和深红褐色的下体羽毛，头部和臀部颜色较灰。雄鸟具有一至两个刺状突起，雌鸟刺状突起可能减小或缺失。幼鸟上体有条纹，边缘为灰褐色或棕褐色，下体颜色较浅，胸部和腹部更显灰色。","call":"艳鹧鸪的鸣叫声被描述为响亮粗糙的‘chuck-a-rick’，通常重复4到5次，有时被描述为‘cock-rack’或‘kre-kar-kre-kar-kre-kor’。它们常在黄昏或黎明时分呼唤同伴。","habits":"艳鹧鸪生活在海拔约1850至3700米的山地森林中，尤其偏好靠近水源或沼泽地带的竹林区域。它们倾向于定居，仅在受迫时才会短距离飞行，更喜欢通过奔跑的方式逃避危险。清晨和傍晚时分，它们会在道路上觅食种子。","breeding":"繁殖季节从四月末至九月，在刚果民主共和国东部的南基武省。尽管观察到小群体，推测为家庭群，但关于繁殖行为的详细信息尚不充分。","identification":"与鳞胸鸡鹧鸪（Scaly Francolin）相比，艳鹧鸪体型更大，羽毛颜色更深，且具有红色裸露的眼周皮肤。雌鸟比雄鸟小，刺状突起不明显或缺失。幼鸟上体有条纹，下体颜色较浅。","protection":"IUCN：LC（无危）。虽然在其分布范围内局部常见，但最近的调查发现，它在乌干达西南部的优质生境中仅在十分之一的调查点被检测到。考虑到其对山地竹林的强烈依赖，这种生境稀少且分散，因此对其保护状况的再评估可能是合理的。","distribution":"艳鹧鸪分布于刚果民主共和国东部（从蓝山南至伊通贝山脉）、乌干达西南部（鲁文佐里山脉、伊姆佩纳特拉布尔森林、基索罗和基巴莱周边）、卢旺达和布隆迪的山脉区域。","other":"艳鹧鸪在1908年由德国鸟类学家安东·赖兴诺夫首次描述，基于在维龙加山脉萨宾尼奥山采集的标本。该物种被列为单一类型，没有已知的亚种。"},{"name":"肯尼亚鹧鸪","english_name":"Jackson's Spurfowl","scientific_name":"Pternistis jacksoni","overview":"肯尼亚鹧鸪（英文名：Jackson's Spurfowl，学名：Pternistis jacksoni），是鸡形目雉科鸡鹧鸪属的鸟类。大型鸟类。以红喙、红腿和眼周裸露的红色皮肤为显著特征。主要栖息于肯尼亚山脉的森林、森林边缘、沼泽地及草地，偶尔出现在乌干达一侧的埃尔贡山。以英国行政官员兼鸟类学家Frederick John Jackson命名。","appearance":"肯尼亚鹧鸪体型庞大，羽毛呈深棕色，雄鸟体重可达1064至1130克，雌鸟较雄鸟小，雄鸟具有1至2个较小的刺。幼鸟颜色较暗淡，上部呈暗褐色条纹，腹部和两肋更多黑白条纹，胸部的栗色最为明显。与Scaly Francolin相比，体型更大，色彩更丰富，眼周有红色裸皮。","call":"肯尼亚鹧鸪的常见叫声是一系列响亮粗糙的“skraa”音符，其广告叫声是一连串高亢的‘grrr’声，类似磨刀的声音，与希氏鹧鸪和鳞斑鹧鸪的叫声相似。进食时还会发出低沉的咕哝声。","habits":"主要栖息在海拔2200米至3700米的高山森林及亚高山带，如杜松、竹林、沼泽灌木丛等地。通常不进入森林深处，偏好茂密的灌木覆盖区，尤其在死竹林被灌木取代的地方。在干燥天气中，它们会在日出前出来觅食，整个白天都会进食。它们在适宜的天气里会进入开阔地带晒太阳和沐浴尘土。","breeding":"繁殖季节在肯尼亚的阿伯代尔山脉和埃尔贡山为12月至1月，在毛高原为1月至2月、8月、10月和12月。一窝蛋至少有三个，呈浅棕色，尺寸约为46.5mm×36mm，一窝最多可有七个雏鸟，与成鸟共同生活约8个月。","identification":"与栗枕鹧鸪相比，肯尼亚鹧鸪的下部花纹更加规则，额头和脸部几乎没有黑色。与体型较小的鳞斑鹧鸪和相比，其红喙、红腿和栗色条纹使其易于辨认。","protection":"IUCN：LC（无危）。在适宜的栖息地中广泛分布，估计面积为16,500平方公里，总体分布在大约50,000至60,000平方公里。目前无需特别的保护措施，但在国家公园内密度较高，埃尔贡山森林保护区的适宜高度区域达到约900平方公里。","distribution":"主要分布在肯尼亚西部的埃尔贡山、切兰甘尼山、毛高原、阿伯代尔山脉和肯尼亚山，以及乌干达一侧的埃尔贡山。","other":"虽然在某些地区的森林边缘受到人类干扰，且存在一定的偷猎现象，但目前肯尼亚鹧鸪并不面临严重的威胁。"},{"name":"栗枕鹧鸪","english_name":"Chestnut-naped Spurfowl","scientific_name":"Pternistis castaneicollis","overview":"栗枕鹧鸪（英文名：Chestnut-naped Spurfowl，学名：Pternistis castaneicollis），是鸡形目雉科鸡鹧鸪属的鸟类。大型雉科鸟类，分布于非洲的山区，具体包括埃塞俄比亚东北部和索马里西北部。其特征为头上有栗色和黑色相间的羽毛，颈部呈红褐色，腹部主要为鳞片状花纹，侧腹有栗色条纹。在海拔1,200至4,000米的山地森林边缘和草甸中，常以小家庭群的形式出现。","appearance":"栗枕鹧鸪是一种体型较大的鸟类，全长约38-43厘米，重550-1,200克。头部特征明显，前额和眉纹为黑色，上体灰褐并带有黑色、白色及栗色斑点。冠羽、颈背和耳羽为姜红色，下体主要为鳞片状花纹，侧腹有栗色条纹。腹部为几乎未着色的淡奶油白色，上体暗灰褐色，臀部和尾上覆羽无斑点，与背部形成鲜明对比。雌鸟体型较小，可能没有或仅有极小的距。幼鸟比成鸟暗淡，尾羽和上覆羽有细小的淡色横斑，喙色较暗。","call":"栗枕鹧鸪发出响亮的‘kawar-kawar’声，伴随尖锐的‘kek kek kek’叫声，被认为是配偶间的二重唱。通常在清晨和傍晚从茂密的遮蔽处发出叫声。","habits":"生活在中高海拔的山地森林边缘和草甸，通常以小群体形式出现，可能是家庭群。它们在地面觅食，以种子和昆虫为主食，如白蚁。白天大部分时间都在觅食，特别是在早晨和傍晚。","breeding":"繁殖季节在埃塞俄比亚为10月至翌年3月，索马里则在雨季和旱季交替时。筑巢于灌木或其他遮蔽物下的地面。巢穴是一个简单的凹陷。每窝产蛋数通常为5-6枚，但也报告过高达10枚的情况。幼鸟与成鸟一起直到完全成熟。","identification":"与棕顶鹧鸪和淡腹鹧鸪相比，栗枕鹧鸪具有红色的喙和腿，而前者则为黑色喙和黄色腿。此外，栗枕鹧鸪的腹部为奶油白色，额头为黑色。","protection":"IUCN：LC（无危）","distribution":"分布于埃塞俄比亚东北部的山脉，索马里西北部，以及肯尼亚的Moyale边境地区。在埃塞俄比亚，常见于Bale和Arussi山脉，Kaffa和Jima省的森林边缘。","other":"栗枕鹧鸪包含两个亚种，其中P. c. atrifrons在一些权威分类中被视为独立物种，数量估计仅1,100-2,100只，因栖息地破坏而面临威胁。"},{"name":"黑额鹧鸪","english_name":"Black-fronted Spurfowl","scientific_name":"Pternistis atrifrons","overview":"黑额鹧鸪（英文名：Black-fronted Spurfowl，学名：Pternistis atrifrons），是鸡形目雉科鸡鹧鸪属的鸟类。延伸至眼上方，白色喉部，颈胸部为淡褐色带暗色条纹，上体和翼上覆羽呈淡褐色，多数羽毛有黑色亚缘斑和细白边，胸侧和上腹有柔和边缘的箭状灰色鳞状斑，腹部几乎无斑点，呈暗奶油色。虹膜棕色，后方有黄色裸皮斑，喙红色，腿为粉红至棕红色。雌雄相似，雌鸟略小，腿部无距。","appearance":"体长约40厘米，黑额鹧鸪具有黑色额头，颜色延伸至眼周和眉区，白色喉咙；颈部和胸部为淡褐色，带有较深的条纹；上体和上翼覆羽为淡褐色，多数羽毛有黑色亚边缘标记和细薄的白色边缘；胸部和上侧腹有柔和边缘的箭头形状灰色鳞片状斑纹，腹部几乎无斑点，呈暗淡的奶油白色；虹膜棕色，后方有一块黄色裸露皮肤；喙为红色；腿为粉红色至粉棕色。雌雄外观相似，雌鸟比雄鸟略小，颜色更偏棕色，腿部无距。幼鸟与成鸟相似，但年轻雄鸟的上喙主要为褐色，额头黑色减少，眼后皮肤蓝色，眼环蓝灰色，腿橙红色。","call":"发出粗糙、刺耳且相当嘈杂的咯咯声，每一系列持续约3秒，由四个元素组成：第一个元素无声，随后每个元素增加一个音节，最后一个四音节元素形成‘咯咯颤音’。叫声通常在清晨听到，但也会在白天稍晚时出现。","habits":"栖息于森林边缘的灌木丛和半开放的林地中，有大面积低矮灌木，穿插着高植被（树木、灌木）和开阔地带（岩石、放牧地），最近的观察均在海拔约1480至2225米之间。不在相邻的农田中被记录到。以种子为主食，同时也吃昆虫，如白蚁。","breeding":"繁殖信息未知，仅有的信息来源于3月和5月中观察到的幼鸟，这可能意味着该物种在主雨季繁殖。","identification":"与栗枕鹧鸪的区别在于其羽毛只有一点或完全不含栗色，缺乏大胆的灰色标记，腹部更为单一和无斑点，体型较小，反映在喙、腿和脚的尺寸上，以及黄色的眼后皮肤。雌雄相似，但雌鸟略小。","protection":"IUCN：EN（濒危）","distribution":"分布于埃塞俄比亚南部（Oromia地区的Mega附近），并在肯尼亚极北地区（Moyale）也有记录。","other":"曾与栗枕鹧鸪归为同一物种，但遗传和生物声学数据支持其独立物种地位。"},{"name":"淡腹鹧鸪","english_name":"Djibouti Spurfowl","scientific_name":"Pternistis ochropectus","overview":"淡腹鹧鸪（英文名：Djibouti Spurfowl，学名：Pternistis ochropectus），是鸡形目雉科鸡鹧鸪属的鸟类。体型较大、圆润的雉科鸟类，分布于非洲东部吉布提的特定山林地带。其体长约为35厘米，重约940克。全身灰褐色，下体有白色条纹和斑点，上体颜色较深，头部带有黑色标记，颈背略带锈色，头顶灰色，眼周有灰色羽冠。生活在高海拔的干燥森林中，以果实、种子和白蚁为食，通常成小群活动，极为羞怯。","appearance":"淡腹鹧鸪长约35厘米，重约940克。全身羽毛灰褐，下体白色条纹和斑点明显，上体颜色较深。额头、眼侧和头侧呈黑褐色，形成面具状图案；耳羽灰，眼后有白色斑点，下颊至喉部淡黄或淡褐色，无条纹。颈侧、胸至大部分下体黑色条纹和淡褐色背景交织，中央腹部和尾下覆羽更显白色条纹。背部暗灰褐色，锈色条纹，与稍浅的初级飞羽和棕色尾羽形成对比。喙深灰色，下颚角黄色，眼睛褐色，腿脚灰绿至橙黄色。雌雄相似，但雄鸟略大，具两个明显腿上刺，雌鸟刺较小，尾部锈色更浓。幼鸟外观似成鸟，但色泽较暗，下体具条纹而非斑点。","call":"叫声为一连串加速的‘erk’声，随后是一系列重复的‘kak’音，逐渐减弱至低沉的咕噜声。","habits":"栖息于海拔700至1500米的原生非洲杜松林中，林下层由黄杨和埃塞俄比亚酸枣构成。也可见于次生林和退化生境。主要食物为种子、浆果和白蚁，亦在森林边缘食用寄生无花果。在觅食时，会耙过地面，包括野猪扰动过的区域。通常以对或小群体出现，最多记录到20个个体一起。","breeding":"可能为一夫一妻制。繁殖季节为12月至次年2月，产卵7至9枚（据当地人所述）。已知唯一巢穴位于山崖上的浅坑，铺垫草本植物。家族群九只在三月被观察到，此时蜜獾为主要捕食者，但也有记录显示幼鸟出现直至六月。","identification":"与棕顶鹧鸪相似，但分布范围不重叠。可以通过黑色的喙和黄色的腿来区分于栗枕鹧鸪。","protection":"IUCN：CR（极危）","distribution":"仅限于吉布提的两处地点：Goda山脉的Forêt du Day森林和东北方向80公里的Mabla山脉。","other":"因栖息地退化导致数量急剧下降，自1980年代以来减少了90%以上。主要威胁来自过度放牧、伐木、狩猎和采集鸟蛋。"},{"name":"棕顶鹧鸪","english_name":"Erckel's Spurfowl","scientific_name":"Pternistis erckelii","overview":"棕顶鹧鸪（英文名：Erckel's Spurfowl，学名：Pternistis erckelii），是鸡形目雉科鸡鹧鸪属的鸟类。雄鸟比雌鸟大。头部的前额、眼周和两侧呈黑色，头顶和颈背为栗色，耳羽灰白带斑点。上体暗褐色，翼覆羽橄榄灰带深栗边。下体灰色，胸腹间有栗色条纹。喉部白色，腹部和胁部乳白色，具深栗色条纹。喙黑，眼棕，腿足黄。雄鸟双距，雌鸟或无距或单距。","appearance":"体长38至43厘米，体重雄鸟1.05至1.59千克，雌鸟约1.136千克。雄鸟较大，雌鸟较小。头部特征明显，头顶和颈背栗色，耳羽后有白色斑块，眼后有一条白色条纹。上体暗褐色，翼覆羽橄榄灰带深栗色边缘。下体灰色，胸腹间有栗色条纹，喉部白色，腹部和胁部乳白色，具深栗色条纹。喙黑色，眼睛棕色，腿足黄色。雌鸟的距较雄鸟小或缺失。","call":"叫声为一连串响亮的‘er-er-er’笑声，音调逐渐降低。","habits":"栖息于海拔2000至3500米的山区，偏好草地、灌木丛和沟壑地带，尤其偏爱湿润环境。常见于埃塞俄比亚北部、厄立特里亚至埃塞俄比亚中部及苏丹东北部。在夏威夷被引入后，常见于考艾岛、拉奈岛和夏威夷岛，偶尔见于欧胡岛和毛伊岛。","breeding":"具体繁殖信息不详，但一般在雨季（4月至11月）产卵，具体时间因地区而异。在埃塞俄比亚，产卵时间为5月至11月；在苏丹，则为4月至5月。","identification":"与淡腹鹧鸪相比，整体上上体颜色更偏橄榄褐色，黑色喙和黄色腿脚可避免与栗枕鹧鸪混淆。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的苏丹东北部，厄立特里亚至埃塞俄比亚中部。在夏威夷被引入。"},{"name":"哈氏鹧鸪","english_name":"Hartlaub's Spurfowl","scientific_name":"Pternistis hartlaubi","overview":"哈氏鹧鸪（英文名：Hartlaub's Spurfowl，学名：Pternistis hartlaubi），是鸡形目雉科鸡鹧鸪属的鸟类。是非洲南部特有种。此鸟种以德国医师兼鸟类学家Gustav Hartlaub命名，分布于纳米比亚中部至北部及西南安哥拉。哈氏鹧鸪是小型的非洲鹧鸪，具有显著的雌雄异型，雄鸟拥有独特的下弯长喙，雌鸟则羽色平淡。","appearance":"雄性哈氏鹧鸪约28厘米长，重245至290克，拥有暗褐色前额、白色眼纹和红色耳羽。背部为灰棕色，饰有深色条纹，腹部呈淡灰色，密布深色斑纹。雌鸟体型较小，约25厘米，体重210至240克，其羽色为单色调的肉桂棕色，缺乏雄鸟的条纹。雌雄双方均具大嘴，雄鸟上喙为棕色，下喙为黄色，腿黄色，带有扁平的刺。幼鸟与成年雄鸟相似，但斑纹更细；幼雌鸟与成年雌鸟类似。","call":"哈氏鹧鸪的领地鸣唱为雄雌二重唱，结合粗糙的咯咯声与高音尖叫，形成重复的节奏短语，如“kor-rack..keerya..keerya..kew”。警报时，雄鸟发出尖锐的“kerr-ack”，雌鸟则发出高音“keer”。被惊飞时，雄鸟会连续发出急促的‘krak’声。","habits":"栖息于海拔800至1600米的干旱和半干旱地区，偏好位于岩石花岗岩和砂岩露头（当地人称koppies）的较高地面，周围环绕着半沙漠草原。它们常成对或小家庭群出现，不太容易被发现，倾向于在巨石间隐蔽。主要食物来源包括Cyperus等植物的球茎、种子和昆虫。与红嘴鹧鸪和橙翅斑鹧鸪共享栖息地，但占据不同的生态位。","breeding":"繁殖季节从4月至8月，可能随降雨量而变，也记录到11月和2月。一夫一妻制并保卫领地。已知的一个巢穴位于悬崖凹处。窝卵数估计为4至8枚，蛋壳颜色为乳白色，尺寸约为42至43.5毫米×29至29.8毫米。孵化后数月可见家庭群体。","identification":"在分布范围内，通过缺乏红色喙和面部皮肤来区别于其他鹧鸪。雄鸟以其独特的头部和下体颜色（黑色条纹）与相似物种区分；雌鸟则通过灰白的颈部和浅肉桂棕色下体识别。","protection":"IUCN：LC（无危）","distribution":"哈氏鹧鸪分布于西南安哥拉（从Benguela区和西南Huíla区）至纳米比亚西部围绕Capricorn回归线一带。在纳米比亚的Waterberg高原和Daan Viljoen公园，以及安哥拉Huíla的Iona国家公园有记录。","other":"哈氏鹧鸪的亚种ovambensis、bradfieldi和crypticus曾被描述，但未被广泛认可。"},{"name":"红嘴鹧鸪","english_name":"Red-billed Spurfowl","scientific_name":"Pternistis adspersus","overview":"红嘴鹧鸪（英文名：Red-billed Spurfowl，学名：Pternistis adspersus），是鸡形目雉科鸡鹧鸪属的鸟类。体型中等，主要分布在非洲中南部，包括安哥拉、博茨瓦纳、纳米比亚、南非、赞比亚和津巴布韦。雄鸟长约38厘米，重340-635克；雌鸟略小，长约33厘米，重340-549克。其显著特征为腹部具条纹，不同于近缘的纳塔尔鹧鸪，且拥有醒目的黄色眼环。","appearance":"红嘴鹧鸪体色呈褐色，腹部、头部和背部有精细的条纹。雄鸟约38厘米长，体重340-635克；雌鸟约33厘米长，体重340-549克。最显著的特征是宽阔的黄色眼环，红色的喙和脚。幼鸟的眼环较淡，条纹不明显。喙为红色，幼鸟的喙带棕色，上颌较浅。虹膜深棕色，腿也为红色，幼鸟腿色偏黄灰色。","call":"红嘴鹧鸪的鸣叫声粗糙低沉，从低矮的栖木发出的领土叫声为“chak, chak, chak, CHAK, chakitty, chakitty”，声音嘶哑且音调较低。","habits":"栖息于干旱的灌木草原、泛滥平原、Baikaiea、金合欢和混合林地、灌丛国家和灌木丛，常靠近水源，包括流动和静止水体，甚至人造水井。活动范围不大，一般不超过5公里，主要在清晨和傍晚活跃，白天高温时段会寻找阴凉处休息。受到威胁时更倾向于奔跑而非飞行，但在必要时也会飞入树上。","breeding":"繁殖季节通常在雨季后期或旱季初期，当群居解散时开始。筑巢于灌木下或草丛中，巢可能简单铺垫或无衬垫，呈浅坑状。每窝产4-10枚（通常6-7枚）蛋，颜色从奶油色到黄褐色不等，孵化期大约22天。雏鸟出生时具有暗褐色的背部条纹和淡黄色的腹部，胸部颜色较深。成鸟羽毛在约3个月后形成，雄鸟的刺在5个月左右变得明显。","identification":"与纳塔尔鹧鸪的区别在于后者腹部为鳞片状而非条纹状，且缺乏眼环。与斯氏鹧鸪的区别在于后者有裸露的红色喉部皮肤和灰色而非红色的腿。红嘴鹧鸪的亚种mesicus比指名亚种adspersus略暗，白色条纹更窄，黑眼圈更大，喉咙和胸部颜色更深，整个下体颜色较暗，至少在纳米比亚的Waterberg地区的个体体型较大。","protection":"IUCN：LC（无危）。红嘴鹧鸪广泛分布于约115万平方公里的适宜生境，被认为在纳米比亚广泛而丰富，数量稳定。在受保护区域常见，但其生存并不依赖于这些区域。在津巴布韦西北部，红嘴鹧鸪仅限于狩猎区，建议在12月至3月期间开放狩猎季。在南非西北部，过去50年里由于人工水源的增加和耕作面积的扩大，数量可能有所增长。不需要特别的保护关注，体育狩猎可以作为筹集保护物种和栖息地资金的一种方式。","distribution":"分布于非洲中南部，从安哥拉南部至纳米比亚北部和博茨瓦纳，延伸至赞比亚西南部、津巴布韦西北部和南非东北部。已引入夏威夷，但未能成功建立种群。","other":"曾被归类于Notocolinus属，但该名称可能代表了有效亚属，包括南非鹧鸪、纳塔尔鹧鸪和希氏鹧鸪。与纳塔尔鹧鸪在圈养环境下杂交过。形态学和尺寸变异研究显示，应将其分为mesic和desertic两种群，前者被命名为新亚种mesicus。"},{"name":"南非鹧鸪","english_name":"Cape Spurfowl","scientific_name":"Pternistis capensis","overview":"南非鹧鸪（英文名：Cape Spurfowl，学名：Pternistis capensis），是鸡形目雉科鸡鹧鸪属的鸟类。南部非洲特有的大型francolin，主要分布在南非西部省份和南部纳米比亚局部地区。该物种适应力强，能在多种人为改变的生境中生存，但需要灌木丛作为栖息和筑巢的空间。","appearance":"南非鹧鸪长约40-43厘米，体重方面，雄鸟平均600-915克，雌鸟平均435-659克。外观上，全身大致呈深褐色，细密的白色条纹和网状纹路形成独特的鳞片状图案。头部和颈部的冠部与颈背较为平实，雄鸟有两根腿刺，而雌鸟可能仅有一根短腿刺。幼鸟的腿色较暗淡，羽纹更为模糊，且腿色较暗。","call":"雄鸟的广告叫声在清晨和傍晚最为常见，是一连串响亮的“kak-keek, kak-keek, kak-keeeeek”声，音调逐渐升高但音量逐渐减弱。此外，还有被描述为‘喷溅’的飞行叫声，可能在受惊飞起时发出。","habits":"南非鹧鸪常栖息于灌木植被、灌木丛、fynbos、岩石露头和受保护的河岸灌木丛中。它们也能在异域的金合欢树丛中找到，甚至在无人迫害的花园草坪上活动。它们是定居鸟类，除非迫不得已才会飞行，更偏好奔跑以逃避威胁。","breeding":"繁殖期通常在7月至次年2月，高峰在9月至10月，正值冬季雨季晚期或干季初期。可能是单配偶制。巢穴是一个草垫铺底的凹洞，隐藏在茂密的灌木下。每窝产卵6至8枚，颜色从棕奶油色到粉红色或紫粉色不等。平均孵化期约为23天，由雌鸟单独孵化。幼鸟大约在12天大时就能短距离飞行。","identification":"与灰翼鹧鸪相比，南非鹧鸪具有红腿，胸部有赤褐色条纹，颈部有灰棕色的项链状图案。雄鸟有两根腿刺，雌鸟最多一根。幼鸟腿色较暗，羽纹较不明显。","protection":"IUCN：LC（无危）。南非鹧鸪在其适宜生境中广泛分布，估计覆盖约222,000平方公里。尽管局部常见，但其数量被认为保持稳定。虽然在开普角和德胡普自然保护区得到一些保护，但保护区面积较小，指定更多保护区虽有益处，但可能不是长期生存所必需的。农业集约化和过度狩猎可能是潜在问题。","distribution":"主要分布于南非的西部开普省的strandveld、renosterveld和fynbos地区，特别是在低海拔地区。在高海拔地区被灰翼鹧鸪取代。在succulent karoo地区密度较低，在Nama karoo地区靠近河流的区域频繁出现。在Robben岛有人工引入。","other":"在人类改变的生境如公园、农田、果园、葡萄园和入侵的rooikrans树林中觅食。"},{"name":"纳塔尔鹧鸪","english_name":"Natal Spurfowl","scientific_name":"Pternistis natalensis","overview":"纳塔尔鹧鸪（英文名：Natal Spurfowl，学名：Pternistis natalensis），是鸡形目雉科鸡鹧鸪属的鸟类。中等体型，广泛分布于非洲东南部，包括博茨瓦纳、斯威士兰、莫桑比克、南非、赞比亚和津巴布韦等地。其最显著的特征为黄色鼻孔、橙红色喙与腿脚，背部呈斑驳棕色，下体羽毛边缘呈棕白相间，形成独特的大理石鳞片状外观。","appearance":"纳塔尔鹧鸪体长30至38厘米，体重介于370至723克之间，雌雄差异不大。头部暗灰棕色，羽毛边缘较浅，眼周有黑色斑块，下体羽毛紧密排列，黑色边缘明显，尤其在两胁和喉咙至胸部最为显著。上体为暗淡灰棕色，带有不明显的浅色纹路和突出的黑色羽轴条纹。幼鸟颜色较淡，下体羽毛为淡褐色，细密黑杠，白色羽轴条纹，喙色暗绿，腿脚粉红。成年雄鸟有较小的刺，而雌鸟的刺几乎不存在。","call":"其叫声独特，为响亮粗哑的‘kak-kreek’声，音调时快时慢，变化丰富。领地叫声为重复的3至4个音符‘ker-kik-kik’，强调在‘kik’音上，同时也会发出快速的嘶哑或尖锐的咕噜声，有时会连续重复4至5次，受惊时则会发出单个‘kik’或双音‘kerr-ik’。","habits":"纳塔尔鹧鸪偏好有遮蔽的环境，从海平面至海拔1800米的地带皆可见其踪迹，包括山坡上的密集灌木丛、沿水道的干燥森林、有下层植被的灌木或林地，甚至山地森林和灌木丛。它们也栖息在岩石地区的金合欢灌丛、河流边的植被以及农田上的成熟作物中。通常在水源附近活动。","breeding":"繁殖季节因地区而异，通常在雨季后期到冬季，南非洲地区一般在一月至二月和四月至七月，津巴布韦除十月外的各个月份都有繁殖记录，赞比亚则在一月至八月间，四月为高峰期。可能是单配偶制。巢穴简单，位于密集遮蔽处，由草和少量羽毛铺垫。通常产五枚奶油色至淡黄色蛋，平均尺寸为42毫米×34毫米，孵化期大约20至22天，仅由雌鸟负责。雏鸟出生后，由双亲共同照顾，10至14天后能进行短距离飞行，49至56天后飞行能力较强。","identification":"与希氏鹧鸪相比，纳塔尔鹧鸪的下体羽毛呈鳞片状而非条纹状，且具有黄色眼圈。Swainson's francolin的区别在于面部皮肤红色，腿脚深黑色。成年雄鸟和希氏鹧鸪雄鸟的区别在于更细致、更规律的黑色标记。","protection":"IUCN：LC（无危）。在超过100万平方公里的适宜生境内普遍存在，数量普遍丰富或局部常见。南非由于土地开发导致数量下降，但目前被认为稳定，狩猎活动提供了物种保护的经济动力。在多个保护区有分布，但其生存并不依赖于这些区域。津巴布韦允许狩猎，建议的狩猎季节为八月至十一月。无需特别的保护关注。","distribution":"主要分布在南部非洲，从赞比亚南部和津巴布韦延伸至莫桑比克西部和南非东北部。","other":"纳塔尔鹧鸪与希氏鹧鸪被认为是姐妹种，但目前认为是单型种，即没有公认的亚种。"},{"name":"黄颈鹧鸪","english_name":"Yellow-necked Spurfowl","scientific_name":"Pternistis leucoscepus","overview":"黄颈鹧鸪（英文名：Yellow-necked Spurfowl，学名：Pternistis leucoscepus），是鸡形目雉科鸡鹧鸪属的鸟类。以其颈部醒目的黄色斑块命名。分布于非洲的广阔区域，从厄立特里亚至索马里，肯尼亚和坦桑尼亚东北部。具有适应性强的特点。","appearance":"这是一种体型较大的鹧鸪，身长约33-36厘米，体重雄鸟615-896克，雌鸟400-615克。头部有橙红色裸露皮肤环绕眼睛，最显著的特征是颈部的黄色裸露皮肤。初级飞羽上的大块淡色斑点在飞行时尤为明显。喙黑色，雌鸟平均比雄鸟小，且雄鸟有两根脚后跟的刺。幼鸟色彩较暗淡，有灰色底纹和白色细纹的下体，上体有淡褐色虫蚀状斑纹，面部和喉部皮肤颜色较浅。","call":"其叫声是一系列粗糙的“kreaaak”音符，逐渐减弱。","habits":"栖息于各种较为干旱的草原生境，包括人类耕作的田地。偏好有Acacia/Commiphora灌木丛和混合年度及多年生草本植物的生境，年降水量约200-400毫米。海拔高度可达2400米。清晨可能步行或飞行数百米到达特定区域觅食，受惊时会奔跑或飞往隐蔽处。以莎草块茎为主食，尤其是在肯尼亚南部和坦桑尼亚，占其食物量的一半以上；此外，还吃多种植物的果实、种子、昆虫（主要是白蚁），并在雨季之后依赖草本和禾本科植物的种子。","breeding":"繁殖期通常在雨季后期，以便雏鸟在凉爽干燥的季节孵化。筑巢主要在肯尼亚和坦桑尼亚北部的5月至7月间，但在除2月以外的每个月份都有记录。巢是一个简单的坑洼，有时铺有少量的草、羽毛等。每窝产蛋通常5枚，颜色为奶油色到浅粉色，有深色斑点，尺寸约为43-47.3毫米×32-37.8毫米，重约31克。孵化期大约18-20天，雏鸟出生后24小时左右即可离巢，与父母一起直到成年体型。幼鸟的初级飞羽在4-6周内完全长成，脚后跟的刺在第18周左右开始长出。","identification":"通过其独特的黄色裸露喉部和前颈皮肤很容易识别，这与其他鹧鸪种类形成鲜明对比。雄鸟的黑色喙将它与颜色较深的红喉鹧鸪区分开.而与彩鹧鸪的区别在于后者眼周没有黄色裸露皮肤。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的广阔区域，包括厄立特里亚、埃塞俄比亚、肯尼亚、索马里、苏丹南部、坦桑尼亚东北部和乌干达。在肯尼亚、埃塞俄比亚和索马里普遍可见。","other":"尽管数量被认为正在下降，但黄颈鹧鸪并不处于全球威胁的边缘，主要威胁是过度狩猎。"},{"name":"彩鹧鸪","english_name":"Grey-breasted Spurfowl","scientific_name":"Pternistis rufopictus","overview":"彩鹧鸪（英文名：Grey-breasted Spurfowl，学名：Pternistis rufopictus），是鸡形目雉科鸡鹧鸪属的鸟类。体型较大，喉部和眼周有裸露的红色皮肤，喙红，腿深灰色，腹部两侧有栗色、淡黄色和黑色斑纹。常见于相对干燥的荆棘草原、林地和灌木丛，通常成对或小群体活动。在非洲坦桑尼亚西北部的维多利亚湖东南岸至韦姆贝雷一带分布。","appearance":"彩鹧鸪身长约为32至41厘米，雄鸟体重779至964克，雌鸟体重400至666克。雄鸟具有两个脚刺，而雌鸟几乎无刺。幼鸟上体更灰，有淡黄色条纹，但肩部无栗色。成鸟整体呈灰色，胸腹部有黑白相间的条纹。","call":"发出一系列渐弱的沙哑‘kreaaak’音调的叫声。","habits":"栖息于年降水量500至700毫米的平原和草原，包括草地边缘和金合欢树丛。白天多数时间在树上休息，仅在清晨和傍晚到开阔地带觅食。主要以莎草根茎、种子和昆虫为食，如蚱蜢和白蚁。","breeding":"在雨季后期和旱季早期的二月至四月和六月至七月间繁殖。一夫一妻制，领地性。在高草丛中的凹陷处筑巢，用草和羽毛衬垫。每窝产4至5枚浅棕色蛋，孵化后的小鸟有宽大的暗褐色脊背条纹，下体淡黄色。家庭群通常少于七只个体。","identification":"与黄颈鹧鸪相比，彩鹧鸪有橙红色的喙和喉部裸露的橙色或粉色皮肤，上体有栗色，整体更偏灰色。与红喉鹧鸪的区别在于后者腿黑，羽毛颜色较暗。","protection":"IUCN：LC（无危）。在适宜生境广泛分布，但在人类人口扩张导致密集耕作和家畜放牧的地区遭受影响。","distribution":"分布于非洲坦桑尼亚西北部，包括维多利亚湖东南岸至韦姆贝雷一带。","other":"在东南塞伦盖蒂国家公园与黄颈鹧鸪杂交。"},{"name":"红喉鹧鸪","english_name":"Red-necked Spurfowl","scientific_name":"Pternistis afer","overview":"红喉鹧鸪（英文名：Red-necked Spurfowl，学名：Pternistis afer），是鸡形目雉科鸡鹧鸪属的鸟类。生活在非洲干热地带的典型鹧鸪，以灌木丛、开阔林地、森林边缘和有林木的峡谷为主要栖息环境。红喉鹧鸪广泛分布于从加蓬和肯尼亚南部至南非海岸的广大区域。","appearance":"红喉鹧鸪体长25-38厘米，体重差异显著，雄鸟480-1000克，雌鸟370-690克。其特征为明亮的红色喉咙和面部裸露皮肤，红色喙和腿。羽毛上部呈棕色，下部具黑色条纹。雄鸟拥有1-2个刺，而雌鸟的刺较短。幼鸟色彩较为暗淡，带有白色斑点和斑驳的飞羽，喙色较深，腿色较淡且偏黄。亚成体（7-10个月大）呈现深棕色，面部皮肤清晰红色，但仅有小突起而非成熟的刺。","call":"红喉鹧鸪的叫声是一系列粗糙的“krek”音符，有时带有欢快的前奏。","habits":"红喉鹧鸪栖息于多种生境，包括湿润的灌木丛、草地、灌木林、耕作区和森林边缘。它们通常在清晨和傍晚鸣叫，尤其在求偶期间最为活跃。该物种在不同季节食用不同的食物，如小型块茎、蔬菜物质、昆虫及其幼虫，甚至在飞行中的白蚁。","breeding":"繁殖期多在雨季后期，雏鸟在旱季初期浓密的覆盖物中出现。红喉鹧鸪在雨季和旱季交替时期产卵，如东南非的4月至8月，津巴布韦的1月至7月（主要是4月），安哥拉的2月至6月。它们通常是单配偶制和领地性的，雄鸟会守护约1.5公顷的巢区，驱赶其他雄鸟。巢穴由雌鸟在树或灌木基部长草中挖成，一般产3-9枚粉色至浅褐色的蛋。","identification":"红喉鹧鸪通过其独特的红色喉咙和面部皮肤与大多数其他鹧鸪区分开来。在与Swainson's或灰胸鹧鸪重叠的区域，可通过黑白相间的下部特征识别红喉鹧鸪。","protection":"IUCN：LC（无危）","distribution":"红喉鹧鸪分布于非洲中部、东南部，具体包括加蓬、肯尼亚南部、南非等地。在东非多数月份都能发现，但具体时间取决于地理位置。","other":"红喉鹧鸪在某些地区可能在一年龄时开始繁殖，家庭群解散后。雌鸟可能连续多年在同一区域繁殖。"},{"name":"斯氏鹧鸪","english_name":"Swainson's Spurfowl","scientific_name":"Pternistis swainsonii","overview":"斯氏鹧鸪（英文名：Swainson's Spurfowl，学名：Pternistis swainsonii），是鸡形目雉科鸡鹧鸪属的鸟类。大型褐色鹧鸪，具有深色条纹、暗黑色腿和独特的裸露红脸与喉部。在非洲中南部和东南部广泛分布，被命名为纪念英国自然学家威廉·斯温森。在津巴布韦的绍纳语中，被称为chikwari或horwe，是户外和狩猎爱好者的美食。","appearance":"雄鸟长约38厘米，雌鸟约33厘米；雄鸟体重400至875克，雌鸟340至750克。拥有黑腿和上喙，以区别于其他裸喉鹧鸪。雌鸟比雄鸟小、颜色更深且图案更密集（上方呈深棕色网状，部分翼部有条纹）。幼鸟颜色较淡，呈黄褐色，腿黄色，喙基部黄色。雄鸟有1到2个刺，雌鸟刺减少或缺失。","call":"早晨和傍晚最为活跃，从高处如白蚁丘或低枝上发出响亮的尖叫声'kreeeeet-kreeeeet-kreeeet'。","habits":"栖息于草原和灌木丛，偏好靠近水源的密草地带，有时出现在森林边缘或沿水道的草地。依赖水的程度高于大多数非洲鹧鸪。活动范围包括农田附近的湿润土壤区，夏季捕食昆虫比例可达20%，冬季和春季则以农作物为主食。","breeding":"全年均可繁殖，与降雨相关。一窝通常有4至8枚蛋，由雌鸟单独孵化，孵化期约为21至23天。雏鸟出生后10天左右能进行短距离飞行，3至4个月后完全成长。南非地区的繁殖成功率和雏鸟存活率高。","identification":"与红颈鹧鸪的区别在于后者有红色的腿和脚，常有白色下体或脸部羽毛（视亚种而定），并倾向于栖息在灌木丛和森林而非开阔环境。","protection":"IUCN：LC（无危）。在南非数量稳定，甚至增加，但局部地区有下降趋势。在马拉维，仅限于Vwaza Marsh野生动物保护区的小部分区域。","distribution":"分布于安哥拉东南部、纳米比亚北部、博茨瓦纳东部、南非北部、津巴布韦、莫桑比克南部、赞比亚和莱索托。","other":"在某些地区，如哈拉雷周围的农田，已取代须嘴鸦；但在园艺土地闲置10至20年后会消失或减少。"},{"name":"灰山鹑","english_name":"Grey Partridge","scientific_name":"Perdix perdix","overview":"灰山鹑（英文名：Grey Partridge，学名：Perdix perdix），是鸡形目雉科山鹑属的鸟类。广泛分布在欧洲和亚洲西部至西南部西伯利亚，以及北美的加拿大和美国部分地区。在北美洲，被称为‘匈牙利山鹑’或简称‘hun’。","appearance":"体型圆润，背部棕色，两侧灰褐色，腹部白色，通常带有大块马蹄形的深棕色斑纹，尤其在雄鸟中更为明显。雌雄相似，但雄鸟较大，具有更发达的腹部斑纹。幼鸟主要为黄褐色，缺乏成鸟的面部和下部标记。","call":"发出尖锐刺耳的‘kieerr-ik’叫声，当受惊时，会一边飞升一边发出‘rick rick rick’的声音。","habits":"主要栖息于农田、草地和牧场，偏好有树篱的环境。非繁殖季节可形成多达30只的群落。它们是种子食性，尤其是幼鸟依赖昆虫作为蛋白质来源。","breeding":"繁殖期为每年1-2月，雄鸟会发出求偶鸣叫。巢建于地面，通常隐藏在草丛或灌木下，每窝产卵可达20枚。孵化期为21-26天，孵化由双亲共同承担。","identification":"与斑翅山鹑相比，灰山鹑颜色更深、更棕，胸部无广泛的橙色或肉桂色调。与石鸡幼鸟相比，后者侧翼和腿部条纹更明显，腿色偏红而非淡黄色。","protection":"IUCN：LC（无危）；但在英国因栖息地丧失和农药影响，其数量严重下降。","distribution":"欧亚大陆西部和中西部地区，包括欧洲大部分地区和亚洲西部至西南部西伯利亚。在北美，主要分布在美国北部大草原州和南部大草原省份。","other":"在北美洲，灰山鹑的种群集中于北部大草原州和南部大草原省份，尽管它正在向南扩展至内布拉斯加州和密苏里州。"},{"name":"斑翅山鹑","english_name":"Daurian Partridge","scientific_name":"Perdix dauurica","overview":"斑翅山鹑（英文名：Daurian Partridge，学名：Perdix dauurica），是鸡形目雉科山鹑属的鸟类。俗名: 须山鹑，生活在欧亚大陆温带地区的矮壮陆栖鸟类。其分布区域广泛，从西伯利亚、乌苏里边区至中国新疆、东北等地。偏爱草丛或灌木丰富的开阔地带，冬季则会前往农田觅食。","appearance":"斑翅山鹑体长约28-30厘米，体重在200-340克之间。通体灰棕色，腹部有显著的深色斑点，脸部和胸部为橙色。雄鸟和雌鸟的差异在于雌鸟腹部的斑点较小，颜色较为暗淡，且脸上和胸部的橙色面积较小。幼鸟的上部标记更为粗犷。不同亚种间在羽色上存在细微差异，如suschkini亚种更暗且带有更多红褐色。","call":"斑翅山鹑的叫声为尖锐的金属摩擦声，类似加速的一系列刺耳的摩擦音，如‘rex..rex..rex…’。","habits":"斑翅山鹑栖息于各种开阔环境，包括草甸、灌丛、河岸灌木、林地草原和种植园。它们偏好靠近草地的灌木或轻度林地。它们在秋季形成中等规模的群体，通常由15-30只鸟组成，冬季群体可增至200只。它们主要以杂草种子、谷物和浆果为食，夏季也会食用昆虫。在遭遇恶劣冬季天气时，可能会进行季节性迁移。","breeding":"斑翅山鹑在吉林和山西的繁殖期始于5月末，配对最早于3月中旬开始。巢穴位于遮蔽物旁，由草、树叶、根和柔软的羽毛构成。每窝产卵18-20枚，孵化期约为25天，由雌鸟独自承担。双亲都会照顾雏鸟。","identification":"斑翅山鹑与灰山鹑非常相似，但斑翅山鹑更灰暗，胸前有广泛的栗色标记，肩胛骨上有明显的苍白羽轴纹，腹部黑色斑点周围有赭黄色，而灰山鹑的相应部位颜色更接近白色。雌鸟与雄鸟相比，条纹和蠕虫状斑纹更明显，腹部斑点更小或缺失。","protection":"IUCN：LC（无危）","distribution":"斑翅山鹑分布于吉尔吉斯斯坦、哈萨克斯坦东北部、新疆西部、西伯利亚南部、蒙古东部至外贝加利亚和阿穆尔地区（俄罗斯东北部）以及中国东北部。","other":"斑翅山鹑可能与灰山鹑形成超种，特别是在重叠分布区域。"},{"name":"高原山鹑","english_name":"Tibetan Partridge","scientific_name":"Perdix hodgsoniae","overview":"高原山鹑（英文名：Tibetan Partridge，学名：Perdix hodgsoniae），是鸡形目雉科山鹑属的鸟类。广泛分布于青藏高原，包括尼泊尔、印度以及中国西部。其最显著的特征是黑白相间的脸部图案和亮橙色颈部，通常栖息于干燥的山坡和山谷，以矮小的灌木为掩护。","appearance":"体长28至31厘米，体重介于294至450克之间。整体呈棕色，面部有鲜明的黑白色调，额头、眼眉、下巴、喉咙中央和部分颈带为白色，耳羽和喉咙两侧为黑色，冠部和侧面为栗色，颈侧亦为栗色，腹部白色，胸部两侧和前腹下方有黑色和栗色重叠的斑纹。雌鸟较雄鸟稍小且颜色更暗淡，虹膜为红褐色，喙呈淡绿色角质，腿部灰色角质。幼鸟色彩较为暗淡，缺乏成鸟的特色标记。","call":"早晨和傍晚时，雄鸟会发出连续的、类似‘scherrrrreck-scherrrrreck’的响亮叫声，有时也会发出急促的‘chee, chee, chee, chee, chee’声。","habits":"生活在海拔3600至4600米的区域，夏季可达5600米，冬季可能降至2800米左右的半沙漠平原。以种子和昆虫为食，通常在地面活动，形成小群，数量可达15只，偶尔多达25只。","breeding":"繁殖季节从5月至7月，筑巢于地面，巢穴直径约20至22厘米，用草覆盖，位于岩石或灌木下。一窝产卵8至10枚，孵化期未知。雏鸟出生后不久就能跟随父母活动。","identification":"与其他Perdix种类相比，其独特的面部和腹部标记使其容易辨认。雌雄差异主要体现在色彩的鲜艳程度上。","protection":"IUCN：LC（无危）","distribution":"繁殖于青藏高原，包括西藏、尼泊尔北部、印度西北部、不丹、巴基斯坦北部和中国西部。在非繁殖季节，它们可能会迁移到较低海拔的区域。","other":"尽管同属其他种类常遭猎杀，但高原山鹑因栖息于较高海拔，人类干扰较少，目前状况安全。"},{"name":"长嘴山鹑","english_name":"Long-billed Partridge","scientific_name":"Rhizothera longirostris","overview":"长嘴山鹑（英文名：Long-billed Partridge，学名：Rhizothera longirostris），是鸡形目雉科长嘴山鹑属的鸟类。颈胸灰色，雌鸟头部及颈部为锈褐色。分布于马来半岛、苏门答腊岛及婆罗洲的低地和丘陵森林，较为罕见且分布零散。","appearance":"长嘴山鹑约30至37厘米长，雄鸟体重约800克，雌鸟约697克。雄鸟具有独特的弯曲长喙，头部侧面、颈喉部为锈红色，前额、头顶及颈背为深栗色，冠侧及眼线暗色，胸部、下前颈和肩侧灰色，其余下体锈红色，腹部及尾下覆羽颜色较淡。雌鸟全身丰富锈色，上体自背部至尾上覆羽色调更暖和偏棕黄色。幼鸟似雌鸟，但有细淡色喉纹，胸部及肩部有弱暗斑及条纹，喙色为棕色。","call":"发出响亮回荡的双音节‘weeweew’叫声，配对时进行应答式二重奏，伴侣以更鼻音的‘kengkeng’声回应。","habits":"长嘴山鹑生活在原始和较老的次生低地及山地森林，尤其偏好有竹子的区域，海拔高度从海平面至1000-1500米，包括苏门答腊的高海拔茶园。在婆罗洲，倾向于低地龙脑香森林中的石灰岩丘陵。它们能在小片森林中生存，但在一些看似适宜的大型区域内似乎不存在。","breeding":"在马来西亚半岛，叫声活跃期为2月至5月，8月和11月，但与繁殖季节关系未知。已知两个巢穴，位于婆罗洲加里曼丹，2月发现，含两枚蛋，浅坑状巢由根纤维和竹叶铺垫，置于竹丛中。人工繁殖条件下，产2至5枚带玫瑰红晕的白色蛋，大小36.6-36.7毫米×26.8-26.9毫米，孵化期18-19天。","identification":"雄性长嘴山鹑的灰胸和下体锈红色是辨识关键，而雌鸟全身锈色。与白腹长嘴山鹑相比，后者腹部白色，下胸及两侧灰色，翼覆羽无锈色斑块。","protection":"IUCN：NT（近危）","distribution":"分布于马来半岛南部，苏门答腊，婆罗洲西部、南部及东部。在苏门答腊北部的Leuser国家公园、婆罗洲的Bako国家公园、Sarawak的Lumut保护森林及可能的Ulu Barito等地有记录。","other":"长嘴山鹑在泰国可能已灭绝，自1955年后无记录。在马来西亚（半岛及婆罗洲）稀疏分布，出现在受保护区域如Krau野生动物保护区、Taman Negara国家公园和Fraser's Hill野生动物保护区。"},{"name":"白腹长嘴山鹑","english_name":"Dulit Partridge","scientific_name":"Rhizothera dulitensis","overview":"白腹长嘴山鹑（英文名：Dulit Partridge，学名：Rhizothera dulitensis），是鸡形目雉科长嘴山鹑属的鸟类。珍稀鸟类。拥有独特的白色腹部和较长的弯曲喙部，主要分布在婆罗洲的中央山脉地带，偏好海拔900-1200米的原始山地森林。","appearance":"成年雄鸟面部红褐色，胸部灰色，腹部纯白，雌鸟胸部的灰色被栗色取代。两性均具有细长的颈部和厚实的体态，喙部长而略弯。雄鸟额头至颈背呈棕色，与头侧至喉上部的栗色形成对比；上体棕色，从喉下部到胸上部有一条宽大的灰带，延伸至后颈和肩上部；下胸至腹部全白，肛区微带红褐色；虹膜棕色；喙灰色；腿黄色。雌鸟外观相似，但灰色胸带被红褐色替代。幼鸟特征明显不同，尤其是雌幼鸟有暗褐色眉纹伴以淡色斑点，喉侧和胸部有淡色条纹至后颈，下体无灰色，胸部侧边有深褐色斑纹，腹部和胁部呈奶油色，喙尖淡色；雄幼鸟类似，但颏和喉部较暗且偏灰，胸部两侧有灰色斑纹，胁部、腹部和肛区淡烟灰色。","call":"其叫声尚未被描述，可能与近亲长嘴山鹑相似。","habits":"栖息于婆罗洲北部分布的山地森林，偏好较低的山地环境，具体生态习性尚不清楚，由于其隐秘性极强，观察记录非常罕见。","identification":"白腹长嘴山鹑与长嘴山鹑极为相似，主要区别在于前者腹部和胁部为白色而非红褐色，翼上无白色斑点，翼覆羽无红褐色斑块。雌雄两性在外观上有细微差异。","protection":"IUCN：DD（数据缺乏）。全球估计成熟个体数量在1000-2500之间，自19世纪以来，Sabah的Mount Kinabalu没有确切记录，Sarawak自1930年代后亦无确认记录。面临森林砍伐、狩猎和贸易捕获的威胁，种群可能正在下降。","distribution":"分布于婆罗洲北部山区，具体地点包括E Sarawak的Mount Murud、Mount Dulit和Batu Song；以及Sabah的Mount Kinabalu，但仅有旧记录存在。","other":"1999年，基于形态学差异，白腹长嘴山鹑从长嘴山鹑中分离出来，被认为是独立物种。"},{"name":"马岛鹑","english_name":"Madagascar Partridge","scientific_name":"Margaroperdix madagarensis","overview":"马岛鹑（英文名：Madagascar Partridge，学名：Margaroperdix madagarensis），是鸡形目雉科马岛鹑属的鸟类。栖息于地面，以暗色为主调，雄鸟拥有复杂而美丽的羽纹，而雌鸟则呈现较为单一的褐色。此物种在开放生境中常见，尤其是草地，且在马达加斯加以外的Réunion也有引入记录。","appearance":"马岛鹑长约26至30厘米，体重约220至250克。雄鸟具有独特醒目的头部和下体图案，而雌鸟全身呈暗褐色，下体饰有大型的鳞状斑纹，使其在马达加斯加其他类似羽毛的鹑类中脱颖而出。幼鸟外观与雌鸟相似。虹膜深棕色至红棕色，喙黑色，基部蓝灰色，腿淡灰色。","call":"通常被认为是相当安静的物种。其广告叫声是一连串响亮的“cou”声，远距离亦可听见，但并不频繁。另有低沉的‘weee-ooooooo’声，作用类似，但传播距离仅限6至12米。被惊飞时会发出低音的‘peet’声或短暂的高音颤音。此外，还有报警时的‘poa-poa-poa’声，接触时的低频‘bub...bub...bub...bub...’声，以及雄鸟与雌鸟互动时的鼻音、咕噜或咕咕声。","habits":"栖息于森林边缘和灌木地带，偏好二次生境，同时在草地、零散的桉树林、杂草丛生的农田中可见，但避免在密闭的林冠下活动。在Réunion，偏好有良好地面覆盖的灌木区，包括废弃农田、蕨类和石楠植被，但在高山石楠中罕见。海拔分布从海平面至2700米（马达加斯加）和2400米（Réunion）。以种子、浆果、根茎和昆虫为食，觅食时缓慢行走，用脚刨地，拣食植物物质，偶尔扑向昆虫。","breeding":"繁殖季节未知，但据推测可能具有领地性。在马达加斯加高原的3月至6月筑巢，曾记录到9月雌鸟卵巢增大。在Réunion，繁殖季为11月至3月。巢建于地面，藏匿于草丛或灌木下。每窝产15至20枚蛋，颜色从棕色到橄榄色，带有深棕色或黑色斑点，大小约为35.3至41.7毫米×27.3至30.5毫米，由雌鸟单独孵化18至19天。雏鸟刚孵化时呈淡黄褐色，头上有暗褐色侧冠纹和宽幅暗褐色体侧条纹，头部呈灰黄色，眼线下有黑线。","identification":"雄性马岛鹑通过其独特的头部和下体图案易于识别，而雌鸟则通过其暗褐色和大型的鳞状斑纹与其它鹑区分。与鹌鹑和钮鹑相比，马岛鹑体型更大，且在冲天而起时翅膀声音更响亮，飞行更为有力。","protection":"IUCN：LC（无危）。尽管如此，该物种自1930年代以来有显著下降趋势，目前可能非常稀少，数量可能比预想的还要少。在多个保护区有记录，包括两个国家公园、六个完整保护区和五个特殊保护区。在Réunion被认为较常见（约1845年引入），但在Mauritius一直罕见（约1770年引入），现在可能已灭绝。","distribution":"主要分布在马达加斯加（除最南部外），在Réunion也有引入记录。","other":"由于年度火灾导致的生境退化威胁着该物种，同时过度猎杀和陷阱捕捉也是其面临的挑战，但近年来猎杀压力似乎有所减轻。自然天敌包括马岛鹞和m,541,狐獴。"},{"name":"黑鹑","english_name":"Black Partridge","scientific_name":"Melanoperdix niger","overview":"黑鹑（英文名：Black Partridge，学名：Melanoperdix niger），是鸡形目雉科黑鹑属的鸟类。本属唯一物种，体型小巧（约27厘米），拥有厚实的喙，灰蓝色腿足，深棕色虹膜。雌雄异色明显，雄鸟全身泛着光泽的黑色羽衣，配以黑色喙；而雌鸟则主要为栗褐色，喉部和腹部偏白，喙色暗角质色，体型略小于雄鸟。分布于东南亚的马来半岛、苏门答腊及婆罗洲低地雨林。","appearance":"雄性黑鹑长约24至27厘米，体重约280克，全身羽毛光泽黑亮，飞行羽为深棕色，喙短而厚，黑色；雌鸟体重约281克，上体颜色接近未标记的栗褐色，下巴、喉咙和腹部呈淡色至几乎白色，喙色较浅，为暗角质色，腿部蓝灰色。幼鸟初期似雌鸟，但很快会获得黑色羽毛，雌鸟幼鸟上体更淡，有黑色虫蚀状斑纹和浅色点斑，胸部两侧和胁部有明显的白色斑点。两亚种相似，雄鸟borneensis亚种黑色更深，带轻微绿调，上体羽毛边缘较淡，雌鸟胸部颜色更深的栗褐色。","call":"鸣叫特征知之甚少，曾被认为较为安静。接触叫声类似重门吱呀声，广告叫声有两种类型：一是两个相同长度和音质的哨音，二是初始较短的音符（0.4秒长，略微上升）和第二个带有颤抖质感的音符（0.7秒长，上升更为明显），哨音间隔0.2秒，每对哨音间隔16秒（8至27秒范围内），系列哨音间隔40至67秒。","habits":"栖息于原始和高大的次生低地森林，通常与许多无茎棘棕榈共生，也在湿地森林（如泥炭沼泽和冲积森林）中发现，偏好湿润环境。海拔下限至海平面，上限未知，最近报道在卡利曼丹乌卢巴里托和沙捞越凯拉比特高地达到1200米。通常单个或成对出现，当受惊扰时奔跑，但通常紧坐不动直至人类接近几米之内。食物信息不详，推测以硬种子为主食。","breeding":"繁殖信息有限，交配系统未知。已知的巢中有2至5枚白色蛋，最早记录在1月，5月和9月分别有3和5枚蛋的记录，另有刚孵化的蛋记录于6月中旬。幼鸟在10月末和马来西亚半岛的8月末至9月初观察到，雏鸟橙褐色下方，上方较暗，前冠至颈背为赤褐色，耳覆羽有窄带。孵化期在圈养条件下为18至19天。","identification":"雄性黑鹑的全黑光泽羽毛和厚重的喙是其独特标识，雌鸟则通过栗褐色体羽、较白的喉部和腹部及暗角质色喙与其它主要栗色物种区分。雄鸟borneensis亚种的黑色更深，带轻微绿调，而雌鸟胸部颜色更深的栗褐色。","protection":"IUCN：VU（易危）","distribution":"分布于马来半岛、苏门答腊和婆罗洲的低地雨林。在新加坡已绝迹。","other":"因栖息地丧失、数量稀少及部分地区过度狩猎，被列入《濒危野生动植物种国际贸易公约》附录三的保护名单中。"},{"name":"西鹌鹑","english_name":"Common Quail","scientific_name":"Coturnix coturnix","overview":"西鹌鹑（英文名：Common Quail，学名：Coturnix coturnix），是鸡形目雉科鹌鹑属的鸟类。又名: 红腹鹑，简称:鹌鹑，直译: 普通鹌鹑，小型地面筑巢鸟类。主要迁徙于西帕莱阿尔泰克地区，冬季南迁至非洲和印度南部。西鹌鹑以其独特的三声哨鸣叫声而著名，通常隐藏于作物和草地中，难以察觉的鸟类。","appearance":"体型小巧，长度约为16至20厘米，翼展32至35厘米，体重在70到155克之间，雌雄略有差异。羽毛色泽暗淡，有条纹，头部有明显的白色眉线，雄鸟具有黑色喉纹。幼鸟与雌鸟相似，但两侧有条纹，下颊无线条。不同亚种在大小和颜色上有细微差别。","call":"雄鸟的鸣叫声独特，常被描述为\"wet-my-lips!\"，由三次节奏感强的液体般清脆音符组成，连续重复4至8次，每2至5秒一次。雌鸟则会回应低沉的\"咕噜\"声。","habits":"栖息于开阔地带，包括耕地，避免深林和湿地，但在极热地区需水源。高度可达1000米，甚至高达3600米。偏好不到1米高的密集草丛，迁徙时可在各种杂草覆盖的地方发现。","breeding":"繁殖季节随气候条件变化，通常在北欧5月中旬至8月，南欧3月底至6月中。筑巢于草丛中的浅坑，衬以植被，每窝产卵8至13枚，卵色从白色到奶油色，有巧克力棕色、红棕色或浅棕色标记。孵化期17至20天，由雌鸟单独完成。","identification":"与鹌鹑极为相似，但可通过叫声和雄鸟面部特征区分。雄性鹌鹑的脸部更暗，而西鹌鹑雌鸟的脸部和下体较浅，侧翼少有栗色。","protection":"IUCN：LC（无危）","distribution":"繁殖于西欧至中亚的广阔区域，冬季迁徙至非洲、南欧和南亚。在非洲的记录高达3000米，如肯尼亚高地、留尼汪岛、科摩罗群岛、马达加斯加。","other":"狩猎是主要威胁之一，尤其是在地中海地区和埃及，大量西鹌鹑被捕杀。农业集约化可能也是威胁，但灌溉农业的扩张使一些新繁殖群得以建立。"},{"name":"鹌鹑","english_name":"Japanese Quail","scientific_name":"Coturnix japonica","appearance":"鹌鹑体型紧凑，整体呈灰褐色，上体有褐色与黑色横斑及皮黄色长条纹。夏季雄鸟的脸部、喉咙和上胸部为栗色，冬季与西鹌鹑相似，难以区分。雌雄成鸟头部为淡褐色，有小黑斑，背部和胸部显杂色斑纹，雄鸟在繁殖期脸部和喉部显红褐色。","call":"鸣叫特点为突然的、类似‘chrr-churrk-chrr’的急促叫声，有时会被比作刚刚离巢的欧乌鸫的乞食声，也有类似‘shur-CHRINK!’的金属质感的短促叫声。","habits":"栖息于开放的草地和农田，偏好湿润的草地、步地和靠近水源的干燥山坡。主要以各种植物材料为食，夏季也会摄食陆生无脊椎动物。","breeding":"繁殖期从4月末至8月初，筑巢于地面，由雌鸟建造浅坑并铺垫干草，通常产9-10枚白色到淡黄色带有巧克力色斑点的蛋，孵化期为16-21天，主要由雌鸟负责。","identification":"与西鹌鹑区别在于国内分布无重叠，雄鸟繁殖期脸部红色，冬季较难与西鹌鹑区分。","protection":"IUCN：NT（近危）","distribution":"繁殖区主要在东亚和俄罗斯，包括蒙古、西伯利亚东部、日本、朝鲜半岛。非繁殖期迁徙至东南亚，包括越南、柬埔寨、老挝和中国南部。","other":"已实现大规模人工饲养，雄鸟常用于斗鹌鹑的活动，但呼吁善待野生动物。"},{"name":"黑胸鹌鹑","english_name":"Rain Quail","scientific_name":"Coturnix coromandelica","overview":"黑胸鹌鹑（英文名：Rain Quail，学名：Coturnix coromandelica），是鸡形目雉科鹌鹑属的鸟类。小型、橄榄褐色、具纵向条纹的鹑类，外形似“小号橄榄球”，最显眼的是雄鸟黑白分明的面部图纹和胸前一块像泼洒墨迹般的三角形黑斑。它主要分布于巴基斯坦至缅甸、泰国及印度次大陆，偶见于越南南部与柬埔寨。该鸟栖息于开阔草地、农田与荒地，雨季繁殖，雄鸟发出独特的金属音“whit-whit”双音节广告声。","appearance":"体长16–18厘米，体重64–85克。雄鸟：面部具黑白分明的精致图案，喉至上胸黑色，呈倒三角形黑斑，边缘不规则如泼洒的墨迹；上体棕褐色，密布深色纵纹；翼初级飞羽无横斑；嘴黑色（繁殖期）或暗褐色，基部较淡；虹膜褐色；脚肉粉色至灰肉色，繁殖期最鲜艳。雌鸟：与西鹌鹑及鹌鹑极为相似，但胸部斑点更淡且稀疏；初级飞羽无横斑，可与同域分布的鹌鹑属雌鸟区分；整体褐色，具暗色纵纹。幼雄鸟：喉部及胸部斑纹较不明显。","call":"雄鸟的广告鸣唱为独特的金属质感双音节“whit-whit”，连续重复3–6次，每次6–8秒，音量逐渐升高；两只雄鸟常同时合唱。惊飞时发出尖锐的啭哨声，与鹌鹑惊飞声相似但略高。","habits":"栖息于海拔可达约2500米的开阔草地、农田（包括茶园、旱稻田）、干灌丛、草地、花园及灌丛丛林，繁殖地一般不超过1800米。巴基斯坦种群于6月下旬抵达平原，10月初离开；印度大部分地区为留鸟或游荡性候鸟，西南季风期间向干区扩散；冬季偶至斯里兰卡。通常成小群活动，以草籽、杂草种子及昆虫为食。","breeding":"繁殖季与雨季同步，3–10月，高峰8–10月；偶见12月筑巢。一夫一妻制。巢筑于作物或草丛中，偶尔在灌木基部，为雌鸟刨出的浅坑，内衬干草。每窝产4–6枚白至淡褐色、具巧克力色斑点的卵（曾记录一窝18枚，为多雌共巢）；孵化期18–19天，仅雌鸟孵卵，雄鸟亦参与育雏；一年只育一窝。","identification":"雄性黑胸鹌鹑胸前的黑色倒三角斑及面部黑白图案独特，易识别。雌鸟与西鹌鹑、鹌鹑极难区分，但初级飞羽无横斑，且体型略小；与Coturnix chinensis雌鸟相比，后者体型更小、嘴短、头侧更赤褐色，胸侧具鳞状斑而非点状斑。","protection":"IUCN: LC（无危）。","distribution":"繁殖区：巴基斯坦向东经印度、孟加拉国至缅甸及泰国北部、中部。非繁殖区：印度南部、斯里兰卡，偶为尼泊尔迷鸟。近年记录显示其范围已扩展至越南南部（安南地区）及柬埔寨。","other":"系统分类上与花脸鹌鹑关系最近；单型种，无亚种分化。"},{"name":"花脸鹌鹑","english_name":"Harlequin Quail","scientific_name":"Coturnix delegorguei","overview":"花脸鹌鹑（英文名：Harlequin Quail，学名：Coturnix delegorguei），是鸡形目雉科鹌鹑属的鸟类。而雌鸟则以棕色为主，与西鹌鹑相似，但颜色更深更均匀，腹部无亮白色，背部条纹不显眼。分布于非洲撒哈拉以南地区及阿拉伯半岛，与采集者Adulphe Delegorgue的名字相关联。","appearance":"体型小，长度16至19厘米，雄鸟体重49至93克，雌鸟体重63至95克。雄鸟具有独特的黑白头部斑纹、黑色胸部和栗色侧翼；雌鸟与西鹌鹑极为相似，但在手握时可由初级飞羽外缘无横斑、胸部统一的红褐色、腹部有乳白色轴纹以及胸斑呈灰暗色加以区分。幼鸟似雌鸟，但下面更灰，冠部和颈背较淡，喉部和胸部有深棕色斑点和条纹。","call":"雄鸟的广告鸣声被认为是更快、更尖锐、更具金属感和更高音调的‘wit, wit, witwitwit, witwitwit’组合，雌鸟可能以柔和的‘qwik-ik’回应，被惊起的鸟可能会发出尖锐的‘skreee’叫声。","habits":"偏好开阔草地，有散生灌木覆盖或棕榈树，也见于轻度林木覆盖的草原、潮湿环境中的草丛，如沿水道和低地泛滥平原。在东非和南非，花脸鹌鹑随雨水迁徙，夜间迁移。在南非，它向南迁徙繁殖，雨季结束后大部分北迁，但每年不会回到同一区域。食物主要包括草籽、杂草种子和各种昆虫及其幼虫。","breeding":"繁殖季节与大雨有关，因地区而异。筑巢于草地中的草丛中，通常有4到8枚淡黄色带紫褐色至黑褐色斑点的蛋，孵化期约14至18天，仅由雌鸟孵卵，雄鸟协助照顾幼鸟。刚孵化的雏鸟有暗棕色、黑色和浅黄色条纹，腹部淡黄色，五天大时能短距离飞行。","identification":"与西鹌鹑相比，雌性花脸鹌鹑颜色更深，更均匀，腹部无亮白，背部条纹不显眼。与其他鹌鹑种类如钮鹌鹑的区别在于颜色较暗，图案较简单。","protection":"IUCN：LC（无危）。在某些地区被视为至少常见甚至丰富，如马达加斯加部分地区，整体数量似乎没有减少趋势。在维多利亚湖的卡维龙多湾等地已知存在捕捉现象。","distribution":"广泛分布于非洲撒哈拉以南地区，包括东非、南非、马达加斯加、阿拉伯半岛南部等地。","other":"有报道指出，在肯尼亚，未经控制的引入日本家养鹌鹑品种导致野生非洲花脸鹌鹑在西部肯尼亚部分地区的数量明显减少。"},{"name":"澳洲鹌鹑","english_name":"Stubble Quail","scientific_name":"Coturnix pectoralis","overview":"澳洲鹌鹑（英文名：Stubble Quail，学名：Coturnix pectoralis），是鸡形目雉科鹌鹑属的鸟类。别称灰鹌鹑和胸带鹌鹑。分布广泛，遍及澳大利亚除北部分以外的所有州和领地，但在塔斯马尼亚几乎灭绝。最常见的本地鹌鹑种类，体型较大，具有明显的暗色条纹和浅色腹部，雄鸟喉部橙红，雌鸟相似但色彩较为柔和。","appearance":"澳洲鹌鹑身长16至20厘米，体重82至125克，翼展25至33厘米。雄鸟拥有独特的砖红色面部和喉部，与黑色胸部形成鲜明对比；雌鸟与西鹌鹑在体型上相似，但下体更浅，条纹更多。幼鸟类似于成年雌鸟，但下体有更宽的黑色标记，胸脯较暗，约5周后喉部会变为赤褐色。","call":"雄鸟发出重复的三音节广告叫声，节奏为每分钟约10次，持续可达15分钟，声音似‘two-to-weep’，有时简略为‘two-weep’或‘pippy-wheat’，偶尔在受惊时会发出尖锐的啁啾声。","habits":"栖息于多种生境，偏好干燥的草甸和灌木丛，如Spinifex厚丛，亦常见于农田，包括谷物作物区。主要以草地种子、栽培谷物和杂草种子为食，辅以昆虫等无脊椎动物。分布随降雨和食物可用性而变化，通常在干旱地区，但降雨后范围可扩展至半干旱地带。行为上，更倾向于躲藏或奔跑以应对危险，而非飞行。","breeding":"繁殖期通常为8月至次年3月，但根据当地雨量模式有所变化。可能是一夫一妻制，部分个体全年保持配偶关系。巢由雌鸟建造，位于地面，用干草衬垫，通常设在作物或草丛中。每窝产7至8枚淡黄色带有红棕色和橄榄绿色细斑点的蛋，仅雌鸟孵卵，孵化期18至21天。雏鸟出生时呈姜棕色和黑色条纹，16天后即可弱飞。每季可产2至3窝，罕见情况下可达4窝。","identification":"与Turnix物种相比，澳洲鹌鹑体型更大，翼尖不那么钝圆，且前翅面板与深色飞羽形成对比。与黑胸鹌鹑的区别在于下体颜色更浅，条纹更多。与褐鹌鹑的区别在于后者背部条纹更薄，下体有黑色横条，飞行时声音不同。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚（除北部外），曾广泛存在于塔斯马尼亚，现极为稀少或已近灭绝。在维多利亚和新南威尔士局部常见，近50至100年内向北扩散至昆士兰东部，向西殖民至西澳大利亚南部。","other":"因人类活动，如森林清理、灌溉和农田的建立，其分布范围扩大，数量增加。在某些地区，过度耕作或放牧不适合该物种生存。"},{"name":"新西兰鹌鹑","english_name":"New Zealand Quail","scientific_name":"Coturnix novaezelandiae","overview":"新西兰鹌鹑（英文名：New Zealand Quail，学名：Coturnix novaezelandiae），是鸡形目雉科鹌鹑属的鸟类。现已灭绝的鸟类。由于资料稀缺，其生态习性大多通过现存近亲——褐鹑的行为来推测。新西兰鹌鹑的灭绝时间约为1875年。","appearance":"具体外观细节因资料缺失而难以详述，但可推测其与近亲褐鹑有相似之处，具有鹌鹑类典型的圆胖体型和短小的尾巴。","habits":"推测新西兰鹌鹑偏好乡村环境，遭遇威胁时会快速振翅飞起，随后隐匿于草丛中，以植物性食物为主，包括种子和草，偶尔食用昆虫。它们筑巢于草地隐蔽处，由雌鸟独自孵化，孵化期约三周，雄鸟则负责巢穴的安全警戒。","breeding":"雌鸟会在隐蔽的草地上筑巢并产卵，独自孵化，孵化期大约需三周。雄鸟在孵化期间负责守护巢穴。","protection":"IUCN：EX（已灭绝）","distribution":"新西兰鹌鹑原产于新西兰，包括北岛（North Island）、南岛（South Island）和大障碍岛（Great Barrier Island）。"},{"name":"褐鹌鹑","english_name":"Brown Quail","scientific_name":"Synoicus ypsilophorus","overview":"褐鹌鹑（英文名：Brown Quail，学名：Synoicus ypsilophorus），是鸡形目雉科 Synoicus 属的鸟类。又称沼泽鹌鹑、银鹌鹑和塔斯马尼亚鹌鹑，小型地面栖息鸟类。广泛分布于澳大利亚大陆、塔斯马尼亚岛、巴布亚新几内亚，并已被引入新西兰和斐济。","appearance":"褐鹌鹑是一种体型圆胖的鸟类，体长可达17至22厘米，体重介于75至140克之间。其颜色在广泛分布范围内有所变化。雄鸟头部和上颈处呈红褐色，饰有黑色斑点，背部和翅膀主要为红褐色，下部羽毛颜色从淡黄色至红褐色不等，总伴有细密的黑色人字形条纹。尾巴较短，深棕色，带有黄褐色条纹。雌鸟相似但色调更淡，肩部有小黑斑，上部有暗色人字形标记。雄鸟有红褐色、棕色和蓝灰色变种，雌鸟则较为单一。","call":"褐鹌鹑发出一系列尖锐的叫声，用于在浓密植被中移动时的沟通。其中一种叫声是双音节的哨声，后一音节上升。","habits":"褐鹌鹑生活在农业区、湿地草甸、灌木丛、芒草草原和淡水湿地。它们主要在低地活动，但在新西兰可高达1000米，而在巴布亚新几内亚则可达3700米。这种鸟类倾向于在湿润地区活动，但在澳大利亚干旱地区偶尔也能看到它们的踪迹。它们以草籽、草本植物种子、叶子以及昆虫和其他小型无脊椎动物为食。","breeding":"繁殖季节在南澳大利亚为8月至1月，在北澳大利亚可能晚2至4个月，直至5月甚至全年（南昆士兰州）。筑巢于地面，通常在草丛、蕨类植物或其他密集植被中，巢由草和树叶铺垫。每窝通常产7至11枚浅蓝色、黄色或黄绿色的蛋，有时带有棕色斑点。雌鸟单独孵化，雄鸟协助喂养和保护幼鸟，当雌鸟开始第二次产卵时，雄鸟独自承担照顾幼鸟的责任。雏鸟出生后10至17天即可飞行。","identification":"褐鹌鹑与澳洲鹌鹑的区别在于其下部有横纹而非纵纹；比蓝胸鹑大，比雪山鹑小且条纹不那么密集。雌鸟总体颜色较淡，雄鸟有红褐色、棕色和蓝灰色的变种。不同亚种在大小、颜色饱和度、条纹强度和眼睛颜色上有所不同。","protection":"IUCN：LC（无危）","distribution":"分布在澳大利亚（除中南部）、塔斯马尼亚州、巴布亚新几内亚的北部和东部、小巽他群岛的中部和东部。已引入新西兰和斐济。","other":"褐鹌鹑曾被归类于Coturnix属，但现在被归入Synoicus属。"},{"name":"蓝胸鹑","english_name":"King Quail","scientific_name":"Synoicus chinensis","overview":"蓝胸鹑（英文名：King Quail，学名：Synoicus chinensis），是鸡形目雉科 Synoicus 属的鸟类。又名: 蓝胸鹌鹑，小型鸟类，为最小的‘真鹌鹑’。分布于从印度至菲律宾、南达印度尼西亚、直至澳大利亚、中国的广大地区，有9个不同的亚种。在全世界的养鸟业中很受欢迎，有时被误称为“三趾鹑”。","appearance":"雄性蓝胸鹑色彩丰富，有蓝色、棕色、银色、栗色、深棕色和近黑色等多种颜色，橙色脚趾坚硬，适应地面生活。雌鸟相似于雄鸟，但无蓝色变种。寿命可达13年（圈养状态下），野外寿命约1.5年。蛋呈浅奶油棕色，形状略尖。","call":"雄鸟发出下降的口哨声和沙哑的‘打鼾’叫声。","habits":"蓝胸鹑主要栖息于平原、低山地带，河边草地和沼泽的高芦苇内，也见于灌丛、竹林边缘。飞翔速度快，沿直线低飞。晨昏时在空旷地段寻找谷粒、草籽，同时食用昆虫、蜘蛛，尤其是白蚁。","breeding":"繁殖季节为6月至8月，营巢于地面天然凹坑内，产卵4至8枚，卵色淡橄榄褐色或淡黄色，有时有细而稀疏的暗色斑点，孵化期为16天。","identification":"雄性蓝胸鹑具有蓝色头部和胸部，深肉桂色腹部，与非洲蓝鹑的区别在于栗色腹部和缺乏栗色翼斑。雌鸟与褐鹌鹑的雌鸟区别在于体型较小，上覆羽的条纹不那么明显。","protection":"IUCN：LC（无危）","distribution":"分布于东洋界、澳新界，广泛存在于印度至菲律宾、南至印度尼西亚，北至澳大利亚和中国。","other":"在19世纪末，曾试图将蓝胸鹑引入新西兰，但未成功。"},{"name":"雪山鹑","english_name":"Snow Mountain Quail","scientific_name":"Synoicus monorthonyx","appearance":"体长约25至28厘米，体重约401克。显著特征为体型巨大，上下体表均有黑色条纹；雄鸟下体为栗棕色，带暗色条纹，上体主色调为赤褐色，头部两侧几乎无斑纹，喉部亦然，冠羽、耳羽、胸部及侧腹条纹最重，上体其余部位条纹密集。雌鸟较淡，赤褐色较少，下体白色或淡黄色，条纹更重；条纹一般颜色较浅，定义不清晰，断裂，上体显示出更明显和突出的淡黄色羽轴斑。裸露部分：喙角质色，腿脚黄色，眼睛棕色。幼鸟类似成鸟，但条纹更不规则，定义不明确。比Synoicus ysilophorus小，图案更均匀，后者偶尔在相同高海拔记录，但通常在更低海拔发现。","call":"已知叫声仅在惊飞时发出嘈杂的尖叫，是一种拖长的调制音“squeeeah”，重复4至5次，似乎是在警报。","habits":"在花头、叶片、种子、植被和毛虫中寻找食物，被观察到单独或以2至3只的小群体出现。","breeding":"相关信息未提供。","identification":"与Synoicus ysilophorus相比，本种体型更大，图案更不均匀，而后者通常在低海拔处发现。","protection":"IUCN：LC（无危）","distribution":"分布于西新几内亚的Kemabu高原、Mt Wilhelmina和Mt Carstenz（雪山区）以及Star Mountains。","other":"自20世纪30年代末以来，很少有记录，例如在Mt Trikora附近和Freeport矿附近的L Habbema。"},{"name":"丛林鹑","english_name":"Jungle Bush Quail","scientific_name":"Perdicula asiatica","overview":"丛林鹑（英文名：Jungle Bush Quail，学名：Perdicula asiatica），是鸡形目雉科丛林鹑属的鸟类。主要分布于印度半岛和斯里兰卡。其特征为锈色喉部和锈白相间的眉纹，雄鸟具条纹腹部，而雌鸟腹部呈均匀的粉红肉桂色。生活于干燥石质灌丛和草地。","appearance":"体型小而圆胖，长约15至18厘米，重57至82克。雄鸟上体暗褐色，带黑色和淡色斑点，下体白色具黑色横纹；雌鸟下体粉红肉桂色，翅膀更均匀，少有斑纹。脸部主要为深红棕色，耳羽暗褐色，有明显的白色髭纹。喙黑褐色（雄鸟成年）或淡黄褐色（其他阶段），腿色从粉红到橙红色。雏鸟外观较淡，类似雌鸟，但面部无锈色，头部和胸部有白色条纹。","call":"广告鸣叫为有节奏的、略显刺耳的“chee-chee-chuck, chee-chee-chuck”。群落间保持联系或集结时发出低沉的连续哨音，逐渐增强但音调几乎不变，然后突然停止。","habits":"栖息于干燥的灌木或岩石覆盖的地带，从稀疏草甸到相对密集的落叶林，海拔可达1250米。通常以6至25只的小群体出现，以种子和小昆虫为食。偏好步行或奔跑逃避危险，而非飞行。","breeding":"繁殖期从雨季结束至冷季结束，具体时间因地区而异，如喀拉拉邦为1月至3月，德干高原为10月至3月。一夫一妻制。在隐蔽处筑浅窝，铺垫草料，每窝产4至8枚蛋，通常5至6枚，蛋壳颜色为奶油白至淡黄。孵化由雌鸟单独承担，持续16至18天。","identification":"与岩鹑（Perdicula argoondahi）相比，具有更显著的性二型性，眼纹颜色模式（锈色转白色）和喉部（锈色带白色髭纹）不同。雌鸟比雄鸟显得更小，髭纹更暗淡，上体标记较弱，翅膀较少条纹，最多有微弱的胸纹。","protection":"IUCN：LC（无危）","distribution":"广泛分布于印度半岛北部至古吉拉特邦、奥里萨邦和克什米尔山脚，以及斯里兰卡。在尼泊尔的记录自19世纪后未再出现，可能源于误报。在留尼汪岛有引入种群。","other":"已知在留尼汪岛的种群正在下降，但仍局部常见。在毛里求斯曾被引入，现已灭绝。"},{"name":"岩林鹑","english_name":"Rock Bush Quail","scientific_name":"Perdicula argoondah","overview":"岩林鹑（英文名：Rock Bush Quail，学名：Perdicula argoondah），是鸡形目雉科丛林鹑属的鸟类。广泛分布在印度半岛的半干旱地区，以岩石和灌木丛生地带为栖息地。其特征为矮胖的身躯，雄鸟拥有暗栗色的前额和脸部，细白眉纹覆盖着深棕色的眼线，上体浅褐色带斑点，下体黑白条纹明显；雌鸟头部图案相似但色泽较暗淡，下体酒红色无条纹。通常成对或家庭群居，叫声独特。","appearance":"岩林鹑体长约15至18厘米，体重约59至74克。最外侧的初级飞羽比最内侧的长，初级飞羽内缘有斑驳或条纹状的淡褐色。雄鸟的胸冠和面部呈暗栗色，有细白眉纹和宽大的黑眼线；雌鸟头部图案相似但颜色较暗，下体酒红色，无条纹。喙部为石板灰色，腿脚橙色。","call":"岩林鹑的鸣声为一连串响亮的管状音符，开始为音乐般的颤音，音量逐渐增大，音调略升，变得更为尖锐，通常会转换为双音节、更急促的‘pipipipipipipiPIPIPI-tcher-ink..tcher-ink..tcher-ink’。","habits":"岩林鹑生活在半沙漠环境中，如干燥开阔的平原，散布着荆棘灌木。它们很少出现在海拔600米以上的地方。这种鸟类相当隐秘，但其音乐般的颤音和随后迅速上升的哨音常常被听到。","identification":"岩林鹑与丛林鹑在颜色模式的眼线和喉部有区别。幼鸟与成年雄鸟相似，具有黑色条纹，与同龄的丛林鹑不同，后者条纹逐渐消失。幼鸟与成年雌鸟的区别在于上体有更多的虫蚀状条纹和暗色斑点，某些个体有明显的浅色轴纹。","protection":"IUCN：LC（无危）。岩林鹑分布广泛且数量较多，但在某些地区面临栖息地破坏、城市化和狩猎的压力。","distribution":"岩林鹑分布于印度西部地区，常见于半干旱的灌木草丛地带，很少出现在海拔600米以上的地区。"},{"name":"红嘴林鹑","english_name":"Painted Bush Quail","scientific_name":"Perdicula erythrorhyncha","overview":"红嘴林鹑（英文名：Painted Bush Quail，学名：Perdicula erythrorhyncha），是鸡形目雉科丛林鹑属的鸟类。独特鸟类，拥有醒目的红色喙和腿，广泛分布于印度半岛的山地森林地带。以鲜明的外表和特有的鸣叫声而著称。","appearance":"红嘴林鹑长约17至19厘米，重约68至88克。雄鸟特征明显，具有白色眉纹和喉部，与暗色羽毛形成对比；雌鸟的头部图案较暗淡，呈砖红色下体，缺乏雄鸟的白色喉部和头纹。幼鸟的头部标记不如成年雌鸟突出，背部和胸部有不明显的白色条纹。种族blewitti体型较小，颜色较浅，尤其是灰棕色上部和雄鸟胸部及雌鸟下部更显灰色。","call":"红嘴林鹑的领地叫声是一种重复的悦耳三音节“kirikee..kirikee...”，还有一种重复的单音哨声“hweee..hweee..”。接触叫声则是非常柔和、似腹语的哨声，先升后降，每几秒发出一次。","habits":"它们主要栖息在海拔600至2000米的草地、灌木丛、森林边缘和耕地上。红嘴林鹑似乎为留鸟，早晨和傍晚时分会成群结队地到开阔地带觅食，通常由6至15只组成的小群体活动。食物包括草籽、杂草种子、谷物、绿色植物和白蚁等昆虫。","breeding":"繁殖季节因地区而异，主要在12月至3月和7月至11月。红嘴林鹑被认为是单配偶制。巢穴位于草丛或灌木根部，通常铺有少量草。雌鸟单独孵化4至7枚奶油色蛋，孵化期约为16至18天，雄鸟会协助照顾雏鸟。雏鸟即使很小也能进行短距离飞行。","identification":"与同类相比，红嘴林鹑最显著的区别在于其红色的喙和腿，以及独特的叫声。种族blewitti比指名亚种小且颜色更淡。","protection":"IUCN：LC（无危）","distribution":"主要分布在印度半岛的山地森林，包括西部高止山脉南部、尼尔吉里斯山脉和印度南部的其他山地，如Biligirirangan和Shevaroy山区。","other":"红嘴林鹑的种内寄生虫Hypotrichomonas avium（纤毛纲：Hypotrichomonadida）曾在其肠道中被发现。"},{"name":"阿萨姆林鹑","english_name":"Manipur Bush Quail","scientific_name":"Perdicula manipurensis","overview":"阿萨姆林鹑（英文名：Manipur Bush Quail，学名：Perdicula manipurensis），是鸡形目雉科丛林鹑属的鸟类。主要分布在印度东北部和孟加拉国。栖息于高密度的草地，尤其是象草丛生的湿地，体长约19至20厘米，体重在50至85克之间。雄鸟额头和喉部呈栗色，雌鸟头部颜色较淡，腹部更浅，标记不那么鲜明。","appearance":"阿萨姆林鹑是一种暗灰色的丛林鹑，拥有丰富的淡褐色腹部和臀部，带有白色的眼前斑，微弱的眼眉纹，以及金黄色的腹部和臀部，上面有深黑色的厚重标记。雄鸟具有栗色的额头和喉咙。雌鸟比雄鸟颜色更淡，头部的栗色被灰黄色取代，下体颜色更浅，标记也不那么强烈。喙为暗灰色，基部较淡呈黄色，虹膜深棕色或榛棕色，腿橙红色。幼鸟比成鸟颜色更深，有更重的黑色标记，腿色更浅，偏粉色。亚种inglisi比指名亚种颜色更淡，上体和下体的黑色标记更模糊。","call":"阿萨姆林鹑的叫声为清晰的哨音“whit-it-it-t-t”，音调逐渐升高，变得更大声且连贯，两性都会发出这种叫声。","habits":"它们生活在高大的密草丛中，尤其是象草丛，有时靠近沼泽或灌木丛。通常以5至8只的小群活动，最活跃的时间是在一天的早晚，有时会从茂密的掩蔽处出来，在开阔地带觅食，尤其是在烧过的草地。食物主要包括草籽、草本植物的果实、豆荚和一些昆虫。","breeding":"繁殖期的记录较少，已知的一个巢位于五月，建在草根中的地面凹坑里，含四个白色的蛋。在早春，成年鸟表现出繁殖迹象，尽管有记录显示在1月收集到完全成熟的雏鸟。","identification":"阿萨姆林鹑与其他丛林鹑的主要区别在于其独特的颜色模式，尤其是雄鸟的栗色额头和喉咙，以及腹部和臀部上的黑色标记。亚种inglisi的颜色比指名亚种更淡，标记也更模糊。","protection":"IUCN：CR（极危）","distribution":"主要分布于印度东北部和孟加拉国，特别是在高密度的草地和象草丛中。","other":"自1932年以来，直到2006年在阿萨姆邦再次发现之前，该物种没有任何确认的目击记录。"},{"name":"喜山鹑","english_name":"Himalayan Quail","scientific_name":"Ophrysia superciliosa","overview":"喜山鹑（英文名：Himalayan Quail，学名：Ophrysia superciliosa），是鸡形目雉科喜马拉雅鹌鹑属的鸟类。中型鹌鹑，体长约25厘米。雄鸟呈黑灰色，有白色斑纹，雌鸟褐色带深色斑纹，两性均具独特的白色眼斑。其长尾和刚硬的额羽为其显著特征。分布于印度北部的特定山区，最后一次确证记录是在1876年。","appearance":"雄鸟黑灰色，前额及眼眉白色，眼周有白色斑点；雌鸟褐色，有深色斑纹，眼眉灰色。尾羽长于翅膀，额头羽毛刚硬，喙与脚红色。体长约25厘米，尾羽显著长于其他鹌鹑种类。","call":"据记载，喜山鹑发出尖锐的哨声报警，进食时有低沉、短暂的类似普通鹌鹑的叫声。","habits":"栖息于海拔1650至2400米的陡峭山坡，偏好长草和灌木覆盖的南向或东向斜坡。可能在冬季迁移至较低海拔。以小群（5-12只）活动，主要食物为草籽和昆虫。","breeding":"关于繁殖信息知之甚少，仅知两例收集到的标本为11月的幼鸟。","identification":"与其它鹌鹑相比，喜山鹑具有更长的尾羽，刚硬的额羽，以及独特的红色喙和脚。雌雄有明显的色彩差异。","protection":"IUCN：CR（极危）","distribution":"分布于印度北部，具体地点包括Mussoorie、Dehra Dun和Naini Tal附近。在乌塔拉坎德邦有两个已知的历史分布区域。","other":"自1876年后未再有可靠记录，可能已经灭绝。近年来有未经证实的目击报告。"},{"name":"坦桑尼亚鹑","english_name":"Udzungwa Forest Partridge","scientific_name":"Xenoperdix udzungwensis","overview":"坦桑尼亚鹑（Udzungwa Forest Partridge，学名：Xenoperdix udzungwensis），是鸡形目雉科坦桑尼亚鹑属的鸟类。非洲森林中体型小巧、羽色鲜艳的鹑类，隶属单型属 Xenoperdix，为全球最稀有的鹑之一。1991 年在坦桑尼亚中部乌宗瓦山脉云雾林中被首次发现，曾被归入山鹑属（Arborophila）。其背棕具黑栗横纹，胸腹灰并密布黑色扇贝形斑，喙亮珊瑚红。分布于乌宗瓦山脉的恩通达卢-卢洪贝罗林及附近的纽姆巴尼图林，以及北距约100千米的鲁贝霍山脉马夫韦米罗林的楚古山，海拔1360–2060米。全球成鸟不足3000只，IUCN 列为濒危。","appearance":"体长约29厘米，体重约220克。雌雄相似，雄鸟冠色稍浅、下体黑斑略少。额黑，头顶与后颈具深色横纹；眉纹、颊及喉橙棕色；颈具白色羽缘形成细项圈。上体橄榄棕色，背及尾羽具栗色和黑色横纹；翼覆羽棕，具醒目的黑与灰相间横斑。胸至腹部浅灰色，密布黑色圆形或扇贝形斑，向下逐渐变大；尾下覆羽灰色，羽端具赭白相间横斑。喙珊瑚红色；虹膜栗褐色；腿、趾黄色。指名亚种体型较大，鲁贝霍亚种 obscuratus 体小（25–28厘米），羽色更深，面部具浓暗点斑，无白色项圈，尾羽较窄。","call":"最常见为清晨的宣示声，为响亮重复的三音节“kur-kur-kree”，可在约100米外听到；联系声为柔和的“cluck”或细高音的“peep”连串。受惊时发出急促的轻声。","habits":"栖息于云雾常绿山地森林内部，偏好林下有厚落叶层与0.5–1米高的莎草（Cyperus）的较开阔地面，也见于竹丛附近。活动海拔1360–2060米。通常成3–8只小群在林下缓步觅食，翻动落叶寻找种子及昆虫，黄昏亦沿小径取食。夜宿树上，记录有单独或并肩栖于4–8米高枝。性机警，受扰后多在林下疾走，极少短飞10米即遁入密丛。近年变得极为羞怯，目击困难。","breeding":"繁殖资料匮乏，巢尚未发现。11月至次年1月可见成鸟带雏，推测雨季伊始开始繁殖。每群常仅3–4只，可能为双亲与1–2雏，暗示繁殖力低。鲁贝霍山脉1月曾录得具血管化孵卵斑的雌鸟及带4雏的成鸟。","identification":"与分布区内其他鹑类区别明显：体型小于鳞斑鹧鸪，后者羽色更单调灰褐、具纵纹；与盔鹧鸪、红颈鹧鸪等同域种相比，本种体小且具红喙、橙眉及黑灰翼斑。鲁贝霍亚种与指名亚种相比，体小色深，面暗点密，无白项圈，尾羽较窄。","protection":"IUCN: EN（濒危）。全球仅知三处分布点，其中纽姆巴尼图林种群可能已局部灭绝。主要威胁为非法狩猎（绳套陷阱）及小范围栖息地退化。恩通达卢-卢洪贝罗林大部分位于乌宗瓦山国家公园，受巡护保护；纽姆巴尼图林2021年起纳入基洛姆贝罗自然保护区并增派巡护；鲁贝霍山种群位于马夫韦米罗林保护区。","distribution":"繁殖区域：坦桑尼亚东部乌宗瓦山脉的恩通达卢-卢洪贝罗林及纽姆巴尼图林（海拔1350–2060米），以及鲁贝霍山脉马夫韦米罗林的楚古山（1700–1900米）。非繁殖区域：全年留居，无迁徙。纽姆巴尼图林自2012年后已无记录，可能已局部消失。","other":"1991年的发现不仅新增一鸟种，更建立新属 Xenoperdix，与亚洲山鹑属及冕鹧鸪近缘，为非洲鸟类区系演化研究提供重要线索。鲁山鹑与本种合并。"},{"name":"鲁山鹑","english_name":"Rubeho Forest Partridge","scientific_name":"Xenoperdix obscuratus","overview":"鲁山鹑（英文名：Rubeho Forest Partridge，学名：Xenoperdix obscuratus），是鸡形目雉科坦桑尼亚鹑属的鸟类。小型雉科鸟类，约29厘米长，具有明显的条纹，棕色基调，脸部呈红褐色，腹部灰色，头部和背部橄榄棕色。拥有红色的喙，棕色的眼睛和黄色的腿。雌雄外观相似。该物种特有于坦桑尼亚的鲁贝霍山脉森林。","appearance":"鲁山鹑长约29厘米，羽毛密集条纹，主色调为棕色。面部为红褐色，腹部颜色较淡，为灰色，头部和背部呈橄榄棕色。其喙为红色，眼睛棕色，腿为黄色。两性在外观上没有显著差异。","habits":"鲁山鹑居住在坦桑尼亚鲁贝霍山脉的森林中，以昆虫如甲虫、蚂蚁及种子为主要食物来源。","identification":"鲁山鹑与Udzungwa森林鹑（Xenoperdix udzungwensis obscurata）曾被认为是同一种的不同亚种，但现在被认定为独立物种。","protection":"IUCN: EN（濒危）","distribution":"非洲：鲁贝霍高地，位于坦桑尼亚南部。","other":"现为 坦桑尼亚鹑的亚种。"},{"name":"环颈山鹧鸪","english_name":"Hill Partridge","scientific_name":"Arborophila torqueola","overview":"环颈山鹧鸪（英文名：Hill Partridge，学名：Arborophila torqueola），是鸡形目雉科山鹧鸪属的鸟类。雄鸟具有鲜艳的橙色冠羽和黑色头部，雌鸟胸部和上腹部为灰褐色，带有白色条纹的姜棕色羽毛。分布于喜马拉雅山脉西部至越南西北部，常见于海拔1500米以上的常绿阔叶林。","appearance":"环颈山鹧鸪体长约27-30厘米，体重在230克至390克之间。雄鸟拥有独特的橙色冠羽和脸部图案，头部为黑色，喉部有条纹。雌鸟缺乏雄鸟的头部图案和灰色胸部，其胸部和腹部为灰褐色，带有白色条纹的姜棕色羽毛。虹膜颜色从棕色到栗棕色，眼周皮肤呈暗粉色至鲜红色，喙呈暗棕色至黑色，腿为橄榄棕色至黑色。幼鸟类似于成年雄鸟，但缺少眼纹和胸部的红褐色标记。","call":"其叫声为哀伤的哨音，重复数次，接以3-6个双哨音do-eat, do-eat……，叫声越升越高，有时为响亮而清脆的‘吱—吱’双声。在二重唱时，雌鸟发出kwik, kwik, kwik, kwik, kwik叫声，雄鸟则回应一连串的do-eat叫声，高潮后骤然停止。","habits":"环颈山鹧鸪栖息于海拔1500米以上的常绿阔叶林，尤其偏爱林下植被丰富、林间空旷或成块状分布的栎树林、竹林以及山溪和山谷地带的稠密常绿林。它们成对或小群体活动，主要在林下落叶层较厚的地方刨食，食物包括灌木和草本植物的叶、根、芽、浆果和种子，也吃昆虫和小型无脊椎动物。","breeding":"繁殖期为4-6月，营巢在海拔1500-4000米的山地森林中的林下地面上，每窝产卵3-5枚，卵为纯白色，大小约35.6-44.2×27.4-34.0毫米，孵化期为24天。","identification":"雄性环颈山鹧鸪可通过其橙色冠羽和黑头条纹来辨认，与相似的红喉山鹧鸪区分开。雌鸟缺乏雄鸟的特征，尤其是头部图案和颈部带。四个亚种在头部标记和颜色上有细微差异。","protection":"IUCN：LC（无危）；国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"分布于喜马拉雅山脉西部至越南西北部，包括印度、尼泊尔、不丹、西藏、云南、缅甸、泰国和越南。","other":"环颈山鹧鸪在多数分布区内并不面临全球威胁，但在某些地区可能由于栖息地丧失和退化而数量减少。"},{"name":"红喉山鹧鸪","english_name":"Rufous-throated Partridge","scientific_name":"Arborophila rufogularis","overview":"红喉山鹧鸪（英文名：Rufous-throated Partridge，学名：Arborophila rufogularis），是鸡形目雉科山鹧鸪属的鸟类。长约26至29厘米。雄鸟体重介于325至430克之间，雌鸟略轻，重约261至386克。该物种分布于印度北部至东南亚的蒙特纳森林地带，偏好于海拔600至3000米间的茂密林区。红喉山鹧鸪以其鲜明的橙色喉咙和蓝灰色胸部著称，侧翼带有橙白相间的斑点。","appearance":"雄性红喉山鹧鸪头部前额呈灰色，橄榄褐色的冠和颈背饰有黑色斑纹，具有一条白色的眉纹和髭纹。喉咙和颈部两侧橙红色，点缀着黑色斑点，胸和侧腹蓝灰色。雌鸟外观与雄鸟相似，但下巴和喉咙上的黑色较少，腹部白色斑点较多，冠部颜色偏棕色。幼鸟色彩较淡，喉咙颜色更接近淡橙色，下身灰暗，腹部白色，冠部和侧翼有棕色和黑色的细线纹。不同亚种在喉咙图案上有显著差异。","call":"红喉山鹧鸪的鸣叫声优美响亮，尤其在黄昏和黎明时分更为明显。领土歌通常由一系列间隔均匀、纯正、哀婉的长哨声开始，逐渐过渡到重复的双音节，音调和音量渐增，形成“whuu...whuu...whu-hu..whu-hu..”的旋律。伴侣可能加入，发出一连串更快、单调且尖锐上升的音符，‘kwit-kwit-kwit-kwit…’。","habits":"红喉山鹧鸪栖息于常绿森林中的密集植被，海拔范围从600米到3000米，偶尔可达4000米，最低可降至400米。它们在竹林、灌木丛和次生林中也有发现。通常以5至10只的小群体活动，以种子、浆果、绿色植物和无脊椎动物为食，包括幼虫。","breeding":"繁殖季节一般在4月至8月间，主要集中在5月至6月，但在某些地区可能提前至2月至5月。红喉山鹧鸪可能是单配偶制。巢穴或简单为一个凹坑，或由草构成有顶盖的小屋，入口较小，通常位于森林植被下的隐蔽处，如竹林中。每次产卵4至5枚，最多可达九枚，蛋色白色，孵化期约为20至24天。","identification":"红喉山鹧鸪与其他山鹧鸪的区别在于其独特的头部和喉咙图案，雌雄差异主要体现在下巴和喉咙的黑色程度以及腹部白色斑点的多少。亚种间在喉咙的斑点模式上存在显著差异。","protection":"IUCN：LC（无危）国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"分布于东洋界，从印度北部至越南中部，主要栖息于海拔1800至3000米的高山森林，偏好橡树林、含月桂和杜鹃花的林地。","other":"红喉山鹧鸪的种群数量估计正在下降，主要受到栖息地破坏和不可持续狩猎的影响，但由于其分布范围广泛，目前仍被评估为无危物种。"},{"name":"白颊山鹧鸪","english_name":"White-cheeked Partridge","scientific_name":"Arborophila atrogularis","overview":"白颊山鹧鸪（英文名：White-cheeked Partridge，学名：Arborophila atrogularis），是鸡形目雉科山鹧鸪属的鸟类。一种留鸟，其特征在于灰褐色的身体与鲜明的白色脸颊斑块。广泛分布于印度东北部、缅甸北部以及东北孟加拉国的低山丘陵地带，主要栖息于常绿森林的密集灌木丛中，偶尔可见于竹林、草地及耕作区。在中国，仅限于云南西部盈江地区的分布。","appearance":"体长约25至28厘米，体重介于200至312克。头部与颈部有独特的图案，与大多数同属物种明显不同。头顶呈灰色和棕色，后头至颈侧橙黄色条纹，脸颊白色略带淡黄色，喉咙和颊部黑色，眼纹黑色环绕裸露的红色眶周皮肤，延伸至耳羽后方连接喉咙黑色。上胸部白色带有黑色条纹，腹部灰色至中央白色，两胁有白色泪滴状标记。尾羽覆羽红褐色边缘黑色点斑，背部橄榄棕色，翼羽金色棕色，尾羽覆羽黑缘红边。喙黑色，虹膜棕色，眶周裸皮粉红或红色（繁殖季节鲜艳），腿橙色至红色或黄褐色。","call":"其鸣唱由一系列重复、柔和的双音哨声组成，首音滑降，第二音平缓音调较低。伴侣（可能为雌鸟）可能会加入，发出一连串快速、单调且尖锐下滑的音符。","habits":"栖息于海拔1500米以下的低山丘陵地带，偏好稀疏而潮湿的常绿阔叶林和竹林。以植物性食物为主食，包括杂草种子、浆果、嫩芽及各种无脊椎动物。","breeding":"关于繁殖习性的信息有限，但已知形成5至8只的小群觅食。繁殖期间的详细行为模式尚待研究。","identification":"通过其独特的头颈图案和颜色组合与同属物种相区分，尤其是其特有的白色脸颊斑块和灰褐色的冠部。","protection":"IUCN：LC（无危）。被列入中国国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）。","distribution":"主要分布在印度东北部、缅甸东北部以及东北孟加拉国，中国仅见于云南西部盈江地区。","other":"白颊山鹧鸪面临的主要威胁是栖息地丧失，尤其是在山丘的较低斜坡，由于森林砍伐和人类活动的干扰。"},{"name":"台湾山鹧鸪","english_name":"Taiwan Partridge","scientific_name":"Arborophila crudigularis","overview":"台湾山鹧鸪（英文名：Taiwan Partridge，学名：Arborophila crudigularis），是鸡形目雉科山鹧鸪属的鸟类。俗名: 深山竹鸡，为台湾特有种。其独特的黑白脸部图案使其易于识别，分布于台湾的丘陵和山地的阔叶林与混交林中。","appearance":"体长约28厘米，雄鸟重约311克，雌鸟约212克。头部和颈部有显著的黑白相间图案，比其他Arborophila属的鸟有更多的白色面部区域。雄鸟的前额灰色，头顶红棕色，喉部和耳羽白色，颈侧和下喉部有黑色和赤褐色条纹，黑眼线，下体灰白，腹部中心白色，两侧有白色泪滴状斑点，尾下覆羽白色带暗色中心。上体灰色，背部橄榄棕色，翼羽灰棕色，尾羽短圆。雌鸟下方有更多白色斑点，尤其是两侧，喉部黑色标记较少，可能裸部颜色较暗淡。雏鸟特征未详述。","call":"发出一系列重复的、温和的双音哨声'weah-huuu...weah-huuu...'，第一个音过滑，第二个音平坦且音调较低。还有一系列渐强的温和模糊哨声，音调逐渐升高，然后突然结束。整体上与白颊山鹧鸪的声音相似。","habits":"栖息于海拔700至3000米的温带原生阔叶林和混交林，主要在1500至2000米之间。在地面上觅食，以种子、浆果、嫩芽、叶子和无脊椎动物（如蚯蚓和昆虫）为食，通常形成2至3只的小群。清晨和傍晚时分，会发出响亮连续颤抖的鸣唱。","breeding":"繁殖季节从2月底持续到8月，视海拔高度而定。似乎是一夫一妻制。巢建在巨石间的裂缝中或树根下的隐蔽处。产6至8枚白色蛋，孵化期约为24天，雏鸟出生后不久便能跟随亲鸟活动。","identification":"通过黑白相间的脸部图案与同属其他种类区分开来，雄鸟的脸部图纹更为醒目。","protection":"IUCN：LC（无危）","distribution":"仅分布于台湾的中央山脉和东部山脉，主要在海拔1500至2000米的阔叶林和混交林中。","other":"在中国国家重点保护野生动物名录中列为Ⅱ级保护（2021年2月5日）。"},{"name":"红胸山鹧鸪","english_name":"Chestnut-breasted Partridge","scientific_name":"Arborophila mandellii","overview":"红胸山鹧鸪（英文名：Chestnut-breasted Partridge，学名：Arborophila mandellii），是鸡形目雉科山鹧鸪属的鸟类。独特鸟类，分布于东喜马拉雅山脉北侧的印度东北部至西藏东南部，包括不丹、达吉岭和锡金等地。红胸山鹧鸪以其醒目的红褐色胸部和灰色腹部著称，生活在海拔250至2450米的常绿阔叶林和湿润的竹林地带。","appearance":"体长约28至30厘米，体重约268克。红胸山鹧鸪具有鲜明的红褐色胸部带状羽毛和灰色腹部，头部和侧面呈暗锈红色，黑色和白色的颈环使其外观独特。成年鸟的前额至颈背呈红棕色，眼上纹灰白，颈后和肩部点缀黑色斑点，喉咙橄榄色微带淡红，两侧有精细的黑色斑点，白色髭纹显著。胸部深红，与喉咙间有一条黑白相间的窄环。下体灰白，腹中部渐变为白色，两胁有白色斑点，下尾羽覆有白色斑点和红褐色斑纹。上体橄榄褐色，背部细黑条纹，臀部、上尾羽覆有黑色斑点。幼鸟尚未具体描述。","call":"其鸣唱为一系列间隔开的重复、圆润的哨音，每个哨音起始模糊，结尾清晰，音调轻微上扬，持续时间约1.5秒。春季中期至夏季，尤其是在不丹的4月，鸣唱最为频繁。在印度东北部，下午和傍晚也能听到其鸣叫。受到惊吓时，会发出一连串快速滑音的‘kwiuh…kwiuh…kwiuh…’，频率约为2.5至3个音节/秒。","habits":"红胸山鹧鸪偏好居住在海拔3000米以下的常绿阔叶林中，常在林下植被丰富、靠近溪流与河流的环境中活动。它们通常以4到12只的小群体出现，性情相对大胆，擅长在地面快速奔跑，多数时候在林下灌丛中移动，仅在紧急时刻才会飞翔。","breeding":"繁殖季节集中在4月至6月，筑巢于海拔1500至4000米的山地森林地面，利用自然凹坑或雌鸟挖掘的小坑作为巢穴，巢穴通常被茂密的灌木丛或林下植物遮蔽。每窝产卵4至5枚，最多可达8枚，卵的尺寸为33.4至44×26.6至33毫米，孵化期大约为20至21天。","identification":"与相似的红喉山鹧鸪相比，红胸山鹧鸪的冠部和头部侧面更偏向锈红色，喉咙白色，上胸部完全红褐色。通过其独特的红褐色胸部带和灰白色腹部可以轻易识别。","protection":"IUCN：NT（近危）。被列入中国国家重点保护野生动物名录，保护级别为二级（2021年2月5日）。","distribution":"分布于东洋界，自印度东北部至西藏东南部。在繁殖区域主要见于不丹、达吉岭、锡金等地。","other":"红胸山鹧鸪的鸣叫声为清晰响亮的单调哨音，发展成连续的双音节哨音，逐渐升高。配偶在对唱时发出快速的kew-kew-kew声。"},{"name":"褐胸山鹧鸪","english_name":"Bar-backed Partridge","scientific_name":"Arborophila brunneopectus","overview":"褐胸山鹧鸪（英文名：Bar-backed Partridge，学名：Arborophila brunneopectus），是鸡形目雉科山鹧鸪属的鸟类。主要分布在西南中国和东南亚，包括柬埔寨、中国、老挝、缅甸、泰国和越南。栖息于低山常绿阔叶林中，偶尔出现在低山丘陵和山脚平原地带的竹林与灌丛，偏好常绿森林环境。","appearance":"褐胸山鹧鸪总长约280毫米，雄鸟平均翼展144毫米，雌鸟约134毫米，尾巴长度约6-7厘米，喙长20-21毫米。雄鸟和雌鸟的外观相似，以褐色为主色调，黑色从喙部延伸至眼周和喉咙，黑冠和背部的羽毛尖端带有黑色。红眼圈和白黑相间的翼羽，尾部附近呈棕色。雌鸟比雄鸟略小且色彩较淡。幼鸟腿部呈粉红色至橙色，胸部可能有断续的黑色条纹。","call":"其叫声为单调的喉音，发展为一高一低的双哨音'ti-hu, ti-hu, ti-hu...'，音量和频率保持不变。配偶对唱时会加上'kew, kew, kew...'的叫声。","habits":"褐胸山鹧鸪通常以4-9只的小群体活动，由两只成鸟和它们的后代组成，有时为两个家庭群。它们在森林地面的落叶中寻找种子、小壳类和昆虫为食。受到干扰时，会迅速躲入灌木丛中。在繁殖季节，雄鸟通过展示喉部的红色羽毛和鸣叫吸引配偶。","breeding":"繁殖期一般在5月至6月间，营巢于森林或竹林中的地面凹坑内。已知的卵大小为36.8×28.4mm至37.6×28.5mm，每窝产卵数约为4枚。","identification":"与白颊山鹧鸪最相似，但可通过更长、更厚的白色眉纹，延伸至颈部，以及环绕眼睛的红色裸皮区来区分。背部细密的暗色条纹不如侧翼上的大胆黑白斑点明显。","protection":"IUCN：LC（无危）。在中国，褐胸山鹧鸪自2021年2月5日起被列为国家二级保护野生动物。","distribution":"主要分布于东南亚的低山地区，包括中国西南部、老挝、缅甸、泰国和越南。中国大陆主要见于西南部的云南省。","other":"尽管分布广泛，但由于栖息地丧失和猎杀，褐胸山鹧鸪的种群数量正在缓慢下降。"},{"name":"四川山鹧鸪","english_name":"Sichuan Partridge","scientific_name":"Arborophila rufipectus","overview":"四川山鹧鸪（英文名：Sichuan Partridge，学名：Arborophila rufipectus），是鸡形目雉科山鹧鸪属的鸟类。俗名: 荀鸡、砣砣鸡，是中国特有种，体型为一般灰褐色的山鹧鸪，拥有独特头部和胸部图案。分布于中国中南部，尤其是四川南部及云南东北部的部分地区。","appearance":"体长28至30.5厘米，雄鸟体重410至470克，雌鸟350至380克。雄鸟具有宽阔的栗色胸带，狭窄白色眉纹在前额交汇，红褐色冠羽饰有黑色条纹，黑色眼周和宽阔眼线，橙红色耳羽斑块，以及蓝灰色两胁带有白色羽轴条纹和栗色羽毛边缘，腹部白色，下腹区域淡黄色，背部棕色，覆羽具黑色边框和宽阔的栗色边缘。雌鸟略小，下巴和喉咙呈淡黄色，被灰色胸带包围，两胁有弱而苍白的条纹。","call":"发出一系列响亮、上升的哨音，通常在黎明和黄昏时分以二重唱形式展示领土鸣叫，持续时间长达半小时，最频繁的鸣叫发生在日出后的前四个小时和傍晚，偶尔在一天中的其他时间也会鸣叫。","habits":"栖息于亚热带和温带混合常绿阔叶林及次生林，海拔1000至2250米，偏好树冠密集、灌木层丰富、落叶层深厚且接近水源的环境。冬季偏爱向阳坡面的森林。以橡果、胡颓子、悬钩子等果实及部分昆虫为食。","breeding":"繁殖季节为4月至6月，雌鸟独自孵化3至7枚卵，雄鸟在孵化后仅陪伴雌鸟和幼鸟1至2周。巢建在树根附近。","identification":"与环颈山鹧鸪的区别在于喉部主要是白色，胸部有赤褐色；与棕胸竹鸡和灰胸竹鸡相比，体型更大，尾巴更长，头部图案明显不同，胸部侧边和两胁有大胆的暗色斑点。","protection":"IUCN：VU（易危）","distribution":"主要分布在四川南部及云南东北部的特定区域，尤其在老君山自然保护区、马边大风顶自然保护区等地有分布。","other":"面对的主要威胁包括狩猎、农业扩张、非法伐木以及森林中采集竹笋和药用植物的人为干扰。"},{"name":"白眉山鹧鸪","english_name":"White-necklaced Partridge","scientific_name":"Arborophila gingica","overview":"白眉山鹧鸪（英文名：White-necklaced Partridge，学名：Arborophila gingica），是鸡形目雉科山鹧鸪属的鸟类。俗名: 山鸡、新竹鸡，具有醒目的头部图案和独特的黑白胸带，分布于中国东南部的福建、广东、广西等地，主要栖息于树木茂密的山地森林中。","appearance":"体型约25至30厘米，体重约253克。额头白色，眼眉长而斑驳黑色，颈侧与喉部橙红色，黑领与白胸带分明。下体暗灰色渐变为腹部的白色，背部红棕色并有黑色斑点。两翼灰至黄褐色，嘴灰色，眼睛棕色，腿脚红色。雌鸟较小，幼鸟胸部颜色较淡。","call":"鸣声为一系列悠长哀婉的双音调哨音，‘whuuuuu...whuuuuu...’，音调略升且逐渐增强，主要在清晨和傍晚发出。","habits":"栖息于海拔150至1700米的森林中，偏好有密集灌木的溪流和峡谷地带。白天活动于林下，夜晚栖于树上。主要食物为种子、浆果和昆虫。","breeding":"繁殖季节可能为4月至5月，每窝产5至7枚白色蛋，孵化期约为23天。","identification":"通过其独特的黑白胸带和橙色喉部与同类区分开来。与近缘物种相比，其头部图案和色彩组合独特。","protection":"IUCN：NT（近危）。在中国重点保护野生动物名录中列为Ⅱ级保护（2021年2月5日）。","distribution":"分布于中国东南部，从浙江西南部至广东和广西东部。主要在福建山脉特有鸟类区域。","other":"因栖息地丧失和非法狩猎而受到威胁，估计全球成熟个体数介于10,000至19,999之间。广州已开展圈养繁殖计划。"},{"name":"橙颈山鹧鸪","english_name":"Orange-necked Partridge","scientific_name":"Arborophila davidi","overview":"橙颈山鹧鸪（英文名：Orange-necked Partridge，学名：Arborophila davidi），是鸡形目雉科山鹧鸪属的鸟类。小型森林鸟类。仅分布于越南南部和柬埔寨东部极小区域内的茂密常绿林与半常绿林中。拥有独特的白喉、黑眼线和白色侧斑标记，喉咙处橙色调较弱，仅在阴暗的森林下层偶尔可见。其鸣声为一系列上升的悦耳哨音。","appearance":"体长约27-28厘米，重约241克。头部与颈部花纹独特，额头、眉区和中央冠羽至颈背为暗褐色，带有棕色斑点；从喙基部至眼后延伸至颈侧有一条黑色粗线，与黑色胸带相连；眼后至颈侧有白色条纹，逐渐变为锈橙色；下颏淡黄，喉部及脸颊锈橙色；胸部橄榄褐色，两胁有明显的黑白相间的鳞状斑纹；腹部中央和下尾覆羽白色，腹底暗色；背部至尾上覆羽橄榄褐色，有窄暗褐色横斑；肩羽和翼羽黑色，外缘灰色形成明显的翼折纹；喙黑色，虹膜棕色，腿脚粉红色，眼周裸皮亦为粉红色，繁殖季节可能更红。","call":"发出一连串悠扬的哨音，音量逐渐增大，音高略有提升，整个系列的长度可达23秒，重复‘whu-whu-whu-whu-whu...’，节奏与长度变化大。还有单个延长的哀婉哨音。经常成对鸣叫，伴侣以重复的‘tchew-tchew-tchew...’回应。警戒时发出微弱、尖细的‘pher’或‘phu’声。","habits":"栖息于起伏丘陵地带的浓密阔叶常绿林与半常绿林，尤其偏好高达10米的无刺竹林，伴有厚厚的落叶层，但似乎避开大片单一竹林。活动范围在海拔130至250米之间。叫声频繁，在旱季经常被记录到。","breeding":"繁殖信息极少，但在柬埔寨东部4月有繁殖记录。","identification":"与褐胸山鹧鸪相似，但可通过白喉、更粗的黑眼线和更精细、不那么突出的侧身白色鳞状斑纹来区分。","protection":"IUCN：NT（近危）","distribution":"分布于越南南部和柬埔寨东部，特别是在Cát Tiên国家公园和Mondulkiri省Seima保护区。","other":"1927年首次描述，1991年在Cát Tiên国家公园再次发现。2002年在柬埔寨通过相机陷阱首次记录。"},{"name":"栗头山鹧鸪","english_name":"Chestnut-headed Partridge","scientific_name":"Arborophila cambodiana","overview":"栗头山鹧鸪（英文名：Chestnut-headed Partridge，学名：Arborophila cambodiana），是鸡形目雉科山鹧鸪属的鸟类。羞涩隐秘的小型猎鸟，仅分布于柬埔寨豆蔻山脉及泰国极东部。体羽绚丽，橙红胸羽、黑白鳞纹体侧及黑条棕色上背最为醒目；柬埔寨指名亚种头颈亦为鲜亮橙红色。成对活动，在林下层觅食，清晨与午后以响亮二重唱相互应答。","appearance":"体长约28–29厘米；雄鸟体重约318克，雌鸟257–283克。头顶中央、后颈及上耳羽黑色，形成过眼黑带；额、眉纹、头侧、喉及胸锈栗色，颈侧带黑斑；胸侧褐色，体侧黑色，羽基具醒目白色三角斑；腹及尾下覆羽棕黄色渐白。上体棕褐，肩背、翼覆羽及三级飞羽具黑条或黑斑，三级飞羽末端有黑色宽带及栗色羽端。喙黑色，虹膜褐色，脚粉红色，眼周裸皮红色。雌鸟略小，斑纹变化较大，有时上体黑纹更重。幼鸟下体斑纹可能较稀疏。","call":"鸣声似褐胸山鹧鸪，清晨与午后可闻。二重唱由一对鸟完成：先由其中一只发出间隔较大的重复双音，音调先平后逐渐升高，骤然停止；另一只随即接以一连串急促的“chip”声。","habits":"栖息于海拔约400–1500米的热带常绿山地森林，环境多附生植物与兰花。通常成对活动，行走于林下层地面觅食；迁徙信息缺乏。食性推测与其他山鹧鸪属近似，以地面昆虫、果实及种子为主。","breeding":"指名亚种繁殖期可能在5–6月，6月中曾见成鸟带领雏鸟活动。其余繁殖细节信息缺乏。","identification":"与同属物种相比，上背宽阔的黑色横斑是区分栗头山鹧鸪与赤胸山鹧鸪的关键。亚种间差异：diversa面部色泽较暗，眼纹明显，黑白鳞纹延伸至腹部；chandamonyi头顶黑而稀布栗斑，介于指名亚种与diversa之间，上背斑纹同diversa，但面部、喉胸的深栗色及下体图纹又似指名亚种。","protection":"IUCN: LC（无危）。指名亚种被评估为易危，亚种 diversa 为濒危，新描述的亚种 chandamonyi 尚未评估。总体因栖息地破坏及狩猎压力呈下降趋势。","distribution":"繁殖区：指名亚种分布于柬埔寨东南部；亚种 chandamonyi 限于柬埔寨西南部豆蔻山脉的 Samkos 山系，可能向北延伸至泰国边境并向东南进入中部豆蔻山；亚种 diversa 仅见于泰国东南部的 Namtok Phliu 国家公园及 Khao Soi Dao 野生动植物保护区。","other":"亚种 diversa有学者建议提升为独立种泰国山鹧鸪；亚种 chandamonyi 于21世纪初才被正式发现。"},{"name":"泰国山鹧鸪","english_name":"Siamese Partridge","scientific_name":"Arborophila diversa","overview":"泰国山鹧鸪（英文名：Siamese Partridge，学名：Arborophila diversa），是鸡形目雉科山鹧鸪属的鸟类。原被视为栗头山鹧鸪的一个亚种。主要分布在泰国东南部的高海拔森林中。","appearance":"泰国山鹧鸪的详细外观描述暂缺，通常此类鸟具有明显的性别二态性，雄鸟和雌鸟在羽毛颜色和图案上可能有所不同，但具体细节需参考更详细的资料。","habits":"泰国山鹧鸪生活在泰国东南部的高海拔森林中，其具体的栖息地偏好、迁徙模式和飞行特性尚未详细记录。它们的活动范围、觅食方式以及食物种类也是研究中的内容。","identification":"与栗头山鹧鸪（如果存在）的区别辨识要点未详，但可能涉及外观特征、声音或分布差异。","distribution":"泰国山鹧鸪主要分布于泰国东南部的高海拔森林区域。","other":"栗头山鹧鸪的亚种"},{"name":"马来山鹧鸪","english_name":"Malayan Partridge","scientific_name":"Arborophila campbelli","overview":"马来山鹧鸪（英文名：Malayan Partridge，学名：Arborophila campbelli），是鸡形目雉科山鹧鸪属的鸟类。这一小型而隐秘的物种主要分布在马来半岛的高山森林地带，以其独特的黑白头部斑纹和橄榄棕色上体而著称。","appearance":"马来山鹧鸪长约28厘米，成年体重介于320至352.6克之间。其头部以黑白相间的独特图案为特色，上体主要呈现橄榄棕色，翅膀边缘较浅。喉咙处的羽毛稀疏，呈红橙色；下体灰色，腹部逐渐变为白色。虹膜为棕色，眼周有一圈宽大的红橙色皮肤。喙黑色，腿红色。雌雄相似，雌鸟头部可能略显橄榄色，体型较小，裸露部位颜色较暗淡。幼鸟通常上体呈锈色，下体更偏锈色，胸部有条纹，羽轴有浅色条纹。","call":"马来山鹧鸪会发出响亮的鸣唱，一系列连续上升的清脆音符，重复播放，有时会转换为约12个双音节音符的较短序列，第二部分音调低八度。报警时，会发出弱但快速重复的‘wut-wit’声。","habits":"马来山鹧鸪栖息在海拔约1000至1600米的山地森林，主要在高大乔木区以及常绿和高山森林中发现。它们偏好植被茂密的成熟森林，即使是在Campbell高地的小片森林中也能生存。觅食时，多以家庭群的形式出现，食物包括棕榈藤果实、Pratia begoniaefolia攀缘植物的红色果实、白蚁和软体动物。","breeding":"繁殖季节记录到的月份为三月，巢穴为扁平松散编织的垫子，直径约15厘米，由枝条和叶子构成，位于地面的棕榈树下，有的巢穴有通往深叶垫的通道。一窝产四枚蛋，可能是白色，尺寸约为42mm x 31.5-32mm，关于孵化和离巢期的信息未知。","identification":"马来山鹧鸪鸣声与苏门答腊山鹧鸪, A. orientalis and A. brunneopectus类似，但声音更为柔和且持续时间更长。与长嘴山鹑相比，声音更柔和。与灰胸山鹧鸪的区别在于分布区域和叫声特征。","protection":"IUCN：LC（无危）。种群数量未量化，但分布稀疏。由于其栖息地大多人类难以到达，认为该物种面临严重的栖息地损失的风险不大。","distribution":"马来半岛山区，主要分布在海拔1000米以上的山地森林。在远东地区，马来半岛的山脉为其主要分布地。","other":"有时被归为灰胸山鹧鸪的一个亚种。"},{"name":"罗氏山鹧鸪","english_name":"Roll's Partridge","scientific_name":"Arborophila rolli","overview":"罗氏山鹧鸪（英文名：Roll's Partridge，学名：Arborophila rolli），是鸡形目雉科山鹧鸪属的鸟类。主要分布在印度尼西亚苏门答腊岛北部的Batak高原，海拔500至2000米的山地森林中。","appearance":"成年罗氏山鹧鸪长约30厘米，重约300克。雄鸟枕部、上背、下体及两翼有明显的白点，背部和尾部具有白色横斑。头部黑色带有栗色眉纹，眼周至耳羽有一宽阔的白色条带，颏部和喉部白色。雌鸟与雄鸟类似，但下体为皮黄色带黑斑，上体更多棕褐色。上背黑色，布满椭圆形白斑，尾下覆羽棕色。脚短，颜色从橙黄色到红褐色。","call":"鸣唱为一系列快速上升的呼啸哨音，连续不断，容易听到而非看到。通常成对或小群合唱。","habits":"栖息于丘陵、山地的草丛或灌木丛中，活动范围在500至2000米的海拔。似乎为留鸟，不迁徙。食物主要包括谷物、豆类、昆虫及植物种子。","breeding":"繁殖信息缺乏，但据观察，可能在春季繁殖，于草丛或灌木丛中筑巢，每窝产卵数通常为3至5枚。","identification":"与苏门答腊山鹧鸪相似，但可通过温暖的棕色胸部和脸部更广泛的白色区分，以及分布范围的不同。","protection":"IUCN：LC（无危）。然而，由于栖息地破坏和过度狩猎，部分地区种群数量下降，需加强保护。","distribution":"分布于印尼苏门答腊岛山区西北部，主要在Batak高原。","other":"罗氏山鹧鸪的繁殖率较低，目前尚未有大规模养殖的报道。"},{"name":"苏门答腊山鹧鸪","english_name":"Sumatran Partridge","scientific_name":"Arborophila sumatrana","overview":"苏门答腊山鹧鸪（英文名：Sumatran Partridge，学名：Arborophila sumatrana），是鸡形目雉科山鹧鸪属的鸟类。小型而圆胖，主要分布在印度尼西亚苏门答腊岛的西部和南部山区，位于Batak高原以南。在海拔500至2000米的常绿阔叶林中栖息。","appearance":"体长约28厘米。头部大部分呈灰色，前额到颈背有暗斑点的棕色，眼后有白色斑点；上身淡褐色，有黑色条纹，肩羽和翼覆羽为栗色，边缘为灰色；喉咙灰白色，胸部蓝灰色，腹部逐渐变为白色，两胁黑白相间的条纹；虹膜棕色，眼周红橙色；喙黑色；腿红色。雄雌外观相似，但雌鸟似乎更小。幼鸟描述不详，可能具有灰白色的裸露部分。","call":"声音和鸣叫行为与罗氏山鹧鸪和灰胸山鹧鸪非常相似：领地鸣叫是一种双音节的哨声，音量逐渐增大，通常以一系列较为规律的单个哨声开始。","habits":"在森林地面单独、成对或小群体觅食。生活在苏门答腊岛的山区。","identification":"与罗氏山鹧鸪相比，但它们的分布范围并不重叠。","protection":"IUCN：LC（无危）。据报告，数量因栖息地丧失和过度狩猎而减少。","distribution":"分布于苏门答腊岛中部和南部山区。","other":"有时被视为灰胸山鹧鸪的亚种。"},{"name":"灰胸山鹧鸪","english_name":"Grey-breasted Partridge","scientific_name":"Arborophila orientalis","overview":"灰胸山鹧鸪（英文名：Grey-breasted Partridge，学名：Arborophila orientalis），是鸡形目雉科山鹧鸪属的鸟类。特有种，分布于印尼爪哇岛东部山区，如Kawah Ijen自然保护区等地。体型紧凑，腿部短小，主要羽毛呈灰色，背部和尾部有条纹，头部黑色，额头、脸颊和喉咙显眼地白色，眼部周围裸露皮肤为红色。","appearance":"灰胸山鹧鸪长约28厘米，体重约268克。头部黑白相间，冠和颈背深黑色，其余部分几乎全白，包括前额、眉纹、颈侧，有一条暗褐色线从喙基延伸至眼周和颈侧，胸部棕色灰色，略带黑色斑点，两侧和腹部灰色，广泛而无规则地黑白色条纹，后腹部边缘锈色，尾下覆羽白色，羽毛基部黑色；上身暗棕色，窄黑条纹，肩羽、三级飞羽和翼羽具栗色边缘和黑色中心；喙红棕色，虹膜浅红黄色，眼周和喉部裸皮红色，腿脚红黄色。雌鸟头部黑色较暗淡，可能较小，裸部颜色也较暗淡。幼鸟有苍白的羽轴纹，下方通常更偏锈色，胸部有条纹。","call":"其鸣声为一系列重复的“wut-wut”音符。在二重唱中，另一方以一系列双音节悦耳的口哨声“wee-hoo”回应。有时在二重唱开始前会发出一连串悦耳颤抖的口哨声“whrrreuw”。叫声与棕腹山鹧鸪极为相似。","habits":"关于饮食和觅食的数据较少。预计饮食包括棕榈果、浆果和无脊椎动物。它们在森林地面觅食，常以小组形式活动，通常非常害羞，但在建立的喂食站附近可能会变得容易接近。","identification":"独特的面部特征，尤其是明亮的白色脸部，使它在有限的范围内与其他所有鸡形目鸟类区别开来。与棕腹山鹧鸪相比，叫声几乎无法区分。","protection":"IUCN：VU（易危）。分布范围历史覆盖约7000平方公里，现今不到2500平方公里。数量可能超过初步估计的1000-10,000个个体，但栖息地质量和狩猎压力可能导致实际数量远低于此。总共有11,000-28,000对可能仍然存在，但考虑到狩猎和栖息地质量，数量可能低得多。其数量保守估计为10,000-19,999个成熟个体。","distribution":"分布于爪哇岛山区东部，特别是在Yang Highlands的东部。繁殖区域与非繁殖区域未明确区分。","other":"一些权威认为马来山鹧鸪、罗氏山鹧鸪和苏门答腊山鹧鸪是灰胸山鹧鸪的亚种。"},{"name":"棕腹山鹧鸪","english_name":"Chestnut-bellied Partridge","scientific_name":"Arborophila javanica","overview":"棕腹山鹧鸪（英文名：Chestnut-bellied Partridge，学名：Arborophila javanica），是鸡形目雉科山鹧鸪属的鸟类。身长约28厘米，以其独特的外观和分布于印尼爪哇岛的山地森林而知名。拥有橙红的头部和颈部，灰蓝色的胸部，棕色的翅膀，以及鲜明的黑脸和红色的腿。其腹部为醒目的栗色，中间带有白色。性别间差异不大，幼鸟具有白色的面部和红棕色的喙。","appearance":"成年棕腹山鹧鸪体长约为28厘米，体重介于257至286克之间。头部和颈后部呈现橙红至赤褐色，饰以深灰色和棕色条纹与斑点。脸部为亮丽的橙黑色相间图案，喉部中央锈橙色，脸颊橙红。胸部蓝灰色，下腹部及两胁栗棕色，腹部中部白色，下尾覆羽锈黄带黑色羽基。上体灰蓝色，密布黑色细横纹，翼羽更偏棕色，具栗色边缘和黑色中心斑点。喙黑色，虹膜灰色，眼周及喉部裸露皮肤红色，腿亦为红色。雌鸟与雄鸟相似，但可能体型较小，色彩略淡，裸露部分颜色稍暗。幼鸟喉部白色，胸腹部暗棕色，肩羽上有白色斑点，喙色红棕色。","call":"棕腹山鹧鸪的鸣唱通常为一对鸟的二重唱，一只发出快速响亮的哨声，音量逐渐增大，音调略有提高，另一只则以较慢的节奏发出低沉柔和的‘boo-goo’双音节哨声。此外，还有警戒时发出的不规则短调和柔和的联系叫声。","habits":"棕腹山鹧鸪栖息于海拔300米至3000米的山地森林，常见于600至2500米的高度。它们不会出现在大片的松树、橡胶树、香脂树或桃花心木等种植园中。它们在森林地面小群觅食，群体可达六只。一年中大部分时间都有鸣叫。","breeding":"已知会在穹顶状的长草巢中产卵，由雄鸟筑巢，雌鸟产卵数可达四枚。","identification":"棕腹山鹧鸪在其属内最为独特，与近缘种有显著区别，尤其是在头部的图案上。不同亚种间头部图案有所差异。","protection":"IUCN：LC（无危）。尽管在有限范围内常见，但由于栖息地丧失、退化和碎片化，仍面临威胁。部分个体被非法捕捉用于鸟类贸易，但狩猎并非重大威胁。","distribution":"仅限于印尼爪哇岛的山地森林，分布于西部和东部的山区。","other":"棕腹山鹧鸪是印尼特有种，目前约有250只个体在圈养环境中。"},{"name":"红嘴山鹧鸪","english_name":"Red-billed Partridge","scientific_name":"Arborophila rubrirostris","overview":"红嘴山鹧鸪（英文名：Red-billed Partridge，学名：Arborophila rubrirostris），是鸡形目雉科山鹧鸪属的鸟类。其独特之处在于拥有完全红色的喙，这是该属中唯一具有这一特征的物种。分布在印度尼西亚苏门答腊岛的巴里桑山脉高海拔森林（900-2500米）。","appearance":"这种小型鹧鸪有着鲜亮的红色嘴巴，胸部呈红棕色，侧翼羽毛黑白相间如同鳞片，背部条纹交错，黑色与棕色相融。头部图案各异，可能是以黑色为主带白色斑点，或是以白色为主，头顶和颈背黑色。雌雄成鸟的羽毛颜色相似，幼鸟特征未详。","call":"红嘴山鹧鸪的鸣唱是一系列逐渐升高的哨音，其中一些带有双重音质：“wuew, wuwuew, wuew”。通常，一对鹧鸪会进行二重唱，一只发出上升的哨声，另一只会发出一系列较低沉的“ooh”音符。","habits":"红嘴山鹧鸪栖息在苏门答腊山脉的森林中，偏好高海拔环境。它们的活动范围和具体觅食方式尚待研究，但基于其他山鹧鸪的行为，可能以植物性食物为主。","breeding":"有关红嘴山鹧鸪的繁殖习性的具体信息有限，但预计与同属的其他物种类似，包括营巢、产卵和孵化等过程。","identification":"红嘴山鹧鸪最显著的辨识特征是其完全红色的喙，这在同属物种中独一无二。","protection":"IUCN：LC（无危）；Mace Lande: vulnerable。红嘴山鹧鸪的分布范围虽受限，但在苏门答腊北部和西部山区仍有适宜的栖息地。目前，山地生境相对安全，数量可能保持稳定。然而，某些地区的栖息地威胁仍然是一个问题。在印度尼西亚法律中并未受到保护。","distribution":"红嘴山鹧鸪仅分布于苏门答腊岛的山脉区域，特别是在巴里桑山脉的高海拔森林中。已知记录存在于苏门答腊的几个特定地区，如Sibayak山（Aceh）、Brestagi山和Kerinci山。"},{"name":"赤胸山鹧鸪","english_name":"Red-breasted Partridge","scientific_name":"Arborophila hyperythra","overview":"赤胸山鹧鸪（英文名：Red-breasted Partridge，学名：Arborophila hyperythra），是鸡形目雉科山鹧鸪属的鸟类。其特征在于明亮的红褐色脸部和胸部，以及独特的黑白侧斑。该物种特有于婆罗洲中部山脉的森林地带，偏好竹林和灌丛环境。","appearance":"成年赤胸山鹧鸪约25至27厘米长，重约270克。头部和颈背呈黑褐色，点缀着棕色斑点。眼上有一条灰色或红褐色的眉纹，眼睛周围有黑色带状条纹。脸颊和喉咙为红褐色，胸部鲜亮的栗色，腹部白色。两侧为黑白相间的斑驳图案。背部棕色，带有黑色细条纹。眼睛灰褐色，喙黑色，腿脚为鲑鱼粉色。雌鸟的羽毛较雄鸟略暗淡，侧斑较小且颜色更接近棕色。幼鸟的描述尚不详尽。","call":"赤胸山鹧鸪的鸣声通常以二重唱形式呈现，一只鸟发出快速响亮的哨音，音量逐渐增大，音调略微上升，另一只则发出低沉圆润的双音节哨声，速度较慢。","habits":"栖息于婆罗洲北部中央山区的各种类型山地森林，包括原始和次生低山森林，海拔高度从约600米到1890米，甚至可达3050米。偏好竹林和灌丛密集区，夜间在靠近地面的灌木丛中休息。","breeding":"在野外，雄鸟于12月初进入繁殖状态。圈养条件下，巢穴为穹顶形，侧面有孔，离地约2至3厘米。关于繁殖行为的更多信息尚未可知。","identification":"与同属的栗头山鹧鸪相比，赤胸山鹧鸪的上部羽毛颜色更浅，斑点更模糊，眼部暗线更为明显。雌雄之间主要区别在于体型和色彩亮度。","protection":"IUCN：LC（无危）。在1990年代中期之前，仅知九个分布点，近年来记录较少，特别是在婆罗洲南部。然而，在适宜的生境中可能广泛分布。受威胁因素包括森林砍伐导致的栖息地丧失和退化，以及可能的过度狩猎。","distribution":"分布于婆罗洲北部中央山脉，包括沙巴、砂拉越、北加里曼丹和北中加里曼丹的部分地区。主要栖息于海拔600至1890米的山地森林。","other":"红胸山鹧鸪的分类历史涉及早期描述和命名，目前被认为是单型种。"},{"name":"海南山鹧鸪","english_name":"Hainan Partridge","scientific_name":"Arborophila ardens","overview":"海南山鹧鸪（英文名：Hainan Partridge，学名：Arborophila ardens），是鸡形目雉科山鹧鸪属的鸟类。仅见于海南岛南部热带雨林，是该区域唯一的森林居住型雉科山鹧鸪属鸟类。头部黑色带亮白耳斑和橙色颈环，上身橄榄褐色，下身灰白，体长26-28厘米。分布于海南岛山区，数量极为有限。","appearance":"体长约26-28厘米，雄鸟体重约300克，雌鸟略小，约237克。头部黑色，具显著的白色耳羽斑和白色眉纹。冠和颈背暗棕色，有黑色斑点。背部橄榄褐色，覆以黑色鳞状斑纹。喉部和颈侧黑色，颈下有一橙色领圈。腹部灰色，中央腹部呈淡黄色。翅膀灰褐色，喙黑，眼棕，腿淡红。","call":"鸣唱由两音节重复构成，包括‘ju-gu ju-gu ju-gu’的叫声，有时伴有快速的单音节叫声。清晨和傍晚最为活跃。","habits":"栖息于海拔500-1400米的热带雨林，包括原生和次生林。以单个、成对或小群（最多5只）活动，食物包括树籽、昆虫（如白蚁）和蜗牛。天敌包括青鼬和猛禽。","breeding":"繁殖期为4-6月，营巢于地面，每窝产2-4枚纯白色卵，卵大小约为33.4-34.7×25.5-26.2毫米，卵重11.6-13克。曾有实验饲养成功的记录。","identification":"与海南孔雀雉相比，海南山鹧鸪体型较小，全身颜色差异明显，头黑耳白，颈有橙环。鸣叫声亦有别。","protection":"IUCN：VU（易危）；在中国属于国家一级保护动物，面临栖息地减少和非法狩猎的威胁。","distribution":"仅分布于中国海南岛的山脉区域，包括Bawangling、Jianfengling、Wuzhishan、Diaoluoshan Limushan和Nanweiling自然保护区。","other":"近年来新发现的种群增加了对其保护的紧迫性，但森林砍伐和非法猎杀仍对其构成威胁。"},{"name":"栗胸树鹧鸪","english_name":"Chestnut-necklaced Partridge","scientific_name":"Tropicoperdix charltonii","overview":"栗胸树鹧鸪（英文名：Chestnut-necklaced Partridge，学名：Tropicoperdix charltonii），是鸡形目雉科Tropicoperdix的鸟类。生活在马来半岛和苏门答腊热带雨林中的雉科鸟类。以独特的橙褐色颈带和黄绿色腿脚著称，全球数量稀少且正面临威胁。","appearance":"栗胸树鹧鸪长约26至32厘米，雄鸟约重290克，雌鸟约250克。头部呈暗褐色，具深色斑点，眼上纹、喉部和颈部为白色并带有棕色条纹。上胸部呈栗色，有一黑色领圈，腹部橙褐色，下胸至侧腹有棕色鳞状斑。背部和翅膀为暗褐色，饰以深色条纹和斑点。喙绿黄色，腿脚黄绿色。雌鸟比雄鸟稍小且色彩略淡，幼鸟色泽更暗，背部有更多深色条纹。不同亚种在面部和翼部图案、胸带栗色强度上有差异。","call":"其鸣唱为重复的颤音哨声“whrrreuw”，音调逐渐升高，通常以二重唱形式出现，伴侣间相互呼应，形成加倍或三倍的旋律。","habits":"居住在低地常绿森林和平原至海拔约300米的较低斜坡，有时出现在严重扰动的森林和竹子为主的次生林。以种子、浆果和白蚁为食，通常小群活动。","breeding":"关于繁殖的信息有限，具体细节尚不清楚。","identification":"与绿脚树鹧鸪相比，栗胸树鹧鸪具有更明亮的羽色，尤其是上胸的栗色带和橙褐色腹部，耳羽有红褐色斑块，腿脚黄色。亚种间在脸和翼部的图案以及胸带的栗色强度上有所不同。","protection":"IUCN：VU（易危）","distribution":"分布于马来半岛和苏门答腊的低地森林。在泰国-马来半岛、Aceh和南苏门答腊有记录。","other":"沙巴树鹧鸪曾被认为是本种的亚种，现被视为独立物种，近受威胁。"},{"name":"绿脚树鹧鸪","english_name":"Green-legged Partridge","scientific_name":"Tropicoperdix chloropus","overview":"绿脚树鹧鸪（英文名：Green-legged Partridge，学名：Tropicoperdix chloropus），是鸡形目雉科Tropicoperdix的鸟类。分布于东南亚的森林地带，范围延伸至中国南部云南省。绿脚树鹧鸪以其独特的绿色腿部而著称，通常栖息在成熟丘陵和低地森林的茂密植被中。","appearance":"体长约26至31厘米，体重约250至300克。全身呈斑驳的棕色，脸部灰白，喉部橙色且带有斑点。头部和上身棕色，有黑色斑点和条纹；下胸部橙色，腹部更偏向奶油色。喙绿色，基部红色，虹膜棕色，眼周皮肤红色。雌雄相似，但雌鸟可能较小。幼鸟的胸部和侧翼可能显示出白色的羽毛轴或尖端。","call":"绿脚树鹧鸪的鸣唱是一系列上升的喘息哨音，最终以一连串回响的响亮音符结束。其领地呼唤为一组两到三个均匀的清晰哨声，经常以二重唱形式发出。","habits":"栖息于密集的原始森林，但也可见于次生林和竹林，高度可达海拔1400米。主要在雨季期间活动，种子、浆果和白蚁为其主要食物来源。","breeding":"繁殖季节为雨季（5月至9月），巢建于大树根部的浅碗中，由枯叶和羽毛铺垫。一窝产卵2至4枚，平均3.19枚，由雌鸟单独孵化，孵化期18至20天。孵化成功率约为96%，巢穴存活率在26.7%左右，面临来自北方长尾猴、北方树鼩等天敌的威胁。","identification":"与Alectoris charltonii相比，绿脚树鹧鸪缺乏颈部下方的黑色细线，耳羽灰色而非红褐色。与Alectoris tonkinensis在羽毛颜色上介于绿脚树鹧鸪和Alectoris charltonii之间。","protection":"IUCN：LC（无危）。在中国，被列入国家二级保护野生动物名录（2021年2月5日）。","distribution":"主要分布在东南亚，包括缅甸、老挝、泰国以及中国的云南省。在繁殖区域，绿脚树鹧鸪主要见于稠密的常绿灌丛、燕麦地以及稀疏的落叶林。","other":"尽管在某些地区数量稳定，但绿脚树鹧鸪总体上在当地较为罕见，特别是在中国云南省。"},{"name":"沙巴树鹧鸪","english_name":"Sabah Partridge","scientific_name":"Tropicoperdix graydoni","overview":"沙巴树鹧鸪（英文名：Sabah Partridge，学名：Tropicoperdix graydoni），是鸡形目雉科Tropicoperdix的独特鸟类，分布于远东地区的婆罗洲北部。其最显著的外部特征包括深褐色的颈圈，带有斑点的头部图案，以及淡色的喉咙。该物种较为罕见，数量正在减少。","appearance":"沙巴树鹧鸪具有复杂而独特的羽色模式，全身呈棕色，腹部为淡色，胸部有锈色围兜，头部有黑白相间的斑点。雌雄差异不大，但雌鸟可能略显暗淡。全长约26至32厘米，上体和翅膀为暗褐色，密布深色条纹，下体由棕色重叠深色至后腹和侧翼处转为更丰富的红褐色。腿和脚趾颜色为暗黄色到黄绿色。","call":"沙巴树鹧鸪的鸣声通常以颤音的哨声开始，随后是一系列升降音调的‘weep! churrrrr…!’。这种鸣唱经常以二重奏的形式呈现。","habits":"沙巴树鹧鸪栖息于热带低地雨林，通常在较低海拔的森林地面活动，以小群觅食。它们的食物包括种子、浆果和白蚁。该物种似乎全年定居，没有迁徙行为。","breeding":"繁殖信息未知，但沙巴树鹧鸪可能遵循类似其他雉科鸟类的繁殖模式，包括营巢、产卵和育雏。","identification":"沙巴树鹧鸪与其他雉科鸟类的区别在于其明显的胸环和腹部的淡色鳞状斑纹，以及头部缺乏锈色。在分布区域内，它可以通过这些特征与赤胸山鹧鸪区分开来。","protection":"IUCN：NT（近危）","distribution":"沙巴树鹧鸪仅在北婆罗洲（Borneo）发现，具体分布在马来西亚的沙巴州（Sabah）。","other":"沙巴树鹧鸪的历史分类曾与栗胸树鹧鸪视为同种，但基于分子数据的研究将其重新划分为独立物种。"},{"name":"锈红林鹧鸪","english_name":"Ferruginous Partridge","scientific_name":"Caloperdix oculeus","overview":"锈红林鹧鸪（英文名：Ferruginous Partridge，学名：Caloperdix oculeus），是鸡形目雉科锈红林鹧鸪属的鸟类。其显著特征包括南瓜橙色的头部和胸部，棕色的翅膀，以及背部和侧面的黑白相间的鳞状斑纹。分布于东南亚，包括印尼、马来西亚、缅甸和泰国，是CITES保护物种。","appearance":"锈红林鹧鸪体长约27至32厘米，重约191至230克。雄鸟有时有两个脚刺，而雌鸟只有一个短脚刺。幼鸟的颈背和胸部有黑色标记，羽缘呈淡褐色而非白色，整体颜色较暗且灰。不同亚种在细节上略有差异，如斑点的分布和颜色深浅。","call":"锈红林鹧鸪的鸣唱是一系列逐渐加速并升高的哨音，随后突然转变为粗糙、尖锐的音符，如同声音突然破裂。","habits":"栖息于常绿和半常绿森林，包括山区干燥森林、沙谷中的原始和次生森林，以及次生灌木丛，主要在地面觅食。主要以种子、草、浆果、落地无花果和昆虫为食。","breeding":"繁殖季节不详，但在马来西亚半岛9月中旬可见到半成长的幼鸟。在婆罗洲，当地人报告说在12月至1月期间，鸟巢呈圆顶状，有入口洞，含8至10枚纯白色的蛋。孵化期在圈养条件下大约为18至20天。","identification":"锈红林鹧鸪以其明亮的赤褐色头部和下体、背部和胸部两侧的黑白色鳞状斑纹为显著特征，与其它雉科鸟类容易区分。","protection":"IUCN：NT（近危）","distribution":"锈红林鹧鸪分布于东洋界，包括缅甸、马来半岛、印尼苏门答腊岛和婆罗洲。","other":"由于栖息地破坏和过度猎杀，锈红林鹧鸪的数量被认为正在减少。"},{"name":"红头林鹧鸪","english_name":"Crimson-headed Partridge","scientific_name":"Haematortyx sanguiniceps","overview":"红头林鹧鸪（英文名：Crimson-headed Partridge，学名：Haematortyx sanguiniceps），是鸡形目雉科红头林鹧鸪属的鸟类。本属唯一种。以其醒目的红头和黑身而著称，分布于婆罗洲北部和中部山区的低海拔山地森林中。","appearance":"红头林鹧鸪长约25厘米，雄鸟体重可达330克。雄鸟头部、颈部、胸部及最长的尾下覆羽为鲜艳的红色，其余部分呈深黑色；喙黄色至黄白色，虹膜棕色带黄眼环，腿脚灰色，最多有三个跗跖刺。雌鸟无刺，毛色总体偏褐色，喉部、颈部和胸部为赤橙色，喙呈角褐色。幼鸟色泽较暗淡，以头顶的红色为主，有锈色斑纹的黑褐色胸羽，翼羽边缘微红。","call":"发出响亮、金属质感的‘ring-YING, ring-YING, ring-YING’声，有时为重复的‘KRO-krang, kong-krrang’或‘whu-kweng...whu-kweng..whu-kweng…’双音节鸣叫，第二个音节粗糙且高亢。兴奋时会发出急促的‘whu-keng-keng-keng-kok-kok’叫声。","habits":"栖息于婆罗洲的低山森林，包括砂质地带的劣质森林、河岸森林和卡朗加斯森林。主要活动在1000米至1700米的海拔，偶尔降至185米或升至3050米。以浆果、昆虫和小型甲壳类动物为食。","breeding":"繁殖信息知之甚少。最早记录的产卵时间在1月中旬，幼鸟记录于4月。筑巢于卡朗加斯森林，巢由干叶构成，位于草丛或类似环境。每窝产8-9枚咖啡奶色蛋，孵化期约18-19天（圈养条件下）。","identification":"其独特的红头黑身外观使它不易与其它物种混淆，仅可能与幼年黑鹑相似，但后者有更宽的黑色喙可资辨别。","protection":"IUCN：LC（无危）。虽然局部地区常见，但分布范围大幅缩减，种群数量被认为正在下降，估计剩余个体不足10,000只。在一些保护区如基纳巴卢公园和穆鲁国家公园有记录。","distribution":"分布于婆罗洲北部和中部山区，包括砂拉越和沙巴。在卡里曼丹中部的水文区域，其状况未知。在卡亚恩门塔朗自然保护区有记录。","other":"主要威胁是栖息地丧失和退化。印尼法律未对其加以保护。"},{"name":"冕鹧鸪","english_name":"Crested Partridge","scientific_name":"Rollulus rouloul","overview":"冕鹧鸪（英文名：Crested Partridge，学名：Rollulus rouloul），是鸡形目雉科冕鹧鸪属的鸟类。又名:冕鹧鸪鸪，小型鸟类。栖息在热带常绿雨林的底层，分布于泰国南部、马来半岛、苏门答腊岛和婆罗洲等地。雄鸟拥有闪亮的黑色身躯和醒目的红色羽冠，雌鸟则是苔绿色，翅膀带有暖棕色，两者均有鲜红的眼圈。","appearance":"冕鹧鸪体长约26厘米，圆润且尾短。雄鸟上半身为金属绿色，下半身呈深蓝色，双翼呈褐色，头部顶着高耸的红色羽冠，前额有白色斑点，喙全黑。雌鸟体色为绿色，翼底褐色，头部灰，无斑点和羽冠。雏鸟颜色较暗，与成鸟相似。","call":"其鸣叫声为一系列悠长且略带双音节的哨声，‘si-ul’，每次持续约1.3秒，通常在黎明时分稳定重复。","habits":"冕鹧鸪栖息于低地至海拔1550米的热带雨林，包括低地和山地森林、河岸冲积林、泥炭沼泽森林和砍伐过的森林。它们以种子、大型果实（尤其是无花果）、大型甲虫、木蚁和小型软体动物为食，有时会跟随野猪觅食。群体活动，最多可达13只。","breeding":"繁殖季节分散，筑巢于干燥树叶下的凹陷处，直径约15-20厘米，深度2-3厘米，主要由雄鸟建造。每窝产5-6枚白色蛋，孵化期为18-19天，仅雌鸟孵卵，雏鸟出生时呈深红棕色，下部较淡，颈部有暗条纹，耳羽黄色，虹膜黑色，喙棕色，脚粉色。","identification":"雄鸟的红冠和全黑羽毛，雌鸟的绿色体羽和灰色头部，以及两者共有的红色眼圈是识别特征。雏鸟与成鸟相似，但色彩更暗。","protection":"IUCN：VU（易危）。","distribution":"分布于泰国西南部、缅甸南部（Tenasserim地区）、马来半岛南部至苏门答腊岛（包括一些邻近小岛）和婆罗洲。在马来西亚半岛，分布可达海拔1550米。在婆罗洲，常见于Ketambe（Gunung Leuser国家公园）和Way Kambas。","other":"在泰国，冕鹧鸪的数量已经变得稀少，最近十年似乎没有记录。在苏门答腊和婆罗洲，尽管面临栖息地破坏的威胁，但仍可能广泛存在。"},{"name":"棕胸竹鸡","english_name":"Mountain Bamboo Partridge","scientific_name":"Bambusicola fytchii","overview":"棕胸竹鸡（英文名：Mountain Bamboo Partridge，学名：Bambusicola fytchii），是鸡形目雉科竹鸡属的鸟类。分布于东洋界，从印度东北部至缅甸和中国中南部。其命名纪念了Major-General Albert Fytche。以小群栖居，雄鸟在春季异常喧哗，多在近溪水的环境中活动。","appearance":"棕胸竹鸡的羽毛呈混合的棕色、奶油色和灰色，具有独特的黑白眼纹，胸部和腹部为淡色，带有棕色斑点。雄鸟体重278-400克，雌鸟256-340克，体长约为32-37厘米。雄鸟比雌鸟大，雌鸟通常无距，眼虹膜为棕色至淡黄褐色，喙颜色因性别而异，腿橄榄褐色。幼鸟类似雌鸟，但有更淡的红褐色冠羽，灰黄色上部和灰色胸部。","call":"鸣叫特征为响亮的连续高音尖叫系列，通常由沙哑的喉音尖叫开始，形成‘che-chirree-che-chirree’的节奏，约4个音符/秒，音调可能升降然后逐渐减弱，有时会合唱或二重奏，尤其在清晨听到。","habits":"生活在海拔3000米以下的山坡森林、灌丛、草丛和竹林中，偏好在陡峭山沟溪流旁的灌丛和草丛地带活动。杂食性，主要食用植物幼芽、浆果、种子和大豆、小麦等农作物，以及昆虫、蠕虫、蜗牛等动物性食物。","breeding":"繁殖期在3月至9月，巢建于草地或竹林中的地面，通常为简单的凹坑，铺垫枯草和树叶。每窝产卵3-7枚，通常4-5枚，卵壳厚且硬，卵的大小约为36-41mm×27-31mm，平均39mm×29mm，孵化期18-19天，由雌鸟单独孵化，雄鸟在附近守护并可能喂养雏鸟。","identification":"雄鸟有明显的头纹和较大体型，雌鸟通常无距，眼后有红褐色带而非黑色。幼鸟与雌鸟相似，但有更淡的红褐色冠羽。与其它小型雉类相比，它更倾向于开阔地活动。","protection":"IUCN：LC（无危）。在中国属于国家保护的有益或有重要经济、科学研究价值的陆生野生动物名录。","distribution":"分布于印度东北部至缅甸和中国中南部，包括泰国北部、缅甸上部、中国广西等地。在泰国北部广泛分布，可能数量增加；在缅甸上部常见；在中国较为罕见，但最近确认在广西有分布；在孟加拉国无近期或确凿记录；在印度东北部曾经大量存在，但目前缺乏最新信息。","other":"尽管在部分地区面临栖息地丧失和猎杀威胁，但棕胸竹鸡在某些区域仍然较为常见，它们能够适应次生林环境，甚至出现在耕地上。"},{"name":"灰胸竹鸡","english_name":"Chinese Bamboo Partridge","scientific_name":"Bambusicola thoracicus","overview":"灰胸竹鸡（英文名：Chinese Bamboo Partridge，学名：Bambusicola thoracicus），是鸡形目雉科竹鸡属的鸟类。俗名: 华南竹鹧鸪、泥滑滑、山菌子、竹鹧鸪、普通竹鸡、中华竹鸡、竹鸡，是中国南方常见的小型雉科鸟类。分布范围广泛，从中国东部的四川东部到福建和浙江南部，向南至广东北部。其显著特征包括灰蓝色的眉纹和胸部，橙色的脸颊和胸部带纹，以及棕色羽翼上的大型黑色斑点。","appearance":"灰胸竹鸡体型约30-32厘米，雄鸟体重242-297克，雌鸟200-342克。头部特征明显，包括棕色的冠羽和颈背，带有红棕色的羽尖，蓝灰色的额部、眼上区和眉纹，以及锈红色的喉部、下耳羽、颈侧和前颈。大部分下体为肉桂色，带有大的黑色或黑栗色的心形斑点，但胸部为蓝灰色，下方有一条狭窄的锈红色带。上体主要为暖橄榄棕色，有灰色网状花纹和大胆的黑色及栗色斑点，较小的白色斑点覆盖在肩羽和翼覆羽上，背部至尾上覆羽逐渐变为棕色，尾部为栗色，饰有深棕色和肉桂色条纹。雌雄基本相似，但雌鸟通常无距（雄鸟有明显的单距）。喙灰色，尖端黑色，虹膜深棕色，腿为灰橄榄色。幼鸟色彩较暗，头部为棕色，眉纹为淡黄色；有淡色的轴纹；背部、臀部和尾上覆羽有深色斑点。","call":"雄鸟广告鸣叫响亮而共鸣，连续发出“gi-gi-gi-gi-gi-gi-gigeroi-gigeroi”的声音，通常还发起与雌鸟的‘killy-killy’二重奏，后者变成‘e-put-kwai’并在高潮中结束；非繁殖季节，鸟类发出‘sih-mo-kuai, sih-mo-kuai’的声音，也被转写为‘people pray’。","habits":"栖息于竹林、灌木丛和草地，海拔高度可达1000米，有时高达2000米。白天活动，夜晚栖息于树上。偏好隐藏而非飞行，但在受威胁时会突然飞起，翅膀拍打声大。以家庭群形式栖居，飞行笨拙，活动于干燥的矮树丛、竹林灌丛。以杂草种子、嫩芽、叶片和昆虫为食，包括蝗虫、白蚁和蠕虫。","breeding":"繁殖季节从3月开始，雄鸟占据领地，驱逐其他雄鸟，导致争斗。筑巢于茂密的灌丛、草丛或竹林地面，巢内铺垫树叶和干草。4-5月间产卵，每窝7-12枚，卵重15克，颜色为暗乳色或淡褐色，有棕色细点和浅灰色斑。仅雌鸟孵化，孵化期16-18天，雏鸟出生后即能跟随成鸟活动。","identification":"与其他Bambusicola物种的区别在于头部更广泛的锈红色，上体颜色较浅，白色斑点更多，下体颜色较浅，黑色标记较少且较小。与台湾竹鸡的主要区别在于头部锈色更多，上体颜色较浅，白色斑点较多，下体颜色较浅，黑色标记较少且较小。","protection":"IUCN：LC（无危）。尽管面临栖息地丧失和过度狩猎的威胁，但由于其广泛分布（估计面积1,280,000平方公里）和在许多地区的常见性，灰胸竹鸡被认为安全免于灭绝。然而，其种群正在减少，在某些地区变得稀少，但下降尚未达到严重程度。","distribution":"分布于中国南部，从四川东部到福建和浙江南部，穿过贵州至广东北部。在日本被引入。","other":"遗传数据支持灰胸竹鸡与台湾竹鸡的分类分离。研究表明灰胸竹鸡种群在不同区域内存在显著的遗传分化，识别了两个不同的谱系。"},{"name":"台湾竹鸡","english_name":"Taiwan Bamboo Partridge","scientific_name":"Bambusicola sonorivox","overview":"台湾竹鸡（英文名：Taiwan Bamboo Partridge，学名：Bambusicola sonorivox），是鸡形目雉科竹鸡属的鸟类。主要分布于台湾，为台湾特有种。其头部石灰色，喉部深橙色，侧面和翅膀带有锈色斑点，常见于低地和山麓森林的浓密植被中。","appearance":"台湾竹鸡长约30至32厘米，头颈至背部呈现橄榄灰至灰绿色，冠部带锈色，下巴和喉咙为锈色，其余头部至上胸部呈灰色，翼覆羽有不明显的淡色斑点和边缘。下胸部至尾下覆羽为锈黄褐色，带有广泛的宽大栗色斑点和鳞片状纹。眼睛暗棕色，喙深灰色尖端黑色，腿灰色橄榄色。雌雄相似，雌鸟缺少雄鸟的单个腿刺。幼鸟比成鸟更暗淡。","call":"鸣唱为连续的颤音，声音逐渐升高，类似浴缸玩具的声音'rik-a-yeeee！'，雄鸟会发出响亮、共鸣的系列叫声。","habits":"栖息于密集灌木区、竹林和草地，一般活动高度在1000米以下，偶尔更高。在地上成对或成小群觅食，食物包括种子、嫩芽、叶子和一些无脊椎动物。","breeding":"在日本（引入种）从4月中旬开始繁殖，巢建于地面隐蔽处，幼鸟记录于9月。","identification":"与灰胸竹鸡的区别在于头部的锈色仅限于下巴和喉咙，下胸部至尾下覆羽颜色更深，具有更大范围的栗色斑点，上体颜色较深，翼覆羽上的白色斑点较少较小。","protection":"IUCN：LC（无危）。全球种群数量未量化，但在分布范围内普遍较为常见，种群似乎稳定，无明显下降迹象，无已知威胁，但可能存在对栖息地的压力。","distribution":"分布于台湾，属于东洋界。","other":"台湾竹鸡在台湾原住民中拥有几种象声词命名，如Seediq和Truku的tkurih，Thao的tikulhat，Bunun的tikulas，Paiwan的tjikulai，以及Amis的tikolac。"},{"name":"赤鸡鹑","english_name":"Red Spurfowl","scientific_name":"Galloperdix spadicea","overview":"赤鸡鹑（英文名：Red Spurfowl，学名：Galloperdix spadicea），是鸡形目雉科鸡鹑属的大型鸟类。原生于印度森林，体型略小于家鸡，体长35.5至38厘米，体重284至454克，以红褐色为主色调，具有独特的长尾巴。其分布区域广泛，从尼泊尔至印度南部。赤鸡鹑通常栖息于干燥和湿润的森林中，有时也会出现在村落附近的林地。","appearance":"赤鸡鹑体色红褐色，雄鸟上部有较淡的条纹，而雌鸟背部条纹更明显。头部和颈部颜色偏灰，下体呈栗色，带有黑色尖端的羽毛。两性均有一到两个红色的腿上的刺，雄鸟的刺更为显著。雄鸟有四根明显的刺，而雌鸟可能没有或仅有一到两个。面部皮肤裸露部分为砖红色（雄鸟）或粉红色（雌鸟），在繁殖季节颜色更加鲜艳。幼鸟的颜色比成年雌鸟更丰富，有时黑色体羽条纹更粗。不同亚种间在冠羽的黑色程度和整体的栗色深浅上有所差异。","call":"赤鸡鹑的雄鸟具有独特而有力的叫声，快速重复的“k-r-r-r-kwek, kr-kr-kwek, kr-kr-kwek”声音，常在清晨和傍晚时发出。当受到惊吓时，无论雄雌都会发出尖锐、咯咯的“kuk-kuk-kuk-kukaak”叫声。","habits":"赤鸡鹑生活在各种类型的森林中，偏好有良好灌木丛覆盖的丘陵地带，如落叶灌木丛、兰塔纳灌木丛或竹林。它们通常是留鸟，长期居住在同一区域。当受惊时，它们会迅速从一处掩护转移到另一处，只有在极度紧迫时才会飞行，通常是在上坡方向，且很少飞远。赤鸡鹑主要以种子、浆果、果实（尤其是无花果）和各种无脊椎动物为食。它们在植被中觅食，也会在清晨和傍晚沿着路径和田边觅食，通常以五只小鸟的小群体活动。","breeding":"繁殖季节一般在1月至6月，主要在雨季前。赤鸡鹑为一夫一妻制。巢穴是一个简单的浅坑，有时铺垫几片草叶和一些树叶，隐藏在茂密的植被中，如竹林中。通常产下2至5枚淡黄色的蛋，由雌鸟单独孵化，但双亲都会照顾雏鸟。","identification":"赤鸡鹑与同属其他物种的主要区别在于其栗色的下体，带有黑色尖端的羽毛。雌鸟与其他雌鸟Galloperdix的区别在于其胸部的栗色和黑色尖端的羽毛。与Francolinus pondericianus雌鸟的区别在于后者下体有明显的条纹，体型更短。","protection":"IUCN：LC（无危）。尽管分布广泛，但在某些地区的保护区，如古吉拉特邦的部分地区，近年来已发生局部灭绝事件。Aravali山脉内的caurina亚种被认为在其相对较小的范围内普遍稀少，但在至少一个保护区，如拉贾斯坦邦的Sariska虎保护区，仍有记录。相比之下，指名亚种在许多保护区，如卡纳塔克邦的Kanha虎保护区、Bori野生动物保护区和Pench虎保护区，数量相当多。","distribution":"赤鸡鹑主要分布在印度南部至尼泊尔的区域，常见于印度南部，特别是在丘陵地带和有良好植被覆盖的森林中。在印度北部，如古吉拉特邦的部分地区，虽然曾经常见，但近年来已有局部灭绝的报道。","other":"赤鸡鹑在不同地区的名称反映了其叫声，如Marathi中的Kokee-tree，可能是拟声词。"},{"name":"彩鸡鹑","english_name":"Painted Spurfowl","scientific_name":"Galloperdix lunulata","overview":"彩鸡鹑（英文名：Painted Spurfowl，学名：Galloperdix lunulata），是鸡形目雉科鸡鹑属的鸟类。体型略小于家鸡的雉科鸡鹑属鸟类。雄鸟色彩鲜艳，斑点密集，而雌鸟则以褐色为主。主要分布在印度半岛的岩石和灌木森林中，通常成对或小群体出现。","appearance":"雄性彩鸡鹑具有独特的白色密斑，绿色带黑的头部、胸部、肩羽、翅膀和尾巴，以及栗色的背部、翼覆羽、臀部和后侧。雌鸟则以红褐色面部、黄色喉咙和赭石棕色胸部为特征。眼睛呈棕色，喙和腿为灰至深灰色。雏鸟比成年雌鸟更暗淡，上体有黑色条纹，胸部有黑色斑点，其余下体部分有更多的黄褐色斑点。成年雄鸟的体重在255-285克之间，雌鸟在226-255克左右。","call":"彩鸡鹑发出响亮、快速重复的“chur, chur, chur”声，雄鸟被惊扰时还会发出类似鸡啼的“chugak”声。","habits":"彩鸡鹑偏好干燥的生境，如荆棘灌丛、竹林和布满巨石的山丘，但也会出现在靠近水源的地区。它们生活在海拔1000米以下的环境中，更倾向于在岩石间跳跃而非飞行，仅在极度受压时才会短暂飞行。它们主要以种子、块茎、浆果、小型陆生软体动物和昆虫为食，尤其是白蚁。","breeding":"繁殖期从1月持续到6月，主要在2月至5月初。巢穴通常建在岩石下或树根旁，由树叶和草铺垫。每窝产3-4枚浅黄色蛋，有时多达5枚。孵化期间，仅雌鸟参与，但双亲都会照顾雏鸟。","identification":"与红鸡鹑相比，彩鸡鹑的生境更为干燥，且雄鸟拥有明显的白色斑点。雌性彩鸡鹑的面部为红褐色，而红鸡鹑雌鸟面部颜色较浅。","protection":"IUCN：LC（无危）","distribution":"彩鸡鹑主要分布在印度半岛南部，从拉贾斯坦邦东部到西孟加拉邦，南至卡纳塔克邦和泰米尔纳德邦北部。也有报道指出在孟加拉国西部有分布，尼泊尔的旧记录存在错误。"},{"name":"斯里兰卡鸡鹑","english_name":"Sri Lanka Spurfowl","scientific_name":"Galloperdix bicalcarata","overview":"斯里兰卡鸡鹑（英文名：Sri Lanka Spurfowl，学名：Galloperdix bicalcarata），是鸡形目雉科鸡鹑属的鸟类。分布于斯里兰卡，特别是在南部至特林科马利周边的东海岸地区。其最显著的特征为雄鸟个体上覆盖着醒目的白色斑点和条纹，以及明亮的红色喙、面部皮肤和腿。","appearance":"雄性斯里兰卡鸡鹑拥有栗色的背部和翅膀，肩部和翼覆羽上有黑白相间的条纹，前部则以大胆的白色斑点点缀黑色基底。雌鸟则呈现均匀的红棕色，头部灰褐色（头顶最深），并具有白色的喉部。雌雄两性的裸露部位均为红色，但在雌鸟中颜色较淡。雄鸟有2-3个明显的刺，而雌鸟通常有一个，偶尔会有两个。雏鸟与成年鸟相似，但颜色更深，上面有一些赤褐色的斑点，年轻的雄鸟比成年雄鸟具有更少、更大的白色标记。","call":"斯里兰卡鸡鹑的雄鸟领地呼唤声为逐渐升高的三音节序列，每秒约4-5个音符，每个音符都是三音节的“yuhuhu”，最后的音符与第一个音符在同一音高上结束，邻近的雄鸟会回应。雌鸟则发出短暂上升的双音节或三音节系列，随后下降到起始音高，然后再次上升。","habits":"这种鸟类主要栖息在潮湿环境中的未受干扰的高大森林区域，最高可达2100米，偶尔也会出现在斯里兰卡东部和南部的干燥地区。它们通常是定居的，当受到惊吓时，会在掩护之间迅速躲闪，跑得非常快，只有在迫不得已的情况下才会飞行，而且飞行距离很短。它们以种子、浆果、白蚁和其他昆虫为食，尤其喜欢在开花季节吃Strobilanthes的种子。它们通常以高步态行走，成对或小家庭群体出现。","breeding":"繁殖季节主要在11月至3月的东北季风期间，但也可能在7月至9月进行繁殖。它们是一夫一妻制的。巢穴是一个由叶子和草衬里的浅坑，位于岩石或灌木下。通常产两个奶油色或温暖的象牙色蛋，但有时可达五个；雏鸟的绒毛呈深棕色。关于孵化和育雏的进一步信息尚缺。","identification":"雌性斯里兰卡鸡鹑与较大的雌性蓝喉原鸡可以通过其均匀的颜色和完全缺乏任何显著的条纹或斑点来区分。雄鸟则因独特的白色斑点和条纹而无可混淆。","protection":"IUCN：LC（无危）。虽然目前全球范围内并不受威胁，但考虑到森林正在消失，其数量可能正在减少。在锡纳哈拉森林保护区附近的库达瓦剩余森林、霍顿平原、乌达瓦拉维和瓦斯戈穆瓦国家公园中发现的数量较为可观。","distribution":"主要分布在斯里兰卡，特别是在南部和特林科马利周边的东海岸。在印度次大陆及中国的西南地区也有记录。","other":"斯里兰卡鸡鹑的分布范围有限，仅出现在斯里兰卡的特有鸟类区域，需要进一步的调查工作。"},{"name":"血雉","english_name":"Blood Pheasant","scientific_name":"Ithaginis cruentus","overview":"血雉（英文名：Blood Pheasant，学名：Ithaginis cruentus），是鸡形目雉科血雉属的鸟类。别名: 血鸡、松花鸡、绿鸡、柳鸡、松鸡子、红脚鸡，在中国西部和西南部广泛分布的留鸟，为国家二级保护动物。雄鸟的特征是大覆羽、尾下覆羽、尾上覆羽、脚、头侧、腊膜呈鲜艳的红色，因此得名血雉。在甘肃等地，因羽毛沾绿，又有‘绿鸡’、‘柳鸡’之称，由于栖息于松林和云杉林，食松（杉）叶和种子，亦被称为‘松鸡子’。血雉体型类似小型的鸡，长度约43厘米，拥有短尾和小而多彩的羽冠。","appearance":"血雉的雄鸟体型较粗壮，体长约44至48厘米，尾长16.5至18厘米，体重410至655克。全身覆盖着银灰色羽毛，带有广泛的淡色条纹，面部、尾部、胸部和尾羽上呈现醒目的猩红色，这是该物种的标志性特征。雌鸟颜色较为柔和，主要为温暖的棕色，面部橙色，有时带有微弱的红色调。幼鸟相比成鸟更为暗淡，雄鸟幼鸟在约三周大时，明显比雌鸟更灰。不同亚种之间在雄鸟的头部红色和黑色分布、下体颜色以及上翼覆羽的颜色上存在显著差异，雌鸟则变化较小，但在不同地区呈现出不同的色调。","call":"血雉的领地叫声独特，是一种刺耳的尖叫，通常被描述为‘glee-glee-keweee！-keweee！-keweee！’或类似的音节。此外，还有各种短促的咯咯声和尖锐的‘chic’声作为警报，以及在觅食时发出的高音‘sree’声，这是一种重复的、拉长的、高音的颤音，据说类似鸢的叫声，由两性共同发出，用于群体成员间的联系和重聚。","habits":"血雉主要栖息在海拔2000米以上至4500米的高山针叶林、混交林和杜鹃灌丛地带，靠近雪线。随着季节变化，它们会有垂直迁移行为，冬季时迁移到较低的山地。血雉倾向于群居，形成由5到30只组成的群体，偶尔多达60至70只。它们在一天中的大部分时间都在活动，从黎明到黄昏，中午会在岩石下或树荫处短暂休息。血雉主要以植物为食，已记录到的食物种类超过90种，包括各种树木的嫩叶、芽苞、花序、灌木和草本植物的嫩枝、浆果、种子，以及苔藓、地衣等，偶尔也会食用昆虫和小型无脊椎动物。","breeding":"血雉实行一雄一雌制，繁殖期在4月至7月，具体时间受地理位置和海拔影响。繁殖期间，血雉群体解散，由一雄一雌结成伴侣，雌鸟在灌木丛、岩石下或林中大树旁寻找隐蔽的凹地筑巢，巢由落叶、苔藓、松针、蒿草和细根构成。产卵间隔2至3天，每窝约3至9枚，卵呈浅黄色，带有浓赭色或浓褐色斑点。雌鸟独自孵卵，雄鸟则负责保护和警戒，直至雏鸟孵化。孵化期为28至29天。","identification":"血雉与其他雉科鸟类的区别在于其独特的颜色模式，尤其是雄鸟的银灰色带淡色条纹的身体和醒目的红色面部、尾部和胸部。雌鸟的温暖棕色和橙色面部也是识别特征。不同亚种在色彩和图案上有所不同，例如头颈部的红色程度和翅膀覆羽的颜色变化。","protection":"IUCN：LC（无危）","distribution":"血雉广泛分布于喜马拉雅山脉，包括尼泊尔、锡金、北印度、不丹、南中国和缅甸北部。在中国，分布于西藏、四川、云南、青海、甘肃和陕西等省区，包括万郎、太白山、祁连山和佛坪自然保护区。","other":"血雉是印度锡金邦的州鸟，尽管总体数量稳定，但在部分地区受到栖息地破坏、非法狩猎和人为干扰的威胁。"},{"name":"黑头角雉","english_name":"Western Tragopan","scientific_name":"Tragopan melanocephalus","overview":"黑头角雉（英文名：Western Tragopan，学名：Tragopan melanocephalus），是鸡形目雉科角雉属的鸟类。以深色带白点的外观著称，雄鸟具有独特的橙色胸斑和红色颈背，雌鸟为灰褐色。分布于喜马拉雅山脉，从巴基斯坦东北部至印度北部，主要栖息于未受干扰的山地森林。","appearance":"雄性黑头角雉体长约68.5-73厘米，尾长22-25厘米，体重1800-2150克；雌鸟约60厘米长，尾长19-20厘米，体重1250-1400克。雄鸟全身深色，遍布白色圆点，颈部有红色区域，面部有橙红色裸露皮肤，眼下方有蓝斑，喉咙裸露呈蓝色，脸颊蓝绿色，有可充气的蓝色角状突起和粉色喉垂。雌鸟灰褐色，上部有黑色斑点，下部有白色小点。虹膜棕色，喙黑色或角棕色，腿粉红色。幼鸟似雌鸟，但体型较大，腿较长，头部有黑色，颈部有红色。","call":"黑头角雉的叫声是短促的鼻音哀号，由两性发出，尤其是在早晨和傍晚，尤其是繁殖季节，重复7-15次，间隔约5秒。报警声类似，但更短更快，随着焦虑加剧而加速。","habits":"黑头角雉偏好生活在成熟的山地森林，通常为棕色橡树或冬青橡树林，冬季在约1735米的高度，夏季高达3600米。它们主要以植物为食，包括新叶、根、花、昆虫和蛴螬，既在地上觅食也在树上。它们较为害羞，经常单独或成对出现。","breeding":"黑头角雉为一夫一妻制，繁殖期在5-6月，雄鸟会在雌鸟面前展示其膨胀的肉质角和肉裙，每窝产卵2-6枚，颜色为暗红褐色，带有深褐色斑点。雌鸟负责孵化，雄鸟初期会巡视巢穴，之后离开。","identification":"雄性黑头角雉是最暗的角雉种类，红色仅限于颈部和上胸部。雌鸟与雄鸟在颜色上有明显差异，上部有黑色斑点，下部有白色小点，易于区分。","protection":"IUCN：VU（易危）","distribution":"黑头角雉分布于喜马拉雅山脉的西北部，从巴基斯坦北部（印多斯-科希斯坦区）至印度西北部，向东至北阿坎德邦（加尔瓦尔）；可能延伸至库马昂（东乌塔拉坎德邦）和相邻的西藏西南部。","other":"黑头角雉受到生境丧失和碎片化、过度放牧、采集柴火和非木材产品的影响，导致其数量减少。在多个保护区得到保护，如印度的大喜马拉雅国家公园和达尔安加提野生动物保护区，以及巴基斯坦的马奇拉国家公园和萨尔卡哈拉游戏保护区。"},{"name":"红胸角雉","english_name":"Satyr Tragopan","scientific_name":"Tragopan satyra","overview":"红胸角雉（英文名：Satyr Tragopan，学名：Tragopan satyra），是鸡形目雉科角雉属的鸟类。大型的雉科鸟类，分布于喜马拉雅山脉的印度、西藏、尼泊尔和不丹地区。栖息在潮湿的橡树林和杜鹃花丛中，夏季海拔可达4200米，冬季下降至约1800米。雄性红胸角雉以其深红色下部和独特的蓝色面部裸皮著称。","appearance":"雄性红胸角雉体长约70厘米，脸部黑色，配有深蓝色脸颊和下巴，背部及尾羽上部为灰褐色，全身散布白色斑点，尤其是红色胸部上的白色圆点。雌鸟则呈灰棕色至赤褐色，背部有细白条纹，翅膀红棕色，尾巴具红色倾向。雌雄个体均有蓝色眼周皮肤。成年雄鸟的体重约为1600至2100克，雌鸟则为1000至1200克。幼鸟颜色接近雌鸟，但体型更大，腿更长，头部有变化的黑色，身体上有红色和白色斑点。","call":"红胸角雉的叫声独特，雄鸟在清晨发出深沉的哀号声‘wah waah oo-ah oo-aaaaa’，声音渐强，最远可达300米。此外，受惊或交配时，两性会发出较轻的‘wak wak’声，春季或秋季可能重复发出‘wah’声。","habits":"红胸角雉栖息于海拔3000至4000米的山地森林，冬季可降至2000米。它们偏好陡峭山坡的森林，清晨和黄昏时会在林缘开阔地带活动觅食。性格隐秘，但相对大胆，行动谨慎。善于快速奔跑，也能短距离飞行。主要食物为植物根、嫩芽、叶、种子和球茎，偶尔捕食昆虫和小型爬行动物。","breeding":"繁殖期在5月至6月，雄鸟间为争夺配偶会发生争斗。巢建于海拔3000米左右的山地森林中的树上，结构简陋。每窝产卵2至6枚，卵色为棕黄色或浅黄色，带有红褐色斑点。人工饲养下，雌鸟的取食和繁殖行为与野生状态有所不同。","identification":"雄性红胸角雉的红色下部和胸部的白色圆点是其独特标志，与同类物种区分明显。雌性红胸角雉的灰色至赤褐色外观，以及尾部的红色倾向，帮助识别。与同属的其他物种相比，红胸角雉的背部、臀部和上翼覆羽呈棕色，而非鲜红色。","protection":"IUCN：LC（无危）","distribution":"红胸角雉主要分布于喜马拉雅山脉，包括印度北部的乌塔拉坎德邦至阿萨姆邦西部，以及尼泊尔、锡金、不丹等地。在中国大陆，其分布于西藏自治区的部分地区。","other":"红胸角雉的寿命在圈养条件下可达21年。尽管是角雉中受威胁程度较低的物种，但其仍面临栖息地丧失和狩猎的威胁。"},{"name":"灰腹角雉","english_name":"Blyth's Tragopan","scientific_name":"Tragopan blythii","overview":"灰腹角雉（英文名：Blyth's Tragopan，学名：Tragopan blythii），是鸡形目雉科角雉属的鸟类。别名: 寿鸡、灰斑角雉，体型较大，常见于喜马拉雅山脉东段的山地常绿阔叶林中。其显著特征包括雄鸟的黄色面部皮肤、锈红色头部和背部的白色小圆点，以及雌鸟的暗褐色外表和淡色斑点。食物来源多样，包括树叶、浆果、种子以及昆虫。","appearance":"雄性灰腹角雉身长可达65至70厘米，尾长约18至22厘米，体重约1930克；雌鸟略小，身长约58厘米，尾长约17厘米，体重介于1000至1500克。雄鸟具有鲜明的红胸和烟灰色腹部，面部裸露皮肤黄色。雌鸟全身呈深褐色，背部有长矛状淡色标记，眼周有淡色环。幼年雄鸟类似成年雌鸟，但颈部和胸部有红色，头部黑色，体型更大，腿更长。","call":"雄鸟的叫声响亮且具挑战性，发出类似‘gnau,gnau’的声音。在炫耀时，会发出重复的‘gock…gock…gock’叫声，类似于双角犀鸟的叫声。","habits":"灰腹角雉栖息于海拔2000至3000米的山地常绿阔叶林中，冬季会下降至1500至2000米的低山地带。它们偏好林下植被茂密的环境，如橡树林和杜鹃花林。主要以植物嫩芽、种子、浆果为食，也会摄取昆虫和小型两栖动物。","breeding":"繁殖期为每年的4月至6月，营巢于树上，巢由树枝和草叶构成，较为粗糙。每窝产卵2至5枚，多为3至4枚，卵呈浅皮黄色或灰黄色，带有少量褐色斑点。","identification":"雄性灰腹角雉通过其独特的红胸和烟灰色腹部与同属其他物种区分开来。雌鸟与同属其他雌鸟相比，颜色更深，背部有独特的长矛状淡色标记。molesworthi亚种比指名亚种体型更小，红胸仅限于上部，上体颜色更暗。","protection":"IUCN：VU（易危）。在中国《国家重点保护野生动物名录》中被列为I级保护动物，在《中国濒危动物红皮书•鸟类》中被列为稀有种。","distribution":"灰腹角雉分布于喜马拉雅山脉东段，包括不丹、印度东北部、缅甸北部至中国西藏东南部以及中国境内的相关地区。在印度东北部的那加兰邦、阿萨姆邦以及缅甸的蓝山国家公园等地均有记录。","other":"灰腹角雉有两个公认的亚种，molesworthi亚种的特征和分布区域与指名亚种有所不同。"},{"name":"红腹角雉","english_name":"Temminck's Tragopan","scientific_name":"Tragopan temminckii","overview":"红腹角雉（英文名：Temminck's Tragopan，学名：Tragopan temminckii），是鸡形目雉科角雉属的鸟类。又称: 寿鸡，中等体型，体长约64厘米，以其独特的外观和分布于喜马拉雅山脉东部至中国中南部的原始森林中著称。雄鸟拥有醒目的火焰橙色羽毛，点缀以白色斑点，面部为黑色，具有蓝紫色的可膨胀面部皮肤，在求偶期间展示出迷人的红蓝相间的翻领状装饰。雌鸟为暗褐色，覆盖以白色斑点。红腹角雉在多个地区有分布，包括远东北印度、中国中部、北部缅甸至西北越南，是中国国家二级保护动物。","appearance":"雄性红腹角雉体长约64厘米，尾长18.5-23厘米，体重980-1600克，全身明亮的火焰橙色，遍布白色斑点，脸部黑色，具有电蓝色面部皮肤，求偶时膨胀成肝形的红蓝相间翻领。雌鸟体长约58厘米，尾长16-17.5厘米，体重907-1100克，整体暗褐色，覆盖以白色斑点和条纹。眼睛棕色，喙黑色（雄鸟尖端粉红色），腿粉色。幼鸟外观与雌鸟相似，第一年雄鸟颜色类似成年雌鸟，但带有黑色和红色，体型更大，腿更长。","call":"在繁殖季节，雄性红腹角雉会发出一系列哀婉的呼叫声，声音延长且逐渐增强，描述为'woh...woah...woah...waah...waah...waah...waah...griiik'。","habits":"红腹角雉栖息于海拔1000-3500米的密集常绿或混合森林中，偏好有长流水的沟谷、山涧及潮湿悬崖下的环境。主要食物包括各种植物的嫩芽、叶子、浆果和种子，偶尔也会食用昆虫。春季和夏季偏爱鳞毛蕨、宝兴冷蕨、报春花等的嫩叶和嫩芽；秋季摄食玉竹、花楸、悬钩子等的叶、茎和果实，以及少量动物性食物；冬季则以扒开雪被，啄食草本植物为主。","breeding":"每年三月进入繁殖期，雄鸟在清晨和傍晚发出响亮的占区叫声吸引雌鸟。雄鸟求偶时会展开肉裙和角，发出低沉的呼唤，随后冲向雌鸟进行交配。巢建于树上，每窝产卵3-5枚，由雌鸟单独孵化，孵化期28-30天。雏鸟出生时覆有绒羽，一个月后换羽接近成鸟。","identification":"红腹角雉雄鸟特征明显，全身红色，珍珠灰色斑点，与其他角雉属物种易于区分。雌鸟与同类物种中的雌鸟相似，但可通过其独特的灰褐色斑点和白色斑块识别。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉东部至中国中南部，包括远东北印度、中国中部、北部缅甸至西北越南。","other":"红腹角雉在多个地区被视为罕见物种，如在中国东南西藏。"},{"name":"黄腹角雉","english_name":"Cabot's Tragopan","scientific_name":"Tragopan caboti","overview":"黄腹角雉（英文名：Cabot's Tragopan，学名：Tragopan caboti），是鸡形目雉科角雉属的鸟类。别名: 角鸡、吐绶鸟，是中国特有种，主要分布在东南部的山林中，包括福建、江西、浙江、广东、广西和湖南。这种美丽的雉类以其奶油色、类似鹧鸪的外观著称，是其分布范围内唯一的角雉，也是世界上唯一具有淡色腹部的角雉。","appearance":"雄性黄腹角雉身长约为61厘米，体重约1400克，下体呈淡黄色，上体斑点繁复，背景为黑色和栗色，头部具有黑色和栗色，面部皮肤橙色，包括蓝色和红色可充气的‘耳垂’和‘角’状肉垂。雌鸟较短小，身长约50厘米，体重约900克，全身暗灰褐色，脸部和腹部略淡，翅膀和腹部有浅色条纹。第一年的雄鸟与成年雌鸟相似，但头部有黑色和红色，下体有淡黄色斑点。幼鸟外观与成年雌鸟非常接近。","call":"雄鸟在繁殖季节会发出婴儿般的哭泣声“wa-r”，随后是一系列3到5个响亮的‘gua’音符。此外，雄鸟也会在繁殖季节发出快速的翼振声。","habits":"黄腹角雉栖息于海拔600至2000米的亚热带针阔混交林内，偏好Fagaceae、Lauraceae、Theaceae、Aquifoliaceae、Symplocaceae、Rosaceae和Ericaceae等树种丰富的地区。它们在春季活跃，以植物的根、茎、叶、花、果为食，特别依赖于Daphniphyllum macropodum的果实和叶子。","breeding":"繁殖期为3月至6月，雄鸟在清晨通过鸣叫宣示领地，进行复杂的求偶炫耀。巢建于树上，通常在树干侧枝的基部，有时使用其他鸟类的旧巢或松鼠窝。雌鸟于4月初开始产卵，一般每窝3至6枚，由雌鸟单独孵化约28天。雏鸟孵化后随母鸟下树觅食，形成家庭群过冬。","identification":"雄性黄腹角雉是唯一具有淡黄色腹部的角雉，与红腹角雉相比，下体更淡，上体斑点更为精细。雌鸟与红腹角雉的雌鸟相比，下体有较小的白色椭圆斑点，上体有更明显的箭头状标记，眼眶皮肤为橙色而非蓝色。","protection":"IUCN：VU（易危）；CITES：1；中国国家重点保护野生动物名录：一级。黄腹角雉面临栖息地丧失和非法猎杀的威胁，保护工作正在进行中。","distribution":"主要分布在中国东南部的山林中，包括福建、江西、浙江、广东、广西和湖南，栖息于海拔600至2000米的亚热带针阔混交林内。","other":"黄腹角雉的栖息环境狭窄，种群密度低，浙江乌岩岭是黄腹角雉的唯一保种基地和原产地人工繁殖基地。"},{"name":"勺鸡","english_name":"Koklass Pheasant","scientific_name":"Pucrasia macrolopha","overview":"勺鸡（英文名：Koklass Pheasant，学名：Pucrasia macrolopha），是鸡形目雉科勺鸡属的鸟类。又名: 柳叶鸡、角鸡，大型雉类，雄鸟头部为金属暗绿色，具有棕褐色长形冠羽，颈部两侧有明显白色块斑；雌鸟体羽以棕褐色为主。广泛分布于中国辽宁省以南至西藏东南部的中部地区，栖息于海拔1500-4000米的高山针阔叶混交林中。","appearance":"雄鸟体长约58-64厘米，尾长22-28厘米，体重1135-1415克；雌鸟体长约52.5-56厘米，尾长17-19.5厘米，体重930-1135克。雄鸟身体大部分银灰色，胸、腹部酒红色，颈侧有白斑；头部墨绿色，顶部有一长羽冠。雌鸟通体布满褐色纵纹，胸部、腹部和颈侧的羽色较淡，有较短的羽冠、黄褐色的眉纹及带黑边的白色喉部。幼鸟和雌鸟相似。","call":"有节奏的领地叫声，通常在黎明时分从树上的栖息处发出，声音为4-5个粗糙的嘶哑音符'krra-krra..krakrra-krra'，有时会被一个短暂的、单一的、粗哑的'kok'声所预示，强度较低。还有一种爆炸性的'barked karrh-kar'声，以及在受惊时发出的尖锐重复的'chick'或'qui-quik'声。","habits":"栖息于海拔1000-4000米的松林及针、阔叶混交林中，偏好有茂密竹子和灌木的环境。冬季会向低海拔迁移约1000米。以植物的根、果实及种子为主要食物，夏季大量捕食昆虫和蠕虫。一般成对或小家庭群活动，主要在清晨和傍晚觅食。","breeding":"繁殖期在4月底至7月初，一雄一雌制。在地面以树叶、杂草筑巢，每窝产卵5-7枚，乳黄色，带有不规则浅红或茶褐色的粗斑。雌鸟独自孵卵，孵化期21-22天。雏鸟出壳后能独立活动。","identification":"与西部角鸡相比，勺鸡颜色较为朴素，展示中等程度的性别二型性。雄鸟有独特的黑色头部，栗色胸部和明显的白色颈侧斑块。雌鸟上部覆盖着淡棕色羽毛。","protection":"IUCN：LC（无危）。勺鸡是中国国家二级保护动物。","distribution":"分布于喜马拉雅山脉至中国中南部，从阿富汗到中国东北部和东部。在中国，从辽宁省以南至西藏东南部的中部地区均有分布。","other":"尽管分布区范围较大，但因栖息地破坏和人类活动，每地数量不多。"},{"name":"棕尾虹雉","english_name":"Himalayan Monal","scientific_name":"Lophophorus impejanus","overview":"棕尾虹雉（英文名：Himalayan Monal，学名：Lophophorus impejanus），是鸡形目雉科虹雉属的鸟类。又名: 九色鸟，色彩鲜艳夺目，尤以雄鸟为甚，拥有绿色金属光泽的冠羽、铜色背部与颈部羽毛、醒目的白色臀部，以及均匀的棕红色尾羽。雌鸟颜色较为朴素，有独特的白色喉部斑纹和白色尾条。分布于喜马拉雅山脉的森林和灌木地带，海拔介于2100至4500米之间，是中国西藏南部、尼泊尔等地的特有种，也是尼泊尔的国鸟。","appearance":"雄性棕尾虹雉长约70厘米，体重可达2380克，雌鸟略小，约63厘米，重约2150克。雄鸟拥有绚丽多彩的羽毛，包括金属绿的冠羽、红色颈羽、绿色肩羽、蓝色背部、橙色尾羽和黑色下部。雌鸟则以淡蓝色眼圈、白色喉部和条纹状棕色体羽为特色。幼鸟和雌鸟相似，但体型较小，标记不那么鲜明。","call":"在繁殖季节和早些时候，雄鸟会发出类似白腰杓鹬的‘kur-lieu’或‘kleeh-wick’的叫声，每次哨音之间伴随单一高音符。两性在警报时也会发出双音节的响亮哨声。","habits":"栖息于开阔的松树林或混合林，通常位于陡峭山谷中的杜鹃花和竹子下层。活动于海拔2100至4500米间，夏季可能上升至雪线以上，冬季下降至较低高度。在不同季节展现出显著的垂直迁移模式。以种子、根茎、嫩芽、浆果、昆虫及其幼虫为食，会挖掘至25厘米深寻找食物。","breeding":"黎明鸣叫全年都有，但在1月至6月更为规律。筑巢于植被较稀疏的森林地面，通常靠近岩石、灌木或树木遮蔽处。每窝产卵3至8枚，孵化期约为28天，卵色为淡黄或皮黄色，带有红褐色和紫色斑点。","identification":"雄鸟与其他虹雉区别明显，尤其是独特的金属丝状冠羽和全棕红色尾羽。雌鸟与雄鸟的色彩差异显著，通过白喉斑和条纹状体羽辨识。","protection":"IUCN：LC（无危）。在中国属于国家一级保护动物，面临栖息地破坏和过度捕猎的威胁。","distribution":"分布于喜马拉雅山脉，从阿富汗东部至巴基斯坦、印度东北部、尼泊尔、中国西藏南部、云南西北部，以及缅甸东北部。","other":"棕尾虹雉是尼泊尔的国家鸟，亦是印度Uttarakhand邦的州鸟。"},{"name":"白尾梢虹雉","english_name":"Sclater's Monal","scientific_name":"Lophophorus sclateri","overview":"白尾梢虹雉（英文名：Sclater's Monal，学名：Lophophorus sclateri），是鸡形目雉科虹雉属的鸟类。别名: 雪鹅，大型林栖雉类，因雄鸟尾羽具白色端斑且尾基多呈纯白而俗名“白尾虹雉”。其分布以海拔2500–4200 米的东喜马拉雅—横断山系针叶林与高山杜鹃灌丛为核心，见于印度东北部、藏东南、缅北及滇北。雄鸟通体金属辉亮、头具短冠、眼周裸皮呈亮蓝色，远看似“小型秃鹫”；雌鸟通体褐黑并具细密虫蠹纹，尾端白色。该种被当地部分社区视为“神鸟”而禁猎，但因生境片段化及潜在捕猎压力，全球种群估计不足一万只。","appearance":"雄鸟体长63–68厘米，体重2267–2948 g；雌鸟2126–2267 g。雄鸟头顶具短而向前卷曲的丝绒黑冠；颈背铜绿，上背铜红并带金属绿辉；自中背至尾上覆羽及尾基纯白，中央尾羽末端具栗色端斑（orientalis 亚种白色带仅10–20 mm，指名亚种20–28 mm；arunachalensis 亚种雄鸟尾全白）。肩、翼及胸腹呈金属绿蓝，翼覆羽泛铜紫；下腹黑色。眼周裸皮亮蓝色，虹膜褐，喙淡角质色，脚灰绿。雌鸟无冠，通体暗褐并具黑褐色虫蠹纹；喉部具大块白斑；尾羽黑褐并具细白横斑，末端白色；眼周具深青灰裸皮。幼雄似雌鸟，但背较暗、腰更白，尾羽带肉桂色；第一年雄鸟体型大于雌鸟，前颈散生黑斑，上体出现金属绿羽。","call":"领域叫声为拖长而哀婉的“waaaaaaahee”，音调末尾上扬，持续约0.8 s，每3 s重复一次，远听似鸮与杓鹬混合声。惊飞时发出尖锐“wah-waheeee！”或急促“ki-ki-ki…kiyak, kiyak, kiyuk kvuk kvuk”；降落后雄鸟可发出双音节“koo(n)iak, kooo(n)iak, kooooo(n)iak”连串叫。","habits":"栖息于东喜马拉雅—横断山区海拔2500–4200 米的冷杉、云杉及铁杉原始林，林下具茂密杜鹃、箭竹或高山灌丛；缅甸记录多限于林线以上>2600 m。冬季在印度东北可下移至约3000 m，当地村民称有季节性垂直迁移。晨昏在林窗、杜鹃丛或巨石间掘土觅食，主食植物地下部分：Polygonum 种子、天南星属(Arisaema)块茎、蓟属等坚硬头状花序；胃检含小碎石、根、块茎、种子及树皮叶屑，雌鸟嗉囊见委陵菜属、碎米荠属与白珠树属叶片。天敌信息缺乏，成鸟惊飞时迅速掠过林隙，落地后多停于巨岩或倒木。","breeding":"繁殖资料稀少。印度东北通常可见2–3只小群，群内仅1只成年雄鸟，配偶制度未明。云南高黎贡山同一岩壁凹处被连续使用2–3年；巢位于距地3.8 m的巨石平台，3月下旬产卵，5月初雏鸟出壳，窝卵数2–3枚（文献记最多5枚），卵乳白具细密红棕点，平均重85.8克，孵化期28天。5月中旬在西藏采集的个体已处于繁殖状态。","identification":"与棕尾虹雉同域但海拔多低于后者。雄鸟易识：背至尾基纯白，冠短而卷曲；雌鸟无冠，下体虫蠹纹而非纵纹，喉具大白斑，尾具白端与细横斑，与棕尾虹雉雌鸟的上体粗纵纹及白喉缺失明显不同。orientalis 亚种雄鸟白色尾带最窄，雌鸟腰臀烟灰、横斑不显；arunachalensis 雄鸟尾全白，雌鸟体色更深。","protection":"IUCN: LC（无危）；CITES 附录 I。因分布偏远，资料陈旧，Mace-Lande 评估为“濒危”。全球种群估计<10,000只，中国境内或稳定，其余地区疑呈下降趋势。云南高黎贡山自然保护区及泸水保护区有局域常见记录。主要潜在威胁为生境退化与捕猎，但在印东北部分社区被奉作神鸟而禁猎。尚无专项保护行动，需开展调查、社区教育与保护区效能提升。IUCN: LC（无危）；CITES 附录 I。因分布偏远，资料陈旧，Mace-Lande 评估为“濒危”。全球种群估计<10,000只，中国境内或稳定，其余地区疑呈下降趋势。云南高黎贡山自然保护区及泸水保护区有局域常见记录。主要潜在威胁为生境退化与捕猎，但在印东北部分社区被奉作神鸟而禁猎。尚无专项保护行动，需开展调查、社区教育与保护区效能提升。","distribution":"繁殖区：印度东北、藏东南、缅北及滇北（怒江、高黎贡山）。非繁殖季节短距离下移，仍在同一山系内。中国大陆集中见于藏东南及滇西北海拔3000–4200 米的原始针叶林与杜鹃灌丛。","other":"新近描述的亚种 arunachalensis 与指名亚种间存在渐变迹象，其独立地位仍需更多分子与形态研究。本种与 impejanus 亲缘最近，二者在喜马拉雅东坡形成海拔梯度替代。"},{"name":"绿尾虹雉","english_name":"Chinese Monal","scientific_name":"Lophophorus lhuysii","overview":"绿尾虹雉（英文名：Chinese Monal，学名：Lophophorus lhuysii），是鸡形目雉科虹雉属的鸟类。别名: 贝母鸡、鹰鸡、火炭鸡、羊鸡，是中国特有种，主要分布在四川、甘肃南部及云南西北部的高海拔地区。雄鸟拥有华丽的羽毛，包括紫色垂下的羽冠、金属绿色头部、蓝色眼周裸皮、红金色披肩、蓝绿色羽毛和黑色下部。雌鸟则为暗褐色，喉部白色。","appearance":"雄性绿尾虹雉体型庞大，长约76-80厘米，重约3.18千克，拥有显著的垂挂紫色羽冠、金属绿色头部、蓝绿色背部和尾部、红金色颈项、黑色腹部。雌鸟体长约72-75厘米，重3178克，体羽呈条纹状的褐色，眼周有淡色皮肤，喉部白色。雌雄皆有灰角色的喙，明亮的蓝色眼周皮肤，棕色虹膜，灰角色腿，雄鸟有单个短刺，雌鸟无。","call":"雄性绿尾虹雉在春季和夏季早晨会发出类似门铰链的哨音，重复‘guo-guo-guo’音调，随后变为更哀伤的音色。冬季时会发出沉闷的‘a...awu, a...awu’声。起飞时会发出一系列急促的‘gee’音。","habits":"绿尾虹雉栖息于3300-4500米的亚高山和高山草甸带，偏好有裸岩露头的环境，冬季不下迁，保持在相同高度。它们以植物的根、球茎、叶子和花朵为食，包括贝母的球茎。活动于2-8个小群体中，特别是在冬季。","breeding":"繁殖季节为3月至6月，筑巢于海拔3800-4000米处，通常在峭壁旁。每次产卵3-5枚，孵化期约为28天，仅由雌鸟负责。幼鸟出生后，由双亲共同抚养。","identification":"绿尾虹雉比其他虹雉体型更大，雄鸟有下垂的羽冠，雌鸟有后冠上的独特羽毛簇和喉咙上的白色。雄鸟的尾羽主要为蓝绿色，而雌鸟尾羽上有较窄的赤褐色和黑色条纹。","protection":"IUCN：VU（易危）","distribution":"绿尾虹雉主要分布在中国中部的四川、甘肃南部和云南西北部，具体在岷山、卧龙和白水江保护区等地。在海拔2800-4900米的高山草甸和灌丛地带活动。","other":"绿尾虹雉受到栖息地退化和非法狩猎的威胁，尤其是因人类的放牧和药材采集活动导致的栖息地破坏，以及作为食物来源的捕猎。"},{"name":"红原鸡","english_name":"Red Junglefowl","scientific_name":"Gallus gallus","overview":"红原鸡（英文名：Red Junglefowl，学名：Gallus gallus），是鸡形目雉科原鸡属的鸟类。原生于南亚和东南亚，广泛分布在热带和亚热带地区，包括印度、东南亚诸国。是现代家鸡（Gallus domesticus）的祖先，拥有橙色、棕色、红色、金色、灰色、白色、橄榄色甚至金属绿色的羽毛组合，雄鸟个体尾羽可长达28厘米，整体长度可达70厘米。红原鸡适应性强，能在多种环境中生存，包括森林、农田、灌丛、草坡、荒地和防护林带。","appearance":"雄性红原鸡身长65至78厘米，体重672至1450克；雌鸟则为41至46厘米，体重485至1050克。雄鸟拥有鲜艳的装饰羽毛，尾羽长而呈拱形，背部有金色的羽毛。雌鸟的羽毛颜色较为隐秘，适合伪装。雄鸟有单个长刺，雌鸟通常没有或仅有非常短的刺。在非繁殖季节，雄鸟会脱去金色的羽毛，变得暗淡，头部和颈部的羽毛变为暗黑色，短而钝，尾羽缩短，但翅膀上的锈色仍保留。","call":"雄性红原鸡在繁殖季节发出著名的“公鸡打鸣”声，叫声比家鸡更短促，尾音突然终止。这种叫声既吸引潜在的配偶，也向其他雄鸟宣告领地。红原鸡的叫声复杂，还有针对空中和地面掠食者的独特报警声。","habits":"红原鸡偏爱被干扰的生境边缘，包括自然和人为创造的环境。它们在森林、次生林、竹林、农田、灌木丛和草坡中活动，尤其是在靠近人类居住地或再生森林区域。红原鸡在早晨和傍晚访问开阔地带觅食，干旱季节每日前往水源。它们通常以小群体形式活动，由一只或多只雄鸟和几只雌鸟组成。红原鸡的食谱多样，包括种子、水果、昆虫和其他小型无脊椎动物。","breeding":"红原鸡的繁殖期多在旱季，如印度、尼泊尔、泰国等地的冬季或春季，但在马来西亚的油棕榈种植园全年都可繁殖。雌鸟每日产一枚卵，孵化期约为21天。雏鸟在4至5周后离巢，12周后被母鸡驱逐，此时它们开始独立或加入其他群体。性成熟年龄为5个月，雌鸟达到成熟的时间略晚于雄鸟。雄鸟通过展示食物（tidbitting）吸引雌鸟。","identification":"红原鸡与其他原鸡属物种的区别在于雄鸟的头冠形状和缺乏明显的条纹。雌鸟与灰原鸡和蓝喉原鸡的不同在于下体缺乏醒目的图案，与蓝喉原鸡和绿原鸡的不同在于飞羽上没有明显的图案。不同亚种之间在繁殖季节雄鸟的羽毛颜色、长度和形状上有差异。","protection":"IUCN：LC（无危）","distribution":"红原鸡的分布范围从印度西部的印度、尼泊尔和孟加拉国，向东穿过中国南部，到达中南半岛；向南/东南进入马来西亚、新加坡、菲律宾和印度尼西亚。在马来西亚，红原鸡广泛存在且数量众多，尽管受到持续的猎捕压力。在中国大陆，红原鸡在保护区内的数量稳定，但在保护区外因栖息地退化和过度狩猎而减少。","other":"红原鸡在大约8000年前被人类驯化成为家鸡，是人类的重要食物来源。然而，野生红原鸡面临来自与家养或野鸡杂交的遗传侵蚀威胁，导致‘野生型’基因组的消失。"},{"name":"灰原鸡","english_name":"Grey Junglefowl","scientific_name":"Gallus sonneratii","appearance":"雄性灰原鸡体长70-80厘米，体重790-1136克，整体呈现灰色基调，翅膀有金色斑点，颈部具独特白色斑点，尾羽长且光亮黑色，腿爪粉红色，冠和肉垂较红原鸡小。雌鸟体长38厘米，体重705-790克，外表朴素，无长尾、冠和肉垂，下体有白色条纹，腿黄色至红色。非繁殖期雄鸟失去颈部斑点和延长的尾羽，头部和颈部羽毛变短且暗黑，冠缩小且色浅。雌鸟胸部有白色条纹，飞羽无条纹。嘴黄褐色，眼黄色至橙褐色，腿黄色至红色，雄鸟有单长脚刺，雌鸟通常无脚刺。幼鸟暗色，雄鸟很快展现成年特征，尾巴比雌鸟黑。","call":"灰原鸡雄鸟在繁殖季发出响亮、断续且略带沙哑的“kuk ka kuruk ka”或“kuck kaya kaya kuck”叫声，重复频率可达每分钟五次，有时伴有拍翼声。雄鸟间争斗时发出单调的“klick...kluck kluck”。雌鸟仅发警报叫声。","habits":"灰原鸡栖息于落叶和常绿森林，偏好竹林和灌木丛，活动高度一般不超过1500米，但在东西高止山脉可达1700米，尼尔吉里斯山甚至到2400米。它们也频繁出没于耕作地、废弃的橡胶、咖啡和茶园，尤其是在长满Lantana的地方。在Melghat老虎保护区，它们出现在多种树种混合的森林中。灰原鸡在树上筑巢，最高可达18米。饮食多样，包括竹子种子、草本作物、根茎、无花果、浆果、昆虫、小型爬行动物，以及在牛、象粪便中觅食。群体活动，有时可达5-6只，季节性食物丰富时数量更多。","breeding":"繁殖期可能全年发生，但多数记录显示2月至3月为主。在西尼尔吉里斯山，可能10月至12月繁殖；Travancore地区，3月至7月，有时延续至8月。在热带干燥常绿森林和桉树林中筑巢。繁殖模式可能包括一夫一妻制和一夫多妻制。巢建于灌木旁的小凹处，曾有记录显示在树洞中筑巢。每窝通常4-5枚蛋，白色至粉红或米色，偶尔无斑点，由雌鸟单独孵化20-21天。","identification":"雄性灰原鸡较同属其他物种更灰，冠状突起和领羽较小，颈部有独特的斑纹，与红原鸡相比，体色更暗，更灰色，颈部有明显的白色斑点，尾部基部无白色斑块，腿部更亮丽，肩羽不明显延长。雌鸟通过胸部的白色条纹和无条纹的飞羽组合来区分于其他同属物种的雌鸟。","protection":"IUCN：LC（无危）。CITES II。灰原鸡面临森林转化为农业用地、过度放牧、焚烧灌木和非法狩猎的威胁，尤其在Kerala地区，保护状况令人担忧。在多个保护区有记录，包括Bori、Mount Abu、Anamalais野生动物保护区、Vansda、Silent Valley、Eravikulam国家公园、Kalakad-Mundandurai老虎保护区、Pench和Melghat老虎保护区。","distribution":"灰原鸡分布于印度半岛，自古吉拉特邦、拉贾斯坦邦南部、中央邦、戈达瓦里河口东岸的安得拉邦东部。主要栖息地包括落叶和常绿森林，以及耕作地和废弃的种植园。","other":"灰原鸡的基因对家鸡的黄色色素有贡献，它们的羽毛自1862年起在英格兰被驯养，自1978年起用于制造钓鱼诱饵。它们有时会与红原鸡杂交，尤其是在野外接触地带。"},{"name":"蓝喉原鸡","english_name":"Sri Lanka Junglefowl","scientific_name":"Gallus lafayettii","overview":"蓝喉原鸡（英文名：Sri Lanka Junglefowl，学名：Gallus lafayettii），是鸡形目雉科原鸡属的鸟类。又名: 黑尾原鸡、斯里兰卡原鸡、锡兰原鸡或锡兰野鸡，是斯里兰卡特有种，被尊为国鸟。雄鸟具橙红羽色，暗纹点缀，尾羽黑亮，红冠黄尖，雌鸟灰褐，翼部条纹明显，白纹点缀下颈胸。体型介于66-72厘米（雄）与35厘米（雌）之间。","appearance":"雄鸟长66-72厘米，体重790-1140克，羽毛呈橙红色，翼尾深紫至黑色，头部至脊椎底金色羽毛，红面无羽，具红色鸡冠中央黄斑。雌鸟约35厘米，重510-625克，羽毛深褐色，下颈胸有白色斑点，翅膀条纹显著。雄鸟较雌鸟大，具发达的鸡冠和垂肉，雌鸟较小，羽毛色彩低调。","call":"领地呼唤声为短促、强调的三音节嘶哑啼鸣，首音较高，间歇约0.5秒，后两音间隔重复，伴有拍翅产生的响亮拍击声。雌鸟发出尖锐金属音，双方皆能发出刺耳的‘clock..clock’声。","habits":"栖息于沿海灌丛至山地森林，海拔从海平面至2300米，偏好干燥森林，亦见于种植园和灌木丛林。晨昏沿林间空旷路径觅食，食谱广泛，包括草籽、果实、昆虫等，常以小群活动。","breeding":"繁殖期全年可见，尤其2月至5月最常见。筑巢于地面灌木、树根或离地高达4米的树洞，利用废弃松鼠巢或旧乌鸦巢。每窝产2-4枚淡奶油色蛋，具浅棕紫斑点，孵化期20-21天，雏鸟类似绿原鸡，由雌鸟独自孵化和养育。","identification":"雄鸟相比红原鸡，鸡冠和垂肉发育较差，具红腿黄眼。雌鸟白纹下腹与条纹翅膀独特。与家鸡区别在于尾根无白，雄鸟鸡冠有黄斑，雌鸟翅膀具条纹。","protection":"IUCN：LC（无危）。蓝喉原鸡分布范围有限（约55,600平方公里），适应人类干扰和环境退化，广泛分布于斯里兰卡，尤其东部干燥地区数量较多。","distribution":"繁殖与非繁殖区域皆位于斯里兰卡，包括基图尔格勒、雅拉国家公园及辛哈拉加热带雨林等地。","other":"蓝喉原鸡与原鸡亲缘关系密切，雏鸟主要以活食为食，如昆虫和等足目动物，对细菌性疾病敏感，难以人工饲养。"},{"name":"绿原鸡","english_name":"Green Junglefowl","scientific_name":"Gallus varius","overview":"绿原鸡（英文名：Green Junglefowl，学名：Gallus varius），是鸡形目雉科原鸡属的鸟类。亦称爪哇原鸡或绿领原鸡。岛屿原鸡，分布仅限于东南亚印度尼西亚的爪哇、巴厘和龙目岛至Alor一带的小巽他群岛。绿原鸡拥有独特的美丽外观，但在亲缘关系上与家鸡相比，与红原鸡、灰原鸡、蓝喉原鸡更为疏远。","appearance":"雄性绿原鸡体长65-75厘米，体重672-1450克，其外观如同被不同颜色的鳞片覆盖，头部、颈部和背部呈现黑色，背部、臀部、尾巴和翅膀光泽蓝黑，背部有黄边的毛发和橙红色的翼覆羽。雌性绿原鸡体长40-46厘米，体重485-1050克，呈暗褐色，有黑色尾巴和淡粉色的脸部，与雌性红原鸡相比，整体色调更温暖，带有更多橙色。雄鸟的独特特征还包括蓝绿色基底、紫色到红色边缘的多彩鸡冠和大型红白蓝渐变的喉垂。","call":"绿原鸡的鸣叫声独特，领土叫声为短暂的粗哑三音节啼鸣，'crrrro-wow-whorr!'。雄鸟还发出缓慢的咯咯声'wok-wok-wok...'，而在警报时会发出急促的'chop..chop..chop...'声，雌鸟则发出快速的'kok..kok..kok...'叫声。","habits":"绿原鸡栖息于沿海地带、低洼山谷及内陆森林边缘，偶尔进入密集林区。它们在稻田、种植园周围、灌木丛和草原活动，高度从海平面至3000米，但通常在较低海拔活动，例如爪哇西部和巴厘岛的1500米，小巽他群岛的2400米。它们以昆虫和杂草种子为食，经常光顾谷物田，有时在清晨和傍晚出现在开阔地带。绿原鸡通常单独或以5-6只的小群体出现，最多可达12只。","breeding":"繁殖季节长且变化，一般认为在6月至11月间，筑巢于密林中的地面凹陷处，可能位于树蕨顶部。有关窝卵数的数据不可靠，平均约3-4枚蛋较为可信。孵化期为21天，雏鸟上部巧克力棕色，下部奶油白色，颈部和胸部为棕色。","identification":"绿原鸡的辨识要点在于其独特的色彩模式，尤其是雄鸟的多彩鸡冠和喉垂，以及雌鸟的暗褐色羽毛和淡粉色脸部。与红原鸡和其他原鸡种类相比，绿原鸡的上体呈鳞片状图案，翅膀有条纹，胸部缺乏明显的花纹。","protection":"IUCN：LC（无危）。绿原鸡在多个保护区广泛分布，但其野生种群因人工饲养和繁殖导致遗传多样性下降。","distribution":"绿原鸡分布于爪哇、巴厘岛和龙目岛至Alor，即小巽他群岛西部至中东部。此外，也被引入到Cocos（Keeling）群岛。","other":"绿原鸡与家鸡的杂交现象已报告，这导致了其遗传多样性的减少。"},{"name":"黑鹇","english_name":"Kalij Pheasant","scientific_name":"Lophura leucomelanos","overview":"黑鹇（英文名：Kalij Pheasant，学名：Lophura leucomelanos），是鸡形目雉科鹇属的鸟类。又名: 鸬雉、黑鸡，其最显著特征是雄鸟的蓝黑色光泽羽毛，雌鸟则呈灰褐色。广泛分布于喜马拉雅山脉、印度北部至泰国西部，中国境内仅见于海拔2100~3200米的亚热带森林。2021年，黑鹇被宣布为印度Jammu和Kashmir地区的象征性鸟类。","appearance":"雄性黑鹇总长63-74厘米，雌鸟50-60厘米，雄鸟以蓝黑色为主调，带有金属光泽，雌鸟则为均匀的灰褐色或暗褐色。雄鸟的头部有向后指向的冠羽，面部皮肤裸露呈红色，腿部颜色从淡棕色到灰绿色不等。雌雄幼鸟的羽毛在暗褐色基底上，下部羽毛末端有白色斑点，上部羽毛有暗色亚端横纹和淡色边缘。成年后，雄鸟的羽毛色彩会变得更加鲜艳。","call":"黑鹇在鸟群分散时会发出低沉的‘kurr-kurr-kurrchi-kurr’联络叫声。雄鸟会发出响亮的咯咯哨音，伴有翅膀拍打身体的声音。争斗时，会发出恐吓的‘koor koor’声，紧接着是尖锐的‘waak, waak’声。告警时，会重复‘koorchi koorchi koorchi’叫声或发出‘whoop-keet-keet’的喉音。","habits":"黑鹇栖息于海拔1300~3300米的山地箭竹丛和林间草丛中，偏好有水边的环境。它们通常成对或小群体活动，以植物嫩叶、种子为主食，偶尔也会食用昆虫。黑鹇在喜马拉雅山脉南麓的卡玛山谷中被发现，这里是世界上十大景观之一。","breeding":"繁殖期主要在5月至6月，黑鹇会在草丛中筑巢，每窝产卵5-15枚，卵色为深皮黄粉红色，大小约为46.1-53.0毫米×27.7-39.0毫米。孵化期大约24-25天，期间由雌鸟独自承担孵化任务。","identification":"黑鹇与白鹇在外观上有明显差异，尤其是腿部颜色，黑鹇的腿部为灰或淡棕色，而银雉为鲜红色。此外，雄性黑鹇的羽毛色彩更为丰富，雌鸟则较银雉的雌鸟更暗淡。","protection":"IUCN：LC（无危）","distribution":"黑鹇分布于东洋界，从巴基斯坦北部至泰国西部，中国境内的分布限于亚热带森林，海拔高度在2100~3200米之间。","other":"黑鹇已被引入夏威夷群岛作为狩猎鸟类。"},{"name":"白鹇","english_name":"Silver Pheasant","scientific_name":"Lophura nycthemera","overview":"白鹇（英文名：Silver Pheasant，学名：Lophura nycthemera），是鸡形目雉科鹇属的鸟类。又名: 银鸡、银雉、越鸟、越禽、白雉。体态优雅，外观绚丽。雄鸟上体及双翅覆以白色，饰以黑纹；羽冠与下体为灰蓝色；长尾中央羽毛几乎纯白，外侧带黑色波纹。雌鸟整体呈橄榄褐色，羽冠近黑色，与雄鸟相比色彩较为朴素。白鹇是广东省的省鸟。","appearance":"雄性白鹇总长度变化显著，最长可达120至125厘米（含尾羽60至75厘米），而最短的亚种仅约67厘米（尾羽约30至33.5厘米）。雌鸟的尺寸明显小于雄鸟，长度在55至90厘米之间，尾羽长度约为24至32厘米。雄鸟体重在1.13至2千克之间，雌鸟体重则介于1至1.3千克。雄鸟的特征在于其鲜明的黑白对比羽毛，雌鸟则主要为红棕色或深棕色，带有不同程度的淡色斑纹。","call":"雄鸟的领地叫声被形容为类似于雉鸡或黑鹇的声音，但更为短促和低沉。展示时，雄鸟会发出翅膀振动声和轻微的颤音'koo koo'。两性在觅食时会发出柔和的哨声，受惊扰时则会发出尖锐的哨声。","habits":"白鹇栖息于多种类型的森林环境，包括阔叶林和松树林为主的区域，常见于海拔1000米以上，但在某些地区也可降至300米。它们偏好在浓密的竹林和灌木丛中活动，白天隐匿，夜晚栖息于树上。食物主要包括昆虫、浆果、种子、嫩叶和苔藓。","breeding":"繁殖季节从3月中旬开始，实行一雄多雌制。雄鸟好斗，发情期时脸部裸露部分变红，羽毛光泽增强。雄鸟通过侧面展示的方式吸引雌鸟，筑巢于林下灌丛间地面凹处或草丛中，巢由枯草、树叶、松针和羽毛构成。每窝产卵4至8枚，卵淡至棕褐色，孵化期24至25天，雏鸟早成性。","identification":"雄性白鹇与黑鹇的主要区别在于白鹇的尾羽更长更白，腿为红色。雌性白鹇与黑鹇雌鸟的区别在于脚的颜色，白鹇雌鸟脚为粉红色，外侧尾羽颜色不同于黑鹇。","protection":"IUCN：LC（无危）。在中国某些自然保护区内，白鹇的种群密度较高，但由于栖息地破坏，如砍伐、药材采集、道路建设和森林旅游开发，其生存仍面临威胁。","distribution":"广泛分布于东南亚的山脉森林中，从山脚到海拔1500米的高度均有其踪迹。在中国南方省份有广泛的分布。","other":"白鹇在历史上曾被认为是稀有物种，但现在在适宜的环境中仍然常见。然而，一些亚种如whiteheadi、engelbachi和annamensis处于濒危状态。"},{"name":"爱氏鹇","english_name":"Edwards's Pheasant","scientific_name":"Lophura edwardsi","overview":"爱氏鹇（英文名：Edwards's Pheasant，学名：Lophura edwardsi），是鸡形目雉科鹇属的鸟类。又名: 爱德华氏鹇或爱德华雉，极度濒危，特有于越南中部的季节性热带森林。体长约58-65厘米，脚及面部皮肤呈红色，雄鸟以蓝黑色为主，具冠羽，雌鸟则为黄褐色。","appearance":"爱氏鹇体型中等，长58-65厘米，雄鸟尾长24-26厘米，雌鸟尾长20-22厘米。雄鸟体重约1100克，雌鸟约为1050克。雄鸟全身羽毛为深蓝色并带有金属绿光泽，具有白色小冠羽和大片鲜红面部皮肤；喙绿色带黑基，虹膜红棕色，腿脚鲜红。雌鸟通体黄褐色，无冠羽，尾部较暗。幼鸟大多黄褐色，上体有黑色斑纹。","call":"雄鸟发出翅膀振响的展示声，警报声为低沉的连续'uk uk uk uk uk'，有时被描述为硬质的'puk puk puk puk puk'。","habits":"栖息于越南中部的次生低地常绿森林，偏好有棕榈和藤蔓的茂密下层植被，间杂竹林。最常见于密集灌木丛和藤蔓覆盖的山坡。历史上曾报道生活在海拔约600米的湿润森林中，但具体证据表明其不会出现在300米以上的高度。","breeding":"繁殖资料仅来自圈养个体：产卵数4-7枚，蛋壳颜色为乳白色至淡粉色；孵化期21-22天；雏鸟上体暗褐色，头部和两侧栗色，下体淡黄色。","identification":"雄性爱氏鹇与完全异域的蓝腹鹇相比，色彩较为暗淡，上背和尾巴缺乏大面积白色；与相似的黑鹇 hamiltoni 亚种（同样是蓝黑色带白冠和红面部皮肤）相比，下体缺少大量淡色标记。雌鸟则无明显区别点。","protection":"IUCN：CR (PEW)（极危（可能已野外灭绝））","distribution":"繁殖区域位于越南中部（中安南）。","other":"自2000年后，再无野外确认记录。2012年，被提升至极度濒危状态。历史分布于Ha Tinh、Quang Binh、Quang Tri和Thua Thien Hue四省。"},{"name":"蓝腹鹇","english_name":"Swinhoe's Pheasant","scientific_name":"Lophura swinhoii","overview":"蓝腹鹇（英文名：Swinhoe's Pheasant，学名：Lophura swinhoii），是鸡形目雉科鹇属的鸟类。又名:蓝腹鹇鹇、台湾蓝腹鹇、华鸡，为台湾特有的大型雉类，由英国自然学家罗伯特·斯文侯于1862年首次描述。雄鸟通体石蓝，雌鸟浓褐，两者皆具红色面部裸皮。分布于台湾山地森林，高度可达2,300米，是台湾的象征之一，具代表色彩（红、白、蓝）。","appearance":"雄鸟全长约79厘米，尾长约41-50厘米；雌鸟约50厘米，尾长约20-22厘米。雄鸟主要为黑色蓝调，覆羽光泽绿，肩部有栗红色斑块，白色顶冠、上背和尾羽中心，红色面部裸皮；雌鸟无顶冠，总体栗红至红褐色，上体有宽阔的淡色箭状斑纹。幼鸟颜色暗淡，具斑点。","call":"两性通常发出轻微的咯咯声和尖锐的吸气声，有时会伴随哀怨的“oot-oot, oot-oot”叫声，尤其是在警戒时。","habits":"栖息于台湾中低海拔的原始和成熟次生硬木林，偏好林下灌木丰富而不致密的地带。主要以植物性食物为主，包括嫩叶、果实、种子等，也吃昆虫和小型动物。活动时间从清晨至傍晚，常在路边和开阔地带觅食。","breeding":"繁殖期大致在3月至5月，可能延续至10月。筑巢于林下隐蔽处，巢由落叶、草茎、羽毛构成，产卵4-8枚，红色至奶油色，孵化期25天，由雌鸟独自孵化。","identification":"雄鸟可通过白色的尾羽和背部区分于黑长尾雉；雌鸟的羽毛色更深，尾巴更宽，喙色淡，腿红，腹部无斑纹。","protection":"IUCN：NT（近危）。曾在多个地区灭绝，面临栖息地破坏和非法贸易威胁，全球数量估计超过10,000只，部分种群在保护区安全。","distribution":"仅分布于台湾山脉，最高可达海拔2,300米。","other":"过去因狩猎和山地开发导致数量减少。"},{"name":"苏门答腊鹇","english_name":"Hoogerwerf's Pheasant","scientific_name":"Lophura hoogerwerfi","appearance":"雄性苏门答腊鹇为无冠的蓝黑色，面部皮肤裸露呈红色，尾巴短小，腿部灰色。雌鸟则为赤褐色，腿色暗蓝灰色，尾部短且颜色较深。外观上与萨尔瓦多里雉鸡相似，常被视为其亚种，但雌鸟的羽色更深，缺乏淡黄色斑点，羽毛更为单一。","habits":"这是一种印尼特有的雉鸡，栖息于苏门答腊岛阿齐省的勒瑟国家公园的中海拔山区森林。过去仅知于两份雌鸟标本，最近在北苏门答腊省棉兰市场被重新发现。","identification":"与黑尾鹇相比，苏门答腊鹇雌鸟具有更深的棕色羽色，缺乏淡黄色斑纹，羽毛图案更加朴素。","protection":"IUCN：NT（近危）","distribution":"主要分布在印尼苏门答腊岛的勒瑟国家公园，具体位于阿齐省的中海拔山区森林。"},{"name":"黑尾鹇","english_name":"Salvadori's Pheasant","scientific_name":"Lophura inornata","overview":"黑尾鹇（英文名：Salvadori's Pheasant，学名：Lophura inornata），是鸡形目雉科鹇属的鸟类。大型陆禽，特有种于印度尼西亚苏门答腊岛的山地雨林。由意大利鸟类学家Tommaso Salvadori于1879年首次描述。物种名inornata意为\"无装饰\"。苏门答腊鹇通常被认为是其亚种。IUCN 将其分类为近危物种，由于生境破坏和猎捕导致种群数量减少。","appearance":"雄性黑尾鹇体长46至55厘米，尾长约15.2至17厘米，全身呈蓝黑色，带金属光泽，腹部、尾羽和飞羽稍暗淡。尾部较短且圆。喙呈淡绿白色，眼环黄绿色或灰绿色，面部裸露皮肤鲜红，腿脚灰蓝。雌鸟体型略小，无距，毛色红栗色，每根羽毛带有细小黑斑点和浅色羽轴纹，喉部颜色较浅，尾羽深棕色。幼鸟类似雌鸟，但羽缘泛淡黄色，形成鳞状图案。","call":"通常较为安静，但会发出低沉的\"bwoop\"声接触叫声，雄鸟在近距离时可听见翅膀振动展示声。","habits":"栖息于海拔1000至2200米的山地森林，偶尔在轻度退化的森林中被记录到，但附近需有原始森林。以单独或成对的方式在林地地面觅食，具体食性和觅食行为信息不明。","breeding":"繁殖期信息有限，雌雄对在繁殖季节常被观察到一起，可能实行一夫一妻制。巢穴记录显示含2枚咖啡色蛋，孵化期约22天，仅由雌鸟孵化。","identification":"雄鸟与雌鸟外观差异显著，雄鸟蓝黑色，雌鸟红栗色，具斑点。与苏门答腊鹇的区别在于前者较长，喙色较淡，尾部下垂，后者更健壮，喙色深，尾部上翘。生境上，黑尾鹇在苏门答腊的海拔高于crestless fireback。","protection":"IUCN：NT（近危）","distribution":"黑尾鹇是苏门答腊岛的特有种，分布于该岛中部和南部Barisan山脉的多个位置，高度介于650至2200米之间。两个亚种存在，L. i. inornata相对常见，而L. i. hoogerwerfi局限于北部山区，极为罕见。","other":"物种面临的主要威胁包括森林砍伐和非法农业活动导致的栖息地退化，以及狩猎。"},{"name":"棕尾火背鹇","english_name":"Malayan Crestless Fireback","scientific_name":"Lophura erythrophthalma","overview":"棕尾火背鹇（英文名：Malayan Crestless Fireback，学名：Lophura erythrophthalma），是鸡形目雉科鹇属的鸟类。分布于马来半岛和印尼苏门答腊岛的热带低地雨林中，尤其是泥炭沼泽森林。其显著特征为深色外表搭配鲜红面部皮肤，雄鸟拥有竖立的扁平尾巴，雌鸟全身呈现深蓝色。极为害羞，常以成对或小群体形式活动。","appearance":"棕尾火背鹇体型紧凑，雄鸟通体呈光泽黑，翅膀、肩部和侧胸有细小灰白斑点，背部橙红色，臀部紫色，尾羽淡橙色。雌鸟整体蓝黑色。雄鸟的尾羽在基部黑色，而尾端为温暖的肉桂色，雌鸟尾羽短而直，黑色。幼鸟上体有丰富的暗褐色绒毛，头至冠部有一条深棕色条纹，两侧有窄边的暗线延伸至尾，下体颜色暗黄。","call":"发出相对高音的“chick！”声，随后是低沉的“takrow”。","habits":"偏好封闭树冠的森林，包括原始和良好再生的区域，特别偏好河岸和泥炭沼泽森林。在马来半岛，也可在混合硬木和酸性森林中发现，但确切的生境偏好不明。通常在海拔300米以下的平原热带雨林活动。","breeding":"繁殖信息有限，但基于相关物种的观察，可能在春季进行繁殖活动，营巢于地面，雌鸟独自孵化和育雏。","identification":"与马来火背鹇相比，面部皮肤颜色不同，雄鸟尾羽颜色差异明显。雌鸟与黑尾鹇雄鸟相似，但分布不同，后者位于苏门答腊西部而非东部。","protection":"IUCN：CR（极危）","distribution":"分布于马来半岛和印尼苏门答腊岛，主要在热带低地雨林中，包括泥炭沼泽森林。","other":"历史上，由于栖息地丧失，其分布面积自1800年以来可能已大幅减少。"},{"name":"凤冠火背鹇","english_name":"Bornean Crested Fireback","scientific_name":"Lophura ignita","overview":"凤冠火背鹇（英文名：Bornean Crested Fireback，学名：Lophura ignita），是鸡形目雉科鹇属的鸟类。主要分布在婆罗洲和印尼苏门答腊岛南部的邦加岛。雄鸟具有光泽的蓝黑色羽毛，头部带有毛茸茸的羽冠，而雌鸟呈温暖的巧克力棕色，两者都拥有电蓝色的面部皮肤和白色的腿。该物种在低地森林中活动，偶尔在砍伐过的森林中也能发现其踪迹。","appearance":"雄性凤冠火背鹇体长可达70厘米，拥有紧凑而蓬松的羽冠，脸部有大块蓝色肉垂，全身羽毛光泽蓝黑，背部橙红。雌鸟也有羽冠和蓝色面部皮肤，但羽毛为赤褐栗色，下体有黑白相间的斑点。雏鸟上半身黑褐色，下半身有红褐色羽毛，头部有红褐色羽冠。","call":"雄鸟发出喉音“chuckit！”或柔和的“weep”叫声，还会进行振翅展示。","habits":"凤冠火背鹇栖息于热带低地和较低山地的雨林中，单个或小群体在林地地面觅食。它们对森林退化有一定容忍度，曾在砍伐森林中被记录。以植物、果实和小型动物为食。","breeding":"雌鸟通常产4至8枚奶白色的蛋。","identification":"与鳞背鹇相似，但凤冠火背鹇雄鸟有亮橙色腹部和黄色尾巴，雌鸟下体羽毛边缘较淡。与婆罗洲火背鹇相比，面部皮肤更蓝，有顶冠，雄鸟上体栗色。","protection":"IUCN：VU（易危）","distribution":"主要分布于婆罗洲，包括邦加岛（印尼苏门答腊岛南部）。在繁殖季节，记录高度可达1,300米。","other":"历史分类中曾与马来火背鹇混为一谈，现基于显著的羽毛差异而分离。"},{"name":"戴氏火背鹇","english_name":"Siamese Fireback","scientific_name":"Lophura diardi","overview":"戴氏火背鹇（英文名：Siamese Fireback，学名：Lophura diardi），是鸡形目雉科鹇属的鸟类。体型较大的雉鸡，全长约80厘米。雄鸟拥有独特的蓝色灰色羽毛，面部裸露部分为鲜艳的红色，配以长长的光泽黑尾。雌鸟则呈棕色，翅膀和尾羽带黑白条纹。主要分布于东南亚的低地和山麓的阔叶林中，是泰国的国鸟。","appearance":"雄性戴氏火背鹇长约80厘米，尾部长度33至36厘米；雌鸟约60厘米，尾长22至26厘米。雄鸟特征显著，上体大部分灰色，面部皮肤大块红色，腿和脚为鲜红色。雌鸟上翼和中央尾羽黑色，有明显的浅黄白色条纹。幼鸟与雌鸟相似，但颜色更暗淡。","call":"雄鸟发出响亮的哨音，用于吸引雌鸟，同时在展示中频繁发出持续2至5秒的翼鸣。","habits":"戴氏火背鹇栖息于低地森林，包括原始和次生的常绿森林，以及干常绿、混合落叶、竹林和干硬木森林。它们通常在平原到海拔800米的地方活动，有时出现在严重退化的森林。早晨和黄昏时分，它们会在道路旁觅食，以各种落果、浆果、昆虫、小陆蟹等为食，偶尔也会在树叶堆中刨食或在牛群附近寻找昆虫。","breeding":"繁殖季节在泰国中部大约为3月至6月。雄鸟在求偶时表现出多配偶制，通过展示和鸣叫吸引雌鸟。筑巢在植被覆盖密集的区域，平均产卵量为6.4枚，孵化期23至24天。雏鸟孵化后主要为棕色，腹部淡黄色。","identification":"与白鹇相比，雌性戴氏火背鹇具有更为显著的翼条纹，而雄鸟的特征更为明显，包括独特的羽毛和鸣叫。","protection":"IUCN：LC（无危）","distribution":"分布于缅甸东部、泰国北部、中部和东南部、老挝中部和南部、柬埔寨北部和中部以及越南中部和南部。","other":"戴氏火背鹇在泰国的民间文学中被称为Kai Fah Phaya Lo，是泰国的国家象征之一。"},{"name":"鳞背鹇","english_name":"Bulwer's Pheasant","scientific_name":"Lophura bulweri","overview":"鳞背鹇（英文名：Bulwer's Pheasant，学名：Lophura bulweri），是鸡形目雉科鹇属的鸟类。雄鸟拥有令人难以置信的外观，雪白的巨大扇形尾羽从圆胖的煤黑色身体伸出，雌鸟为全红褐色，尾羽较短。两者共有的天蓝色面部皮肤是其显著特征。该物种主要分布于婆罗洲的山麓和山地森林，以果实丰富的树木为觅食目标。","appearance":"雄性鳞背鹇总长约80厘米，尾羽长达45-46厘米，体重介于1470至1800克之间，其特征为黑羽身着蓝边，紫色光泽的喉咙和胸部，独特的白色尾羽由长硬轴构成，以及红色腿部。雌鸟体型较小，约55厘米，尾羽17.5-19厘米，呈单调的红褐色，具红色腿部和蓝色面部皮肤。幼鸟与雌鸟相似，但上覆羽带有暖色调的蓝灰色尖端，第一年雄鸟尾羽直立，数量较少，呈深栗色，而非白色，具有较窄的蓝边，胸部和前颈有更多红棕色羽毛。","call":"鳞背鹇的叫声描述非常有限，已知的叫声包括尖锐的领地呼唤，类似于某些松鼠的叫声，还有双音‘kak’或单调的‘gack’警报声，以及接触时发出的穿透力强、略带金属感的‘kook！, kook！’叫声。","habits":"鳞背鹇栖息于婆罗洲的混合龙脑香林、竹林和阿加西斯森林，海拔高度可达1475米。它们可能随果实丰盛的事件而游牧移动，主要食物包括蚂蚁、白蚁、小蟋蟀、正统目昆虫和小种子，通过在森林地面刮食。","breeding":"繁殖季节似乎较长，间接证据显示至少从4月开始。配偶模式尚不清楚，可能为一夫多妻制，曾观察到一只雄鸟与三只雌鸟在一起。雄鸟求偶时会展开白色尾羽，面部皮肤充血形成锤头状蓝色斑块。已知的一个巢穴位于1985年文莱的树根旁，含有一个淡粉色蛋。窝卵数一般为2至5枚，孵化期24-25天，雏鸟孵化时重约35克。","identification":"雄性鳞背鹇的独特白色尾羽和蓝色面部皮肤使其与其他雉科鸟类容易区分。雌鸟与凤冠火背鹇的雌鸟类似，但后者有羽冠、斑点下体和白色的腿。","protection":"IUCN：VU（易危）","distribution":"鳞背鹇分布于婆罗洲内陆，包括东加里曼丹、沙巴和砂拉越的山地森林和高地雨林，海拔高度在300至1475米之间，偶尔低至150-250米。","other":"尽管在当地一些保护区内还算常见，但因栖息地丧失和退化，以及过度猎捕，其种群数量正在下降。"},{"name":"婆罗洲火背鹇","english_name":"Bornean Crestless Fireback","scientific_name":"Lophura pyronota","overview":"婆罗洲火背鹇（英文名：Bornean Crestless Fireback，学名：Lophura pyronota），是鸡形目雉科鹇属的鸟类。分布于北婆罗洲。曾被称为‘无冠火背鹇’，当物种划分尚不明确时与棕尾火背鹇混为一谈。婆罗洲火背鹇以其独特的红脸皮肤和紧凑的体型著称，栖息于热带低地雨林中。","appearance":"婆罗洲火背鹇具有暗色的整体羽毛，雄鸟拥有浅色细纹，胸部有精细的白色条纹，橙红色背部（火背）和淡橙色尾巴。雌鸟全身深蓝色，头部颜色略显暗淡。雄鸟的下部背部呈亮红棕色，臀部颜色更鲜艳。雌鸟的上体与尾羽呈黑褐色，带有蓝黑色光泽。雄鸟的尾羽温暖的肉桂色，基部黑色。","call":"婆罗洲火背鹇发出相对高音的“chick！”声，随后是低沉的“takrow”。","habits":"婆罗洲火背鹇栖息在潮湿的热带低地雨林，尤其是泥炭沼泽森林，通常成对或小群活动，极为害羞。它们的饮食主要包括浆果、水果、昆虫和其他小型无脊椎动物，偶尔也吃叶子和种子。","identification":"婆罗洲火背鹇与凤冠火背鹇和鳞背鹇相比，面部皮肤为红色而非蓝色，体型较小。雌鸟全深蓝色，而雄鸟下体部分为栗色，尾羽有明显的颜色过渡。","protection":"IUCN：EN（濒危）","distribution":"婆罗洲火背鹇主要分布在北婆罗洲的繁殖区域。","other":"关于其分类历史，婆罗洲火背鹇曾被视为棕尾火背鹇的亚种，但基于显著的羽毛差异，现已作为独立物种得到认可。"},{"name":"马来火背鹇","english_name":"Malayan Crested Fireback","scientific_name":"Lophura rufa","overview":"马来火背鹇（英文名：Malayan Crested Fireback，学名：Lophura rufa），是鸡形目雉科鹇属的鸟类。分布在泰国-马来西亚半岛和苏门答腊低地森林中。其最显著的特征是雄鸟的蓝黑色光泽羽毛、红色臀部、黑色外侧尾羽、红色虹膜和蓝色裸露面部皮肤。雌鸟呈棕色，具短冠，蓝色面部皮肤，下体黑白色斑点相间。马来火背鹇曾被认为是凤冠火背鹇的一个亚种，后因显著的羽毛差异被独立为种。","appearance":"雄性马来火背鹇拥有蓝黑色光泽的羽毛，头部有竖立的蓝黑色绒毛冠，面部皮肤为亮蓝色，背部为血红色，尾羽中央几对为白色，其余为深蓝色至黑色。雌鸟则为温暖的巧克力棕色，下体有白色边缘的羽毛，面部皮肤蓝色，上体棕色。雄鸟全长约70厘米，尾长24-29厘米；雌鸟长约56-57厘米，尾长17-20厘米。","call":"马来火背鹇会发出沙哑的“chuckit！”声或柔和的“weep”声，雄鸟还会展示翅膀振动的声音。","habits":"马来火背鹇通常在热带低地雨林中生活，偏好较湿润的区域，常在森林地面单独或小群觅食。它们主要以浆果、果实、昆虫和其他小型无脊椎动物为食，有时也吃树叶和种子。它们白天活动，群居觅食效率最高时是在落叶层最厚的时候，如泰国-马来西亚半岛的9月至12月。","breeding":"繁殖季节未知，但据观察，雄鸟在3月、4月、7月和10-12月可能会换羽，这可能与繁殖周期有关。雄鸟有大型淡色脚距。","identification":"马来火背鹇与凤冠火背鹇的区别在于前者有白色的中央尾羽、红色的腿和蓝黑色条纹的下体。雌鸟与萨尔瓦多雉有相似之处，但可通过面部皮肤颜色、下体斑纹和体型大小进行区分。","protection":"IUCN：VU（易危）","distribution":"马来火背鹇主要分布在泰国-马来西亚半岛和苏门答腊北部及中部的低地森林中。","other":"历史上，马来火背鹇与凤冠火背鹇曾被视为同一物种，但在发现二者之间显著的表型差异后，IUCN 和 Clements 系统将其分裂为两个独立的物种。"},{"name":"白马鸡","english_name":"White Eared Pheasant","scientific_name":"Crossoptilon crossoptilon","overview":"白马鸡（英文名：White Eared Pheasant，学名：Crossoptilon crossoptilon），是鸡形目雉科马鸡属的鸟类。又名: 雪雉，拥有醒目的耳羽簇，全身以白色为主调，分布在中国中西部、中南部及西藏地区。白马鸡生活在高山和亚高山森林地带，集群活动，冬季至春季时群可达50-60只。","appearance":"白马鸡体型大，雄鸟体重2350-2750克，雌鸟1400-2050克，体长75-96厘米，尾长46-58厘米。雄雌相似，但雌鸟略小，颜色较暗淡。耳羽簇短于其他有耳雉鸡，面部皮肤红色，腿脚鲜红。幼鸟灰白，带有多种深色标记，8-10周后换上成鸟羽毛。成鸟羽毛颜色在白色与灰蓝之间变化。","call":"白马鸡的叫声宏亮而短促，类似‘咯……咯……咯……’的声音，传播距离远。","habits":"白马鸡栖息于海拔3000-4000米的针叶林和针阔混交林，冬季下降至2800米左右的阔叶林。它们在白天活动，黎明即起，黄昏结束，中午休息，夜晚栖于树上。白马鸡的食物多样，包括植物嫩叶、果实、昆虫等。","breeding":"白马鸡繁殖期为5-7月，营巢于林下灌丛或岩石洞穴，每窝产卵4-7枚，孵化期约24-25天。","identification":"白马鸡与近似物种的区别在于其独特的耳羽簇和色彩，以及栖息地的差异。","protection":"IUCN：LC（无危），保护级别Ⅱ级。","distribution":"白马鸡分布于中国中西部、中南部和西藏，具体包括四川、西藏东部、甘肃东南部、青海南部和云南西北部。","other":"白马鸡在一些地区的佛教文化中受到非正式保护。"},{"name":"藏马鸡","english_name":"Tibetan Eared Pheasant","scientific_name":"Crossoptilon harmani","overview":"藏马鸡（英文名：Tibetan Eared Pheasant，学名：Crossoptilon harmani），是鸡形目雉科马鸡属的鸟类。主要分布于中国西藏东南部及邻近的印度北部，海拔介于3000至5000米之间，冬季可降至2280米。其特征包括亮红色面部、扇形尾巴及独特的白色‘耳朵’。以藏马鸡命名的是Henry John Harman。","appearance":"体长75至85厘米，体重约1180克。雄雌相似，具有黑色天鹅绒般的前额和冠羽，白色的上颈背、耳羽、下巴、喉咙、颈侧及腹部中间；体羽中灰色，颈部至披肩和胸部颜色最深（微带棕色），背部下方至尾上覆羽颜色最淡（灰白色）；翅膀暗褐色，尾巴蓝黑色，基部淡色且更灰色；虹膜橙黄色，裸露面部皮肤深红；喙红角质色；腿红色。幼鸟信息有限，可能偏棕色。","call":"发出远距离的粗哑叫声，起初缓慢，随后音符连贯成短系列，例如“gag, gag, gagera, gagera...”。与白马鸡的叫声非常相似，但前两个音节发音稍慢。","habits":"栖息于西藏东南部高原的密布灌木区、混合阔叶林和针叶林边缘，以及草地山坡；海拔3000至5000米，冬季偶尔下降至2400米以下。群居，每天的活动范围小于0.75公顷，群落大小与活动范围相关，较大的群体拥有更大的活动范围。通常在植被覆盖率超过40%，高度超过1.2米的地方活动。接受僧侣在寺院提供的食物（主要是高寒大麦）。在软土地带，如溪流附近觅食。","breeding":"繁殖期自4月中旬至6月初（高峰在4月底至5月初）。单配偶制，巢建在岩石缝隙中，靠近溪流，由苔藓、树枝、草和羽毛铺垫，平均宽27至39厘米，深3至11厘米。再利用率约为9%，有时跨多个季节。产卵4至11枚，平均7枚，颜色为白色、淡棕色或淡绿色，大小平均为57.3毫米×41.7毫米，孵化期24至25天，仅雌鸟孵卵。雏鸟出生时体重28至40克。","identification":"与白马鸡相比，整体羽色为中灰色，体型略小，翼展平均286毫米，而白马鸡为310毫米。雄鸟缺少腿上的短刺。与dolani亚种的区别在于更深的灰色和灰而不是白色的前颈，以及白色而非灰色的腹部斑块。","protection":"IUCN：LC（无危）","distribution":"分布于西藏东南部（西至Tsangpo谷约91°E，东至Yigrong山脉约95°E，北至拉萨以北约80公里）和极北印度。","other":"与白马鸡杂交，遗传研究表明harmani与白马鸡关系最近，但差异类似本属其他传统上视为物种的分类群。"},{"name":"褐马鸡","english_name":"Brown Eared Pheasant","scientific_name":"Crossoptilon mantchuricum","overview":"褐马鸡（英文名：Brown Eared Pheasant，学名：Crossoptilon mantchuricum），是鸡形目雉科马鸡属的鸟类。中国特有种，仅见于中国东北部的山林。以其独特的白耳羽和红脸闻名，分布于山西、河北等地的山林中。","appearance":"褐马鸡体型厚实，全长96-100厘米，雄鸟体重1650-2475克，雌鸟1450-2025克，尾长约51.8-58.2厘米。头部黑色，脸部裸露部分红色，具有一对上扬的白色耳羽，如同小胡子。全身灰棕色，臀部霜灰色，尾羽白色，末端暗色。雄鸟有单个短距，雌鸟略小且无距。幼鸟呈深灰褐色斑驳，尾较短，成年后毛色变化明显。","call":"在繁殖季节，雄鸟发出类似''的叫声，初始音量柔和，迅速增大，持续时间可达一分钟，有时突然结束。","habits":"褐马鸡栖息于海拔1100至2600米的山地落叶和针叶混交林，偏好有密集灌木的生境。日行性，喜沙浴，善于奔跑，警惕性高。食物包括植物根茎、果实和小型动物。群体活动，冬季形成小群，非繁殖季节可能集结成较大群体。","breeding":"繁殖期通常为春季，雄鸟通过战斗争夺配偶，叫声宏亮。巢建于地面隐蔽处，雌鸟独自行孵化，孵化期约26-27天。一窝产卵数4-14枚，颜色淡石绿色，幼鸟出生后由雌鸟独自抚育。","identification":"褐马鸡是唯一分布在北方的耳状雉鸡，具有独特的白色耳羽和红脸，与其它马鸡属物种没有地理重叠，易于识别。","protection":"IUCN：LC（无危）。总成熟个体数估计为3300-11000只，大部分位于保护区内，如山西、河北的山区。面临旅游、森林破坏、偷猎威胁，遗传多样性低。","distribution":"繁殖区域为中国东北部的山西吕梁山、芦芽山、黄龙山、河北小五台，以及陕西黄龙山自然保护区。在北京东灵山也有分布。","other":"中国鸟类学会将其作为会标，山西省定为省鸟。"},{"name":"蓝马鸡","english_name":"Blue Eared Pheasant","scientific_name":"Crossoptilon auritum","overview":"蓝马鸡（英文名：Blue Eared Pheasant，学名：Crossoptilon auritum），是鸡形目雉科马鸡属的鸟类。又称: 叫角鸟、松鸡，是中国特有的一种大型雉类。拥有独特的灰蓝色羽毛和醒目的白耳簇，分布于中国中部的高山森林地带","appearance":"蓝马鸡长约96厘米，雄鸟体重1700至2110克，雌鸟1450至1880克，尾长49至56厘米。雄鸟头部黑色带丝绒质感，面部皮肤鲜红，眼后有白色耳羽，形似‘八字胡’。颈及身体蓝灰色，翅膀暗棕色，尾羽蓝灰色，尖端泛紫色光泽。喙色偏红，眼睛黄色，腿脚鲜红。雌鸟略小，无雄鸟的刺突。幼鸟暗灰棕色，羽端呈淡色，尾短，成年后换羽。","call":"受惊的雄鸟发出‘gela-gelage’叫声。求偶期雄鸟的叫声为‘wu, wu, wu’或‘ga, ga’。受惊时，雄雌鸟均发出‘ziwo-ge, ziwo-ge’的叫声。","habits":"蓝马鸡栖息于高海拔的针叶林和混交林，偏好亚高山和高山的开阔林区及灌丛草地，夏季活动于2700至4400米，冬季可能降至3000米以下。以小群活动，主要食用植物性食物，包括浆果和蔬菜，也会食用昆虫。冬季偏好在松树林中觅食。","breeding":"繁殖季节从3月下旬开始，雄鸟间会激烈竞争配偶。营巢于灌木丛中，巢简陋，由树叶、树枝构成，内部铺有羽毛。4月初开始配对，5月产卵，每窝5至13枚，卵呈淡青绿或浅褐色，重约45至58克，孵化期约26天，由雌鸟独自孵化。","identification":"蓝马鸡的灰蓝色羽毛、白色耳羽和红色面部皮肤是其显著特征。与其他雉科鸟类相比，蓝马鸡的尾巴更长且呈松散状态，末端颜色独特。","protection":"IUCN：LC（无危）。在中国，蓝马鸡属于国家二级重点保护野生动物，自1989年起生效。然而，栖息地破坏和过度捕猎仍是威胁其生存的因素。","distribution":"分布于中国中部的高山森林，包括青海东部、甘肃、内蒙古贺兰山、四川西部及西藏东北部唐古拉山脉。","other":"蓝马鸡的羽毛美丽，曾用于装饰，受到国际市场欢迎。"},{"name":"彩雉","english_name":"Cheer Pheasant","scientific_name":"Catreus wallichii","overview":"彩雉（英文名：Cheer Pheasant，学名：Catreus wallichii），是鸡形目雉科彩雉属的鸟类。又名: 瓦氏雉鸡，又名瓦氏雉鸡，是雉科彩雉属唯一物种。这种中大型雉鸡拥有淡灰色羽毛和长长的尾羽，尾部由18根羽毛组成，中央尾羽尤为突出。主要分布在喜马拉雅山脉的印度、尼泊尔和巴基斯坦高海拔地区。","appearance":"雄性彩雉体长90至118厘米，尾长45至58厘米，体重1250至1800克；雌鸟体长61至76厘米，尾长32至47厘米，体重900至1360克。雄鸟全身浅灰色，带有黑色横纹，尾羽有明显的黑色带纹，背部锈色，腹部暗色。雌鸟较雄鸟小，上部呈棕色，有白色条纹，尾部较短，腹部锈色，胸部有黑色斑点。幼鸟类似雌鸟但色泽更暗淡，标记不明显，缺乏成年雄鸟的羽冠。","call":"彩雉叫声独特，会发出一系列尖锐而有节奏的‘chir-a-pir chir-a-pir chir chir-chirwa chirwa’声和高音的‘chewewoo’声，其间夹杂着短促的‘chut’和刺耳的断音，有时会达到高潮，叫声变化多样，有时以二重唱或合唱形式出现。","habits":"彩雉栖息于喜马拉雅山脉的陡峭草坡和岩石地带，覆盖有灌木丛、矮树和次生植被，一般在海拔1200至3050米之间活动，但在特定区域如尼泊尔中部，活动范围可从600米至3500米。它们以植物的根、块茎、球茎、埋藏种子以及可能的昆虫幼虫和蚯蚓为食。彩雉通过挖掘寻找食物，有时形成15只左右的小群。","breeding":"彩雉在4月至6月间繁殖，具体时间受海拔影响，高海拔地区比低海拔晚约一个月，高峰期通常在5月。它们是一夫一妻制，雄鸟和雌鸟都会在黎明和黄昏时分鸣叫，除了繁殖季节后的7月至9月。巢建在险峻地带的草丛中，靠近岩石峭壁底部，通常不筑巢坑。每窝产8至10枚淡黄灰色、带有红褐色斑点的蛋，孵化期约为26天，由雌鸟单独孵卵，雄鸟在附近守护并参与幼鸟的抚养。","identification":"彩雉最显著的识别特征是头部后方的长而乱的羽冠，以及非常长、尖锐且逐渐变细的尾羽。雄鸟的黑色标记在翼覆羽和下体上非常多样，尤其是浅灰色的雄鸟更为明显。雌鸟体型较小，颜色偏棕色，没有脚蹼（雄鸟有）。","protection":"IUCN：VU（易危）","distribution":"彩雉分布于喜马拉雅山脉，从巴基斯坦东北部到尼泊尔西部。在中国大陆，主要见于西藏东部、四川西部、云南西北部、甘肃南部、青海东南部以及陕西西南部的喜马拉雅山区。","other":"彩雉的生存面临人类活动的威胁，包括栖息地丧失、狩猎和农业侵占。在一些保护区，如大喜马拉雅国家公园、Vinaiyak、Pindari和Adwani森林（印度），以及尼泊尔的Rara湖国家公园，仍有彩雉分布。"},{"name":"白颈长尾雉","english_name":"Elliot's Pheasant","scientific_name":"Syrmaticus ellioti","overview":"白颈长尾雉（英文名：Elliot's Pheasant，学名：Syrmaticus ellioti），是鸡形目雉科长尾雉属的鸟类。俗称: 横纹背鸡、山鸡、红山鸡、高山雉鸡和地花鸡，是中国特有的一种大型雉科鸟类，俗称横纹背鸡、山鸡、红山鸡、高山雉鸡和地花鸡。该鸟以鲜明的红脸、银色头部、白色腹部和带有锈色条纹的灰白色长尾著称。分布在中国东南部的多个省份，如浙江、安徽、福建、江西、湖北、湖南、广东、广西和贵州等地，偏好海拔200至1900米的常绿阔叶林、混交林和竹林。","appearance":"雄性白颈长尾雉长约80厘米，尾长39至47厘米，体重介于1044至1317克之间；雌鸟体型较小，约50厘米长，尾长17至19.5厘米，体重726至1090克。雄鸟拥有独特的白色腹部、银灰色头部和红色面部裸皮，尾羽长而带有锈色横纹；雌鸟为淡褐色，喉部黑色，腹部白色，尾部条纹较淡。幼鸟比雌鸟更暗淡，有白色的喉咙。","call":"雄鸟展示时会发出翅膀旋转声，随后是连续低沉的'ge-ge-ge-ge-ge-ge'叫声，通常在早晨或午后。两性在惊恐时都会发出尖锐的尖叫。","habits":"栖息于海拔200至1900米的常绿阔叶林、混交林、针叶林和竹林，偏好在晨晚活动，以小群体（3至4只）活动，主要食物为种子、浆果、叶子和少量蚂蚁。它们通常在地面觅食，也会挖掘土壤。","breeding":"繁殖期在3月中旬至5月底，雄鸟通过翅膀旋转和叫声吸引雌鸟，一雄多雌制。巢穴简单，位于灌木丛中，通常产5至8枚奶油色或玫瑰白色的蛋，孵化期约为25至26天，仅由雌鸟承担。","identification":"与同属其他物种相比，白颈长尾雉雄鸟的独特特征在于其白色腹部和银灰色头部。雌鸟可以通过其黑喉和白色腹部区别。","protection":"IUCN：LC（无危）。白颈长尾雉被列入中国国家重点保护野生动物名录，为国家一级保护动物。尽管面临栖息地丧失和猎杀的压力，但其种群数量似乎并未大幅下降。","distribution":"白颈长尾雉分布在中国东南部的多个省份，包括浙江、安徽、福建、江西、湖北、湖南、广东、广西和贵州等地，主要栖息在海拔200至1900米的常绿阔叶林、混交林、针叶林和竹林。","other":"白颈长尾雉在某些保护区被认为是局部常见的物种，如在江西官山自然保护区，2001年的调查显示，该区域内的种群数量正在增长。"},{"name":"黑颈长尾雉","english_name":"Mrs. Hume's Pheasant","scientific_name":"Syrmaticus humiae","overview":"黑颈长尾雉（英文名：Mrs. Hume's Pheasant，学名：Syrmaticus humiae），是鸡形目雉科长尾雉属的鸟类。体长范围55至90厘米，以蓝钢色颈部和翼斑、白色翼条以及黑白相间的长尾为显著特征。雌鸟较短尾，上体有黑斑点，面部红色斑块，生活在海拔1000至3000米的开阔森林地带。","appearance":"雄性黑颈长尾雉身长近90厘米，尾长40至53.5厘米，体重975至1080克；雌鸟约60厘米，尾长约19.5至20厘米，体重650至850克。雄鸟拥有独特的上翼图案和蓝黑色颈部，尾羽延长且外侧尾羽渐长；雌鸟尾部较短且末端钝圆。雌鸟外观类似，但颜色更淡，喉部呈淡赤褐色，肩部羽毛黑白相间。喙呈黄角色，裸露面部皮肤红色，虹膜橙色至棕色，腿灰色，雄鸟有短跗跖刺，雌鸟则无。幼鸟似雌鸟但色泽更暗，年轻雄鸟很快获得成年尾羽模式。burmanicus亚种雄鸟的蓝钢色颈部略带紫色，扩展至胸部和背部，臀部因更宽的白色条纹而显得更白，尾羽颜色更淡。","call":"黑颈长尾雉的鸣叫包括响亮的接触声“chuck”，低沉的咕哝声“buk-buk-buk-buk”，当群体进食时发出，还有更响亮的报警叫声，有时表现为尖锐的尖叫；雄鸟在展示时会发出翅膀拍打的声音；有时在飞行时发出短促的咕噜声“pu...pu...”。文献中曾报道类似的高亢叫声，但这似乎是错误的，因为这种叫声在Syrmaticus属中未被其他成员证实。","habits":"黑颈长尾雉栖息于海拔1200至2800米的开阔橡树-松树林，喜居于散落的林间空地、草地、乡村路边，尤其在清晨活动。在中国，它们出现在多种森林环境中，包括废弃的刀耕火种地块边缘、陡峭岩石山坡上的草丛和蕨类植物，以及云南的海拔1100米处。在广西，它们偏好常绿、阔叶和混合森林（包括松树种植园），高度在740至3000米之间。它们在高大的树木上筑巢，通常离地约3.5米。可能在家庭群中觅食，靠近或在森林边缘的茂密草丛和灌木中。在中国，主要在上午中期至晚期和傍晚时分喂食三小时，春季和秋季偏爱面向东方和北方的斜坡。","breeding":"繁殖期始于3月，广西地区的配对最早在3月初出现，森林空地可见交配行为。繁殖系统不明，推测为多配偶制。巢由干叶、云南松树枝、藤蔓和鸟体羽毛构成，直径约25至30厘米。产卵数3至12枚，颜色为奶油色至玫瑰白色，由雌鸟单独孵化27至28天（圈养条件下）。","identification":"黑颈长尾雉与白颈长尾雉相似，但颜色更淡，喉部颜色不同，肩部羽毛条纹有异。burmanicus亚种与指名亚种相比，颈部颜色略带紫色，臀部白色条纹更宽，尾羽颜色更淡。","protection":"IUCN：VU（易危）","distribution":"黑颈长尾雉分布于印度东北部至中国西南部（云南），泰国北部。在中国，至少有22个已知分布点，最近在极端西南部的贵州发现。在泰国，估计有几百只。在中国，它们分布在云南的哀牢山自然保护区、广西的金钟山国家级自然保护区等地。","other":"金钟山自然保护区内的黑颈长尾雉种群超过300只，占全球数量的10%以上，是极其重要的原生地和全球重要栖息地。"},{"name":"黑长尾雉","english_name":"Mikado Pheasant","scientific_name":"Syrmaticus mikado","overview":"黑长尾雉（英文名：Mikado Pheasant，学名：Syrmaticus mikado），是鸡形目雉科长尾雉属的鸟类。又名帝雉，是台湾特有珍稀雉类，雄鸟通体黑蓝并具白色点斑，脸裸皮鲜红，尾长而尖；雌鸟深褐具浅色羽缘。栖息于中海拔原始阔叶林及针阔混交林，常单独或成对活动于浓密杜鹃与箭竹下层。","appearance":"雄鸟体长约87.5厘米，尾长49–53厘米，体重约1300克；通体黑蓝色带紫蓝鳞状斑，上背及尾上覆羽有可变白斑，下背及腰纯黑；尾极细长，具淡色窄横斑。雌鸟体长约53厘米，尾17–22.5厘米，体重约1015克；羽色似黑颈长尾雉雌鸟但更深，黑褐与白色斑纹对比强烈。幼鸟似雌鸟，头颈喉具淡皮黄色点斑；雄幼鸟尾已现黑白横斑。","call":"平时安静。领域鸣唱为重复的高亢下滑哨音“chip-chi-cheeeuuweet”，间插柔和“chup”低鸣；受惊时发出低沉“wok…wok…” bubbling声，若被迫起飞则叫声变大；雌鸟对雏轻声“cluck”以保持联系。","habits":"栖息于海拔1600–3300米具浓密杜鹃及箭竹下层的原始或次生林，偏好冷温带山地森林。无迁徙记录，但雌鸟家域显著大于雄鸟，且随季节变化：春秋季家域最大，冬季最小。","breeding":"繁殖期可能从3月下旬至7月中旬；交配制度不详，野外多见雄鸟单独或与雌鸟同行，雌鸟则常与雄鸟、其他雌鸟或幼鸟共行。巢以竹秆筑于倒地树干主干或侧枝上，距地约1米。圈养条件下每窝5–10枚乳白色卵，雌鸟单独孵化约28天；雏鸟上体淡栗、红褐与土褐色，下体灰白。","identification":"台湾岛内另两种雉类为蓝腹鹇与环颈雉雉鸡。雄黑长尾雉无蓝腹鹇的白色背与尾；雌鸟具暗色喙、灰色腿、腹面淡斑及尖长渐尖尾，明显不同于雌蓝腹鹇的钝尾及不同色斑纹。","protection":"IUCN: NT（近危）。CITES附录Ⅰ。","distribution":"繁殖区：台湾中央山脉1600–3300米山地森林。非繁殖区：无迁徙，全年留居同一山区。","other":"单型种，无亚种分化。玉山国家公园（640平方公里）近年估计约有一万只个体，种群在保护区内外呈稳定至下降趋势。"},{"name":"铜长尾雉","english_name":"Copper Pheasant","scientific_name":"Syrmaticus soemmerringii","overview":"铜长尾雉（英文名：Copper Pheasant，学名：Syrmaticus soemmerringii），是鸡形目雉科长尾雉属的鸟类。以铜色光泽的羽毛和优雅的长尾著称。常见于本州、四国和九州的森林中，尤其是靠近溪流的密林。该鸟不仅是多个日本地方的官方象征，也曾因过度狩猎而数量锐减。","appearance":"雄性铜长尾雉身长87.5至136厘米，尾长可达48至98厘米；雌鸟较短，约51至54厘米。雄鸟拥有鲜艳的红眼圈和带状长尾，头部呈红栗色，颈部和肩部黑色基底，覆羽具亮铜紫色边缘。雌鸟似环颈雉的日本亚种，但整体偏红，尾短，胸羽有明显白色边缘，羽毛图案不均。幼鸟与雌鸟类似，但年轻雄鸟迅速长出成年雄鸟般的长尾。","call":"铜长尾雉通常不很鸣叫，偶尔发出低沉、沙哑的‘kuk-kuk’声，尤其是在繁殖季节或受威胁时。雄鸟在冬季晚期和春季早期会发出深沉的鼓声。","habits":"铜长尾雉栖息于本州、四国和九州的山地森林，偏好靠近溪流的密林，如杉木和柏树林。它们在树上筑巢，偏好松树，常在陡峭的山坡上。通常单独或成对出现，有时形成六只左右的小群。以橡子、种子为主食，也吃昆虫、蠕虫和小型甲壳类动物。","breeding":"繁殖季节在南方为三月，在北方为四月至五月。雄鸟通过翼鸣展示和争斗来吸引配偶。巢建于地面，常由倒下的树木遮蔽。每窝产7至13枚奶油色或淡黄色的蛋，孵化期约为25天。幼鸟出生后几小时就能行走，跟随母亲直至成年。","identification":"与绿雉相比，雌性铜长尾雉尾更短，颜色更偏红，且胸羽有白色边缘。雄性铜长尾雉与绿雉的区别在于尾部的条纹和颜色差异。","protection":"IUCN：NT（近危）","distribution":"铜长尾雉分布在本州、四国和九州的森林中，海拔高度可达1800米。在日本的南端，如九州，更多见于常绿和落叶阔叶林。","other":"铜长尾雉曾是日本流行的狩猎对象，其数量自1970年代以来持续下降，主要原因是过度狩猎。"},{"name":"白冠长尾雉","english_name":"Reeves's Pheasant","scientific_name":"Syrmaticus reevesii","overview":"白冠长尾雉（英文名：Reeves's Pheasant，学名：Syrmaticus reevesii），是鸡形目雉科长尾雉属的鸟类。大型陆地雉科鸟类，以金色、白色相间的独特羽毛和极长的黑白条纹尾羽著称。雄鸟拥有令人印象深刻的金色胸毛，镶嵌着黑色边缘，而雌鸟则呈现较为朴素的外观，腹部呈桃色，眼部后方有一条深色逗号状条纹。在中国中部和东部的山林中生活，偏好常绿和落叶林地带，包括橡树林。历史上，英国自然学家John Reeves首次将这种鸟引入欧洲。","appearance":"雄性白冠长尾雉体型庞大，总长约210厘米，尾羽长达100-160厘米，体重平均1529克。头部白色，颈部有黑色面具，身体金色带有明显的黑白色鳞片状花纹，尾羽橙色且有黑白相间的醒目标记。雌鸟体型较小，约150厘米长，尾羽33-45厘米，重约949克，颜色较暗淡，脸部呈奶油色，除黑冠外，其余部分与雄鸟有明显差异。幼鸟类似雌鸟，但色泽更淡，前颈更白，胸部有浅棕色条纹。","call":"雄鸟在繁殖季节会发出一系列复杂的鸣叫声，包括嘶嘶声、咕噜声和啾啾声，以及响亮的翅膀鼓动声，用于吸引雌鸟。群落成员间保持联系时会发出柔和的‘pu pu pu’叫声。","habits":"白冠长尾雉栖息于常绿和落叶林中，尤其偏好橡树林，主要活动在海拔200米到2600米之间，常见于陡峭的山坡上。它们主要食用豆科植物、橡子、种子、块茎、萝卜和野生柿子，偶尔也会捕食昆虫。通常在开阔地带或农田边缘觅食，常以小群体的形式活动，尤其是冬季。","breeding":"繁殖季节从4月中旬持续到7月中旬，雌鸟在草丛或灌木丛中筑巢，产卵6-9枚，孵化期约为24-25天。雏鸟由雌鸟独自照顾，孵化后不久便能跟随母鸟外出觅食。","identification":"雄性白冠长尾雉以其醒目的黑白条纹尾羽和金色体羽著称，雌鸟则通过其黑色冠羽和脸部颜色与雄鸟区分。","protection":"IUCN：VU（易危）","distribution":"白冠长尾雉原产于中国中部和东部，分布于陕西、河南、安徽、湖北南部、甘肃南部、四川、云南、贵州和湖南等地。在欧洲、美国、捷克共和国、法国和英国有人工引入的种群。","other":"白冠长尾雉的尾羽在中国传统戏剧中用于头饰，这导致了过度猎捕。在中国，该物种已被列为国家一级重点保护野生动物（自2021年2月5日起）。"},{"name":"雉鸡","english_name":"Common Pheasant","scientific_name":"Phasianus colchicus","overview":"雉鸡（英文名：Common Pheasant，学名：Phasianus colchicus），是鸡形目雉科雉属的鸟类。俗名: 野鸡、山鸡、项圈野鸡、野山鸡、七彩山鸡，又名: 环颈雉，直译: 普通雉。以颈部下方的一圈显著白色环纹命名，足后具革质距，用作防御武器。雉鸡广泛分布于中、低山丘陵的灌丛、竹丛或草丛中，善于奔跑，飞行快速有力。分布于欧亚大陆中部、东部、中国大陆南部、台湾和越南北部。","appearance":"雄性雉鸡脸部红色，颈部蓝绿色，具白颈环，尾长且尖，羽色由橙、金和灰色点缀而成。雌鸟整体深黄褐色，体长50-63厘米，尾长约20厘米。雄鸟体长60-89厘米，尾长占总长近半，约50厘米，胸腹羽毛呈现金色或火红铜色，带有绿紫色光泽，翼覆羽白色或奶油色，尾部有黑色条纹。雌鸟和幼鸟的羽毛较朴素，呈斑驳的棕色。","call":"繁殖季节，雄雉鸡会发出清脆响亮的‘咯-咯咯咯’鸣叫，尤其是在清晨最为频繁，每次鸣叫后，多伴随翅膀的扇动。","habits":"雉鸡栖息于中、低山丘陵的灌丛、竹丛或草丛中，夏季繁殖期可迁至高山，冬季则迁至山脚草原及田野。喜食谷类、浆果、种子和昆虫。飞行快速有力，但偏好奔跑。","breeding":"繁殖期为3-7月，雄雉鸡在繁殖期间占据领域，通过鸣叫宣示领地，进行求偶展示。营巢于地面的草丛、芦苇丛或灌丛中，巢呈碗状或盘状，较为简陋。每年繁殖1窝，南方可达2窝，每窝产卵6-22枚，卵色多样，大小随地理位置变化。","identification":"雄性雉鸡以其独特的蓝色颈部和丰富的羽毛色彩与其它物种区分开，雌鸟则通过斑点和条纹的胸部和腹部与同类相区别。与绿雉相比，雉鸡雄鸟的尾巴更长，颜色更丰富，雌鸟则通常缺少明显的红色标记。","protection":"IUCN：LC（无危）","distribution":"雉鸡原产于亚洲和部分欧洲地区，包括中国南部、台湾、越南北部以及欧亚大陆的中部和东部。在北美、日本、新西兰等地也有引入分布。","other":"雉鸡是全球范围内被广泛猎杀的鸟类之一，同时也被人工饲养和繁殖。"},{"name":"绿雉","english_name":"Green Pheasant","scientific_name":"Phasianus versicolor","appearance":"雄性绿雉有深绿色的胸部、颈部、肩部和侧翼，带有蓝紫色的头部，红色肉垂，以及一条长长的、带有浅灰色条纹的尾巴。雌鸟较小，尾巴较短，羽毛为暗褐色，边缘带有淡褐色。雄鸟的羽毛颜色最深，主要是绿色，而雌鸟通常羽毛颜色较暗。","call":"雄性绿雉发出远传的‘ko-kyok！’叫声，随后是嘈杂的翅膀振动声。它们在惊飞时会大声拍打翅膀并发出嘶哑的叫声。","habits":"绿雉栖息于田野、树篱和灌木丛地区，它们的饮食包括小动物如蠕虫和昆虫，以及谷物和植物。在野外，绿雉经常出现在农田和人类居住区附近。","breeding":"绿雉的繁殖季节始于3月或4月，持续到6月。一窝蛋的数量在6到15个之间，孵化期为23至25天。绿雉可以在大约一年大的时候开始繁殖。","identification":"雌性绿雉可能与铜长尾雉的雌鸟相混淆，尽管后者更倾向于森林环境。绿雉的不同亚种在羽毛颜色上有细微差别，雄性绿雉的羽毛颜色比雌鸟更深。","protection":"IUCN：LC（无危）","distribution":"绿雉遍布于本州、四国、九州以及一些较小岛屿；在日本中部和南部有分布。它们在夏威夷也被引入，但在北美作为狩猎鸟的引入并不成功。","other":"在文化上，绿雉在日本被视为地震的预兆，因为人们认为它们会被地震吓到并尖叫。"},{"name":"红腹锦鸡","english_name":"Golden Pheasant","scientific_name":"Chrysolophus pictus","overview":"红腹锦鸡（英文名：Golden Pheasant，学名：Chrysolophus pictus），是鸡形目雉科锦鸡属的鸟类。雄鸟长约1米，雌鸟约60厘米。雄鸟以金黄色丝状羽冠、红色腹部和金色臀部著称，色彩鲜艳夺目。分布于中国中部和南部的山地森林，亦在英国、加拿大等地建立有野化种群。在中国，被提议作为国鸟候选，其形象在古代曾用于帝王服饰的图案。","appearance":"雄性红腹锦鸡长达100–115厘米，尾长63–79厘米，重575–875克；雌鸟较短，61–70厘米长，尾长34–37.5厘米，重350–700克。雄鸟拥有醒目的红色下体、黄色脸部、金色的冠和臀部，以及金色披肩羽，可扇形展开。雌鸟比雉鸡更显斑驳，腿部和眼周皮肤呈黄色，头部花纹简单，尾羽更尖锐。幼鸟外观似雌鸟，但色调更暖，条纹更少且不规则。成年雄鸟的首年特征介于雌雄之间。","call":"雄鸟的广告鸣叫在2月至5月间最为频繁，声音清脆远扬，带有‘ka-cheek’音节，其中第二音节响亮而高亢，与白腹锦鸡有所不同。","habits":"红腹锦鸡栖息于中国西部山地的常绿阔叶林、针阔混交林及针叶林，冬季下山至农田觅食。它们偏好有矮树的山坡和次生亚热带阔叶林，夜晚栖息于树上。食性杂，以植物为主，包括蕨类、豆科植物、草籽等，偶尔食用昆虫和小型无脊椎动物。","breeding":"繁殖期在4月至6月，雄鸟通过展示华丽羽毛求偶，一雄多雌。雌鸟独自从4月开始在隐蔽处筑巢产卵，每窝产卵5–9枚，卵孵化期约为22–23天，雏鸟为早成鸟。","identification":"雄性红腹锦鸡的金色羽冠、红色腹部和金色臀部使其独特且易于识别。雌鸟与白腹锦鸡的区别在于更轻的条纹、更多的橙色色调和眼部后方无裸露灰皮。","protection":"IUCN：LC（无危）。尽管数量估计在数十万，但因非法捕猎和栖息地破坏导致数量下降。在中国，受多个保护区保护。","distribution":"原生于中国中部和南部，包括青海东南部、甘肃南部、陕西南部、河南西部、湖北西部、四川、云南西北部、贵州北部至广西北部。引入英国、加拿大等地。","other":"自18世纪以来，欧洲广泛饲养繁殖，现为全球动物园常见雉类。"},{"name":"白腹锦鸡","english_name":"Lady Amherst's Pheasant","scientific_name":"Chrysolophus amherstiae","overview":"白腹锦鸡（英文名：Lady Amherst's Pheasant，学名：Chrysolophus amherstiae），是鸡形目雉科锦鸡属的鸟类。俗名: 有铜鸡、笋鸡、衾鸡、箐鸡、宽宽鸡、花箐鸡（雄）、麻箐鸡（雌）、鸟林、垅宗、打敲、庄七、尖冲，是中国特有鸟类之一，亦在缅甸东北部有分布。雄鸟拥有华丽的羽毛，长条纹尾，白色腹部，颈部长有黑白相间的鳞状斑纹。雌鸟棕色，有黑色条纹，眼周皮肤灰。分布于中国西南山区，是清代二品文官官服上的鸟类图像，地位仅次于皇帝的龙、皇后的凤凰及一品文官的丹顶鹤。","appearance":"雄性白腹锦鸡身长130-173厘米（尾长83-115厘米），体重675-850克；雌鸟身长66-68厘米（尾长28-37厘米），体重624-804克。雄鸟特征鲜明，长尾黑白分明，颈项有独特的黑白鳞状斑纹，下背及臀部亮黄色，上尾覆羽橙红色，头部橙红色羽毛下垂。雌鸟较小，颜色较暗，腿和眼周皮肤蓝灰色，尾羽更圆润。幼鸟色泽较淡，缺乏成鸟的丰富色彩，条纹不明显。","call":"雄鸟在繁殖季节会发出响亮而尖锐的叫声，通常是三音节，强调第一个音符，类似于'cheek ker-chek'。","habits":"白腹锦鸡栖息于海拔1800至4600米的山地，偏好常绿阔叶林、针阔叶混交林和针叶林，夏季可能进行显著的垂直迁移。它们以植物茎叶、花果、种子和昆虫为食，冬季会形成20-30只的大群，通常白天在地面活动，夜晚栖于树上。","breeding":"繁殖期为4月至6月，实行一雄多雌制。雄鸟在3月初开始发情，通过鸣叫和展示羽毛吸引雌鸟。巢建于隐蔽的灌木丛、草丛或枯木下，产卵5-9枚，卵呈浅黄褐色或乳白色。孵化期约22-23天，由雌鸟单独孵化。","identification":"与同属的白颈长尾雉相比，白腹锦鸡的雌鸟具有更丰富的锈红色调，尾羽更圆，腿和眼周皮肤为蓝灰色而非黄色。雄鸟的羽毛更加艳丽，尾部特征明显。","protection":"IUCN：LC（无危）。在中国野外仍有一定数量，但在云南、四川和贵州的主要分布区面临栖息地破坏和过度捕猎的压力。","distribution":"分布于中国西南山区，包括缅甸东北部、西藏东南部，以及中国的四川、云南和贵州西部。在英国曾有人工引入，但目前数量极少。","other":"白腹锦鸡是中国国家二级保护动物，历史上曾在英国被引入，但其在英国的自然种群已几乎消失。"},{"name":"铜尾孔雀雉","english_name":"Bronze-tailed Peacock-Pheasant","scientific_name":"Polyplectron chalcurum","overview":"铜尾孔雀雉（英文名：Sumatran Peacock-Pheasant，学名：Polyplectron chalcurum），是鸡形目雉科孔雀雉属的鸟类。原生于印尼苏门答腊山区的鸟类。体型小巧，长约56厘米，全身深褐色，脚色深灰。其特征为细小的头部与16根长而窄的栗褐色尾羽，尾端带有金属紫色条纹。雄鸟个体比雌鸟更大，腿上具两距，眼黄；雌鸟无距，眼色深褐。","appearance":"铜尾孔雀雉体长可达56厘米，雄鸟尾长26至38厘米，体重370至590克；雌鸟尾长18至22厘米，体重238至269克。雄鸟拥有较雌鸟更长的尾羽和两距，眼色为黄色。雌鸟无距，眼色深褐。幼鸟与成年雌鸟相似，但色彩稍淡，带红，尾羽上的蓝紫色较少。亚种scutulatum比chalcurum斑纹更明显，但个体差异大。","call":"雄鸟发出远传的'karau, karau, karau'叫声，第二音节音调略高。在圈养环境中，会发出颤音、重复的'pitt'声和各种咕噜声。最活跃的鸣叫期可能在11月至次年1月。","habits":"栖息于苏门答腊山脉的多种低海拔山地森林，包括未受干扰和已砍伐的森林，以及松树林。活动范围在800至1800米之间。通常单独活动，偏好在茂密灌木丛中悄悄觅食。以小型果实和昆虫为食。","breeding":"繁殖习性知之甚少。巢筑于树基部的草丛中，形状为杯状，宽约15厘米，深10厘米，用干枯的深棕色树叶和小树枝搭建。巢中发现过两枚蛋，蛋壳颜色为淡褐色或白色。孵化期约为22天，雏鸟上身黑色，下身棕褐色。","identification":"铜尾孔雀雉与同属其他物种的区别在于其尾羽末端的金属紫色斑块，而非眼状斑点。雄鸟有距，雌鸟无距，这是辨识要点之一。亚种scutulatum与chalcurum相比，上方斑纹更明显，但个体间变异较大。","protection":"IUCN：LC（无危）","distribution":"铜尾孔雀雉分布于印尼苏门答腊岛西部的山区，包括北部和中部苏门答腊，从Ketambe（Gunung Leuser）南部到Mt Kerinci。在Padang高地等地较为常见。"},{"name":"山孔雀雉","english_name":"Mountain Peacock-Pheasant","scientific_name":"Polyplectron inopinatum","overview":"山孔雀雉（英文名：Mountain Peacock-Pheasant，学名：Polyplectron inopinatum），是鸡形目雉科孔雀雉属的鸟类。中等体型，身长可达65厘米，以黑色棕色为主色调，拥有小眼斑和长长的渐层尾羽。雌雄两性外观相似，雄鸟具有金属蓝色上部眼斑、绿色尾部眼斑以及腿部的两个刺状突起，而雌鸟的上部眼斑为黑色，尾巴略短且无腿刺。雌鸟比雄鸟更小、颜色较暗淡。","appearance":"雄性山孔雀雉长约65厘米，尾羽占32至40厘米；雌鸟约46厘米，尾羽22至27.5厘米。身形修长，尾羽显著，头部较小，无明显冠羽，与凤冠孔雀雉相比，头部和下体颜色更深，上体呈红棕色，尾羽更长更窄。雄鸟有微小蓝绿色眼斑，雌鸟类似雄鸟但体型更小，尾羽更短，眼斑被黑点替代。喙和腿灰色，虹膜棕色；雄鸟有一或两个腿刺，雌鸟无腿刺。","call":"通常被认为比同类物种叫声少。雄鸟领地叫声由1至4个（通常为2个）响亮、嗡嗡作响、拉长的呱呱声或咯咯声组成，带有轻微的电子质感，每间隔5至6秒发出一次；报警叫声类似于家鸡的咯咯声；还发出一种下降的气泡式哨声。","habits":"生活在未被砍伐的上层龙脑香森林和低地山地森林与高山森林，海拔高度从820米到2000米，偶尔或局部可能降至600米。以蜘蛛、白蚁、幼虫和其他未识别的动物物质为食，也食用Calamus竹类果实和其他无脊椎动物（如甲虫）。","breeding":"繁殖季节大约始于1月，基于马来西亚发现轻度孵化的卵和2月底的小雏鸟以及6月时的半大幼鸟。推测其交配制度为一夫一妻制。雄鸟展示包括身体摇晃、快速交替展翅行走、站立振翅、下垂飞羽倾斜尾羽、前胸降低翼尾上扬、步伐抬高头颈羽毛抖动、点头和仪式性的食物传递。巢穴位于岩石间或倒下的树木之间，也有简单的刮痕巢穴。","identification":"与凤冠孔雀雉的区别在于头部和下体颜色更深，上体红棕色，尾羽更长更窄。与冠眼斑雉和大眼斑雉相比，体型更大，头部图案独特。第一年雄鸟比成年雌鸟更小、颜色更暗。雏鸟与成年雌鸟相似，但年轻雄鸟腿更长。","protection":"IUCN：NT（近危）","distribution":"分布于马来半岛山区，从金马伦高地南至云顶高原，延伸至拉鲁特山脉西北部，东部山峰包括Tahan山和Benom山。有证据表明，该物种也可能出现在泰国南部的Yala省。","other":"面临栖息地破坏、农业扩张和城市发展的威胁。拟建连接Genting Highlands、Fraser's Hill和Cameron Highlands的公路可能会破坏大量山地森林。"},{"name":"眼斑孔雀雉","english_name":"Germain's Peacock-Pheasant","scientific_name":"Polyplectron germaini","overview":"眼斑孔雀雉（英文名：Germain's Peacock-Pheasant，学名：Polyplectron germaini），是鸡形目雉科孔雀雉属的鸟类。中等体型，长约60厘米，以深褐色带淡黄色斑点的羽毛、短冠、红色裸露面部皮肤和紫蓝色眼斑而著称。该物种分布于越南南部和柬埔寨东部，常在季节性热带森林中发现。","appearance":"眼斑孔雀雉体长约60厘米，全身呈深褐色，点缀着精细的淡黄色斑点。雄鸟拥有一对长达20根的尾羽，雌鸟尾羽则为18根，体型较雄鸟略小。其面部裸露部分为红色，瞳孔为褐色，上体羽毛和半数尾羽上布满独特的紫蓝色大眼斑点。雌雄两性外观相似。","call":"雄性眼斑孔雀雉发出一系列低沉、沙哑的颤音，每个颤音持续2至4秒，间隔3至11秒重复，当受到惊吓或回应竞争对手时，间隔时间会缩短。","habits":"眼斑孔雀雉主要栖息于低地和亚山地森林，包括以龙脑香为主的常绿和半常绿森林，也能在荆棘竹林中看到它们的身影。这种雉类似乎能容忍一定程度的生境干扰，曾在沼泽、采伐和次生林中被记录到，海拔高度可达至少1400米。它们通常通过步行逃避危险，但在迫不得已时也会低飞快速逃离。","breeding":"繁殖信息有限，仅知一对眼斑孔雀雉携幼鸟在四月被观察到。在野外，已知的唯一巢穴是一个浅坑，内衬绒毛，含一枚蛋。在圈养条件下，产卵数为1至2枚乳白色的蛋，孵化期约为21天。雏鸟上体覆有深栗褐色绒毛，下体颜色更偏黄褐色。","identification":"眼斑孔雀雉雄鸟与同属的其他物种的区别在于缺乏头冠或颈饰，上体和翅膀上的眼斑被一圈淡金色棕色环包围。雌鸟相比同性别的，整体颜色更深、更均匀，上体的眼斑较小、尖锐且边界更清晰。","protection":"IUCN：VU（易危）","distribution":"眼斑孔雀雉分布于越南南部（从南安南北至14°N）和柬埔寨东部（包括拉塔纳基里省和蒙多基里省）。有报告称在老挝和泰国也有出现，但可能性极低。在越南的Cat Tien国家公园和柬埔寨的Snoul野生动物保护区及Seima保护区森林中较为常见。","other":"眼斑孔雀雉的分类学位置有些神秘，分子数据证实它与灰孔雀雉、青铜尾孔雀雉和山孔雀雉属于同一演化支。"},{"name":"灰孔雀雉","english_name":"Grey Peacock-Pheasant","scientific_name":"Polyplectron bicalcaratum","overview":"灰孔雀雉（英文名：Grey Peacock-Pheasant，学名：Polyplectron bicalcaratum），是鸡形目雉科孔雀雉属的鸟类。又名: 孔雀雉、诺光贵，大型亚洲雉科鸟类，分布于孟加拉国、印度东北部和东南亚部分地区，排除了大部分印度支那和马来半岛。雄鸟体长可达76厘米，雌鸟略小。全身灰褐，点缀有绿色虹彩的眼状斑点，拥有独特的前倾冠羽，面部皮肤粉或黄色，喉部白色。该物种面临栖息地破坏的威胁，被列为国家一级重点保护动物。","appearance":"雄性灰孔雀雉体长56-76厘米，尾长35-40厘米；雌鸟48-55厘米，尾长23-25.5厘米。雄鸟具有丰满的冠羽，展开时前垂过喙，每颗眼状斑被白色环包围。雌鸟较小，缺乏雄鸟的刺（雄鸟最多有四颗），羽毛较暗淡，眼状斑小且黑色，带有紫光。雄鸟的腿和喙为暗灰色或黑色，虹膜白色或浅灰色，眼周裸露皮肤呈淡黄色至暗粉色。幼年雄鸟比成年雄鸟小，冠羽和颈毛相对较短，眼状斑黑色，尾部较短，仅有弱刺。雌鸟幼鸟类似成年雌鸟，但年轻雄鸟腿更长，几周后可能有更大的金属紫眼状斑。","call":"雄性灰孔雀雉发出尖锐的哨音，重复多达五次，间隔不规则，声音如‘trew-tree’，第二声较长且上升，以及粗哑的‘qua qua qua’声，可能在警报时发出。","habits":"灰孔雀雉栖息于低地和山地森林，最高可达海拔1400米，但在不丹、泰国和云南可达1700米、1800米和2000米。它们偏好有大量竹子的浓密常绿和半常绿森林。它们在降级和烧过的次生森林以及老林碎片中也有记录，至少在老挝是这样。它们的饮食主要包括浆果、水果（如李子和枣）、种子、野无花果、幼虫、蚂蚁、其他昆虫、蜗牛和其他小型动物，特别偏爱白蚁。它们会吃竹子的种子和来自村庄耕种的稻谷和谷物。觅食时动作缓慢而隐蔽，通常独自、成对或小家庭群体活动。","breeding":"在印度东北部，繁殖期为3月至6月，主要集中在4月至5月；在孟加拉国，繁殖期为4月至5月。繁殖系统不明，推测为一夫一妻制，但在圈养中报道有多配偶制。巢位于空洞中，通常在竹丛底部或茂密灌木中；次生植被纠结处似乎受到青睐。一窝蛋数为2-5枚，颜色从浅奶油色到丰富的巧克力色，表面有白色斑点，但可靠数据较少；孵化期21天（在圈养条件下）；雏鸟的上部为深棕色绒毛，下部为肉桂色。","identification":"雄鸟katsumatae亚种与其他灰孔雀雉雄鸟的区别在于体型较小、面部皮肤颜色更为鲜艳、眼状斑形状不同、缺乏延长的冠羽、头部颜色更深、身体羽毛更加密集和整齐、整体色彩更偏向棕色而非灰色。","protection":"IUCN：LC（无危）；CITES: 附录II；中国国家重点保护野生动物名录：一级","distribution":"灰孔雀雉分布于锡金至越南中部的低地和山地森林，包括孟加拉国、印度东北部和东南亚部分地区，但不包括印度支那大部分地区和整个马来半岛。","other":"过去描述的一些亚种目前不再被认可，如Lowe's灰孔雀雉。海南孔雀雉现被认为是独立物种。该物种的系统发育关系复杂，分子数据显示它属于一个主要分布在大陆亚洲的分支，与眼斑孔雀雉、铜尾孔雀雉和山孔雀雉关系密切。"},{"name":"海南孔雀雉","english_name":"Hainan Peacock-Pheasant","scientific_name":"Polyplectron katsumatae","overview":"海南孔雀雉（英文名：Hainan Peacock-Pheasant，学名：Polyplectron katsumatae），是鸡形目雉科孔雀雉属的鸟类。是中国特有的珍稀濒危雉类，体型较小，具红面部皮肤，区别于灰孔雀雉的黄橙色面部皮肤。分布仅限于中国海南岛，是极度濒危物种。","appearance":"雄鸟体长53-65厘米（含尾），雌鸟40-45厘米（含尾）。雄鸟头部和颈部暗棕色，有细浅色条纹，前冠羽延长形成向前指的蓬松顶冠；下巴和喉咙白色，其余羽毛深棕色至黑色，饰有淡色花纹和斑点。上部羽毛，包括翼覆羽和三级飞羽，每个都有一个突出的蓝或绿色眼斑，靠近尖端，尾上覆羽类似。雌鸟比雄鸟小，颜色较为暗淡。幼鸟信息有限，可能与雌鸟相似。","call":"雄鸟发出短暂的响亮系列‘guang-gui’声，首音较拖长，雌鸟在警戒时发出快速的‘ga-ga-ga’声串。","habits":"栖息于海拔150-1500米的热带常绿阔叶林及竹丛中，偏好成熟次生林环境，常见于Homalium hainanense、Podocarpus imbricatus、Vatica mangachapoi等树种为主的森林。单独或成对活动，以昆虫、蠕虫、果实、种子为食。夜间在树上休息。","breeding":"繁殖期通常在2-3月开始，巢建于地面，由枯叶和草构成，直径可达23厘米。每巢产卵1-2枚，白色，孵化期未知，但估计高捕食率威胁着繁殖成功率。","identification":"与灰孔雀雉相比，海南孔雀雉更小，具有红色而非灰色或黄色的面部裸露皮肤，绿色而非紫色的眼斑，更暗的冠羽，身体羽毛更加密集且有花纹，整体色调更偏褐色。","protection":"IUCN：EN（濒危）。全球估计数量在250-1000只之间，分布于18个地点。自1990年以来严重下降，当时估计约有2700只。自20世纪中叶以来，栖息地丧失和狩猎导致其数量锐减，目前仍为主要威胁。在九个保护区中存在，但保护力度可能不足。","distribution":"分布于中国海南岛的中部和西南部，包括Bawangling、Jianfengling和Diaoluoshan国家自然保护区，以及Baomei、Ganshiling、Houmiling、Huishan、Jiaxi、Limushan和Yinggeling省级自然保护区。","other":"曾被认为是灰孔雀雉的亚种，但分子标记研究确认了其独立物种的地位，两物种的分化时间约为1.4±0.3百万年前，与中国大陆分离的时间相近。"},{"name":"凤冠孔雀雉","english_name":"Malayan Peacock-Pheasant","scientific_name":"Polyplectron malacense","overview":"凤冠孔雀雉（英文名：Malayan Peacock-Pheasant，学名：Polyplectron malacense），是鸡形目雉科孔雀雉属的鸟类。中等身形的雉。其最显著的特征是雄鸟的蓝绿色眼斑与独特的向前指向的羽冠。分布于泰国南部和马来半岛低地雨林中。","appearance":"雄鸟长约50至53厘米，尾长24至25厘米，体重581至680克。雌鸟较短，约40至45厘米，尾长18至19厘米，体重455至540克。雄鸟拥有厚实的体型、鲜艳的红色面部皮肤和向前指的羽冠。雌鸟无刺，羽冠较短，眼斑由三角黑点替代。","call":"雄鸟领地鸣叫为缓慢、忧郁的“puu pwoii”声，第二音更长且上扬，另有响亮的“tchorr”声。叫声主要在黎明和黄昏发出，可传至约250米远。","habits":"栖息于低地常绿雨林，偏好有高大龙脑香树的森林地带，通常不超过150米海拔，偶尔可达300米。以昆虫、果实为主要食物，通过扒开枯叶觅食。","breeding":"繁殖季节不确定，但可能是多妻制。雄鸟清理展示区，吸引雌鸟。已知的巢仅四个，产卵数为一，孵化期约22至25天，由雌鸟单独孵化。","identification":"与山孔雀雉相比，体型较小，胸部和下体几乎呈黑色，尾部更长更窄，缺乏羽冠和红色面部皮肤。","protection":"IUCN：EN（濒危）","distribution":"分布在泰国南部和马来半岛（几乎仅限克拉地峡以南），可能在泰国已灭绝，未确认在苏门答腊和缅甸的存在。","other":"自1970年以来，其分布范围大幅收缩，目前仅在部分保护区得以生存。"},{"name":"加里曼丹孔雀雉","english_name":"Bornean Peacock-Pheasant","scientific_name":"Polyplectron schleiermacheri","appearance":"雄性婆罗洲孔雀雉长约50厘米，尾长19至20厘米；雌鸟约35.5厘米，尾长15.5至18厘米。雄鸟的喉咙和胸中心为纯白色，两侧胸为金属蓝绿色，上体较红棕色，具较小的眼状斑点和类似毛发的冠羽，能竖起形成小而蓬松的前倾冠。雌鸟缺乏雄鸟的脚部刺突，头部标记不明显，全身偏红棕色，尾巴较短，尾覆羽无眼状斑点，尾羽上的眼状斑点较小且界定不明。喙和腿为深灰色，眼周皮肤为红色，虹膜雄鸟为淡蓝色，雌鸟为棕色。第一年雄鸟似成年雌鸟，但体型更大、色彩更鲜艳，飞羽外缘有红棕色和淡色斑驳，下体有虫蚀状纹。幼鸟描述不详，但可能与成年雌鸟相似。","call":"雄性婆罗洲孔雀雉的叫声为一系列逐渐增强的嘶哑声，典型于Polyplectron属，还有响亮的双音节‘kank kank’叫声，带有类似鸭子般的音质。","habits":"主要栖息于原始低地森林，包括火灾后再生的地区、低地龙脑香林和冲积森林，偏好森林山脊而非平地或斜坡。在东加里曼丹，没有明显的森林类型偏好。报道的海拔范围从海平面到1070米。运动、饮食和觅食行为未知。","breeding":"繁殖季节可能为10月底至次年3月中旬。野生状态下的繁殖信息不详，但推测其繁殖系统为一雄多雌制。在圈养条件下，一只雌鸟产下了三个单卵窝；孵化期为20至22天。","identification":"雄性婆罗洲孔雀雉与马来亚孔雀雉相比，上体更红棕色，眼状斑点较小，冠羽质地似毛发，可竖立形成小而蓬松的前倾冠。雌鸟比马来亚孔雀雉雌鸟更红棕色，尾巴更短，尾覆羽无眼状斑点，尾羽上的眼状斑点较小且界定不明。与帕拉旺孔雀雉相比，尾羽形态和图案介于两者之间。","protection":"IUCN：EN（濒危）","distribution":"婆罗洲孔雀雉分布于婆罗洲，确切分布范围不确定，但已知存在于多个保护区，包括东加里曼丹的Sungai Wain和Gunung Lumut保护森林、西加里曼丹的Gunung Palung国家公园、沙巴的Deramakot森林保护区和砂拉越的Gunung Mulu国家公园。","other":"因持续的栖息地丧失、种群数量少和分布范围有限，婆罗洲孔雀雉面临严重威胁。"},{"name":"巴拉望孔雀雉","english_name":"Palawan Peacock-Pheasant","scientific_name":"Polyplectron napoleonis","overview":"巴拉望孔雀雉（英文名：Palawan Peacock-Pheasant，学名：Polyplectron napoleonis），是鸡形目雉科孔雀雉属的鸟类。大型壮观的地面鸟类，主要分布在菲律宾西南部的巴拉望岛。雄鸟拥有独特的蓝色标记翅膀、灰色斑点背部和蓝色孔雀“眼睛”的尾羽，而雌鸟全身棕色，脸部淡色，具有独特性。","appearance":"雄鸟约50厘米长，尾长24至25厘米，体重约436克；雌鸟约40厘米长，尾长16.5至17厘米，体重约322克。雄鸟具长而尖的冠羽，全身乌黑，翼上点缀着蓝色光泽，背部和上翼覆羽闪耀蓝绿，脸部黑白相间的图案鲜明。雌鸟总体棕色，散布着淡色标记，尾巴有模糊的黑斑，脸、眼圈和喉咙为棕白色。","call":"发出刺耳的‘skrark！’或尖锐的‘skrik！’叫声。","habits":"栖息于巴拉望岛的原始森林和次生森林，海拔可达1500米，包括密集的竹林区域。它们可能偶尔出现在海岸低地森林和矮树丛中。","breeding":"繁殖资料缺乏，但在圈养条件下，产两枚粉红至乳白色的蛋，仅由雌鸟孵化，孵化期18至20天，雏鸟上部为淡褐色绒毛，下部更偏黄褐色。","identification":"雄鸟与所有近缘种显著不同，雌鸟与菲律宾塚雉或红原鸡雌鸟相似，但腿更短，尾巴更长，颜色更均匀的棕色。","protection":"IUCN：VU（易危）；CITES I（濒危野生动植物种国际贸易公约附录一）。","distribution":"仅分布于菲律宾西南部的巴拉望岛，包括山区和沿海低地森林。","other":"在巴拉望岛的文化中占有重要地位，出现在当地民族的语言和艺术中，也是Puerto Princesa市的官方标志。"},{"name":"冠眼斑雉","english_name":"Vietnamese Crested Argus","scientific_name":"Rheinardia ocellata","overview":"冠眼斑雉（英文名：Vietnamese Crested Argus，学名：Rheinardia ocellata），是鸡形目雉科冠眼斑雉属的鸟类。体型庞大的物种，拥有黑褐相间、斑点密布的羽毛，粉红喙，棕色虹膜，以及眼周蓝色皮肤。雄鸟以其超长的十二根尾羽闻名，尾羽长度超过体长，最长可达1.73米。雌鸟体型较小，尾部较短，背部花纹更为醒目，脸部白羽具独特图案。","appearance":"雄性冠眼斑雉体长1.9至2.39米，尾羽展开时极为壮观，雌鸟平均体长74至75厘米。雌雄两性均具有独特的双冠，其中后冠在警戒或求偶时会竖立。雌鸟的冠羽更刚硬，覆盖头部和上颈更多面积。雄鸟体重略重于雌鸟，平均约1.5千克。翼展宽大，形状类似Argusianus属，脚趾修长，雄鸟腿部鳞片发达，形似蜥蜴。","call":"雄性冠眼斑雉的领地叫声与大眼斑雉相似，响亮而富有回音，通常在繁殖季节发出，包括三音节的\"WOO KIA'WAU\"，以及一系列六到八个远距离传播的双音节\"oowaaa\"叫声。","habits":"栖息于东南亚越南和老挝的次山原始森林，偏好海拔680至1900米的环境。饮食以昆虫、软体动物、两栖动物、小型爬行动物、竹笋、树叶、果实和真菌为主。夜间休息于树冠层。","breeding":"繁殖季节始于3月，雄鸟通过维护跳舞场和鸣叫吸引雌鸟，可能为一雄多雌制。在野外，巢址选择于高处，产卵数量少，每窝1至2枚，孵化期25天。雏鸟孵化时已具备飞行能力，前几周由亲鸟喂食。","identification":"马来冠眼斑雉比冠眼斑雉颜色更深，尾羽更长，白色部分更多。","protection":"IUCN：CR（极危）","distribution":"分布于越南中部和老挝东部，包括越南的Bach Ma国家公园、Vu Quang自然保护区，以及老挝的Nakai-Nam Theun国家生物多样性保护区。","other":"面临栖息地丧失和过度狩猎威胁，被列入CITES附录I。曾与马来冠眼斑雉同属一种。"},{"name":"马来冠眼斑雉","english_name":"Malayan Crested Argus","scientific_name":"Rheinardia nigrescens","overview":"马来冠眼斑雉（英文名：Malayan Crested Argus，学名：Rheinardia nigrescens），是鸡形目雉科冠眼斑雉属的鸟类。以其独特的黑褐色斑点羽毛、粉红色喙、棕色虹膜和蓝色眼周皮肤著称。雄鸟拥有宽大的尾羽，长达1.73米，是目前已知鸟类中最长的羽毛之一。雌鸟体型较小，羽色多彩，尾羽较短。","appearance":"雄性马来冠眼斑雉具有显著的双冠，后冠可竖立，尾羽极长，可达1.9至2.39米，尾羽覆羽为最长。雌鸟体型较小，约74至75厘米，背部羽毛色彩丰富，尾羽压缩且较短。两性均有独特的白色面部羽毛，但雌鸟的羽冠更为刚硬，覆盖头部后部及上颈。雄鸟的体重比雌鸟重约20%，平均体重约为1.5公斤。其翅膀宽大，边缘无明显的次级飞羽缺口，表明有持续飞行能力。脚和腿具有扩展的鳞片，趾长而细。","call":"马来冠眼斑雉发出的短叫声为流畅的哨音，开始时音调平稳，中间颤动，结尾音调稳定。长叫声则为一系列响亮的抑扬顿挫的双音节音符，有时以哨音开始和结束。尖锐叫声罕见，可能与警报有关。","habits":"马来冠眼斑雉生活在马来西亚半岛的山地森林中，海拔高度介于650至1380米之间。它们主要以昆虫、软体动物、小型脊椎动物、竹笋、叶子、果实和真菌为食。雄鸟占据领地，维护跳舞场地，进行各种展示行为，包括翅膀和尾巴的垂直推入地面，以及展翅和展尾。","breeding":"繁殖季节始于三月，雄鸟通过鸣叫吸引雌鸟，维护领地。巢址位于陡峭斜坡的落叶层中，产卵数为一到两个，孵化期约为25天。雏鸟出生时已具备发达的翼羽，最初几周由母鸟喂食。","identification":"马来冠眼斑雉与冠眼斑雉有明显的形态差异，包括羽色、羽冠、叫声等，且分布区域不同。与大眼斑雉相比，其白喉更明显，眉纹颜色不同，尾羽覆羽的白色斑点更加突出。","protection":"IUCN：NT（近危）, CITES: I","distribution":"马来冠眼斑雉分布于马来西亚半岛中部的塔曼纳加拉国家公园附近山区，包括Gunung Rabong、Gunung Gagau、Gunung Tulang Rabong、Gunung Mandi Angin、Gunung Penumpu和Gunung Tahan等山脉。","other":"马来冠眼斑雉曾被认为是冠眼斑雉的同种，直到最近才被确认为独立物种。"},{"name":"大眼斑雉","english_name":"Great Argus","scientific_name":"Argusianus argus","overview":"大眼斑雉（英文名：Great Argus，学名：Argusianus argus），是鸡形目雉科大眼斑雉属的鸟类。又名: 青鸾或百眼雉鸡，大型鸟类。以其蓝头红胸、褐色羽毛、以及雄鸟独特的长尾和翼上的大眼装饰著称。广泛分布于东南亚的马来半岛、苏门答腊和婆罗洲的热带雨林中。","appearance":"雄性大眼斑雉总长可达160至200厘米，其中尾长105至143厘米，体重2.04至2.72千克。拥有非常长的尾羽和宽大的次级飞羽，上面饰有众多眼状斑点，这些飞羽在第三年发育成熟。雌鸟体型较小，全长72至76厘米，尾长30至36厘米，体重1.36至1.7千克，尾羽和眼状斑点比雄鸟少，颜色也较为暗淡。雌雄均有蓝色面部皮肤，雄鸟的头部和颈部相对较小，几乎无毛，雌鸟的冠部呈棕色。幼鸟外观与雌鸟相似，但更为红棕色。","call":"雄性大眼斑雉有两种独特的响亮叫声，一种是双音节的'kwow-wow'声，另一种是单音节的音乐般的'wow'声，后者可连续发出多达70次，声音逐渐升高至突然停止。","habits":"大眼斑雉栖息于低地至山脚的森林中，偏好植被较稀疏且有成熟树木的环境。它们主要在清晨和傍晚于地面觅食，以各种植物和无脊椎动物为食，尤其喜欢棕榈科、木兰科和豆科的果实。雄鸟有固定的领地，通常保持在1.0至2.7公顷之间，而雌鸟的移动模式尚不清楚。","breeding":"繁殖季节在不同地区和年份间有所变化，但通常在3月初至7月初，雌鸟每次产两枚淡黄白色至浅红褐色带褐色斑点的蛋，大小约为61.5至69.1毫米×42.4至46.3毫米，孵化期大约24至25天。雄鸟会在森林中清理出一片空地作为求偶场，展示其翅膀上的数百个‘眼睛’。","identification":"雄性大眼斑雉与（另一种雉类）在马来西亚半岛可能混淆，但后者具有图案化的脸部、更长的白色顶冠和较淡的腿部颜色。雄性大眼斑雉的头部和颈部极小且相对裸露，尾羽极为延长，雌鸟则有特色顶冠和棕色的冠部。","protection":"IUCN：VU（易危）。","distribution":"大眼斑雉分布于东洋界，具体包括马来半岛、印尼苏门答腊岛和婆罗洲的热带雨林。","other":"尽管大眼斑雉的求偶展示类似多配偶制鸟类，但实际上它们是一夫一妻制的。"},{"name":"蓝孔雀","english_name":"Indian Peafowl","scientific_name":"Pavo cristatus","overview":"蓝孔雀（英文名：Indian Peafowl，学名：Pavo cristatus），是鸡形目雉科孔雀属的鸟类。主要分布于巴基斯坦、印度和斯里兰卡，为印度国鸟。雄鸟拥有引人注目的蓝色羽毛和壮观的尾羽，尾羽上带有独特的‘眼睛’图案，用于吸引雌鸟。雌鸟体型较小，羽毛色彩较暗淡，主要为褐色。","appearance":"雄性蓝孔雀的颈部、胸部和腹部呈现出鲜艳的蓝色，羽毛闪耀着金属光泽，背部呈紫铜色，尾羽长达1米以上，能展开成扇形。尾羽上的‘眼睛’由多种色彩构成，展开时光彩夺目。雌性蓝孔雀体长约1米，羽毛以灰色和褐色为主，无尾屏，体型较小。幼鸟的冠羽为棕色，颈部为深蓝绿色，羽毛较为松软，有时带棕黄色。","call":"蓝孔雀会发出响亮的‘pi-ow’或‘may-awe’叫声，特别是在雨季前叫声频率增加，可能在受到惊吓或听到噪音时也会发出叫声。森林中的叫声常指示附近有天敌如老虎的存在。","habits":"蓝孔雀栖息于海拔2000米以下的开阔草原、灌木丛和竹丛地带，适应性强，能在较宽的温度范围内生存。它们通常以小群体活动，包括一只雄鸟和3到5只雌鸟。食物多样，包括果实、谷物、昆虫（如蟋蟀和蝗虫）、小型爬行动物，尤其是白蚁。白天在地面觅食，晚上飞至树上休息。","breeding":"繁殖期始于每年4月，持续至8月。雄鸟在此期间极具攻击性，甚至会攻击镜中的自己。雌鸟在灌木丛、草地或落叶林中筑巢，每次产卵4至8枚，孵化期约为28天，仅由雌鸟承担孵化任务。雏鸟孵化后跟随母鸟。","identification":"与绿孔雀相比，蓝孔雀的腿、颈和尾羽相对较短，雌雄差异明显。雄性蓝孔雀的‘眼睛’数量是吸引雌鸟的关键特征。","protection":"IUCN：LC（无危）","distribution":"主要分布在印度、巴基斯坦和斯里兰卡。在中国大陆地区，蓝孔雀可能在某些动物园或私人饲养中可见。","other":"蓝孔雀在印度文化中具有重要意义，被视为驱蛇的象征，且在很多地方受到法律保护。"},{"name":"绿孔雀","english_name":"Green Peafowl","scientific_name":"Pavo muticus","overview":"绿孔雀（英文名：Green Peafowl，学名：Pavo muticus），是鸡形目雉科孔雀属的鸟类。东南亚热带森林中的大型鸡类。以其绚丽的绿色颈羽和独特的外观著称，分布于东南亚和印度支那地区。雄鸟拥有壮观的尾屏，而雌鸟则无长尾羽，两者均有着暗绿色的头部羽毛。绿孔雀曾广泛分布，现今仅存零星群体，特别是在泰国、越南、中国云南和印尼的爪哇岛。绿孔雀是中国国家一级保护动物。","appearance":"绿孔雀的雄鸟体长可达180-250厘米（尾部40-47.5厘米，尾屏140-160厘米），体重3850-5000克；雌鸟则较小，体长100-110厘米（尾部40-45厘米），体重1060-1160克。雄鸟具有闪耀的绿色颈羽，尾屏在求偶时展开，雌鸟虽无尾屏，但仍保留部分尾羽的绿色光泽。幼鸟与成年雌鸟类似，但具有一些白色羽毛，尤其在脸部和前颈，整体较为暗淡。成年雄鸟的尾屏完全发育可能需至第五年。","call":"雄性绿孔雀的叫声为重复的远距离‘ki-wao’或‘yee-ow’，有时夜间从栖息地发出，其声音不如蓝孔雀那么尖锐。雌鸟发出响亮且快速重复的‘AOW-aa’叫声，首音节重音明显。在警戒时，会发出‘tak tak ker-r-r-r oo oo, kerr-r-r-roo’的声音。主要在清晨和傍晚鸣叫，尤其是在春季。","habits":"绿孔雀栖息于靠近水源的开放热带森林，包括溪流和河流附近。在爪哇，它们出现在开放的林地、草原、季风灌木林边缘，但不进入雨林内部，海拔从海平面至3000米，以及2000米以上的高山草地。在中国云南，它们通常在针叶林、落叶阔叶林、常绿阔叶混交林、灌木丛、草地和农田中活动，海拔680-1400米。它们主要以白蚁、浆果、草籽、辣椒、花瓣、蟋蟀、蚱蜢和小型蛾类为食，偶尔在农田中觅食。","breeding":"绿孔雀在一月到五月期间在印度东北部繁殖，也可能在七月到九月繁殖。在泰国，四月到五月繁殖，在爪哇，则在八月到十月。雄鸟拥有后宫，可拥有多达五个雌鸟伴侣。它们在地上筑巢，通常选择受保护但视野良好的地点。一窝通常有3-6个浅奶油色、咖啡色或淡褐色的蛋，由雌鸟独自孵化，孵化期为26-28天。","identification":"绿孔雀与蓝孔雀的区别在于体型（绿孔雀略大）、羽毛颜色（颈部绿色而非蓝色）、面部特征（眼周蓝色，眼后有黄斑）、冠羽形状（簇状而非扇形）、雌雄颜色差异（绿孔雀雌雄颜色相近，蓝孔雀差异显著）以及叫声（绿孔雀音调较低沉）。","protection":"IUCN：EN（濒危）","distribution":"绿孔雀主要分布在东南亚至爪哇岛，包括印度东北部、缅甸、老挝、越南、柬埔寨、中国云南和西藏的部分地区，以及印尼的爪哇岛。","other":"绿孔雀在缅甸被视为国鸟，是当地皇室的象征。在中国，绿孔雀是国家级保护动物，禁止商业经营。"},{"name":"刚果孔雀","english_name":"Congo Peafowl","scientific_name":"Afropavo congensis","overview":"刚果孔雀（英文名：Congo Peafowl，学名：Afropavo congensis），是鸡形目雉科刚果孔雀属的鸟类。唯一一种非洲本土的雉科孔雀，分布于刚果民主共和国的中心地带，主要栖息在低海拔热带雨林中。刚果孔雀的雄鸟拥有深蓝色的羽毛，带有绿色和紫色光泽，而雌鸟则呈红褐色，背部有金属绿光泽。体型较小，雄鸟体长64至70厘米，雌鸟60至63厘米，是刚果盆地特有的珍稀物种。","appearance":"刚果孔雀雄鸟体长64至70厘米，尾长约20.6至26厘米，体重在1.361至1.475千克之间；雌鸟体长60至63厘米，尾长约16.9至22.5厘米，体重在1.135至1.154千克之间。雄鸟主要呈现黑色腹部，上部闪烁着绿色，带有青铜反光和翼羽尖端的紫色。头部较小，颈部细长，尾巴圆润且适度长。雄鸟冠部有白色硬羽，有时很短，伴有较短的裸黑硬羽；颈部有变化的裸露红色皮肤，覆盖着稀疏的黑色绒毛。雌鸟通常有肉质突起，两性均为白色。第一年的雄鸟较为暗淡，缺乏跗跖上的肉质突起和冠状羽簇，冠部硬羽也较短。成年羽毛在第二年获得。幼鸟斑驳的肉桂色和黑色，但年轻的雄鸟很快在肩部和翅膀覆羽上长出绿色羽毛。","call":"刚果孔雀最常见的是二重唱，通常在夜间听到，尤其是在晚上7点到10点之间，但每周只出现大约3个夜晚。二重唱开始时，雄鸟会发出响亮的“rro-ho-ho-o-a”声，逐渐达到高潮，随后是高音的“gowe”声，雌鸟则以较低的“gowah”声回应，这一序列可能重复多达20到30次。另一种二重唱由雄鸟的“ko-ko-wa”声和雌鸟更高的“hi-ho-hi-ho”声组成。","habits":"刚果孔雀栖息于海拔1200米以下的热带雨林，尤其是干燥的高地森林，同时也利用旧的次生林，至少用于觅食。它们被认为是杂食性的，饮食包括Celtis ituriensis和C. adolfi-friedericii的核果、常见的阔叶树、水生昆虫、蚂蚁、白蚁，通过啄食地面或在落叶层中刨食。已知它们会访问Musanga cecropioides和Margaritaria discoidea的果实，以及Sapium ellipticum、Ficus spp.、Strombosia grandifolia、Xymalos monospora和Caesalpinia decapetala的种子和果实。刚果孔雀通常单独或以最多六只的小家庭群体出现，偶尔与一群Francolinus lathami一起。","breeding":"关于野生刚果孔雀繁殖的信息有限，但似乎繁殖时间取决于当地的降雨条件。在赤道南300公里处，一月到二月间能找到幼鸟。推测它们是一夫一妻制；雄鸟在孵化期间似乎留在巢附近。在圈养环境中，它们往往在离地不到1.5米的树上筑巢，但在野外疑似在树根之间筑巢。巢通常包含2到3个无斑点的锈色或奶油色蛋，大小在56至63.3毫米×43至46.9毫米，重量在67至71克之间，间隔1至3天产下。孵化期约为25至28天，仅由雌鸟承担，直到第二或第三个蛋产下才开始。雏鸟出生时上部为黑色和黑褐色，下部为明亮的乳黄色，翅膀为肉桂色；最初与雌鸟在树上过夜，但很快转到地面，由雄鸟照料。在圈养条件下，仅有22%的蛋能够孵化。雌鸟大约在12个月大时具备繁殖能力，雄鸟则在18个月左右。","identification":"刚果孔雀是非洲唯一的雉科孔雀，与亚洲的蓝孔雀和绿孔雀明显不同，雄鸟没有修长的尾羽，雌鸟的羽毛更为华丽。与亚洲的近亲相比，它们的生理特征和外观差异显著，尤其在羽毛颜色和形态上。","protection":"IUCN：NT（近危）。刚果孔雀仅生活在刚果民主共和国的中心地区，分布范围异常狭小且呈高分散型分布，数量稀少，繁殖率低。由于刚果的内战和大量卢旺达难民涌入造成的环境破坏，使得刚果孔雀的数量日趋减少，目前野生数量估计在2500只左右，分布范围仅70万平方公里。圈养数量约150只，分布于世界各地的动物园中。","distribution":"刚果孔雀主要分布在刚果民主共和国的中心地区，具体在中央刚果盆地。","other":"刚果孔雀在1930年代中期被发现，由于其隐蔽的生活习性和难以察觉的特性，在野外很少被观察到。"},{"name":"红喉潜鸟","english_name":"Red-throated Loon","scientific_name":"Gavia stellata","overview":"红喉潜鸟（英文名：Red-throated Loon，学名：Gavia stellata），是潜鸟目潜鸟科潜鸟属的鸟类。潜鸟科最小的成员，体长53-69厘米，体重1-2.7公斤，以细长的颈部和尖锐的喙为显著特征。分布于北极圈内的湿地和苔原湖泊，以及沿海地带。冬季迁徙至北美的东西海岸及东亚的沿海地区。在繁殖季节，其头部呈灰色，喉部有砖红色斑块，背部深色，非繁殖期则头部和颈部的大部分区域为白色，与暗色的冠部形成鲜明对比。","appearance":"红喉潜鸟体型纤细，颈部和喙均细长，喙常略向上倾斜。繁殖期头部呈灰色，喉部有一块醒目的红棕色斑，背部暗色，带有黑白细条纹。非繁殖期头部和颈部大部分为白色，与暗色的冠部和后颈形成对比，背部有白色斑点。幼鸟上体颜色较暗，下体有不同程度的白色，喉部颜色较淡。成年雄鸟比雌鸟稍大。","call":"红喉潜鸟有多种鸣叫声，包括飞行中的快速鹅鸣般的叫声、警告时的短促吠声、低沉的呻吟声、下降音调的哀鸣声，以及用于领土争斗和亲子互动的长叫声。","habits":"栖息于北极苔原湖泊，迁徙期间和冬季多见于沿海水域。飞行迅速，善于潜水捕食鱼类。在繁殖季节，会在小型淡水湖泊筑巢，而非在巢湖内觅食，而是前往更大的湖泊或海洋捕食。迁徙时可能集结成松散的群体。","breeding":"繁殖期在北极圈内，营巢于靠近水边的地面，通常在4月末5月初到达繁殖地。成对结合稳定，交配时双方会在水面游动追逐，孵化期约27-29天，雏鸟早熟，出生后10-12小时即可下水，约40天后能飞行。","identification":"与其它潜鸟相比，红喉潜鸟喙更细长，头部和喙的形状及头部图案的对比度较低。与太平洋潜鸟和北极潜鸟区别明显，特别是在头部和喙的比例上。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美、欧亚高北极至亚北极区域，包括格陵兰、冰岛、法罗群岛、不列颠群岛北部等地。非繁殖期分布于北美的东西海岸、欧洲的伊比利亚半岛、地中海、黑海和里海、日本、朝鲜半岛等地。","other":"在人类文化中，红喉潜鸟曾被用作食物源，其行为在某些地区被用来预测天气。"},{"name":"黑喉潜鸟","english_name":"Black-throated Loon","scientific_name":"Gavia arctica","overview":"黑喉潜鸟（英文名：Black-throated Loon，学名：Gavia arctica），是潜鸟目潜鸟科潜鸟属的鸟类。中型潜鸟，广泛分布于欧亚大陆北部和美国阿拉斯加州远西部。其头部呈浅灰色，喉部和背部黑色，具金属光泽。前颈墨绿色，颈侧白色，具黑色纵纹。繁殖于北极和亚北极苔原、岛屿上的内陆湖泊，冬季迁徙至沿海海域。飞行能力强，善游泳和潜水。","appearance":"体长58至73厘米，翼展100至130厘米，体重1.3至3.4千克。繁殖羽具灰色头部和后颈，黑色喉部和前颈，带有紫色光泽。下喉部有项链状的白色短线。颈侧有五条平行的白色长线延伸至胸部，后者具有平行的黑白线条。下体纯白。上体黑色至翼基，有几行高对比的白色方形斑点覆盖肩部和背羽。非繁殖羽上体较暗，部分上翼覆羽保留白色斑点，下体白色，两侧稍暗。","call":"繁殖期雄鸟发出响亮、有节奏的呼哨声和哀嚎声，以及夜间特有的咕哝声。","habits":"繁殖期栖息于北极和亚北极地区的湖泊、河流及大水塘，偏好植物茂盛、鱼类丰富的水域。冬季栖息于沿海海域。善潜水，最长可达90至120秒，飞行能力强，需助跑起飞。成对或小群活动。","breeding":"繁殖期为5月至7月，营巢于水生植被中，产卵2至3枚，孵化期27至29天，幼鸟早成性，60至65天后离巢。","identification":"与红喉潜鸟区别在于头较大、颈较粗、嘴较厚且上体无白色斑纹。第一冬的鸟上体具白色鳞状纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆北部至北极地带，越冬于欧洲中部、地中海、黑海、日本、加利福尼亚以及中国辽东半岛、福建、台湾等东南沿海地区。","other":"数量稀少，应注意保护。"},{"name":"太平洋潜鸟","english_name":"Pacific Loon","scientific_name":"Gavia pacifica","overview":"太平洋潜鸟（英文名：Pacific Loon，学名：Gavia pacifica），是潜鸟目潜鸟科潜鸟属的鸟类。中型潜鸟，常见于北美西部及横跨太平洋至日本。其体色较深，喙相对较短，头部和颈背圆润。繁殖羽具有灰色头部、黑白相间的背斑点和颈部细白线条。非繁殖羽整体呈暗灰，上半身与下半身颜色界限明显，有特征性的暗色‘下巴带’，但幼鸟中可能不明显。与北极潜鸟在分布上有重叠，但太平洋潜鸟的喙略小，头部更水平。繁殖于北极和亚北极的淡水湖，冬季主要在近海海域度过，偶尔在内陆水库和湖泊中出现。","appearance":"太平洋潜鸟体长58-74厘米，翼展110-128厘米，体重1-2.5千克。繁殖羽时，头部灰，背部黑白斑点交错，颈侧有细白线，下颏有暗色带。非繁殖羽上半身暗灰，下半身白色，头颈交接处有暗边。喙灰色，脚黑色，眼睛红褐色。幼鸟上体有鳞状斑纹，下体暗至水面线，成年鸟腹部在特定姿势下露出白色。","call":"太平洋潜鸟春季和夏季最活跃地鸣叫，叫声多样。包括喂食时发出的类似‘ark’的短促叫声，以及类似于共同潜鸟的响亮、怪异的oo-loo-lee哀鸣或号叫，能传数里，通常在繁殖季节听到。此外，还有短促尖锐的‘kok-kok-kok-kok’叫声和其他小声的咯咯声、咆哮、吠叫和咯咯声。","habits":"太平洋潜鸟栖息于北极湖泊，冬季迁至开阔海域或大型水体。繁殖于北加拿大和东西伯利亚，冬季沿北美太平洋海岸分布。与其他潜鸟相比，这种鸟可能会群迁。在开阔海域过冬，或在更广阔的范围内，包括中国、日本、朝鲜半岛、美国和墨西哥的大湖上过冬。","breeding":"太平洋潜鸟在靠近深湖的地面筑巢，由堆叠的植被构成。每窝产1-2枚淡黄或绿色带有棕色斑点的蛋，平均孵化期23-25天。社会单配偶制，领域保留率高，雄鸟比雌鸟更成功。太平洋潜鸟会积极防御领地内的威胁，包括其他鸟类。","identification":"太平洋潜鸟与北极潜鸟相似，但前者体型略小，喙更细长，头部更水平。非繁殖羽下体白色，无侧面白斑。与红喉潜鸟的区别在于后者外观更淡，头部与颈背与喉咙对比度较小，喙看起来向上翘。太平洋潜鸟在所有羽衣中，缺乏白色侧腹斑块。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美高北极至亚北极区域，从西伯利亚中北部的Yana和Indigirka河流以东至Chukotka，Wrangel岛，美国阿拉斯加州，加拿大不列颠哥伦比亚省中西部至Baffin岛和James湾。冬季迁至日本、朝鲜半岛和黄海北部（中国东北部）、墨西哥下加利福尼亚州中部。","other":"太平洋潜鸟与黑喉潜鸟曾被认为同种，1985年起被确认为独立物种。"},{"name":"普通潜鸟","english_name":"Common Loon","scientific_name":"Gavia immer","overview":"普通潜鸟（英文名：Common Loon，学名：Gavia immer），是潜鸟目潜鸟科潜鸟属的鸟类。体型较大(约76厘米)，是北美洲广泛分布的标志性水鸟之一。作为潜鸟代表，不仅是加拿大的象征，出现在一元硬币('loonie')和20加元纸币上，而且在许多文化中具有深远的影响。繁殖期的普通潜鸟拥有引人注目的黑白色羽毛，黑色头部与白色颈环相映成趣。生活在偏远的淡水湖泊，是北方荒野的显著标志。","appearance":"普通潜鸟是一种大型潜鸟，长度介于66到91厘米之间，翼展可达127至147厘米。体重范围广泛，从2.2公斤到7.6公斤不等，雄鸟通常比雌鸟重约26.6%。繁殖期的成鸟拥有黑色头部和颈部，带有绿色、紫色或蓝色光泽，上身黑色或深灰黑色，下身纯白色，尾部下方和腹部边缘有黑色斑点。非繁殖期成鸟呈棕色，头部和颈部有深灰色标记，上身暗棕灰色，带有模糊的方形斑点。幼鸟背部和肩部有暗色羽毛，边缘较浅，头、颈和上身暗灰至黑色，下身和脸颊白色。","call":"普通潜鸟的叫声多样，最常见的是颤抖声、嚎叫声、呼呼声和夜间的长鸣，这些声音在不同的社交场合中表达不同的信息。","habits":"普通潜鸟在繁殖季节独居于淡水湖泊，冬季则在近岸海域形成小群体。它们以鱼、甲壳类、昆虫幼虫和软体动物为食，偶尔吃水生植物。潜水捕鱼是其主要的觅食方式，能在水下追逐猎物长达一分钟。迁徙期间，它们会在白天飞行，通常选择清晨开始，飞行高度在1500至2700米。","breeding":"普通潜鸟是终身伴侣，每年在同一地点筑巢。巢位于湖泊岸边，由死草和其他植物构成。每次繁殖仅产一窝，通常含有一到两枚橄榄棕色的卵，带有深棕色斑点。双亲共同孵卵约28天。雏鸟出生后几日内就能潜水，约70至77天后离巢飞翔。","identification":"与黑喉潜鸟相比，普通潜鸟体型更大，头顶更平坦，后颈颜色更深。与白嘴潜鸟的区别在于嘴部颜色、上颌中线的颜色以及头部相对于上体的颜色更深。非繁殖期与黑喉潜鸟易混淆，但普通潜鸟的嘴更厚实，头顶较平。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，包括西格陵兰、冰岛、阿拉斯加、加拿大北部至美国北部边境州，以及新英格兰。冬季分布于欧洲西北部沿海、阿留申群岛、墨西哥下加州南部和加利福尼亚湾、大西洋西岸至美国佛罗里达、墨西哥湾至墨西哥东北部。","other":"普通潜鸟是汞沉积的指示物种，其体内汞含量反映了其食物链顶端的位置。"},{"name":"王企鹅","english_name":"King Penguin","scientific_name":"Aptenodytes patagonicus","overview":"王企鹅（英文名：King Penguin，学名：Aptenodytes patagonicus），是企鹅目企鹅科王企鹅属的鸟类。大型物种，体长可达94至95厘米，重9至15千克，颈部两侧有显著的橙色或金色斑块，是仅次于帝企鹅的第二大企鹅种类。王企鹅主要分布于南极洲及其附近岛屿，包括福克兰群岛、南乔治亚岛等地，常在无雪无冰的平坦海滩上繁殖。","appearance":"成年王企鹅高约70至100厘米，体重介于9.3至18千克之间，头部黑色或黑褐色，侧面有大块橙色或金橙色斑块，延伸至喉咙一侧，形成鲜明对比。背部、上体和上翼灰色，尾部比背部颜色更深，接近石板色。中央上颈部为淡黄橙色，逐渐过渡到下颈部或胸部更宽的金黄色区域，其余下体部分为奶油白色，头部亮色与上体灰色之间有一条窄的黑色线。","call":"王企鹅的接触叫声为单个喇叭般的音符，持续不到1秒，重复发出。展示叫声为一系列响亮的喇叭音符，根据季节时间的不同，可能短也可能长。雌鸟的叫声音调更高，平均而言比雄鸟的更长，包含更多音节。","habits":"王企鹅主要生活在南极圈附近的海域，大部分时间靠近繁殖区域。它们是最具远洋性的企鹅，卫星追踪显示成年繁殖个体的平均觅食范围为471公里，最长的冬季觅食行程可达3893公里。王企鹅主要以小型灯笼鱼和鱿鱼为食，尤其是电子鱼（Electrona carlesbergi）和Krefftichthys anderssoni，以及Moroteuthis属的头足类。","breeding":"王企鹅的繁殖周期长达14个月，是企鹅家族中最长的。繁殖季从9月至11月开始，产卵则在11月至翌年4月。每对王企鹅大约每3年才能完成两个繁殖周期。孵化期间，双亲轮流孵化，孵化期为52至56天。幼鸟孵化时几乎无毛，首次绒毛为浅灰色或棕色，第二次绒毛为深棕色。幼鸟在约40天后形成托儿群，独立生活发生在10至13个月大时。","identification":"王企鹅与帝企鹅的区别在于王企鹅拥有更长、更直的喙，较大的鳍足，以及更加苗条的身体。王企鹅的颊部斑块是实心的鲜橙色，而帝企鹅的则是黄色和白色的混合。此外，王企鹅的胸部上方往往更橙色，而非黄色。","protection":"IUCN：LC（无危）","distribution":"王企鹅主要在南极圈以北的次南极岛屿上繁殖，包括福克兰群岛、南乔治亚岛、爱德华王子群岛、克罗泽特岛、凯尔盖伦岛和赫德岛，以及麦夸里岛。非繁殖期，它们主要分布在南极汇合带周围，偶尔出现在新西兰南端、南美洲尖端和南极半岛。","other":"王企鹅的繁殖地曾遭受19世纪和20世纪早期的商业剥削，但近年来大多数繁殖群体已显著增加，如凯尔盖伦岛每年增长7%，克罗泽特岛每年增长3%。"},{"name":"帝企鹅","english_name":"Emperor Penguin","scientific_name":"Aptenodytes forsteri","overview":"帝企鹅（英文名：Emperor Penguin，学名：Aptenodytes forsteri），是企鹅目企鹅科王企鹅属的鸟类。现存最大的企鹅种类，平均体高约115厘米，体重介于22至45公斤。雄鸟和雌鸟在羽毛颜色和大小上相似，头部和背部呈深黑色，与白色的腹部形成鲜明对比，耳部具有亮黄色斑块。分布于南极大陆的66°至77°S纬度之间，主要栖息于稳定海冰上。","appearance":"帝企鹅拥有112-115厘米的体长，体重在19-46公斤之间。它们是最大的企鹅种类，具有灰色和白色的短尾，尖而弯曲的细长喙，头部后侧有对比明显的斑块。成年帝企鹅头部全黑或黑褐色，耳部有大型淡黄色斑块，逐渐变为橙色接近脸部，颈部后侧呈灰色。雄鸟和雌鸟的外观相同。雏鸟头部颜色较暗，耳部斑块颜色更淡。","call":"帝企鹅发出响亮的喇叭声，尤其是在求偶期间。","habits":"帝企鹅生活在南极水域，通常在靠近海岸的冰架上繁殖，有时距离开阔海域多达200公里。它们在海洋中觅食，主要以鱼类、磷虾和头足类为食，能够潜水至500米深度，每次潜水可持续20分钟。帝企鹅适应了极端寒冷的环境，能够在-40°C的温度下生存。","breeding":"帝企鹅在南极冬季繁殖，雄鸟在孵化期间守护着蛋，孵化周期为62-66天。雌鸟返回后，双方共同照顾幼鸟。幼鸟孵化时几乎无毛，第一次换羽后长出灰色绒羽，第二次换羽后绒羽更厚更长，胸腹部带有棕色斑点。","identification":"帝企鹅与国王企鹅类似，但体型更大，喙部更短且略微弯曲，下颌基部的明亮皮肤区域较小，耳部斑块与前颈接触更广泛。","protection":"IUCN：NT (近危)","distribution":"帝企鹅繁殖区域主要位于南极大陆的66°至77°S纬度之间，包括罗斯海区域、皇后毛德地沿岸和恩德比地。非繁殖季节，它们可能分散至边缘地带，甚至超出南极条约区域。","other":"气候变化对帝企鹅的栖息地构成了严重威胁，预计到2100年，大部分帝企鹅群体可能会面临\"准灭绝\"的风险。"},{"name":"白眉企鹅","english_name":"Gentoo Penguin","scientific_name":"Pygoscelis papua","overview":"白眉企鹅（英文名：Gentoo Penguin，学名：Pygoscelis papua），是企鹅目企鹅科阿德利企鹅属的鸟类。又名: 巴布亚企鹅、金图企鹅，是本属体型较大的物种之一，仅次于帝企鹅和王企鹅。以其独特的白色头带和鲜艳的橙色喙著称，生活在英属福克兰群岛等地，擅长深海捕鱼，且是企鹅中游泳速度最快的，时速可达36公里。全球繁殖种群估计超过30万对。","appearance":"白眉企鹅体长76-81厘米，体重4.5-8.5公斤，头部、颈部和上部呈板岩黑色，头部有时带有棕色调，最显著的是从眼到眼横跨头顶的白色条纹。喙为红色或橙色，脚橙黄色至粉红色。幼鸟的喙较弱且暗淡，白色的眶上斑较小且暗淡，有时喉部呈灰色。","call":"白眉企鹅发出多种声音，最常见的是响亮的喇叭声，通常在上岸时发出短暂低沉的‘呱’声。展示时，会向上指向发出一系列‘啊哈’声，还发出‘raaaarr’音符与尖锐的喇叭声混合，以及连续的轻柔嘶嘶声。","habits":"白眉企鹅栖息于岩石海岸，偏好平坦地面，筑巢地会轻微变动。近海觅食，一般在离岸10公里范围内活动。冬季向北迁移到阿根廷43°S附近，偶见于塔斯马尼亚和新西兰。潜水捕食，主要捕获磷虾、鱼和少量头足类。","breeding":"繁殖季节因地区而异，最早在北部6月至7月，南部11月开始。筑巢于石堆，通常由一对企鹅轮流孵化两枚卵，孵化期31-39天。幼鸟形成托儿所在20-37天后，85-117天后离巢。成年企鹅继续喂养幼鸟5-50天。","identification":"白眉企鹅通过其独特的白色头带和橙色喙容易识别，与同属的其他企鹅相比，体型较大。幼鸟与成鸟的区别在于喙的颜色和大小，以及白色的眶上斑差异。","protection":"IUCN：LC（无危）","distribution":"主要分布于亚南极岛屿，局部出现在南极岛屿。关键繁殖区包括福克兰群岛、南乔治亚岛、南桑威奇群岛、克罗泽特群岛、南设得兰群岛和南极半岛。","other":"全球种群在过去20-30年间显著增加，尤其是在福克兰群岛和南极半岛南部。南乔治亚岛上的繁殖群在1980年代中期以来减少了约67%。"},{"name":"阿德利企鹅","english_name":"Adelie Penguin","scientific_name":"Pygoscelis adeliae","overview":"阿德利企鹅（英文名：Adelie Penguin，学名：Pygoscelis adeliae），是企鹅目企鹅科阿德利企鹅属的鸟类。是南极大陆上最为人所熟知的企鹅种类之一。这种企鹅以经典的黑白相间外观著称，拥有醒目的白色眼圈和红色偏黑的喙。主要分布在南极及其周边岛屿，尤其偏好岩石地带的无雪海岸作为繁殖地。在繁殖季形成庞大的群体，叫声嘈杂。","appearance":"阿德利企鹅体长约70至73厘米，体重介于3.8至8.2千克之间。成年个体的头部、上半身、翅膀上方和尾部为黑色，带有蓝色光泽；腹部、翅膀下方和尾羽基部为白色。眼睛周围有显著的白色环状羽毛，喙部大部分被黑色羽毛覆盖，仅露出尖端，呈现红褐色标记。腿脚呈粉红色，足底和胫骨后侧为黑色。幼鸟孵化时全身覆有银灰色绒毛，头部颜色更深；经过第一次换羽后，全身变为烟灰色；第三次换羽后，外观接近成年个体，但体型较小，背部略带蓝色，下颌和喉部为白色，而非黑色。","call":"阿德利企鹅在繁殖地发出响亮的滚动声“aar-rar-rar-rar-raaah”，随后是“kuk-gu-gu-gu-gaaaa”的叫声，通常由伴侣在巢址附近发出。接触呼叫是一种尖锐、响亮的喉咙吠声“aark”及其变体。在争斗情境中，也会发出各种咆哮和咕噜声。","habits":"阿德利企鹅主要栖息在南极海岸线，偏好无雪的岩石海岸作为繁殖地。它们在繁殖季节形成巨大的群体，叫声喧闹。以南极磷虾为主食，辅以少量鱼类、片脚类和头足类。在繁殖期间，主要在近岸水域觅食，而在换羽和冬季觅食期间，则在海冰区域活动。成年个体在繁殖后向北迁移至丰富的觅食区，而幼鸟则在两年内留在海冰区域，有时长达3至5年。","breeding":"阿德利企鹅在9月至10月间到达繁殖地，大多在11月开始产卵。它们在岩石地带的无雪海岸上形成庞大的繁殖群体。巢穴为小型凹坑，铺以鹅卵石。每窝产2枚卵，若初始卵丢失，可能会替换一枚卵。孵化由双亲轮流承担，持续30至43天，孵化期间轮流时间可达7至23天。雏鸟在大约16至19天后形成托儿群，离巢时间为41至64天，通常在50至56天左右。总体繁殖成功率约为50%，性成熟年龄一般在8岁左右。","identification":"成年阿德利企鹅的特征明显，不会与其他企鹅混淆。然而，幼鸟的白色喉部可能使其与颊带企鹅相似，但阿德利企鹅面部的黑色延伸至眼睛下方，且没有颊带企鹅的“颊带”。此外，阿德利企鹅的喙较短，大部分被羽毛覆盖，而颊带企鹅的喙较长，裸露较多。","protection":"IUCN：LC（无危）","distribution":"阿德利企鹅广泛分布于南极洲海岸线和周边岛屿，包括南奥克尼群岛、南设得兰群岛、南桑威奇群岛、鲍尔尼群岛、斯科特岛和南乔治亚岛。繁殖季节时，它们需要无雪的岩石地面作为筑巢场所，通常距离开阔水域较远，但随着夏季的到来和海冰融化，距离逐渐缩短。","other":"阿德利企鹅的生存受到气候变化的影响，特别是在南极半岛地区，但东南极地区的增加抵消了这一下降趋势。"},{"name":"纹颊企鹅","english_name":"Chinstrap Penguin","scientific_name":"Pygoscelis antarcticus","overview":"纹颊企鹅（英文名：Chinstrap Penguin，学名：Pygoscelis antarcticus），是企鹅目企鹅科阿德利企鹅属的鸟类。又名: 颊带企鹅、胡须企鹅、帽带企鹅，以脖子下的独特黑色条纹而得名，如同海军军官佩戴的帽带，外观威武、刚毅。身高约43～53厘米，体重介于3.2-5.3千克之间。广泛分布于南太平洋和南极海域的岛屿和海岸。","appearance":"纹颊企鹅体长68–77厘米，体重3.2–5.3千克。成鸟头部顶部和背部呈全黑或蓝黑色，翼部上方黑色，边缘有狭窄的白色线条，下方白色到粉红色，末端黑色。尾羽黑色，脸部从眼窝到上颈侧直至整个下部均为白色，除了一条从后冠侧通过耳羽到下巴的窄黑线。虹膜颜色从橙棕色到深棕色，裸露的黑色眼圈；喙黑色；腿粉色，脚底和脚背后部黑色。性别相似，幼鸟喙比成鸟小，前脸有微暗条纹，虹膜较暗。","call":"在繁殖地发出响亮的嘶哑叫声。","habits":"栖息于轻度浮冰区（10–30%冰覆盖）的海洋环境，筑巢于南极半岛的不冻地带，偏好不规则的岩石海岸。耐不住冰的物种，繁殖范围近年来向南扩展。冬季分散，最北可达阿根廷南部。近岸觅食，以南极磷虾为主食，偶尔摄食其他甲壳类和鱼类。","breeding":"每年10月至11月抵达繁殖地，最早11月至12月开始产卵。在巨大的群落中筑巢，每巢产两枚蛋，由双亲轮流孵化，孵化期31至40天。幼鸟孵化后约23至29天形成托儿所，48至60天后离巢。繁殖成功率在南奥克尼群岛为0.36只雏鸟/对，在南设得兰群岛为1.06只雏鸟/对。性成熟年龄为三岁。","identification":"纹颊企鹅以其独特的下颌黑带和白脸易于识别，与同属的阿德利企鹅和白眉企鹅有明显区别。在行为上，纹颊企鹅被认为是最具攻击性和暴躁的企鹅种类之一。","protection":"IUCN：LC（无危）","distribution":"繁殖于南极洲、阿根廷、布韦特岛、智利、法属南方领土、南乔治亚岛和南桑威奇群岛。偶见于新西兰、圣赫勒拿岛、特里斯坦-达库尼亚群岛和南非。","other":"1980年代总数量估计为650万至750万对，其中约500万对位于南桑威奇群岛。自1980年代以来，种群显著减少，可能与商业捕鱼活动增加和气候变化导致的磷虾数量下降有关。"},{"name":"黄眉企鹅","english_name":"Fiordland Penguin","scientific_name":"Eudyptes pachyrhynchus","overview":"黄眉企鹅（英文名：Fiordland Penguin，学名：Eudyptes pachyrhynchus），是企鹅目企鹅科冠企鹅属的鸟类。以其独特的宽黄色眉毛和眼睛下方的白色条纹著称，分布于新西兰南岛西南部和斯图尔特岛及其周边卫星岛屿。在澳大利亚水域也有其踪迹。","appearance":"黄眉企鹅体长介于55至71厘米，体重可达2.1至5.1公斤。成鸟的头部、咽喉及上体为深黑色，带有蓝灰色调，下体则为白色。其显著特征为从喙基延伸至眼侧，再垂至颈侧的亮黄色眉纹。喙呈橙色，无裸露皮肤，脚为粉色，趾底呈棕色。雄鸟比雌鸟略大，拥有更粗壮的喙和更宽的眉纹。幼鸟的眉纹较薄且暗淡，头部颜色偏灰，尤其是喙周围，黑色区域与下巴和喉部密集的白色条纹相融。喙较小，初期为黑褐色，逐渐变为红色或橙色。","call":"其叫声变化多样，从响亮的喇叭声到低沉的咆哮或嘶嘶声。当受威胁时，脸颊上的白色条纹会展开。","habits":"栖息于湿润的沿海雨林斜坡，或岩岸洞穴，偏好茂密的森林环境。繁殖和换羽期间在新西兰的西南海岸线。非繁殖季节可能游弋于塔斯曼海和澳大利亚东南部水域。以小型头足类、鱼类和甲壳类为食，如箭鱿、红鳕鱼和磷虾。通过追逐潜水的方式捕食，既可独行也可结小群。","breeding":"通常在6月至7月返回繁殖地，筑巢于树根间或岩洞中，每窝产两枚卵，第二枚卵较大且孵化率更高。雌雄轮流孵卵，孵化期约为31至36天。幼鸟约在21至28天后形成托儿所，约75天后离巢，通常在11月。据估计，约50%的繁殖对能够将一只雏鸟抚养至离巢。","identification":"与翘眉企鹅和斯岛黄眉企鹅的区别在于，黄眉企鹅的喙基部无裸露皮肤，且眉纹更加宽阔。","protection":"IUCN：NT（近危）","distribution":"繁殖于新西兰南岛西南部、斯图尔特岛及其周边卫星岛屿。非繁殖季，分布至塔斯曼海和澳大利亚东南部水域。","other":"历史上，黄眉企鹅的分布范围曾远至新西兰北岛，但由于波利尼西亚人的猎杀，其分布范围大幅缩减，目前仅存于新西兰人口最少的地区。"},{"name":"斯岛黄眉企鹅","english_name":"Snares Penguin","scientific_name":"Eudyptes robustus","overview":"斯岛黄眉企鹅（英文名：Snares Penguin，学名：Eudyptes robustus），是企鹅目企鹅科冠企鹅属的鸟类。新西兰特有的中型冠企鹅。以其鲜明的黄色眉毛和粗壮的红棕色喙部周围的淡粉色裸露皮肤著称。仅在斯奈尔斯群岛繁殖，冬季分散广泛。成年企鹅在繁殖季节结束后分散至南岛、斯图尔特岛、查塔姆岛和南极洲岛屿附近。与黄眉企鹅的区别在于喙基部的粉肉色皮肤和缺乏脸颊上的白色条纹。","appearance":"斯岛黄眉企鹅体长56至73厘米，体重2.4至4.3千克。头部一侧有明亮的黄色眉毛，成年个体头部、背部全黑，常带蓝色调，黑色延伸至鳍肢基部下方；鳍肢上侧颜色与背部相似，仅边缘有一狭窄的白色条纹，下侧白色，带有黑色前缘、宽尖端和宽基部；尾巴蓝黑色；头部侧面从额头到喙基部有一条长而淡黄色的条纹，向后越过眼睛延伸至颈背，形成蓬松的侧向羽冠；脸部至眼上方和下巴、喉咙均为黑色；前颈至两胁和尾下覆羽白色；虹膜深红色；喙暗橙至红褐色，基部周围环绕着一条窄而显眼的淡粉色裸露皮肤，张口处更宽；腿浅粉色，足底和胫骨后方深灰色或黑色。雌雄相似，但雄鸟平均比雌鸟大，喙更厚。","call":"斯岛黄眉企鹅能发出一系列响亮的喇叭状吠声和嘶吼声。联系叫声是一种较短、音调更高的吠声。其鸣叫声与黄眉企鹅非常相似。","habits":"斯岛黄眉企鹅主要生活在海洋环境中，可能在非繁殖季节时在公海活动。通常在泥泞的森林地带筑巢，也可能在岩石斜坡上。小群活动，远离陆地觅食。食物主要包括甲壳类动物，尤其是Nyctiphanes australis，同时也捕食头足类动物和鱼类。","breeding":"斯岛黄眉企鹅繁殖期从8月至9月开始，9月至10月间产卵。密集的繁殖群体由50至500对组成，有时可达1000对以上。巢建于树下或灌木下的浅平台，由树枝和泥土构成，有时缺乏遮荫，也可能在较小岛屿的开阔地带。每窝产2枚卵，双亲共同孵卵，孵化期31至37天，换班时间5至25天；首次孵化的雏鸟下体毛深棕色，上体毛脏白色，第二次孵化的雏鸟下体毛类似但更纯白；约20天后雏鸟开始结群；约75天后离巢，即1月份。总体繁殖成功率约为41.2%。性成熟年龄可能在4岁左右，也可能直到6岁，目前了解不多。已知最长寿命为20年。","identification":"斯岛黄眉企鹅与黄眉企鹅的主要区别在于喙基部的粉肉色皮肤和缺乏脸颊上的白色条纹。与翘眉企鹅相比，羽冠始于喙顶，更戏剧性地展开。与Rockhopper Penguin相比，体型较小。","protection":"IUCN：VU（易危）","distribution":"斯岛黄眉企鹅仅在新西兰斯奈尔斯群岛繁殖，非繁殖季节分散至新西兰南岛东部水域。","other":"虽然斯岛黄眉企鹅当前数量估计在26,000至31,000对之间，被认为稳定或可能增加，但其繁殖范围受限于一个小岛群，使其容易受到随机事件的影响。主要威胁包括商业捕鱼、海洋环境变化和油污。"},{"name":"翘眉企鹅","english_name":"Erect-crested Penguin","scientific_name":"Eudyptes sclateri","overview":"翘眉企鹅（英文名：Erect-crested Penguin，学名：Eudyptes sclateri），是企鹅目企鹅科冠企鹅属的鸟类。中型冠企鹅，仅在新西兰的 Bounty 和 Antipodes 群岛繁殖。其特征为黑色上半身、白色下半身，以及独特的黄色眼纹和竖立的顶冠。该物种冬季在海上度过，对其生物学和繁殖习性的了解有限，二十世纪后期数量急剧下降，被 IUCN 列为濒危级别。","appearance":"翘眉企鹅体长63-68厘米，体重3.3-7千克。头部侧边有一条黄色的眉毛和竖立的顶冠。成鸟额头、头顶及全身背部呈黑色，黑色延伸至两侧，直至翅膀基部下方，较长的尾羽覆羽有时呈灰白或白色；翅膀上部黑色，边缘有一条狭窄的白色线，下部广泛白色，带有黑色边缘、宽黑尖端和基部的宽黑区域；尾巴黑色；长而淡金色的条纹从接近喙部的位置开始，沿头顶侧面和颈背向下，长而蓬松，常向上弯曲；头部至下巴和喉咙为黑色；胸部至腹部和臀部羽毛为白色；虹膜红棕色到深棕色；喙暗红色到橙色，极近嘴裂处基部呈蓝灰色，喙周围有非常淡的粉红色裸露皮肤；腿浅粉色，脚掌和跗跖后部深灰色。雄鸟平均比雌鸟大，喙更粗壮。幼鸟顶冠较短，混杂一些黑色，常被前方遮挡，下巴和喉咙斑驳的黑白相间，看起来总体灰白，前部更白。","call":"展示时发出响亮的吠声和嘶吼声。联系叫声为短促的吠声。鸣叫声与黄眉企鹅相似，但音调较低。","habits":"栖息于海洋环境，可能在繁殖季外的季节过远洋生活。在岩石海岸、悬崖或海滩繁殖，地面光秃或覆盖着苔草，海拔高达75米。在繁殖季节结束后广泛分散。在新西兰东海岸的秋季，少量个体在此换羽。分布广泛，偶尔出现在澳大利亚南部、塔斯马尼亚、麦夸里岛和查塔姆群岛；也有记录显示远至克格伦岛和福克兰群岛。","breeding":"九月抵达繁殖地，十月开始产卵。形成大型密集的群落，有些包含数万对。巢穴位于巨石之间的小凹陷或小石头堆成的边缘。每窝产两枚蛋；由双亲共同孵化，周期约30-35天；第一胎幼鸟头部到下巴和喉咙覆盖深棕色绒毛，上半身为脏白色，下半身类似但纯白；幼鸟约21天后聚集在一起；约70天后离巢，一月时。每巢最多成功抚养一只幼鸟。性成熟年龄未知。","identification":"与Snares和Fiordland企鹅相比，其喙基部的淡白蓝色皮肤和正面看时更不明显的‘V’形顶冠是区分的关键。此外，黄色眉毛起始于较低位置，与mid-latericorn水平，后部更高且常向上弯曲，翻转表面的白色相对较少。","protection":"IUCN：EN（濒危）。全球成熟个体估计13-14万，总数约19.5-21万。自1960年代以来数量急剧下降，仍可能持续减少。繁殖范围非常小，现在可能仅限于两个岛屿。2011年，Bounty Island估计有2.6万对繁殖，Antipodes Island有4.1万对。1978年，总繁殖对数超过20万对，Bounty Island约有11.5万对，Antipodes类似数量。至1995年，Antipodes的地面调查显示约4.9-5.7万对，不到二十年减少了约50%，2011年的调查结果表明持续下降。1940年代，Campbell Island有数百个体繁殖，1986-1987年仍有20-30对，但未记录繁殖。大型下降被认为与影响鸟类生存率的海洋因素有关。","distribution":"繁殖区主要在新西兰的 Bounty 和 Antipodes 群岛。非繁殖季节分布至新西兰南岛东部水域。偶尔记录到的个体远至福克兰群岛，也是阿根廷、南极洲和澳大利亚的迷鸟。","other":"1940年代，Otago半岛上曾有繁殖记录。目前所有提及岛屿均为自然保护区，属于1998年指定的世界遗产地。"},{"name":"凤头黄眉企鹅","english_name":"Southern Rockhopper Penguin","scientific_name":"Eudyptes chrysocome","overview":"凤头黄眉企鹅（英文名：Western Rockhopper Penguin，学名：Eudyptes chrysocome），是企鹅目企鹅科冠企鹅属的鸟类。冠企鹅属体型最小的成员，也是南美洲定期出现的两种企鹅之一。东凤头黄眉企鹅曾为亚种，现已分拆。其最醒目的特征是黑色背部、白色腹部及两侧金黄的细长冠羽。繁殖群集中在智利外海岛屿、阿根廷南端及福克兰群岛，福克兰群岛部分群体数量曾超过十万对。","appearance":"体长45–58厘米，体重1.8–2.5 kg，换羽前可达4.3 kg。成鸟头顶、上背、翼背面及尾羽呈丝光黑，腹面纯白；自眼后延伸出狭长黄色眉纹，再向后生长为长而松散的黄色冠羽。翼下表面白色，仅前缘、后基部及翼尖具黑色区。虹膜鲜红，嘴橙红至暗红，腿脚淡粉色，足底及腿后侧黑色。雄鸟平均体型较大，嘴更粗壮；幼鸟嘴小、冠羽短且混有黑色，喉部具白点条纹。","call":"繁殖地嘈杂。求偶及领域宣示时，发出节奏分明的响亮刺耳吠叫夹杂驴鸣般长鸣，并伴随头部摆动与翼击。个体间以短促高音吠叫保持联系；雏鸟用细小“吱吱”乞食声，随日龄逐渐增大。","habits":"典型海洋性，具广温耐盐能力。繁殖期栖息于近岸碎石坡、岩岸、熔岩台地或草丛，海拔0–600 米；非繁殖期完全离岸，冬季向北扩散，仍留海面，偶有个体漂至乌拉圭或智利中部。日行性，以潜泳追捕猎物，潜水最深113 m、最长252分钟。主要猎物为磷虾、端足类、鱼类及头足类。","breeding":"繁殖期在南半球春夏季，10–11月返回繁殖地，11–12月产卵。每窝2枚卵，间隔约4–5天；A卵显著小于B卵。双亲轮孵32–34天，初期雄鸟守护约18天，雌鸟每日出海觅食。雏鸟20天起结群，约70天后离巢，离巢时体重约为成鸟75%。首次繁殖年龄推测为4岁。","identification":"与同属其他黄冠企鹅相比，本种眉纹较窄且后移，冠羽更长而松散。与极相似的凤头企鹅区分要点：凤头企鹅两束冠羽在额前相接成连续额冠，本种则明显分开。与西凤头黄眉企鹅相比，后者冠羽更长、眉纹更宽，翼下黑色区更大，嘴基裸皮黑色且极窄。","protection":"IUCN: VU（易危）。","distribution":"凤头黄眉企鹅繁殖于南美南端：智利合恩角外海岛屿（Diego Ramírez、Noir、Ildefonso等）、阿根廷Staten Island、Pingüino Island及福克兰群岛。非繁殖期扩散至邻近海域，最远记录达阿根廷沿岸35°S。","other":"曾被视为与西凤头黄眉企鹅、东凤头黄眉企鹅同一物种，后因遗传、形态及生态差异而拆分。历史上曾因人类取卵、捕作饵料及外来放牧动物破坏栖息地而数量锐减，部分智利群体现已回升，福克兰群岛群体仍显著低于20世纪30年代水平。"},{"name":"北凤头黄眉企鹅","english_name":"Northern Rockhopper Penguin","scientific_name":"Eudyptes moseleyi","appearance":"这种小型黑白色企鹅，身长51-62厘米，体重2.4-4.3千克。特征为浓密黄色羽冠，喙粗壮且有时略呈钩状。比凤头黄眉企鹅稍大，黄色羽冠更长更密集，头部和上部羽毛常带有蓝灰色调，鳍足下表面颜色变化较大，后基部和尖端黑色较多。","call":"极其善鸣，经常发出响亮的嘶吼和犬吠声，伴有头部摆动和鳍足拍打。","habits":"栖息于海洋环境，能适应较宽泛的温度范围。繁殖季节在开放的石滩或草丛中筑巢。觅食于近海，以磷虾、端足类、鱼类和头足类为主食。","breeding":"在特里斯坦-达库尼亚群岛，秋季抵达繁殖地，10月开始产卵。筑巢于浅坑中，通常铺垫草、石头等。每窝产两枚卵，由双亲轮流孵卵32-34天。幼鸟孵化后约10周离巢。","identification":"与凤头黄眉企鹅相比，西凤头黄眉企鹅具有更长更密集的黄色羽冠，上眼线较宽，鳍足下表面黑白图案更鲜明。","protection":"IUCN：EN（濒危）","distribution":"主要分布于南大西洋的特里斯坦-达库尼亚群岛和戈夫岛，以及印度洋的阿姆斯特丹岛和圣保罗岛。","other":"自1950年代以来，其数量已减少了90%，原因可能涉及气候变化、海洋生态系统改变和人类过度捕捞。"},{"name":"白颊黄眉企鹅","english_name":"Royal Penguin","scientific_name":"Eudyptes schlegeli","overview":"白颊黄眉企鹅（英文名：Royal Penguin，学名：Eudyptes schlegeli），是企鹅目企鹅科冠企鹅属的鸟类。大型冠企鹅，以其显著的黄色冠羽和白色脸颊闻名。仅在澳大利亚管理下的玛奎丽岛及其附近岛屿繁殖，全球数量估计约为300万只。","appearance":"体长73至76厘米，体重3至8.1千克，喙部结实，头戴黄色至赭色长羽冠，常带淡色脸部。成鸟上身黑色，黄色冠羽起自前额，眼上和颊部白色或部分灰色，颈前及腹部白色。虹膜红褐色，喙橙色或橙棕色，腿粉色。","call":"在繁殖地发出嘈杂的响亮嘶吼声和喇叭声，伴随头部摆动和拍翅动作。接触叫声似吠声，与长眉企鹅的声音极为相似。","habits":"栖息于海洋环境，筑巢于海滩及被苔草覆盖的石质斜坡，离海岸最远可达1.6公里。主要在深水区觅食，食物包括磷虾、端足目动物、鱼类和头足类。","breeding":"9月抵达繁殖地，10月产卵，形成密集的大型群落。巢穴为地面浅坑，有时铺垫草。每窝产两枚卵，由双亲轮流孵化32至37天，幼鸟在21天后开始集群，约65天后羽毛成熟，次年1月离巢。","identification":"与长眉企鹅相比，具有较淡的脸色，平均体型更大，喙部略粗壮。与其它黄色冠羽企鹅的区别在于黄色冠羽始于前额。","protection":"IUCN：LC（无危）","distribution":"繁殖于澳大利亚西南太平洋的亚南极岛屿，包括玛奎丽岛和附近的Bishop and Clerk岛屿（位于澳大利亚东南远方）。","other":"历史上曾因猎油而大量被捕杀，自1918年后，由于捕猎停止，种群数量稳步恢复。现代威胁包括外来掠食者、塑料污染、污染和商业捕鱼导致的食物供应减少。"},{"name":"长眉企鹅","english_name":"Macaroni Penguin","scientific_name":"Eudyptes chrysolophus","overview":"长眉企鹅（英文名：Macaroni Penguin，学名：Eudyptes chrysolophus），是企鹅目企鹅科冠企鹅属的鸟类。分布于南极半岛至亚南极岛屿的大型冠企鹅。其最显著的特征是头部两侧延伸至颈部的黄色羽毛，酷似意大利面中的通心粉，故得名。长眉企鹅平均体重5.5公斤，身长70厘米，雄鸟略大于雌鸟。繁殖季节，它们会聚集在大型且密集的繁殖群中。","appearance":"长眉企鹅的成年个体平均体重在3.2至6.1千克之间，身长介于51至77厘米。雄鸟比雌鸟大，但翼展较小。头部顶部有醒目的黄色羽毛，眼睛为红色，腹部、胸部和尾部为白色，头部和脸颊呈黑色或深灰色，背部呈蓝黑色。幼鸟缺少成鸟的黄色头冠，眼睛为棕色，羽毛和喙为黑色。前肢演化成适应游泳的鳍状肢，全身覆盖着类似鳞片的羽毛，骨骼重而实心，胸骨有明显的龙骨突起，内含高脂肪的骨髓。尾羽短，跗跖短，位于躯体后方，足间有蹼。","call":"长眉企鹅在繁殖地极为喧闹，发出响亮的嘶吼声，伴随着头部摇晃和拍打鳍状肢的动作。它们的接触叫声是一种短暂的犬吠声。","habits":"长眉企鹅在海上漂泊数月后，上岛聚集成群，繁衍后代。每年它们都会回到同一繁殖区，常回到同一巢穴，甚至寻找去年的伴侣。它们拥有强壮的脚，擅长跳跃，若遇入侵者，会用坚硬的喙进行防御。它们的群体意识强烈，共同下水和上岸。主要栖息于陡峭的山地地面，常需穿越碎石地带数百米才能到达巢穴，选择人迹罕至或少有鸟类的地方。它们以磷虾为主食，也会捕食鱿鱼和小鱼，具备优秀的潜水能力。","breeding":"长眉企鹅在10月至11月开始繁殖，雌鸟产两枚蛋，第一枚蛋较小，几乎无法存活。孵化任务由双亲轮流承担，孵化期约34天。幼鸟出生后，父母共同喂养，直至幼鸟约两个月大，羽毛成熟，能够独立下海。","identification":"长眉企鹅与白颊黄眉企鹅极为相似，但白颊黄眉企鹅面部为白色。与南方岩企鹅也有相似之处，但长眉企鹅体型更大，喙更粗壮，黄色头冠更为垂坠。不同亚种间的辨识主要基于地理位置。","protection":"IUCN：VU（易危）","distribution":"分布于南极半岛至亚南极岛屿，包括南乔治亚岛、福克兰群岛、克罗泽群岛、凯尔盖伦群岛、赫德岛、麦克唐纳群岛等地。","other":"长眉企鹅数量自1970年代中期以来普遍下降，全球种群估计约1800万只，被列为易危物种。"},{"name":"黄眼企鹅","english_name":"Yellow-eyed Penguin","scientific_name":"Megadyptes antipodes","overview":"黄眼企鹅（英文名：Yellow-eyed Penguin，学名：Megadyptes antipodes），是企鹅目企鹅科黄眼企鹅属的鸟类。是新西兰特有的大型企鹅，以其独特的黄色眼带和黄色瞳孔著称。体长约66至76厘米，体重3.6至8.9千克，平均寿命20至25岁。分布于新西兰南岛东南岸、斯图尔特岛、奥克兰群岛及坎贝尔岛。黄眼企鹅以鱼类为主要食物，是全球最为罕见的企鹅之一。","appearance":"成年黄眼企鹅有明显的黄色眼带，眼珠浅黄色，头部顶部和脸的前部为淡黄色羽毛，后颈有黄色带，上身黑色，翼下白色或粉红色，腹白。雏鸟头部颜色较暗，无黄色带，眼珠呈灰色。成鸟站立时身高约66至76厘米，体重3.6至8.9千克。","call":"黄眼企鹅发出尖锐刺耳的叫声，伸长脖子对天大叫，胸部肌肉起伏，叫声用于沟通。","habits":"黄眼企鹅生活在有密集植被的海岸附近，主要在斜坡、沟壑或悬崖顶上筑巢。它们栖息在浅海沿海水域，主要在近海觅食。成年企鹅多为定居状态，靠近繁殖地，而幼年企鹅有时会分散到北部，最远可达600公里。","breeding":"繁殖季节为8月至10月，每巢产2枚蛋，由双亲轮流孵育，孵化期39至51天。雏鸟不形成群居，孵化后97至119天离巢独立。雌鸟性成熟年龄为2至3岁，雄鸟为4至5岁。","identification":"黄眼企鹅可通过其独特的黄色眼带和头部特征与其他企鹅种类区分。","protection":"IUCN：EN（濒危）黄眼企鹅是濒危物种，主要威胁包括栖息地破坏、外来掠食者和气候变化。2007年在卡特林斯海岸设立了保护区。","distribution":"繁殖于新西兰南岛东部及东南部、斯图尔特岛、奥克兰群岛和坎贝尔岛。","other":"2004年春季，奥塔哥半岛和北奥塔哥的黄眼企鹅群体遭受未知疾病影响，导致约60%的雏鸟死亡。"},{"name":"小企鹅","english_name":"Little Penguin","scientific_name":"Eudyptula minor","overview":"小企鹅（英文名：Little Penguin，学名：Eudyptula minor），是企鹅目企鹅科小企鹅属的鸟类。又名: 小蓝企鹅、蓝企鹅、神仙企鹅、仙企鹅、小鳍脚企鹅，是企鹅家族中体型最小的物种，因拥有一身蓝色的羽毛而得名。广泛分布于澳大利亚南部和新西兰，包括查塔姆群岛和斯图尔特岛。小企鹅的平均身高约40厘米，体重约1千克，与常见的黑白色企鹅不同，它们的蓝色羽毛成为显著特征。","appearance":"小企鹅的身高普遍为43厘米，体重约1千克，雄鸟略大于雌鸟。头部和背部呈明亮的靛蓝色，耳部为青灰色，腹部为白色。鳍外部为靛蓝色，内部为白色，喙深灰黑色，长约3至4厘米，脚部上方为粉红色，下方和蹼为黑色。未成熟的个体喙较短，蓝色羽毛颜色较淡。平均寿命6.5年，个别个体可达20岁以上。","call":"小企鹅在繁殖地非常喧闹，尤其是夜间，发出各种延长的颤音、嘶吼声、低沉的咆哮和哼哼声，以及响亮的吠叫、号角声和哀号。接触叫声为短暂、尖锐的“huk”。","habits":"小企鹅栖息于温带海洋水域，通常在沙滩或岩石岛屿上筑巢，有时高达300米远离海岸线，海拔超过50米。它们主要以浮游鱼类为食，如澳大利亚鳀鱼、澳大利亚沙丁鱼和小白鱼，偶尔也会捕食头足类动物和甲壳类动物。小企鹅擅长潜水捕食，深度可达50米，偶尔更深，曾记录最深潜水达69米。冬季，它们的活动范围更广，进行单日或数日的远距离觅食旅行。","breeding":"小企鹅的繁殖季节主要在7月至12月，高峰期在8月至11月，但全年都有记录。一窝产2枚卵，偶尔1枚，孵化期为33至37天，由双亲轮流孵化。雏鸟为单个，孵化后50至55天离巢。繁殖成功率在16%至51%之间。首次繁殖年龄在2至4岁。","identification":"小企鹅与其他企鹅种类的区别在于其较小的体型和独特的蓝色羽毛。与其他小企鹅亚种的区别主要在于背羽的颜色、喙的大小和体重差异。","protection":"IUCN：LC（无危）。小企鹅在全球范围内并不受威胁，但某些地区的种群正在下降。在塔斯马尼亚，由于人类活动的压力，小企鹅的数量可能面临灭绝的风险。","distribution":"繁殖区域主要集中在澳大利亚南部沿海和新西兰南岛，包括斯图尔特岛和查塔姆群岛。非繁殖期间，它们的分布可能更为广泛，但不会离开近海大陆架水域。","other":"小蓝企鹅是多个地区著名的旅游吸引点，例如澳大利亚的菲利普岛每年吸引数十万游客前来观看。"},{"name":"南非企鹅","english_name":"African Penguin","scientific_name":"Spheniscus demersus","overview":"南非企鹅（英文名：African Penguin，学名：Spheniscus demersus），是企鹅目企鹅科环企鹅属的鸟类。体型中等的企鹅，高约60至70厘米，体重在2.2至3.5公斤之间。拥有独特的黑色面部面具和粉色眼周皮肤，以及明显的黑脚和腹部的黑色带纹。","appearance":"成年南非企鹅身长约60至70厘米，体重介于2.2至3.5公斤。头部呈现黑色，与白色下体形成鲜明对比，胸部带有黑色的倒U形标记，每只企鹅的黑色斑点图案独一无二。幼鸟上体呈深灰色，下体为白色，随着成长，逐渐发展出成鸟的特征标记。","call":"南非企鹅发出响亮的类似驴叫的声音，这也是它们‘公驴企鹅’别名的由来。","habits":"南非企鹅栖息于非洲西南部的岛屿上，偏好有植被覆盖的平坦沙岛，偶尔也会选择陡峭岩岛。它们主要在近海活动，以小型群居鱼类如沙丁鱼、马鲛鱼和乌贼为食，潜水深度可达130米。","breeding":"繁殖季节通常在11月至翌年3月，每窝产卵2枚，孵化期大约38至41天。成鸟轮流孵卵，孵化后父母共同照顾幼鸟直至其独立。","identification":"与同属的其他企鹅相比，南非企鹅有更圆润的头部轮廓，面部皮肤仅限于上脸，且缺乏喉部的白色线条。","protection":"IUCN：CR（极危）","distribution":"南非企鹅的繁殖区域集中在纳米比亚南部和南非南部沿海岛屿，非繁殖期间分布范围可延伸至纳米比亚中部和非洲东南部。","other":"历史上，人类收集企鹅蛋作为美食，导致其数量大幅下降。气候变化和海平面上升也对其栖息地构成威胁，使得原本隔离的岛屿与大陆相连，增加了陆地捕食者的威胁。"},{"name":"南美企鹅","english_name":"Magellanic Penguin","scientific_name":"Spheniscus magellanicus","overview":"南美企鹅（英文名：Magellanic Penguin，学名：Spheniscus magellanicus），是企鹅目企鹅科环企鹅属的鸟类。温带中型企鹅，高约70厘米，重2.3-7.8千克。头部主要为黑色，具有一条独特的白色宽带从眼睛后方绕过耳朵至下颌附近。主要分布于南美洲的阿根廷、智利沿海以及福克兰群岛，偶尔迁徙至巴西。全球数量约180万对，是环企鹅属中最繁盛的种类。","appearance":"成年南美企鹅具有黑色背部和白色腹部，两条黑色的胸带，下部呈倒U形。头部为黑色，两侧有宽阔的白色边框，从眼睛后方延伸至喉咙。幼鸟背部灰蓝色，胸部颜色较淡。成年后脚部变黑，翼部用于游泳，刚硬而紧凑。成年个体比雌鸟稍大。","call":"在繁殖地发出响亮的嘶吼声。在海上或陆地上，常发出单个“haaa”或“haw”的接触叫声。","habits":"栖息于海洋，繁殖季节在海滩、沙丘或粘土丘上筑巢，有时在森林或草坡。主要捕食小型鱼类、乌贼和甲壳类。冬季向北迁徙至巴西东南部。在繁殖季结束后的换羽期，会离岸出海约一个月。","breeding":"8月至9月抵达繁殖地，9月至11月产卵。在长达2米的洞穴或遮荫处筑巢，产卵2枚，孵卵期38-42天，由双亲交替孵化。幼鸟在20-23天后组成托儿所，80天左右离巢。繁殖成功率在0.02-1.36只幼鸟/对之间。","identification":"与秘鲁企鹅相比，具有双条黑色胸带，更宽的白色眉毛，且喙基部下方无大片粉红色斑块。幼鸟与秘鲁企鹅幼鸟相似，但头颈图案差异明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于智利沿海中部和阿根廷中部至合恩角及福克兰群岛。非繁殖期分布至巴西东南部。","other":"面临石油污染、食物短缺和气候变化的威胁。"},{"name":"秘鲁企鹅","english_name":"Humboldt Penguin","scientific_name":"Spheniscus humboldti","overview":"秘鲁企鹅（英文名：Humboldt Penguin，学名：Spheniscus humboldti），是企鹅目企鹅科环企鹅属的鸟类。分布于南美洲西岸的企鹅，以亚历山大·冯·洪堡命名。栖息于秘鲁和智利沿岸，依赖于洪堡寒流带来的丰富食物资源。体长约70厘米，体重4至4.7千克，寿命可达20年。面部特征显著，有黑色条纹和独特的粉色嘴基，背部、尾巴、脚和蹼为黑色，胸部有一道黑色宽带。繁殖于南美洲西岸的岛屿，营巢于洞穴、裂缝和沙坑中。","appearance":"秘鲁企鹅身长约70厘米，鳍状肢长约17厘米，体重4至4.7千克。头部呈黑色，具有一条从眼后延伸至下颌附近的白色宽带，下颌基部有粉色条纹延伸至眼睛。背部、尾巴、脚和蹼均为黑色，背部有时带有白色斑点。成鸟特征明显，包括大型的粉色嘴基和单一的黑色胸带；幼鸟相似于Magellanic企鹅，但通常显示较大的粉色嘴基，类似于成鸟。","call":"一系列短而响亮的嘶鸣声。联系叫声是一种较为延长的沙哑音符。","habits":"栖息于海洋环境，筑巢于岛屿和岩石海岸，偏好有悬崖和海洞的地区，尤其喜欢有鸟粪沉积的地方挖掘巢穴。主要以浮游鱼类、鱿鱼和甲壳类为食，捕食深度通常在水面下30米内。白天进行大部分觅食活动。雄鸟和雌鸟在育儿期间会进行夜间和日间的觅食行程。","breeding":"群居繁殖，通常在小群体中筑巢。巢位于洞穴或由雄鸟主要挖掘的鸟粪层中的巢穴，有时在岩石裂缝或海洞中，偶尔在受陆地掠食者保护的开放地点。每窝产两枚卵，孵化期约40天。雏鸟褐色灰色，下部较浅，第二层绒毛深棕色灰色，胸前宽阔，面后、喉部和腹部白色。繁殖活动全年发生，但在中智利有两个主要繁殖期，春季（8月至1月）和秋季（4月至6月）。","identification":"与Magellanic企鹅相比，秘鲁企鹅具有较大的粉色嘴基，缺乏黑色颈圈，且翅膀下部有更多黑色标记。成鸟很容易识别，但幼鸟与Magellanic企鹅非常相似，现场识别可能不总是安全的。","protection":"IUCN：VU（易危）。全球种群估计在37,000至60,000只之间，分布在至少73个繁殖群落。历史上因鸟粪采集导致繁殖地减少，近年来由于渔业过度捕捞和环境威胁，数量持续下降。","distribution":"分布于南美洲西岸，从秘鲁北部至智利中部，受洪堡寒流影响的沿岸地区。","other":"秘鲁企鹅的繁殖地历史上的过度开发对其造成了重大影响，而近年来人类活动加剧了食物短缺和生存威胁。"},{"name":"加岛企鹅","english_name":"Galapagos Penguin","scientific_name":"Spheniscus mendiculus","overview":"加岛企鹅（英文名：Galapagos Penguin，学名：Spheniscus mendiculus），是企鹅目企鹅科环企鹅属的鸟类。又名: 加岛环企鹅、加拉帕戈斯企鹅、科隆企鹅、阿拉巴戈企鹅，是世界上分布最北的企鹅种类，仅见于南美洲厄瓜多尔的加拉帕戈斯群岛。这种小型企鹅依靠加拉帕戈斯群岛周边由Cromwell和Humboldt洋流带来的清凉、富含营养的水域生存。在岛屿的裂缝和洞穴中繁殖，主要捕食近海的群居鱼类，如鲻鱼。加岛企鹅数量极为稀少，估计现存约1000只，被列为濒危物种。","appearance":"加岛企鹅体型小巧，站立时高约50厘米，鳍脚长约10厘米，平均体重介于2至2.5千克。其背部为深黑色，腹部为白色，点缀着黑色羽毛斑点。眼睛周围有一圈粉红色裸露皮肤，一条白色线条从眼眉延伸至喉咙，连接下颌。胸部上方有一条不显眼的灰黑色条纹。细长的鳍脚底部带有淡黄色，下部羽毛自白色下巴向下延伸。鳍脚下的裸露皮肤和眼睛周围呈现粉红色，伴有黑色斑点。","habits":"加岛企鹅适应了热带环境，栖息于赤道附近气温高达40℃的孤岛上，海水表层温度可达14至29℃。它们在冷水中觅食和繁殖，日间潜入冷水保持体温，夜间则返回陆地。为了应对酷热，加岛企鹅利用鳍脚遮挡下半身，弯腰掩护双脚，让阳光照射背部。在极端高温下，它们会张开鳍脚增加散热，或通过快速喘息降低体温，必要时选择跳入水中避暑。","breeding":"加岛企鹅全年繁殖，依赖海洋环境中的食物资源波动。它们在岛屿的岩隙和洞穴中筑巢，通常在每年5月至7月间，因食物充足且气候条件适宜而最为活跃。雌雄成对生活，共同筑巢并轮流孵卵，每窝产卵一至两枚，孵化期约为38至40天。雏鸟约需60至65天即可独立。","identification":"加岛企鹅与同属的秘鲁企鹅相似，但后者具有更多裸露的粉红色皮肤在喙基部，而加岛企鹅的喙基部较为暗色，仅在下喙部分呈现粉红。此外，加岛企鹅的面部白色线条较窄且不明显。两物种生态位不同，秘鲁企鹅分布于南美洲中部至智利海岸。","protection":"IUCN：EN（濒危）","distribution":"加岛企鹅主要分布于南美洲厄瓜多尔的加拉帕戈斯群岛西部，包括费尔南迪纳岛和伊莎贝拉岛的西岸，小规模群体亦可见于圣塔克鲁兹岛北部、弗洛雷阿纳岛等地。"},{"name":"黄蹼洋海燕","english_name":"Wilson's Storm Petrel","scientific_name":"Oceanites oceanicus","overview":"黄蹼洋海燕（英文名：Wilson's Storm Petrel，学名：Oceanites oceanicus），是鹱形目洋海燕科洋海燕属的鸟类。数量估计达数百万对，分布广泛，遍布世界各大洋，从南极洲海岸到大西洋北极水域，甚至深入波斯湾、红海和墨西哥湾等内陆海域。以浮游甲壳类为食，主要在飞行中觅食，轻触水面吸引或惊扰接近表面的食物。","appearance":"体型小，约16-18.5厘米长，翼展38-42厘米，全身暗褐色，仅臀部和侧腹白色，形成鲜明对比。腿长，脚蹼黄色，飞行时可见。头部和上体呈烟灰色，翅膀深色，具淡灰棕色的大覆羽。雌雄相似，但雌鸟略大。幼鸟似成鸟，但新羽中有时可见腹部有白色羽毛。","call":"在觅食时会发出柔和的鸣叫声。","habits":"严格远洋生活，非繁殖季节远离陆地。夏季在南极沿岸岛屿繁殖，冬季迁至北半球海域。常见于北大西洋，偶尔被暴风雨推向陆地。在海上低飞，习惯性拍打水面觅食，利用波浪产生的微风稳定飞行。","breeding":"在南极地区筑巢于岩石裂缝或松土中的小洞穴，通常在夜间活动以躲避天敌。每次产一枚白色卵，由双亲共同孵化和喂养。幼鸟在巢中待约60天，以磷虾、鱼和端足目动物为食。","identification":"与暴风海燕相比，黄蹼洋海燕稍大，具有更宽泛的淡色翼斑，而缺乏暴风海燕的白色翼下缘。脚蹼颜色也是区别点。","protection":"IUCN：LC（无危）","distribution":"繁殖于南极沿岸、南乔治亚岛、克罗泽群岛、赫德岛、凯尔盖朗群岛和澳大利亚东南远海的麦夸里岛。非繁殖季节分布于除热带和北太平洋外的世界各大洋。","other":"其独特的飞行方式和适应性使它成为南极地区最小的温血繁殖动物。"},{"name":"白臀洋海燕","english_name":"Elliot's Storm Petrel","scientific_name":"Oceanites gracilis","overview":"白臀洋海燕（英文名：Elliot's Storm Petrel，学名：Oceanites gracilis），是鹱形目洋海燕科洋海燕属的鸟类。小型的海洋鸟类，主要分布在北部洪堡寒流区域（智利北部海岸可见）和加拉帕戈斯群岛海域。以黑色身躯、白色臀部和腹部为显著特征，分布范围虽限，但数量可观。","appearance":"白臀洋海燕体长约15至16厘米，体重约14至17克。全身呈深褐色，头部颜色较浅；上体覆羽具白色，形成鲜明的马蹄形斑纹；尾部方形，尾羽末端两对外侧有基部白色羽轴；上翼深褐色，大覆羽灰白色，尤以外侧和中央覆羽为甚；下翼深色，仅大覆羽、中覆羽尖端及大主覆羽大部分呈白色，形成银色带状；下体除明显的白色腹部至后侧腹及侧尾下覆羽外，其余部位与上体颜色相近；大腿处有窄窄的暗色条纹将其与腹部白色区域隔开。眼睛深棕色，喙、腿和脚黑色，蹼黄色边缘黑色。","habits":"主要栖息于开阔海域，常见于凉水区域，靠近陆地。在洪堡寒流沿岸的南美洲西岸，活动范围大致在北纬2度至南纬33度之间。以小鱼（包括海狮和其他海洋哺乳动物捕食后留下的残余）和浮游甲壳类动物为食。主要在飞行中觅食，通过在水面拍打和偶尔的俯冲获取食物。经常跟随船只和拖网渔船，据报道会与鲸类一同出现。","breeding":"在加拉帕戈斯群岛的繁殖季节可能在4月至9月的冷季。在智利和可能的秘鲁，繁殖习性知之甚少，但在1月初在智利北部观察到正在孵化和喂养雏鸟。筑巢于岩石缝隙中，宽度1至2米，高度可达15厘米，深度约1至2米，离地面0.5至2米高，巢间距仅为30至40厘米。每窝产一枚无斑点的白色蛋，大小约为26.9毫米×19.5毫米。已知的唯一繁殖地面临老鼠和火灾的潜在威胁。","identification":"白臀洋海燕以其体型较小、尾部方形、下体大面积白色为识别特征。与之相比，黄蹼洋海燕体型略大，但不具备白臀洋海燕的白色腹部特征。白臀洋海燕的飞行不如加岛叉尾海燕那样有力。","protection":"IUCN：DD（数据缺乏）。虽然数量众多，但目前只有一个已知的繁殖地，即智利北部的Chungungo岛，那里最多发现了20个巢穴。加拉帕戈斯群岛估计有数千至数万只，但具体数字未知。目前没有已知的直接威胁，但需保护已知繁殖地免受老鼠和火灾的影响。","distribution":"繁殖区域：智利中部的Chungunga岛至少；可能还包括加拉帕戈斯群岛。非繁殖区域：从厄瓜多尔到智利中部的洪堡寒流及加拉帕戈斯群岛周围水域。","other":"尽管在海上频繁出现，但白臀洋海燕的繁殖地十分神秘，仅在2003年前于智利沿海的Isla Chungungo发现过一个巢穴。在加拉帕戈斯群岛，虽然该物种似乎为居民鸟，但具体的繁殖地仍未被发现。"},{"name":"黑洋海燕","english_name":"Pincoya Storm Petrel","scientific_name":"Oceanites pincoyae","overview":"黑洋海燕（英文名：Pincoya Storm Petrel，学名：Oceanites pincoyae），是鹱形目洋海燕科洋海燕属的鸟类。直至2011年正式发现并进行了科学描述。仅在智利Chiloé岛附近的水域被记录。","appearance":"黑洋海燕是一种小型海鸟，体长约16厘米，体重介于22至30克之间。头部、背部、肩羽呈深褐色，新鲜羽毛在良好光照下显现出银灰色光泽。尾上覆羽白色，形成明显的马蹄形图案，与臀部和尾巴的深褐色形成鲜明对比。翼上覆羽和内侧大飞羽有显著的白色边缘，尤其在新鲜羽毛时最为抢眼。初级飞羽外缘有薄薄的白色边缘，次级飞羽和最长的三级飞羽有较细的白色边缘。下体除下巴略淡灰色外，其余部位颜色略浅于上体。两性相似，幼鸟通常色调较浅，翼上的白色边缘更宽，更为醒目。","call":"在觅食群体中，持续发出类似麻雀的嘈杂鸣叫。","habits":"常见于智利峡湾系统中受保护的\"内陆\"水域，水深约100至200米，尚未在远洋水域有记录。以独特的捕食方式，包括翅膀折叠的\"鼠跑\"和半浸入水面的脚蹼，还有反复潜水捕食。常单独或成对出现，但在优质觅食点会聚集数百只。","breeding":"关于繁殖细节未知。据换羽数据预测，繁殖季始于10月初，鸟儿返回繁殖地，11月中旬开始产卵，2月中下旬幼鸟离巢。预计每次产一枚卵。","identification":"与普遍存在的黄蹼洋海燕相似，但平均有更多白色羽毛，尤其是在翼下和腹部区域。'经典'的Pincoya在翼下有大的白色斑块，但其他个体总体颜色更深，可能与黄蹼洋海燕难以区分。","protection":"IUCN：DD（数据缺乏）。2013年基于1983年以来的观察记录、2009年的照片、2011年收集的标本以及1972和1983年被忽视的阿根廷标本描述。据估计现有约3000只个体，相当于2000只成熟个体。Seno Reloncavi和Chilotan Sea是受保护的内陆水域。","distribution":"仅知分布于智利中南部Los Lagos地区的Reloncavi Sound（Puerto Montt北部，Chiloe附近），繁殖地未知。","other":"人类活动增加可能导致航运事故和污染风险增加。该地区商业鲑鱼和贻贝养殖场的扩张涉及使用聚苯乙烯浮标，这些浮标可能分解为微粒并被鸟类吞食。"},{"name":"灰背海燕","english_name":"Grey-backed Storm Petrel","scientific_name":"Garrodia nereis","overview":"灰背海燕（英文名：Grey-backed Storm Petrel，学名：Garrodia nereis），是鹱形目洋海燕科灰背海燕属的鸟类。分布于南极洲周边海域的多个群岛，包括阿根廷、澳大利亚、新西兰等国的南部岛屿。这种海鸟体型小巧，体重约21至44克，翼展可达39厘米。其显著特征是灰黑色的头部、颈部、喉部及上胸部，背部和翅膀上部颜色较淡，臀部呈灰白色，腹部和下体为白色，与暗色的头部形成鲜明对比。灰背海燕被吸引到明亮的灯光下，尤其是在能见度低的情况下。","appearance":"灰背海燕是一种小型海鸟，体长16至19厘米，体重介于21至44克之间，翼展39厘米。其头部至颈后和上胸为黑灰色，形成类似兜帽的外观，而背部和翅膀上部为深灰色，边缘更显黑色。主要特征包括方形或略圆的尾部、灰白的臀部和白色腹部，以及明显的黑白对比。其翅膀上有两道浅灰色的条纹，形成两个苍白的翼斑。下体和下翼白色，与暗色的头形成强烈对比。虹膜深棕色，喙和腿脚为灰黑色。性别相似，但雌鸟通常在多数测量指标上稍大。幼鸟与成鸟相似。","habits":"灰背海燕偏好靠近大陆架的海域，而非完全的远洋环境，以小鱼和甲壳类动物为食。它们的飞行迅速而起伏，几乎贴近海面飞行，展现出轻盈的翅膀拍打。它们在密集的草地或陡峭地形中的群落中筑巢，偶尔单独繁殖，每次产一枚蛋。尽管猫、鼠和短耳鸮对其构成威胁，但总体而言，灰背海燕的全球数量并不处于威胁状态。","breeding":"繁殖期从8月持续至次年3月，灰背海燕在大型群落中繁殖，偶尔也会单独繁殖。它们在密集的草地或陡峭地形中筑巢，每次产一枚蛋，共同承担育儿责任。","identification":"与黑腹舰海燕相比，灰背海燕具有大部分白色的尾下覆羽，且体型略小。与白腹舰海燕相比，后者偏爱温暖水域，不太可能与灰背海燕共存。灰背海燕的腿脚不会像某些同类那样明显超出尾巴。与白臀洋海燕的区别在于分布范围不同，以及艾略特海燕拥有较大的白色腹斑，整体外观更接近深褐色。","protection":"IUCN：LC（无危）","distribution":"繁殖于南大西洋的福克兰群岛、南乔治亚岛和戈夫岛，印度洋西南部的克罗泽群岛和凯尔盖朗群岛，澳大利亚东南远端的麦夸里岛，新西兰的查塔姆群岛、安提波底斯群岛和奥克兰群岛，以及新西兰本土的峡湾地区。非繁殖季节分布至南极辐合带南部和塔斯曼海。"},{"name":"白脸海燕","english_name":"White-faced Storm Petrel","scientific_name":"Pelagodroma marina","overview":"白脸海燕（英文名：White-faced Storm Petrel，学名：Pelagodroma marina），是鹱形目洋海燕科白脸海燕属的鸟类。小型海鸟。拥有独特的白色脸部和黑色眼罩，以及灰褐色背部，翅膀带有黑色飞羽，腹部洁白，易于在海上识别。繁殖于偏远岛屿，包括大西洋的特里斯坦-达库尼亚群岛、澳大利亚和新西兰，以及北极大西洋的几个岛屿。","appearance":"白脸海燕体型中等，长18-21厘米，翼展38-45厘米，体重40-68克。头部呈暗褐色，面部为白色，有一黑色眼罩。上身灰褐色，翼覆羽有较淡的尖端形成狭窄的白色条纹，尾部黑色，下体白色，颈侧有宽幅的棕色带。腿长，飞行时明显超出尾部，脚蹼黄白色。雌雄相似，但雌鸟可能在翼和尾测量上稍大。幼鸟与成鸟类似，但上体羽毛边缘更宽，颜色可能偏灰或棕色。","call":"在巢穴附近发出哀伤的“woooo”或“ooo-aaa-ooo”声，通常在飞行和海上保持沉默，但在喂食时偶尔能听到微弱的吱吱声。","habits":"白脸海燕主要生活在海洋和远洋环境中，远离陆地，除非在繁殖季节。它们在孤立的岛屿上繁殖，偏好平坦沙地或低草植被地带，也见于岩石区和斜坡。其饮食以浮游甲壳类动物为主，辅以一些鱿鱼和至少三种海跳蚤。夜间活动频繁，白天在空中觅食，通过拍打水面和潜水捕捉食物。在繁殖岛屿上，它们会避开明亮的月夜。","breeding":"繁殖期通常在春季到夏季，筑巢于30-120厘米长的洞穴中，通常位于软土下，洞穴内部以干植物材料铺垫。每窝产一枚白色带斑点的蛋，由双亲轮流孵化约38-59天。雏鸟出生时覆盖着灰色绒毛，孵化后前2-4天由父母照料，之后逐渐独立。50-70天后离巢，体重可达54克，高峰期体重约为90克。","identification":"与其他北极大西洋海燕相比，白脸海燕具有明显的白色脸部和黑色眼罩，以及灰褐色背部和白色腹部。幼鸟和成鸟的区别在于上体羽毛边缘更宽，颜色可能偏灰或棕色。不同亚种之间存在大小、颜色和比例上的细微差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于大西洋的特里斯坦-达库尼亚群岛、戈夫岛、萨尔瓦热群岛、加那利群岛和佛得角群岛，以及澳大利亚和新西兰的岛屿。非繁殖期分布广泛，可见于亚热带北、南大西洋，印度洋西北部至塞舌尔群岛，以及太平洋东南部海域。","other":"白脸海燕对人类干扰非常敏感，曾遭受渔民的局部捕猎，同时面临引入的捕食者的威胁，如老鼠、猫、蛇等。"},{"name":"白腹舰海燕","english_name":"White-bellied Storm Petrel","scientific_name":"Fregetta grallaria","overview":"白腹舰海燕（英文名：White-bellied Storm Petrel，学名：Fregetta grallaria），是鹱形目洋海燕科舰海燕属的鸟类。以黑色上部和白色腹部及臀部为显著特征，分布于太平洋、大西洋和印度洋的热带和亚热带海域。其繁殖地分散于多个岛屿群，包括澳大利亚东侧的Lord Howe岛、新西兰东北的Kermadec群岛、法属波利尼西亚的Austral群岛、智利东南的Juan Fernandez群岛以及圣赫勒拿的Tristan da Cunha群岛。","appearance":"白腹舰海燕体型小至中等，长度约18至22厘米，翼展46至48厘米，体重45至65克。近黑色的鸟，具有方形尾巴，尾端之外通常不伸出趾爪，上尾覆羽、腹部和中央翼下覆羽为白色。上部除鲜明对比的宽白色尾上覆羽带外几乎全黑，上翼覆羽略呈褐色，大覆羽具淡色尖端形成窄翼斑，飞羽和尾部更黑，仅在侧尾羽基部有白色。刚换羽时，肩、背和肩羽显现出细窄的白色边缘，使上部呈现精细的鳞片状图案。翼下覆羽黑色，仅大覆羽和中覆羽形成中央翼上的大面积白色板块，外侧初级覆羽通常大部分暗色；颈部、上胸和尾下覆羽为深褐色，其余下部白色，与中央翼下的白色板块和上尾覆羽相连；虹膜深棕色；喙、腿和脚均为黑色。暗色型个体在上尾覆羽和翼下覆羽上有所不同，分别为深褐黑色和暗褐色。雌雄相似，但雌鸟在大多数测量中平均略大，特别是在leucogaster亚种中（例如平均翼长179毫米对162毫米）。幼鸟与成鸟外观相同。不同亚种在体型和颜色上有所差异。","call":"白腹舰海燕在海上通常是沉默的，但在陆地上时会发出类似同属其他物种的叫声，包括持续的哨音颤音（\"pee-pee-pee-pee...\"重复多达20次）和在威胁或警报时的刺耳叫声。","habits":"白腹舰海燕主要栖息于开放海域，极少接近陆地，除非是在繁殖季节接近繁殖地。它们在高盐度的热带水域活动，繁殖于远离大陆的岛屿或岩堆中，有时高达海拔450米。它们的飞行模式类似于同属物种，但可能更加多样和不规则，有时带有更多滑翔，蹦跳飞行时看起来略微头重脚轻。它们在繁殖季节后似乎向北迁移至较低纬度，但具体迁徙模式尚不清楚。","breeding":"繁殖期在夏季后期，筑巢于岩石裂缝或浅洞穴中，有时在平地或斜坡上，偶尔在悬垂的草下，而不是土壤中，巢穴用附近的植被衬垫。繁殖发生在晚夏和早秋，1月到3月间开始产卵，4月中旬至5月间观察到幼鸟离巢。平均一窝仅产一枚淡奶油色带轻微粉色斑点的大端蛋，大小约为36.3mm×26.4mm，重量13.2至14.2克。","identification":"白腹舰海燕通过其独特的上尾覆羽白色带和全部白色的腹部及大部分中央翼下覆羽与同属其他物种区分开来。它与黑腹舰海燕在分布上有局部重叠，但后者完全白色腹部的例子在西南太平洋相对较少。此外，白腹舰海燕的腿较短，飞行时趾爪最多仅略超出尾尖，而头部覆盖范围较小，仅达到中胸或上胸。在大西洋，该物种的翼下黑色边缘比黑腹舰海燕窄。","protection":"IUCN：LC（无危）","distribution":"繁殖区域分布在南半球热带和亚热带海洋岛屿，包括印度洋南部岛屿、澳大利亚东侧的Lord Howe岛、新西兰东北的Kermadec群岛、法属波利尼西亚的Rapa岛（Austral群岛）、智利东部的San Felix和San Ambrosio岛（复活节群岛）以及Juan Fernandez群岛（智利中部西侧）。非繁殖期间分布于赤道与亚热带收敛带之间的热带和亚热带南部海域。","other":"白腹舰海燕面临的主要威胁包括入侵物种如猫和鼠类的捕食，尤其是这些物种通过捕鱼和船只活动引入到繁殖岛屿上。全球气候变化可能影响其繁殖成功和食物分布，增加物种的脆弱性。"},{"name":"黑腹舰海燕","english_name":"Black-bellied Storm Petrel","scientific_name":"Fregetta tropica","overview":"黑腹舰海燕（英文名：Black-bellied Storm Petrel，学名：Fregetta tropica），是鹱形目洋海燕科舰海燕属的鸟类。小型海鸟，以其黑色身躯与显眼的白色腹部著称，分布于南极圈附近的寒冷海域，冬季时会向北迁移至更为温带的水域。其分布范围广泛，从南乔治亚岛到南极半岛，再到新西兰以南的岛屿。","appearance":"黑腹舰海燕体型小，长度约19.5-21厘米，体重介于43-63克之间，翼展可达43-46厘米。其特征为近黑色的羽毛，脚趾略超出尾尖，上尾覆羽和腹部大部分呈白色，背部、肩部及上翅覆羽稍显棕色。翅膀上的大覆羽有较浅的尖端，形成狭窄的翼斑。颈部和胸部为深褐色，尾下覆羽同色，两者间常有一条宽阔的黑色条纹贯穿腹部中部（有时难以观察到）。其余下体和两侧的尾下覆羽为白色，与白色的下翼和上尾覆羽相连。雌雄相似，但雌鸟的翅膀、尾巴和跗跖测量值略大。幼鸟外观与成鸟相同。部分个体腹部中央可能全白或部分白色。","call":"在海上几乎无声，但在繁殖地能听到两种主要叫声：一种是穿透力强的哨声，类似欧亚金鸻的叫声，持续约1-4秒，随后是一秒的停顿，具有回音效果；另一种是连续的啾啾声，如“pee-eep-pip-pip-pip-...”。","habits":"黑腹舰海燕主要栖息于开阔海域，很少接近陆地，仅在繁殖季节靠近岛屿。它们在南极极锋以南的海域繁殖，非繁殖季迁徙至大西洋、印度洋和太平洋的热带和亚热带区域。它们的饮食主要包括鱿鱼、甲壳类动物和小鱼，尤其在繁殖期间。在海上，它们主要通过拍打水面的方式觅食，偶尔也会从空中俯冲。在印度洋，它们经常被发现在长线拖网渔船周围活动。","breeding":"黑腹舰海燕严格一夫一妻制，形成长期的配偶关系。它们在岩缝或浅洞穴中筑巢，通常不加衬垫，偶尔会加入一些苔藓。繁殖季节从九月开始，持续五周左右，每窝仅产一枚蛋，孵化期为35-44天。雏鸟出生时覆盖着淡灰色绒毛，每天平均喂食一次，直到65-71天后离巢，此时体重约为65-75克。","identification":"与威尔逊海燕相比，黑腹舰海燕体型稍大，最显著的区别在于其白色的腹部。然而，腹部的黑色条纹在某些个体中可能不明显。在背面观察时，与白腹舰海燕相似，但腹部的图案具有识别特征。此外，其腿通常比白腹舰海燕更长。","protection":"IUCN：LC（无危）","distribution":"繁殖于南极圈附近的岛屿，包括南乔治亚岛、南极半岛、布韦岛、特里斯坦达库尼亚群岛、王子爱德华群岛、克罗泽群岛、凯尔盖朗群岛、邦蒂群岛、安提波迪斯群岛和奥克兰群岛。非繁殖季节，它们广泛分布于南半球的海洋，北至赤道附近。","other":"黑腹舰海燕的种群数量估计在10万至15万对繁殖对之间，总个体数约为50万。尽管全球并不受到威胁，但在一些繁殖地上，由于迟来的解冻或异常的降雪可能会延迟或阻止筑巢，导致雏鸟饥饿。"},{"name":"新西兰舰海燕","english_name":"New Zealand Storm Petrel","scientific_name":"Fregetta maoriana","overview":"新西兰舰海燕（英文名：New Zealand Storm Petrel，学名：Fregetta maoriana），是鹱形目洋海燕科舰海燕属的鸟类。以深黑色的头部、胸部、上体和尾巴为显著特征，臀部和腹部白色，带有变化的暗色条纹。下翼具有一块浅色区域，边缘较深。其最引人注目的是异常长的腿，脚趾延伸至方形尾部之后。自2003年在新西兰小屏障岛被重新发现以来，这里是已知的唯一繁殖地点。该物种在新西兰北部海域较为常见。","appearance":"新西兰舰海燕长约17厘米，体重约35克，是体型中等的风暴海燕，头部较大，尾部末端呈方形。头部到胸部及上体，包括上翼和尾巴，颜色为深黑褐色，与白色下臀部和尾羽覆羽形成鲜明对比。下翼深色，中央翼下覆羽有白色面板；腹部到肛门部位白色，带有明显的变异性暗黑条纹；眼睛深色，喙和腿黑色。幼鸟特征未详述。","call":"未提供鸣叫特征描述。","habits":"新西兰舰海燕栖息于成熟混合亚热带森林下层，偏好高度超过30米的硬山毛榉和卡瑞树冠。它们在开阔海洋上觅食，可能更倾向于温暖水域。它们被认为有迁徙习性，夏季会在奥克兰附近的豪拉基湾出现，冬季则离开该区域，有记录显示它们会跨越塔斯曼海，向北到达珊瑚海。","breeding":"新西兰舰海燕的繁殖季节为1月至6月，具体时间在2月至6月/7月之间。它们在小屏障岛森林内部的岩石缝隙中筑巢，巢穴位于碎石覆盖的地面之下，远离月光，夜间活动。孵化期大约为5天轮换。","identification":"新西兰舰海燕与其他白腹风暴海燕的区别在于腹部的黑条纹，以及独特的中央下翼白色条带、方形尾巴和长腿。与相似大小的黄蹼洋海燕相比，后者具有白色下体和下翼面板，翅膀更加圆润，飞行姿态更为飘逸。","protection":"IUCN：CR（极危）","distribution":"新西兰舰海燕的繁殖区主要集中在新西兰北岛东部的小屏障岛。非繁殖期，它们会出现在澳大利亚东南部海域和斐济附近区域，以及波利尼西亚西南部。","other":"自1850年以来，人们认为新西兰舰海燕已经灭绝，直到2003年重新发现。全球数量估计在数百只，目前面临的主要威胁可能是引入的捕食者，如鼠类，对潜在繁殖地的影响。"},{"name":"新喀海燕","english_name":"New Caledonian Storm Petrel","scientific_name":"Fregetta lineata","overview":"新喀海燕（英文名：New Caledonian Storm Petrel，学名：Fregetta lineata），是鹱形目洋海燕科舰海燕属的鸟类。正式描述于2022年。主要在珊瑚海一带活动，特别是在新喀里多尼亚周围，但在马尔克萨斯群岛、萨摩亚和澳大利亚东北部也有发现，暗示其繁殖季节之外的活动范围可能更为广阔。与新西兰舰海燕极为相似，但新喀海燕翼下的白色区域更少，仅延伸至‘肩部’，腹部条纹更为密集，尤其是两侧。","appearance":"新喀海燕的外观与新西兰舰海燕非常相似，但它的翼下白色部分较少，仅到‘肩部’，且下体条纹更加密集，尤其是在两侧。平均而言，新喀海燕看起来更瘦长，颈部、尾巴和翅膀显得更长。头部、颈部和喉至上胸呈黑褐色，背部、肩羽和翼上覆羽基本为黑褐色，有绿色或灰色光泽。小尾上覆羽较棕，其余为白色，形成宽大的U形。翼上覆羽颜色与背羽相似，但稍带棕色，形成不明显的淡色斑块。翼下有一片宽阔的黑褐色前缘，与暗色上胸相连，涉及次级飞羽，而主飞羽大覆羽大部分为灰黑色。主飞羽大覆羽尖端和边缘狭窄，白色，但受限的翼下白色斑块主要涉及次级飞羽的中间和较大覆羽。飞行羽本质上是均匀的灰黑色。","habits":"新喀海燕在开阔海域觅食，可能偏好温暖水域。它们像其他Fregetta海燕一样，从海面收集猎物。","breeding":"关于繁殖栖息地一无所知。新喀海燕的繁殖地点疑似在西南太平洋和南太平洋中部，目前唯一的确定繁殖证据来自新喀里多尼亚。","identification":"与新西兰舰海燕相比，新喀海燕体型更大，翅膀和腿更长，腹部条纹通常更浓密、更大胆，翼下的白色斑块通常更窄，外观不那么干净（更多的翼下覆羽有宽的暗色中心）。此外，暗色上胸的下边界在新喀海燕中更圆润，从两侧的下胸弯曲到中央上胸，而在新西兰舰海燕中，这个边界对于其他白色的下体来说明显更直。","protection":"IUCN：DD（数据缺乏）","distribution":"繁殖区域：太平洋的新喀里多尼亚。非繁殖区域：澳大利亚东部海域、萨摩亚和马尔克萨斯群岛（西、东波利尼西亚）。"},{"name":"白喉海燕","english_name":"Polynesian Storm Petrel","scientific_name":"Nesofregetta fuliginosa","overview":"白喉海燕（英文名：Polynesian Storm Petrel，学名：Nesofregetta fuliginosa），是鹱形目洋海燕科白喉海燕属的鸟类。其最显著的特征是拥有宽阔的翅膀和深叉的尾巴，黑白分明的羽毛，尤其是白色的臀部和喉咙斑块。广泛分布在南太平洋热带海域，从新喀里多尼亚至马尔克斯群岛、甘比尔群岛和萨拉伊戈梅兹岛，历史记录显示在瓦努阿图、斐济和萨摩亚也有繁殖。该物种体型较大，展翅可达24至26厘米，体重在56至86克之间。","appearance":"白喉海燕是一种大型风暴海燕，拥有宽大的翅膀和长而深叉的尾巴。其羽毛呈鲜明的黑白色，上体黑色，下体白色，翼下有明显的白色区域，尾巴上有对比鲜明的白色马蹄形斑。头部、喉咙和腹部为白色，胸部有一条宽大的黑色带。幼鸟与成鸟外观相似。该物种具有多态性，某些岛屿上的个体可能仅表现为浅色或深色形态。","call":"在海上时，白喉海燕通常保持沉默，但在繁殖地附近会发出低沉的咕噜声。","habits":"白喉海燕主要栖息在远离陆地的海洋中，偶尔在繁殖季节接近岛屿。它们在偏远的珊瑚礁、岛屿或岩堆中繁殖，筑巢于岩石缝隙或草丛中。该物种广泛分散在南太平洋温暖海域，以甲壳类、头足类和小型鱼类为食，通过在空中拍打水面和浅水潜水的方式觅食。","breeding":"繁殖期在全年内均有发生，高峰期为8月至12月。在基里巴斯的圣诞节岛上，繁殖活动在7月至12月间进行，但在南部春季（8月至12月）更为集中。白喉海燕在夜间访问繁殖地，每次产一枚蛋，平均尺寸为36毫米×27.5毫米。孵化期和离巢期分别约为50天和60天。","identification":"白喉海燕的体型、翅膀形状、尾部特征和飞行模式使其易于识别。与Fregetta风暴海燕相比，它更大，尾巴更长；与最大的Hydrobates风暴海燕相比，白喉海燕的头部显得较小，翅膀更宽，尾巴呈深叉状而非真正叉开。","protection":"IUCN：EN（濒危）。白喉海燕的总成熟个体数量估计仅有250至999只。该物种面临的主要威胁包括人类捕猎、外来哺乳动物的捕食以及全球气候变化导致的栖息地破坏。","distribution":"白喉海燕分布于南太平洋的热带海域，具体包括新喀里多尼亚、基里巴斯、马克萨斯群岛、甘比尔群岛、萨拉伊戈梅兹岛以及历史上的瓦努阿图、萨摩亚和斐济。","other":"白喉海燕的保护措施包括监测繁殖群体和入侵物种，恢复已丧失的繁殖岛屿，以及通过社会吸引和转移技术来重建种群。"},{"name":"黑背信天翁","english_name":"Laysan Albatross","scientific_name":"Phoebastria immutabilis","overview":"黑背信天翁（英文名：Laysan Albatross，学名：Phoebastria immutabilis），是鹱形目信天翁科北太平洋信天翁属的鸟类。中等体型的信天翁，冬候鸟，分布于北纬30°-55°的太平洋北部。繁殖主要在夏威夷群岛的偏远岛屿，如中途岛和莱桑岛，占全球99.7%的种群。近年来，它们的分布范围有所扩大，包括日本附近的波宁群岛和墨西哥的瓜达卢佩岛。黑背信天翁以其独特的北方繁殖地和亚热带繁殖范围而著称。","appearance":"黑背信天翁平均体长81厘米，翼展可达195-203厘米。雄鸟体重介于2.4-4.1千克之间，雌鸟略小，体重1.9-3.6千克。其上体呈黑灰色，翅膀、背部、臀部及尾巴颜色较深，头部、下体及臀下部则为白色。眼周有一黑色斑点，翅膀下表面有变化的黑色边缘和覆羽。喙呈粉色，尖端为暗色。幼鸟喙色较暗，上臀部颜色较深。成鸟无季节性换装。","call":"在海上通常是寂静的，但在繁殖地，黑背信天翁会发出长音似牛哞的叫声、下降的嘶鸣声或嘎嘎声。","habits":"黑背信天翁栖息于开阔的北太平洋，从日本到白令海，南至北纬15°。它们在繁殖季节返回岛屿，在非繁殖季节广泛分布。以动态滑翔的方式飞行，很少拍翅，主要在夜间坐在水面上觅食，捕食鱿鱼和其他小型猎物。","breeding":"繁殖周期较长，成鸟在7-8岁时首次繁殖，形成终身伴侣关系。每年繁殖，但有些个体可能每隔一年繁殖一次。繁殖季从11月持续到次年7月，巢建在开放的沙滩或草地。单产一枚蛋，孵化期约65天，雏鸟约160天后离巢。","identification":"与黑脚信天翁的区别在于全身深色的羽毛，与短尾信天翁相比，体型较小，背部全黑。面部灰色痕迹和翅膀下表面的黑色图案在个体间有差异。","protection":"IUCN：NT（近危）","distribution":"繁殖于北太平洋，主要集中在夏威夷群岛的偏远岛屿，如中途岛和莱桑岛。小群在波宁群岛和墨西哥的瓜达卢佩岛繁殖。非繁殖季节分布广泛，从日本到白令海，南至北纬15°。","other":"黑背信天翁面临的主要威胁包括长期渔业作业，尤其是延绳钓，以及海洋污染。保护努力集中在减少这些威胁和清理繁殖地的铅基油漆污染。"},{"name":"黑脚信天翁","english_name":"Black-footed Albatross","scientific_name":"Phoebastria nigripes","overview":"黑脚信天翁（英文名：Black-footed Albatross，学名：Phoebastria nigripes），是鹱形目信天翁科北太平洋信天翁属的鸟类。几乎全身覆盖着深褐色的羽毛，脸带白色调。成鸟可见淡色腹部，幼鸟则为较暗的褐色。该鸟种主要在夏威夷群岛的偏远海滩上繁殖，随后在北太平洋水域广泛游荡，从阿拉斯加到加州，甚至远至台湾和白令海。黑脚信天翁是唯一在北美太平洋沿岸定期出现的信天翁。","appearance":"体型相对较小的信天翁，身长64-74厘米，翼展193-216厘米，体重约2.8千克。整体呈现深褐色，仅在喙基部和眼下方有一圈白色。性别和年龄类别相似，但成年早期的个体臀部和尾下覆羽的白色较少。雄鸟比雌鸟略大，喙也较大。随着年龄增长，喙基部周围的白色逐渐增多。","call":"叫声范围从战斗时的尖叫声到求偶时的啄喙声、哨声、呻吟和呱呱声。","habits":"栖息于开阔的海洋环境中，远离陆地，主要在北太平洋的广阔水域中活动。以乌贼、鱼卵和鱼类残余为食，偶尔跟随船只捡食丢弃的食物。全年留居于北太平洋海域，但非繁殖季节会四处游荡。","breeding":"繁殖期为每年的10月至12月，实行一雌一雄制。到达繁殖地后开始求偶表演，直至整个繁殖期间。营巢于海滨沙地上的凹坑中，每窝仅产一枚卵，孵化期约为6周。","identification":"与罕见的莱桑信天翁相比，黑脚信天翁的整体暗色身体使其易于区分。窄长的翅膀与褐鹈鹕形成对比。","protection":"IUCN：NT（近危）; 中国国家重点保护野生动物名录新增，保护级别：I级（2021.02.05）","distribution":"繁殖区域主要位于日本南部的岛屿（如Torishima）和西北夏威夷群岛，其中97.5%的总人口集中在这些地区。非繁殖区域遍布北太平洋，从白令海至北回归线。","other":"历史上在中国台湾海峡常见，但近年来变得稀少。"},{"name":"加岛信天翁","english_name":"Waved Albatross","scientific_name":"Phoebastria irrorata","overview":"加岛信天翁（英文名：Waved Albatross，学名：Phoebastria irrorata），是鹱形目信天翁科北太平洋信天翁属的鸟类。仅在加拉帕戈斯群岛和厄瓜多尔沿岸的小岛上筑巢繁殖。成年个体头部和颈部呈黄白色，身体其余部分为褐色，拥有大而醒目的黄色喙。该物种的分布范围有限，主要活动于东部太平洋，尤其是厄瓜多尔和秘鲁沿海。种群数量正面临下降，属于极危物种。","appearance":"加岛信天翁体型中等至大型，长度约80-93厘米，翼展可达220-250厘米。成鸟头部和颈部为白色，带黄褐色调，上体深褐色，下体除胸部有细纹外为褐色，翅下白色带有棕色斑点。喙呈鲜艳的黄色，脚部灰蓝色。雄鸟平均比雌鸟稍大，幼鸟头部更白，喙较暗。","call":"展示行为中的叫声包括呱呱声、吠声和持续的天空鸣叫。","habits":"加岛信天翁栖息于海洋环境中，主要在秘鲁沿岸的洪堡洋流附近活动。它们会接近海岸，但仅限于洪堡洋流区域。繁殖季节结束后，它们会分散到东部太平洋水域，偶尔出现在南秘鲁和智利北部海域，尤其是在厄尔尼诺现象发生时更为常见。它们以鱼、鱿鱼和甲壳类动物为食，有时也会掠夺其他鸟类的食物。","breeding":"繁殖始于4月，雌雄配对通常为单配制，但研究发现雄鸟间存在额外配偶交配现象。繁殖期在加拉帕戈斯和伊莎贝拉岛同时开始，产卵发生在4月中旬至6月中旬。孵化期约为60天，幼鸟在出生后由双亲共同照顾，直到12月初离巢，体重达到3727克左右。","identification":"加岛信天翁的独特之处在于其头部和颈部的黄白色调，以及显著的黄色喙。与其它信天翁相比，其分布区域极为狭窄，仅限于加拉帕戈斯群岛和伊莎贝拉岛。","protection":"IUCN：CR（极危）","distribution":"繁殖区域限于加拉帕戈斯群岛的胡德岛（Hood Island，即西班牙岛Española）和厄瓜多尔沿岸的伊莎贝拉岛（Isla de la Plata）。非繁殖季节，它们分散至厄瓜多尔和秘鲁北部的沿海水域。","other":"加岛信天翁面临着长期线钓渔业的威胁，导致成年生存率下降，种群数量减少。非法捕鱼和食物市场的供应需求增加也对这一物种构成了严重威胁。"},{"name":"短尾信天翁","english_name":"Short-tailed Albatross","scientific_name":"Phoebastria albatrus","overview":"短尾信天翁（英文名：Short-tailed Albatross，学名：Phoebastria albatrus），是鹱形目信天翁科北太平洋信天翁属的鸟类。是北太平洋海域罕见的大型海鸟。历史上曾因羽毛贸易而濒临灭绝边缘，自20世纪50年代起受保护，现数量正逐渐恢复，呈现出增长趋势。分为两个主要亚群，一在伊豆群岛南部的鸟岛（Tori-shima），另一主要在东海的钓鱼岛及附属岛屿。成鸟整体白色，翼展可达215-230厘米，体重介于4.3至8.5千克，头部泛黄，喙呈鲜艳的粉红色。","appearance":"短尾信天翁体型中等，翼展约215至230厘米，身长84至94厘米，体重在4.3至8.5千克之间。成鸟通体白色，翅膀和部分覆羽为黑色，尾部末端黑色，背部带有淡黄或浅黄色调，喙大且粉红色，老年个体喙尖呈蓝色。幼鸟为深褐色，随着年龄增长逐渐变白，成熟需10至20年。与区域内其他两种信天翁相比，其体型更大，喙色独特。","call":"已描述的叫声包括嘶哑声、哀鸣和天空叫声，后者的音调更接近黑脚信天翁，而非翻翅信天翁。","habits":"栖息于开阔的海洋和远洋环境，集中于上升流区域。繁殖于火山灰覆盖的陡峭斜坡上，植被稀疏。在北太平洋范围内广泛迁徙，夏季聚集于白令海，冬季南下至北美的西海岸，最远可达南加州。以鱿鱼、鱼类、飞鱼卵和甲壳类动物为主食，夜间捕食，与暴雪鹱群聚于渔船附近。","breeding":"繁殖期始于十月，成鸟返回繁殖地，筑巢于火山岛的缓坡上，巢直径约60厘米，由泥土和植被构成。每年产一枚白色蛋，尺寸约为110.5×69.8毫米至124.7×79.4毫米，孵化期约64至65天。幼鸟出生时覆盖黑色灰色绒毛，离巢期为150至160天，但报道中提及可能长达180天。初次繁殖通常在8至9岁，平均繁殖成功率约为57%。","identification":"与黑脚信天翁和莱桑信天翁相比，短尾信天翁体型更大，喙色粉红，翼上有独特的白色斑块，头部和颈部带有淡黄色调。亚成体的羽色随年龄增长逐渐变白，区别于幼鸟的深褐色。","protection":"IUCN：VU（易危）；CITES: I（附录一）；中国国家一级保护动物；中国红皮书等级：e；列入《濒危野生动植物种国际贸易公约》附录I；国家重点保护野生动物名录保护级别由Ⅱ级调整为I级（2021.02.05）。","distribution":"繁殖于伊豆群岛南部的鸟岛、钓鱼岛的南岛、小笠原群岛的母岛（Yome-jima）及夏威夷群岛西北部的中途岛（Midway Atoll）。非繁殖期分布于北太平洋，从白令海至北回归线之间。","other":"历史上因羽毛贸易遭受重创，一度被认为灭绝。20世纪50年代后保护措施实施，数量开始缓慢恢复。近年来，通过人工饲养和重新引入项目，成功在多个岛屿建立新种群。"},{"name":"漂泊信天翁","english_name":"Snowy Albatross","scientific_name":"Diomedea exulans","overview":"漂泊信天翁（英文名：Snowy Albatross，学名：Diomedea exulans），是鹱形目信天翁科信天翁属的鸟类。是体型最大、翼展最长的鸟类之一，遍及南冰洋，被誉为‘南方海洋的流浪者’。与特里斯坦信天翁、安岛信天翁和阿岛信天翁同属于漂泊信天翁物种复合体。","appearance":"漂泊信天翁拥有令人惊叹的翼展，平均可达3.1米，已知最大个体翼展达到3.7米。其滑翔能力出众，可在空中持续数小时无需拍翅，每下降1米能滑翔22米。成鸟体长约1.35米，雌鸟较雄鸟略小。体重介于6至12公斤之间，雏鸟首次飞翔前体重可达16.1公斤。羽毛色彩随年龄变化，成年鸟体羽洁白，翼部黑白相间，雄鸟翼色更显纯白，翼尖和后缘为黑色。喙和脚均为粉红色，头部侧面有淡粉色斑点。","habits":"漂泊信天翁偏好南半球的广阔海域，尤其活跃于南纬40度的强风带，善于利用西风进行长距离飞行，一年中10个月可飞行1.5万公里。无风时在海面休息，夜间浮游。它是潜水高手，最深可下潜12米。以乌贼、小鱼和海洋废弃物为食。","breeding":"漂泊信天翁平均寿命约22.8年，大部分时间在海上度过。6-7岁成年后，雌鸟开始产卵。繁殖季节，它们在南冰洋岛屿（如奥克兰、新西兰、爱德华王子群岛）建立巢穴。巢呈火山状，底部宽约1米，顶部约半米，由植物材料构成。每季仅产一卵，孵化期长达78天，双亲共同育雏。","identification":"与同类相比，漂泊信天翁的羽色最为洁白，翼部黑白分明，头部侧面有淡粉色斑点，喙和脚为粉红色。与其他信天翁区分的关键在于翼展、羽色和喙部特征。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于南乔治亚岛、爱德华王子岛、克罗泽特岛、赫德岛和凯尔盖朗岛等高纬度岛屿。非繁殖区广泛分布于所有南半球海洋。"},{"name":"安岛信天翁","english_name":"Antipodean Albatross","scientific_name":"Diomedea antipodensis","overview":"安岛信天翁（英文名：Antipodean Albatross，学名：Diomedea antipodensis），是鹱形目信天翁科信天翁属的大型海鸟。体型稍小于漂泊信天翁，繁殖时羽毛以棕色为主，与年轻漂泊信天翁相似，但保持较暗色调。两个亚种主要在新西兰周边岛屿繁殖，分布于南太平洋至智利海域。","appearance":"成年安岛信天翁总长约110-117厘米，翼展可达2.8-3.3米。雄鸟繁殖羽色头部白色，额头和喉咙亦然，冠部深棕色，其余身体部位多为白色，带有深棕色的细纹。雌鸟颜色更深，巧克力棕色，羽毛尖端有浅色边缘，基部泛白，形成波浪状线条。上翼深巧克力棕色，下翼白色，但初级飞羽处有深色。喙部颜色从粉红到淡紫粉红，上喙尖有时带黄角质色，下喙尖端有一淡蓝灰色斑点。","call":"发出低沉的喉音，类似于漂泊信天翁。","habits":"栖息于海洋开阔区域和深海斜坡，对应海底山脉和大陆架断裂带高生产力区。在繁殖季节，活动于小岛较高地带。迁徙覆盖西南太平洋、南大洋和塔斯曼海。非繁殖期幼鸟迁徙模式不同，雄鸟向西至智利海域，而雌鸟和非繁殖期雄鸟迁往印度洋东南部。","breeding":"繁殖时间从12月底至次年1月间，筑巢于植被稀疏的草甸或灌木丛中，筑造直径约1米的巢穴。每窝仅产一枚蛋，孵化期约75-85天，双亲轮流孵化。雏鸟绒毛白色，抚养期长达九个月。","identification":"与漂泊信天翁和特里斯坦信天翁相比，安岛信天翁体型较小，羽毛更偏向棕白色混合，尾巴更深色。与阿岛信天翁的区别在于喙部无暗色条纹。雌雄差异体现在羽毛颜色深浅上。","protection":"IUCN：EN（濒危）","distribution":"繁殖于查塔姆群岛、安岛、奥克兰群岛和坎贝尔岛（新西兰东部、南部）。非繁殖期分布至塔斯曼海（澳大利亚东南部外海）和太平洋东南部。","other":"面临猪、野猫捕食和长线渔业的威胁，以及可能受海水温度上升的影响。"},{"name":"阿岛信天翁","english_name":"Amsterdam Albatross","scientific_name":"Diomedea amsterdamensis","overview":"阿岛信天翁（英文名：Amsterdam Albatross，学名：Diomedea amsterdamensis），是鹱形目信天翁科信天翁属的鸟类。又译: 阿姆斯特丹信天翁，体型庞大的信天翁，仅在印度洋南部的阿姆斯特丹岛繁殖。以巧克力棕色的羽毛而与众不同，区别于常见的白色信天翁。体重介于11至18磅之间，体长可达42至48英寸，翼展宽达110至130英寸。","appearance":"成年阿岛信天翁具有巧克力棕色的上部羽毛，面部、喉咙、下胸部和腹部为白色，拥有宽阔的棕色胸带和棕色的尾羽覆羽。喙部粉红，尖端和切割边缘深色，下翼除暗色尖端和前缘外均为白色。","habits":"栖息于亚热带沿海地区，可能以鱼、鱿鱼和甲壳类为食。在繁殖周期的孵卵阶段，非繁殖任务的个体可在印度洋广阔海域活动，行程可达2400公里。","breeding":"每两年在开阔的沼泽地繁殖，双亲轮流孵化80天，幼鸟出生后由双亲照料一个月，共需230天才能离巢。幼鸟初始每三天喂食一次，逐渐减少至离巢前。幼鸟成熟后，将在海上度过约五年，随后返回繁殖地并在几年后开始繁殖。","identification":"与漂泊信天翁极为相似，但羽色与其第三阶段羽毛颜色一致，外观酷似幼年的漂泊信天翁。","protection":"IUCN：EN（濒危）","distribution":"繁殖区位于印度洋：阿姆斯特丹岛。非繁殖区覆盖印度洋中南部至西部及澳大利亚水域。"},{"name":"特岛信天翁","english_name":"Tristan Albatross","scientific_name":"Diomedea dabbenena","appearance":"特里斯坦信天翁在海上几乎无法与漂泊信天翁区分，但体型略小，背部颜色稍深。体长约110厘米，翼展可达3.05米。与漂泊信天翁相比，特里斯坦信天翁从未达到完全的白色羽毛，且喙部较短约25毫米。","habits":"特里斯坦信天翁广泛分布于南大西洋，雄鸟通常向西至南美洲海域觅食，而雌鸟则向东至非洲海域。它们以鱼类和头足类为食。","breeding":"它们每两年繁殖一次，倾向于在海拔400至700米的湿润灌木丛中筑巢。特里斯坦信天翁在约10岁时开始繁殖，且是单配偶制。","identification":"与漂泊信天翁相比，特里斯坦信天翁的背部颜色更深，喙部较短，且年轻个体的尾巴颜色更深，头部和背部有棕色斑纹，喙的切割边缘没有黑色唇状突起。","protection":"IUCN：CR（极危）自2000年起，特里斯坦信天翁被列入IUCN红色名录的极危物种，因家鼠及延绳捕鱼对其种群造成了严重的威胁，导致数量急剧下降。","distribution":"繁殖于南大西洋的Inaccessible岛和戈夫岛（特里斯坦-达库尼亚群岛）。非繁殖季节，它们广泛分布于温带海洋亚热带和南大西洋海域。"},{"name":"皇信天翁","english_name":"Southern Royal Albatross","scientific_name":"Diomedea epomophora","overview":"皇信天翁（英文名：Southern Royal Albatross，学名：Diomedea epomophora），是鹱形目信天翁科信天翁属的鸟类。平均翼展超过3米，体长107-122厘米，体重约8.5公斤。曾与北皇信天翁被视为同一物种，现已确认为独立种。皇信天翁主要在新西兰的坎贝尔和奥克兰群岛繁殖。","appearance":"皇信天翁体型庞大，体长可达112至123厘米，平均体重8.5公斤，雄鸟较重，平均比雌鸟重2至3公斤。其翼展范围从2.9到3.28米，上限约3.5米。幼鸟头部、颈部、上背、臀部及下体白色，上背有黑色斑点，翅膀暗褐色或黑色，覆羽有白色斑点，尾巴除黑色尖端外皆白。随着成长，翅膀上的白色逐渐增多，从翼前缘开始显现。所有年龄阶段的个体喙呈粉色，上喙边缘黑色，腿肉色。","habits":"皇信天翁主要分布在南纬30°至45°之间，活跃于南大洋，尤其在南美洲西岸和东岸以及新西兰周边海域。它们倾向于在较浅水域和大陆架附近觅食，主要以乌贼和鱼类为食，偶尔也会摄取少量腐肉、甲壳类和水母。它们的觅食范围通常在繁殖地1250公里半径内。","breeding":"皇信天翁偏好在苔草草原、高原或山脊上筑巢，每隔两年产一卵，通常在11月或12月。双亲轮流孵卵并共同抚养后代。幼鸟大约需要240天才能完全长出飞羽独立飞行。一旦父母安顿下来，已产卵的死亡率极低。","identification":"皇信天翁与流浪信天翁（Wandering Albatross complex）的区别在于更干净的黑白外观，缺乏流浪信天翁常见的桃色颈斑。此外，皇信天翁的喙颜色略淡，上喙边缘的黑色部分较窄。","protection":"IUCN：VU（易危）","distribution":"繁殖区主要集中在太平洋的Enderby（奥克兰群岛）和坎贝尔岛（新西兰南部）。非繁殖季节广泛分布于所有温带海洋南部和南极海域。"},{"name":"北皇信天翁","english_name":"Northern Royal Albatross","scientific_name":"Diomedea sanfordi","overview":"北皇信天翁（英文名：Northern Royal Albatross，学名：Diomedea sanfordi），是鹱形目信天翁科信天翁属的大型海鸟。曾于1998年从近缘的皇信天翁中分离出来，但这一分类仍存争议。以其巨大的体型和独特的白色背部在南方海洋中独树一帜，主要繁殖于新西兰的查塔姆群岛，活动范围广泛。","appearance":"北皇信天翁体长约115厘米，体重介于6.2至8.2公斤，翼展可达270至305厘米。幼鸟头部、颈部、背部上部、臀部及下体呈白色，顶部和臀部有暗色斑点。下背部和背部白色，带有更多的黑色斑点，上翼深黑褐色，覆羽上有白色斑点。尾巴白色，尖端黑褐色，下翼亦如此。翼下前缘至腕关节间有一黑色带。随着年龄增长，头部、背部、臀部、尾部和肩胛区逐渐变白。所有年龄段的个体都有粉色的喙，上喙边缘为黑色，腿也是浅粉色。与皇信天翁相比，其上翼全部为深色。","habits":"以头足类、鱼类、甲壳类、水母及腐肉为食，其中鱿鱼可占其饮食的85%。它们在空中或水面进行广泛的互动或群体展示，一旦形成伴侣关系，展示动作变得朴素。繁殖始于八岁，每两年筑巢一次，偏好在常青草或灌木丛中建低矮的植被巢，由植物、泥土和羽毛构成。","breeding":"每年10月或11月产一枚卵，需双方约80天的孵化。雏鸟一个月后离巢，大约240天后能飞翔。其繁殖地密度高于其他大型信天翁。","identification":"与皇信天翁相比，北皇信天翁的上翼全部为深色，而皇信天翁上翼有大面积白色区域。此外，行为上的差异也能帮助辨别两者。","protection":"IUCN：EN（濒危）","distribution":"繁殖于查塔姆群岛（Forty-fours Island、Big Sister Island和Little Sister Island）、奥克兰群岛的Enderby Island以及新西兰奥塔哥半岛的Taiaroa Head。非繁殖期广泛分布于南半球的温带海洋和亚南极海域，尤其是太平洋的Humboldt Current和Patagonian Shelf。"},{"name":"乌信天翁","english_name":"Sooty Albatross","scientific_name":"Phoebetria fusca","overview":"乌信天翁（英文名：Sooty Albatross，学名：Phoebetria fusca），是鹱形目信天翁科乌信天翁属的鸟类。中等体型的海洋鸟类，体色以烟熏般的褐色为主，头部和尾部颜色更深。这种鸟广泛分布于南大西洋和印度洋，以及南极海域，主要以鱿鱼、鱼类和腐肉为食。一生一侣，每年回到固定的繁殖地，每两年繁殖一次，通常在南大西洋和印度洋的岛屿上筑巢。乌信天翁被列为濒危物种，目前正受到保护。","appearance":"乌信天翁体长约84-89厘米，体重雄鸟2200-3250克，雌鸟2100-2800克，翼展约203厘米。成鸟有鲜明的白色新月形眼环，覆盖上眼半部，连接到下眼半部的相似但较短的新月形眼环，仅至中长，其余羽毛呈深褐色或烟黑色，面部最暗，颈部和身体稍淡，飞羽再次变暗，但通常除了飞行羽毛的苍白轴线外，几乎没有对比。喙基部有黄色至黄橙色的中央线，腿为淡粉色或灰肉色。幼鸟喙部更均匀地呈烟黑色，有较脏的苍白部分眼环，飞羽轴线颜色更深；颈背较淡，翼覆羽边缘也较淡。","call":"主要的叫声是两音节的Sky-call，被描述为‘令人心碎的’叫声，通常在巢穴附近发出，头和喙垂直。","habits":"乌信天翁是远洋鸟类，很少接近陆地，除非是在繁殖地。它们栖息在偏远的海洋岛屿，偏好有陡峭岩石斜坡和草丛的区域，尤其是苔草丛生的地方。它们在南大西洋和印度洋的温带水域分散，主要在南纬30°-60°之间活动，最南端可达南极洲附近的约南纬65°，最北端约南纬20°，经度分布通常从阿根廷向东至塔斯马尼亚，偶尔到新南威尔士甚至麦夸里岛，以及新西兰。","breeding":"繁殖为双年周期，若繁殖成功，83%的失败繁殖者会在下一季尝试。繁殖始于7月至8月，交配平均在产卵前两周，产卵期在10月初至中旬，雏鸟于5月底离巢。繁殖群体松散，通常由多达约50对的小群体组成，有时单独筑巢。巢为低矮的圆锥形，由苔藓、草和泥土构成，高约20厘米，直径约30-40厘米，中间有凹陷。每窝产一枚白色蛋，平均孵化期约为70天，雏鸟在孵化后约21天被抱窝，每隔2.4-2.6天喂食一次，约160天后离巢。","identification":"与灰背信天翁的区别在于后者头部颜色与身体其他部位有更明显的对比，以及较不明显的蓝灰色喙线。与巨型海燕（giant-petrels）在初次观察时可能相似，但后者喙更大，呈球状粉红色，外观更长颈和驼背。与黑脚信天翁相比，后者至少在喙基部有一些白色，尾巴更短，方形而非楔形，脚伸出超出尾巴。","protection":"IUCN：EN（濒危）","distribution":"繁殖区分布在印度洋和大西洋的温带海洋和亚南极岛屿，包括南大西洋的特里斯坦-达库尼亚群岛和戈夫岛，以及印度洋的Amsterdam和圣保罗岛，爱德华王子群岛，Crozet和凯尔盖朗群岛。非繁殖期则分布于南大西洋和印度洋的温带海洋，集中在亚热带收敛带。","other":"乌信天翁面临的主要威胁包括自然因素如幼鸟被巨型海燕和岛上老鼠捕食，感染疾病如禽霍乱，以及人为因素如污染和延绳钓渔业。澳大利亚正在努力保护其繁殖地。此外，乌信天翁在特里斯坦-达库尼亚、戈夫岛（世界遗产地）和爱德华王子岛（自然保护区）受到保护。"},{"name":"灰背信天翁","english_name":"Light-mantled Albatross","scientific_name":"Phoebetria palpebrata","overview":"灰背信天翁（英文名：Light-mantled Albatross，学名：Phoebetria palpebrata），是鹱形目信天翁科乌信天翁属的鸟类。小体型的信天翁，与乌信天翁为伴。其命名由Johann Reinhold Forster在1785年基于南非好望角南部标本首次描述。","appearance":"灰背信天翁体长78至93厘米，体重雄鸟2800至3360克，雌鸟2620至3700克，翼展183至232厘米。具有尖锐的翅膀和楔形长尾，成鸟头部深色，颈背灰白，形成鲜明对比。眼周有一圈白色新月形羽毛，上半身至尾羽覆部灰至浅灰色，最淡于肩背部。喙黑色，具蓝色细纹。性别相似，但雄鸟略大。","call":"主要的叫声是在巢穴附近发出的双音节天空呼叫，伴有垂直举起的头和喙。","habits":"生活在南大洋的开阔海域，偏好较冷水域，繁殖于偏远的次南极岛屿，栖息于陡峭斜坡或悬崖，常位于内陆植被之中，如苔草或蕨类。广泛分布于南大洋，北至约33°S，南至77°50'S，偶尔在加利福尼亚中部被观察到。冬季通常因浮冰扩张而向北迁移。","breeding":"繁殖周期为两年一次，若成功，次年失败的59%的配对会再尝试。9月至10月抵达繁殖地，10月底开始产卵，孵化期67至70天，雏鸟孵化后约141至170天离巢。性成熟在7至12岁之间，但最早6岁时返回繁殖地。","identification":"与乌信天翁的区别在于颈部和背部的灰白色调。霍氏巨鹱虽同为深色海鸟，但体型更大，喙明显巨大且苍白。","protection":"IUCN：NT（近危）","distribution":"繁殖于从南乔治亚向东至麦夸里岛、安提波德斯岛、坎贝尔岛的次南极岛屿。非繁殖季节广泛分布于所有次南极海域，从亚热带收敛至南极。","other":"受全球变暖影响，印度洋地区的繁殖表现可能因高于正常水平的海面温度而较差。历史上曾在一些繁殖站如Kerguelen和爱德华王子岛遭受食物猎取。"},{"name":"黑眉信天翁","english_name":"Black-browed Albatross","scientific_name":"Thalassarche melanophris","overview":"黑眉信天翁（英文名：Black-browed Albatross，学名：Thalassarche melanophris），是鹱形目信天翁科小信天翁属的鸟类。又称黑眉洋海燕，是南大洋最常见、分布最广的中型信天翁，成鸟具白头、黑背及橙黄嘴端，繁殖于46°S–56°S的亚南极岛屿，越冬于30°S以南至南极海域，亦频繁漂泊至北半球。","appearance":"体长79–93厘米，翼展205–240厘米，重2.2–4.7千克。成鸟头颈白色，眼上方具黑色“眉斑”，背及上翼深灰至黑褐，下体及尾基白色；嘴橙黄，尖端粉红；脚灰蓝带粉红。雌雄同色，雄略大，唯嘴深、头宽可辨。幼鸟嘴暗褐具黑尖，翼下全黑褐；随年龄增长，嘴渐转黄，翼下白斑扩大，眉斑及颈灰色项环逐渐淡化，至六龄达成鸟羽色。","call":"主要发出粗哑“呱呱”声以示领地与识别，飞行中常作拖长“哀号”般长啸。坎贝尔亚种鸣声略有差异，但尚未详尽描述。","habits":"栖息于远洋及近岸水域，常随船、鲸群或其他海鸟觅食，可深入港湾甚至35千米内陆湖泊。食物以表层或潜水捕获的磷虾、灯笼鱼、鱿鱼及渔业废弃物为主。具强烈繁殖地忠诚，幼鸟2–6岁起返出生地，成鸟繁殖后向北迁徙，福克兰个体东移至巴西外海，南乔治亚个体则西迁至南非外海。","breeding":"每年9–10月返巢，配对终身。巢为泥草筑成之大型杯状，直径30–33厘米，间距约1米，筑于陡峭草丛坡或悬崖平台。10月下旬产卵一枚，白色，平均104×66毫米，重约257克；双亲轮流孵化66–72天，雏鸟灰白绒羽，育雏期116–130天，出巢体重2.5–3.5千克。性成熟8–12岁，平均10岁。","identification":"与同属相比，成鸟橙黄嘴端及明显黑色眉斑最易识别。大西洋黄鼻信天翁嘴细黑带黄脊，翼下白缘黑前缘；灰头信天翁头颈灰色、嘴大部黑色；白顶信天翁体型更大，嘴灰黑尖，翼下白而仅窄黑边。幼鸟需看翼下全黑、嘴黑尖及颈环区分。","protection":"IUCN：LC（无危）。坎贝尔亚种列为VU（易危）。","distribution":"繁殖：南大洋46°S–56°S，自南美合恩角、福克兰群岛、南乔治亚、克罗泽、凯尔盖朗、赫德、麦夸里岛至新西兰安蒂波德斯、斯奈尔斯及坎贝尔岛。非繁殖：广泛散布于30°S至南极大陆的南大西洋、南印度洋、南太平洋；北迁漂泊记录达欧洲、加拿大、格陵兰及地中海等北半球海域。","other":"文献推测柯勒律治《古舟子咏》中被射杀的信天翁可能为本种；19世纪一只持续造访法罗群岛的个体被射杀，成为“albatross around the neck”典故之一。坎贝尔亚种曾被视为独立种，与指名亚种在坎贝尔岛偶有混交。"},{"name":"坎岛信天翁","english_name":"Campbell Albatross","scientific_name":"Thalassarche impavida","overview":"坎岛信天翁（英文名：Campbell Albatross，学名：Thalassarche impavida），是鹱形目信天翁科小信天翁属的鸟类。中等体型的信天翁，仅在南太平洋新西兰的坎贝尔岛和相邻的Jeanette Marie小岛上繁殖。有时被视为黑眉信天翁的一个亚种，但自1998年起被多数专家认为是独立物种。其显著特征是淡黄色的眼虹膜。","appearance":"坎岛信天翁体重约3.21公斤，身长88厘米。成鸟与黑眉信天翁相似，主要区别在于眼色。它具有白色头部、颈部、臀部和下体，背部、上翼和尾巴为黑色。下翼白色，边缘黑色宽边。面部有黑色三角形环绕眼睛，喙黄色，尖端橙色，眼虹膜淡黄色。幼鸟喙呈棕灰色，尖端黑色，眼睛深色，下翼黑色较少。平均寿命估计为28年，可能因研究不足而偏低，多数信天翁可活过50岁。","habits":"坎岛信天翁栖息于南太平洋，主要在坎贝尔岛和Jeanette Marie岛的北部和西部海岸线繁殖。繁殖期间，它们在新西兰南岛、查塔姆上升流区至罗斯海一带觅食。幼鸟和非繁殖个体主要在南澳大利亚水域、塔斯曼海和西南太平洋活动。以鱼、鱿鱼、甲壳类、腐肉和胶状生物为食。","breeding":"坎岛信天翁偏好在低草丛、灯芯草或泥泞斜坡上筑巢。它们在10岁开始繁殖，繁殖成功率约为66%。成鸟于8月初返回繁殖地，9月底开始产卵。单枚卵需孵化约70天。雏鸟在孵化后约130天离巢。","identification":"与黑眉信天翁相比，坎岛信天翁最明显的区别在于其淡黄色的眼虹膜。幼鸟与成鸟在外貌上有明显差异，尤其是在喙的颜色和眼睛颜色上。","protection":"IUCN: VU（易危）。因繁殖地有限，该物种面临渔业威胁，尤其是长线钓和拖网捕鱼。1997年的调查估计有24,600对繁殖对。1992年至1997年间，样本群落数量以每年1.8%的速度增长。成鸟存活率为94.5%。分布范围广泛，但繁殖地非常有限。","distribution":"繁殖区位于太平洋的坎贝尔岛和Jeanette Marie岛（新西兰南岛南部）。非繁殖期分布至澳大利亚南部、罗斯海（南极）和太平洋中部。","other":"黑眉信天翁亚种"},{"name":"白顶信天翁","english_name":"Shy Albatross","scientific_name":"Thalassarche cauta","overview":"白顶信天翁（英文名：Shy Albatross，学名：Thalassarche cauta），是鹱形目信天翁科小信天翁属的鸟类。中等体型的信天翁，以塔斯马尼亚海岸附近的三个偏远岛屿为繁殖地，分布于南印度洋。这种信天翁寿命约为60年，已知最远迁徙至南非和美国太平洋沿岸。据最新数据，现存约15,350对繁殖对，使其成为澳大利亚唯一的特有种信天翁。","appearance":"成年白顶信天翁体长90-100厘米，翼展210-260厘米，重3.2-5.1千克。其头部呈白色，脸颊灰，形成独特的‘白帽’外观。喙灰绿色，尖端黄。幼鸟头部较灰，喙亦为灰色。成鸟背部暗灰色，翼下白色，翼尖有一黑色斑块。喙色灰蓝，尖端黄色。","call":"发出典型的嘎嘎声、呻吟声和哀嚎声。","habits":"主要栖息于海洋环境，常在大陆架附近活动，而非完全的远洋鸟类。繁殖季节，成鸟保持在繁殖地附近，而幼鸟则更为游荡，可达南非和纳米比亚。主要食物包括头足类、鱼类、甲壳类动物和藤壶。夜间也会进食，常跟随船只和鲸豚类。","breeding":"繁殖季节通常从9月开始，筑巢于岛屿斜坡或平坦地带，巢由泥土、鸟粪、羽毛、草和其他材料构成。产一枚带有红褐色斑点的白色蛋，孵化期68-75天，雏鸟孵化后由父母双方照料3-4周，之后每22小时喂食一次，平均喂食量为372克。雏鸟在112-136天后离巢，体重达到5-5.7千克。","identification":"与其他信天翁的区别在于头部和喙的颜色，萨氏信天翁头部更少白色，而查岛信天翁头部为石板灰色，且两者喙的颜色有所不同。幼鸟之间很难区分。","protection":"IUCN：NT（近危）","distribution":"繁殖于塔斯马尼亚州的阿尔巴特罗斯岛、佩德拉布兰卡岛和梅斯顿岛，以及新西兰的奥克兰群岛。非繁殖季节广泛分布于印度洋和南太平洋，可达南非、纳米比亚、美国太平洋沿岸。","other":"历史上曾因羽绒贸易而数量锐减，现今面临的主要威胁包括渔业误捕和疾病，以及与澳洲鲣鸟的竞争。"},{"name":"查岛信天翁","english_name":"Chatham Albatross","scientific_name":"Thalassarche eremita","overview":"查岛信天翁（英文名：Chatham Albatross，学名：Thalassarche eremita），是鹱形目信天翁科小信天翁属的鸟类。中等体型的黑白相间信天翁，仅在新西兰查塔姆群岛中的The Pyramid岩堆上繁殖。最小型的白顶信天翁群体成员之一。","appearance":"成年查岛信天翁重3.1至4.7公斤，长90厘米。头部、脸、上背部、背部、上翼、尾巴和喉咙呈深灰色，臀部和下体为白色。其翅膀前缘有黑色拇指印记，翼尖黑色，喙黄色，下喙尖端有暗斑。幼鸟的灰色更广泛，喙蓝灰色，上下喙尖黑。两性相似，但雌鸟平均尺寸略小。","call":"通常保持沉默，受威胁或求偶时会发出尖锐的嗡嗡声或嘶哑的叫声。求偶时会展开尾巴，互相对喙，伴随咕噜声。","habits":"栖息于海洋环境，偏好大陆架边缘，甚至靠近海岸。在繁殖季节，主要在查塔姆群岛周边300公里范围内觅食，通常在水深1000至4500米的海域活动。春季迁徙至南美洲西岸，利用洪堡流进入秘鲁沿海水域。飞行速度可达每小时85公里。","breeding":"每年繁殖一次，始于8月，9月中旬完成筑巢，10月至12月孵化，2月至4月幼鸟离巢。单个白色蛋，带有红褐色斑点，孵化期68至72天。幼鸟在第四个年头返回繁殖地，约六岁达到性成熟。","identification":"与萨氏信天翁区别在于后者有灰色喙和较浅灰的头部与颈部；与新西兰信天翁相比，体型较小，且上翼下缘有宽广的黑色边缘。幼鸟与其他种类幼鸟相似，但查岛信天翁头部最暗，喙上显示黄色。","protection":"IUCN：VU（易危）","distribution":"繁殖于查塔姆群岛的Pyramid Rock；非繁殖期分布于南太平洋，从塔斯马尼亚到智利和秘鲁，春季利用洪堡流沿南美海岸北上至6°S。","other":"1985年的一场风暴导致繁殖地植被条件恶化，影响巢穴稳定性，自1998年起状况有所改善。商业捕鱼对其生存构成威胁，尤其是长线捕鱼。非法猎杀雏鸟的情况偶尔发生。"},{"name":"萨氏信天翁","english_name":"Salvin's Albatross","scientific_name":"Thalassarche salvini","appearance":"萨氏信天翁体长约90厘米，翼展可达2.56米，体重介于3.3至4.9千克之间。成鸟具有银灰色的头顶，脸部、上喉部和上背呈灰色，背部、翅膀上部和尾巴为灰黑色。其臀部和下部为白色，翅膀下方有一黑色拇指印，翼尖和边缘为黑色。喙部为淡灰绿色，带有淡黄色的上缘和上颌尖端，下颌尖端有暗色斑点。幼鸟的灰色区域更广泛，喙部为蓝灰色，双颌尖端为黑色。","call":"关于萨氏信天翁的叫声和声乐行为的信息目前未知。","habits":"萨氏信天翁主要以鱼类和头足类为食，通过水面捕食和掠食获得食物。它们的栖息地包括南大洋的小岩岛，植被稀少，筑巢于由干泥、羽毛和一些鸟骨构成的泥台。繁殖期间，萨氏信天翁会在8月至9月间产卵，孵化期约为68至75天，雏鸟在大约4个月后离巢。","breeding":"萨氏信天翁每年繁殖一次，产卵期为8月底至9月，孵化期在10月的第三周开始。雏鸟可能在3月至4月间离巢。巢穴由干泥、羽毛和鸟骨构成，平均高度为85毫米，宽度为155毫米。单个蛋的尺寸约为104毫米×67毫米，孵化期持续68至75天。","identification":"与查岛信天翁相比，萨氏信天翁体型更大，喙部呈灰色；与白顶信天翁相比，头部颜色更深。然而，这些差异在海上观察时难以辨别，导致该物种在海上调查中的代表性不足。","protection":"IUCN：VU（易危）","distribution":"繁殖区：主要在印度洋和太平洋的Bounty群岛（大部分种群位于东部，靠近斯图尔特岛）、Snares西部（南部，新西兰南部）和克罗泽群岛（少数，印度洋南部）。非繁殖区：分布至南半球温带海域，包括澳大利亚东南部的亚热带水域，南美洲西海岸，以及南非沿海。","other":"萨氏信天翁面临来自拖网渔船和延绳钓渔业的威胁，世界种群数量自早期研究以来可能有所下降。1998年，Bounty群岛估计有30,750对，而1978年为76,000对。Snares群岛约有650对，克罗泽群岛的Île des Pingouins记录了4对。"},{"name":"灰头信天翁","english_name":"Grey-headed Albatross","scientific_name":"Thalassarche chrysostoma","appearance":"灰头信天翁平均体长81厘米，翼展可达2.2米，体重介于2.8至4.4千克之间，平均约为3.65千克。头部、喉部和上颈为暗灰色，上翼、背部和尾巴几乎全黑。腹部和臀部白色，眼后有一白色新月形斑纹。喙为黑色，上下边缘呈亮黄色，尖端转为粉橙色。下翼白色，前缘黑色较重，后缘黑色较浅。幼鸟喙和头部黑色，后颈颜色更深，眼后新月形斑纹不明显，下翼几乎全黑。","call":"发出哀号和嘶哑的叫声，类似大多数莫利莫克种类，尤其是黑眉信天翁。","habits":"高度远洋生活，比其他莫利莫克更远离大陆架，主要以乌贼为主食，也会食用鱼类、甲壳类、腐肉、头足类和鳗鱼。偶尔会潜入水下追逐猎物，最深可达7米，但并不频繁。不常跟随船只，除了在福克兰群岛附近。经常与其他管鼻目鸟类和鲸豚类共处。","breeding":"繁殖周期两年一次，始于9月初至10月返回繁殖地，雌鸟预产离巢平均持续约16天，产卵期最长20天，平均日期通常为10月20日左右，孵化大多在12月初，5月离巢，总在繁殖地停留时间约239天。单产一枚蛋，大小约为106毫米×68毫米，重量约276克，孵化期69至78天。雏鸟有白色或淡灰色绒毛，脸最白，每1.26天喂养一次，平均每次喂食量为616克。离巢平均约141天，体重达到3500至4000克，但90天大时体重达到峰值3500至4900克。","identification":"成鸟有灰色头罩，不同于黑眉信天翁的黑色眉毛，下翼前缘黑色较宽，喙的颜色形成独特图案。与黄鼻信天翁和布尔信天翁相比，可通过更明显的头罩外观和更宽的下翼黑色边缘识别。与黑眉信天翁相似，但喙的颜色和较浅的头部/颈部可防止混淆。下翼在'腕'和'肘'处的黑色较少。","protection":"IUCN：EN（濒危）","distribution":"繁殖区位于南大洋的亚南极岛屿，包括伊尔德丰索和迭戈拉米雷斯群岛（火地岛西南）、南乔治亚岛、爱德华王子岛、克罗泽群岛、凯尔盖伦群岛（印度洋西南至东南）、麦夸里岛（澳大利亚东南远海）和坎贝尔岛（新西兰南岛南部）。非繁殖区广泛分布于南部海洋，主要在亚热带收敛带。","other":"世界总数量估计在1990年代末为50万至60万只，每年约有8万至9.5万对繁殖。由于非法捕鱼和长线渔业的影响，种群数量急剧下降，特别是在南乔治亚岛，该地拥有全球一半以上的种群。"},{"name":"黄鼻信天翁","english_name":"Atlantic Yellow-nosed Albatross","scientific_name":"Thalassarche chlororhynchos","overview":"黄鼻信天翁（英文名：Atlantic Yellow-nosed Albatross，学名：Thalassarche chlororhynchos），是鹱形目信天翁科小信天翁属的鸟类。曾一度被视为与印度洋黄鼻信天翁同种，现被确认为独立物种。大型海鸟，但在信天翁家族中体型较小。分布于南大西洋的特里斯坦-达库尼亚群岛和戈夫岛，繁殖于此。","appearance":"平均体长81厘米，典型的黑白色系，头部呈灰色，眼周有明显的眼斑，颈背和后颈白色。喙黑色，带有黄色的上缘和粉色尖端。背部、尾部和上翼深灰，腹部以白色为主。下翼和初级飞羽边缘有一条狭窄的黑色线条。幼鸟头部白色，喙黑色。与印度洋黄鼻信天翁相比，其头部颜色更深。","habits":"栖息于南大西洋海域，活动范围从南美洲至非洲，纬度介于15°S至45°S之间。以鱿鱼、鱼类、乌贼和甲壳类为食，有时夜间觅食。","breeding":"在特里斯坦-达库尼亚群岛和戈夫岛上的岛屿上筑巢繁殖，巢穴建在灌木丛中、悬崖顶上或Blechnum树蕨之间。每年9月或10月初开始筑巢，次年3月底至4月初幼鸟离巢。","identification":"与印度洋黄鼻信天翁的区别在于头部颜色更深，与灰头信天翁相比，下翼黑色边缘更窄，与萨氏信天翁的区别在于翼展较窄，喙色较淡。","protection":"IUCN：EN（濒危）","distribution":"繁殖区域位于南大西洋的特里斯坦-达库尼亚群岛（包括不可达岛、中间岛、夜莺岛、Stoltenhoff岛）和戈夫岛。非繁殖季节主要在南大西洋，从南回归线到亚热带汇合区。","other":"面临的主要威胁来自延绳钓捕鱼业。Gough岛和不可达岛为自然保护区，Gough岛还被列为世界遗产地。"},{"name":"印度洋黄鼻信天翁","english_name":"Indian Yellow-nosed Albatross","scientific_name":"Thalassarche carteri","overview":"印度洋黄鼻信天翁（英文名：Indian Yellow-nosed Albatross，学名：Thalassarche carteri），是鹱形目信天翁科小信天翁属的鸟类。大型海鸟。最小的mollymawks成员之一，2004年被BirdLife International从黄鼻信天翁中分离出来。分布于印度洋南方岛屿，自爱德华王子群岛至阿姆斯特丹岛和圣保罗岛。","appearance":"成鸟体长76厘米，翼展约2米，体重5.6磅，头部呈淡灰色或白色，背部、翅膀上部和尾巴为深灰色。腹部和臀部为白色，翅膀下方白色，带黑色尖端和前缘狭窄的黑色边缘。喙为黑色，带有黄色上缘和红色尖端。幼鸟头部白色，喙全黑，与黄鼻信天翁相比，其头部灰羽更浅。","habits":"在南印度洋的亚热带海域活动，从南非到澳大利亚，偶尔到达新西兰。以鱼、甲壳类和头足类为食。","breeding":"在8岁时开始繁殖，每年在8月开始筑巢，9月至10月产单卵，筑巢于裸露的岩石区或草丛、蕨类中。孵化期约70天，雏鸟约115天离巢。","identification":"与灰头信天翁和黄鼻信天翁相似，但可通过头部颜色和翅膀下的图案加以区分。","protection":"IUCN：EN（濒危）","distribution":"繁殖于爱德华王子群岛、克罗泽群岛、阿姆斯特丹岛、圣保罗岛和凯尔盖朗群岛。非繁殖期主要分布在印度洋的亚热带海域，介于Tropic南部和Capricorn之间。"},{"name":"新西兰信天翁","english_name":"Buller's Albatross","scientific_name":"Thalassarche bulleri","overview":"新西兰信天翁（英文名：Buller's Albatross，学名：Thalassarche bulleri），是鹱形目信天翁科小信天翁属的鸟类。小型信天翁，在新西兰周边岛屿繁殖，主要在澳大利亚和南太平洋海域觅食。","appearance":"新西兰信天翁体长约76-81厘米，体重雄鸟2500-3800克，雌鸟2150-3200克。翼展可达205-213厘米。其显著特征是下翼有宽厚的黑色前缘，成年个体头部有灰色至灰褐色兜帽，头顶银白色，背部、上翼和尾巴暗灰色，腹部和臀部白色。下翼白色，但有较窄的黑色后缘和更宽的黑色翼尖及前缘。喙大部分黑色，有黄色边缘，尖端亦为黄色。幼鸟头部颜色略深，喙色较暗。","call":"新西兰信天翁主要有三种叫声：一种嘶哑的叫声，雄鸟的叫声比雌鸟更持久；一种持续约2.2秒的哀号，主要由雄鸟发出，用于求偶；还有一种多音节的呻吟声。此外，还有四种由上下喙接触产生的机械声音。","habits":"主要栖息于海洋和远洋环境中，极少靠近陆地，仅在繁殖季节访问岛屿。以乌贼（尤其是Ommastrephid乌贼）、鱼（Moridae科）、被囊动物（Pyrosoma）和甲壳动物为食。通常在水面捕食，偶尔会从空中或水面进行浅水潜水。经常跟随船只。","breeding":"每年繁殖一次，开始时间随亚种而异，一般在10月（platei亚种）或1月（bulleri亚种）。雄鸟通常比雌鸟早七天返回繁殖地。筑巢于草坡或巨石之间，常在植被稀疏的地区，如狭窄的海岸台地。巢由草、根和泥土构成。每窝产一枚淡褐色斑点的白色蛋，平均大小103.1 x 64.7毫米，重约246克。孵化期约69-72天，双亲轮流孵卵，平均每次换班10-11天。雏鸟孵化后15-30天仍需父母照料，约167天后离巢。","identification":"与较大的Salvin's和查岛信天翁相比，新西兰信天翁的下翼黑色前缘更宽，但比灰头信天翁的窄。幼鸟头部颜色较深，喙色较暗。成鸟与灰头信天翁的区别在于喙上有更多的黄色。platei亚种头部颜色更深，喙更宽。","protection":"IUCN：NT（近危）","distribution":"繁殖于新西兰的斯内尔斯群岛、索兰德岛、查塔姆群岛（大姐妹岛、小姐妹岛和四十岛）及三王群岛的Rosemary Rock。非繁殖期广泛分布于澳大利亚东西部沿海水域及南美洲南部。"}];
